// Temas de Repercussão Geral do STF (com tese firmada).
// Fonte: planilha oficial temasrg.xlsx do STF. Best-effort; confira no portal do STF.
window.ENTRIES = (window.ENTRIES || []).concat([
  { id: "stf-rg-1", tribunal: "STF", tipo: "Repercussão Geral", numero: "1", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Base de cálculo do PIS e da COFINS sobre a importação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1",
    texto: "É inconstitucional a parte do art. 7º, I, da Lei 10.865/2004 que acresce à base de cálculo da denominada PIS/COFINS-Importação o valor do ICMS incidente no desembaraço aduaneiro e o valor das próprias contribuições." },
  { id: "stf-rg-2", tribunal: "STF", tipo: "Repercussão Geral", numero: "2", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reserva de lei complementar para a suspensão da contagem do prazo prescricional para causas de pequeno valor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=2",
    texto: "I - Normas relativas à prescrição e decadência em matéria tributária são reservadas à lei complementar; II - São inconstitucionais o parágrafo único do artigo 5º do Decreto-Lei 1.569/1977 e os artigos 45 e 46 da Lei 8.212/1991." },
  { id: "stf-rg-3", tribunal: "STF", tipo: "Repercussão Geral", numero: "3", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Prazo prescricional para a cobrança de contribuições sociais devidas à Seguridade Social.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=3",
    texto: "São inconstitucionais o parágrafo único do artigo 5º do Decreto-Lei 1.569/1977 e os artigos 45 e 46 da Lei 8.212/1991, que tratam de prescrição e decadência de crédito tributário." },
  { id: "stf-rg-4", tribunal: "STF", tipo: "Repercussão Geral", numero: "4", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Termo a quo do prazo prescricional da ação de repetição de indébito relativa a tributos sujeitos a lançamento por homologação e pagos antecipadamente.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=4",
    texto: "É inconstitucional o art. 4º, segunda parte, da Lei Complementar 118/2005, de modo que, para os tributos sujeitos a homologação, o novo prazo de 5 anos para a repetição ou compensação de indébito aplica-se tão somente às ações ajuizadas após o decurso da vacatio legis de 120 dias, ou seja, a partir de 9 de junho de 2005." },
  { id: "stf-rg-5", tribunal: "STF", tipo: "Repercussão Geral", numero: "5", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Compensação da diferença de 11,98%, resultante da conversão em URV dos valores em cruzeiros reais, com o reajuste ocorrido na data-base subseqüente.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=5",
    texto: "I - Ao editar a Lei 8.880/1994, a União legislou sobre o sistema monetário e exerceu a sua competência prevista no art. 22, VI, da Constituição de 1988. Assim, qualquer lei, seja ela estadual ou municipal, que discipline a conversão da moeda Cruzeiro Real em URV no que tange à remuneração de seus servidores de uma forma incompatível com a prevista na Lei nº 8.880/94 será inconstitucional, mormente quando acarretar redução de vencimentos; II - O término da incorporação, na remuneração do servidor, do percentual devido em razão da ilegalidade na conversão de Cruzeiros Reais em URV deve ocorrer no momento em que a carreira do servidor passa por uma restruturação remuneratória." },
  { id: "stf-rg-7", tribunal: "STF", tipo: "Repercussão Geral", numero: "7", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Redução, de ofício, de multa fixada em sentença, no caso de descumprimento de obrigação de fazer.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=7",
    texto: "A questão da possibilidade de o juízo reduzir, de ofício, multa fixada em sentença, no caso de descumprimento de obrigação de fazer, ou não fazer (art. 461, § 6º, atual art. 537, § 1º, do Código de Processo Civil), não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica, que transcenda ao interesse das partes" },
  { id: "stf-rg-8", tribunal: "STF", tipo: "Repercussão Geral", numero: "8", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade do lucro da exportação à CSLL após a Emenda Constitucional nº 33/2001.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=8",
    texto: "A Contribuição Social sobre o Lucro Líquido – CSLL incide sobre o lucro decorrente das exportações. A imunidade prevista no artigo 149, § 2º, inciso I, da Constituição Federal, com a redação dada pela Emenda Constitucional nº 33/2001, não o alcança." },
  { id: "stf-rg-9", tribunal: "STF", tipo: "Repercussão Geral", numero: "9", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Indenização por danos morais e materiais decorrentes de manipulação de resultados de partidas de futebol.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=9",
    texto: "A questão do pagamento de indenização por danos morais e materiais decorrentes de manipulação de resultados de partidas de futebol não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica, que transcenda ao interesse das partes." },
  { id: "stf-rg-10", tribunal: "STF", tipo: "Repercussão Geral", numero: "10", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Vício de iniciativa de projeto de lei que tornou obrigatória a instalação de semáforo com dispositivo de acionamento pelos próprios pedestres.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=10",
    texto: "A questão do vício de iniciativa de projeto de lei distrital que torna obrigatória a instalação de semáforo com dispositivo de acionamento pelos próprios pedestres nas vias nele especificadas não tem repercussão geral, por disciplinar situação de interesse local e ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-11", tribunal: "STF", tipo: "Repercussão Geral", numero: "11", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Prazo para pagamento de parcelas em dinheiro fixadas por sentença que julgou processo de desapropriação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=11",
    texto: "A questão da adoção do regime de pagamento parcelado de precatórios do art. 78 do Ato das Disposições Constitucionais Transitórias - ADCT para saldar crédito reconhecido na sentença proferida em ação de desapropriação por interesse social para fins de reforma agrária não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-12", tribunal: "STF", tipo: "Repercussão Geral", numero: "12", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "a) Competência exclusiva dos Municípios para decretar desapropriação por interesse público com vistas à construção ou ampliação de distritos industriais; b) Existência de desvio de finalidade na expedição de decreto expropriatório.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=12",
    texto: "I - A questão da legitimidade do Estado para editar decreto expropriatório por interesse público de imóvel localizado em Município, destinado à construção ou ampliação de distritos industriais, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes; II - A questão da configuração de desvio de finalidade do decreto expropriatório, que beneficia uma pessoa ou somente interesse privado, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-13", tribunal: "STF", tipo: "Repercussão Geral", numero: "13", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Responsabilidade solidária dos sócios das empresas por quotas de responsabilidade limitada por dívidas junto à Seguridade Social.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=13",
    texto: "É inconstitucional o art. 13 da Lei 8.620/1993, na parte em que estabelece que os sócios de empresas por cotas de responsabilidade limitada respondem solidariamente, com seus bens pessoais, por débitos junto à Seguridade Social." },
  { id: "stf-rg-14", tribunal: "STF", tipo: "Repercussão Geral", numero: "14", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Exigibilidade de cobrança amigável prévia ao ajuizamento da execução fiscal, prevista em Código Tributário Municipal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=14",
    texto: "A questão da realização da cobrança amigável pela Administração Pública municipal, prévia ao ajuizamento da execução fiscal, se a exigibilidade está prevista em Código Tributário Municipal, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-15", tribunal: "STF", tipo: "Repercussão Geral", numero: "15", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de praça à remuneração não inferior a um salário-mínimo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=15",
    texto: "Não viola a Constituição o estabelecimento de remuneração inferior ao salário mínimo para as praças prestadoras de serviço militar inicial." },
  { id: "stf-rg-16", tribunal: "STF", tipo: "Repercussão Geral", numero: "16", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Cobrança de taxa pela utilização potencial do serviço de extinção de incêndio.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=16",
    texto: "A segurança pública, presentes a prevenção e o combate a incêndios, faz-se, no campo da atividade precípua, pela unidade da Federação, e, porque serviço essencial, tem como a viabilizá-la a arrecadação de impostos, não cabendo ao Município a criação de taxa para tal fim." },
  { id: "stf-rg-17", tribunal: "STF", tipo: "Repercussão Geral", numero: "17", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "a) Possibilidade de cobrança de ligações sem discriminação dos pulsos além da franquia; b) Justiça competente para dirimir controvérsias acerca da possibilidade de cobrança de ligações sem discriminação dos pulsos além da franquia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=17",
    texto: "Compete à Justiça estadual julgar causas entre consumidor e concessionária de serviço público de telefonia, quando a ANATEL não seja litisconsorte passiva necessária, assistente, nem opoente." },
  { id: "stf-rg-18", tribunal: "STF", tipo: "Repercussão Geral", numero: "18", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Fracionamento de execução contra a Fazenda Pública para pagamento de honorários advocatícios.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=18",
    texto: "Os honorários advocatícios incluídos na condenação ou destacados do montante principal devido ao credor consubstanciam verba de natureza alimentar cuja satisfação ocorrerá com a expedição de precatório ou requisição de pequeno valor, observada ordem especial restrita aos créditos dessa natureza." },
  { id: "stf-rg-19", tribunal: "STF", tipo: "Repercussão Geral", numero: "19", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Indenização pelo não-encaminhamento de projeto de lei de reajuste anual dos vencimentos de servidores públicos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=19",
    texto: "O não encaminhamento de projeto de lei de revisão anual dos vencimentos dos servidores públicos, previsto no inciso X do art. 37 da CF/1988, não gera direito subjetivo a indenização. Deve o Poder Executivo, no entanto, se pronunciar, de forma fundamentada, acerca das razões pelas quais não propôs a revisão." },
  { id: "stf-rg-20", tribunal: "STF", tipo: "Repercussão Geral", numero: "20", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Alcance da expressão “folha de salários”, para fins de instituição de contribuição social sobre o total das remunerações.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=20",
    texto: "A contribuição social a cargo do empregador incide sobre ganhos habituais do empregado, quer anteriores ou posteriores à Emenda Constitucional nº 20/1998." },
  { id: "stf-rg-21", tribunal: "STF", tipo: "Repercussão Geral", numero: "21", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Fixação de alíquota progressiva para o imposto sobre transmissão causa mortis e doação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=21",
    texto: "É constitucional a fixação de alíquota progressiva para o Imposto sobre Transmissão Causa Mortis e Doação — ITCD." },
  { id: "stf-rg-22", tribunal: "STF", tipo: "Repercussão Geral", numero: "22", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Restrição à participação em concurso público de candidato que responde a processo criminal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=22",
    texto: "Sem previsão constitucionalmente adequada e instituída por lei, não é legítima a cláusula de edital de concurso público que restrinja a participação de candidato pelo simples fato de responder a inquérito ou ação penal." },
  { id: "stf-rg-23", tribunal: "STF", tipo: "Repercussão Geral", numero: "23", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Equiparação remuneratória entre procuradores autárquicos e procuradores estaduais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=23",
    texto: "A questão da possibilidade de equiparação dos proventos dos Procuradores de Autarquia e dos Procuradores de Estado para incidência do teto remuneratório da Emenda Constitucional n. 41/2003 não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-24", tribunal: "STF", tipo: "Repercussão Geral", numero: "24", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Base de cálculo do adicional por tempo de serviço de servidor público admitido antes da Emenda Constitucional nº 19/98.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=24",
    texto: "I - O art. 37, XIV, da Constituição Federal, na redação dada pela Emenda Constitucional 19/98, é autoaplicável; II - Não há direito adquirido a regime jurídico, notadamente à forma de composição da remuneração de servidores públicos, observada a garantia da irredutibilidade de vencimentos." },
  { id: "stf-rg-25", tribunal: "STF", tipo: "Repercussão Geral", numero: "25", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Vinculação do adicional de insalubridade ao salário mínimo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=25",
    texto: "Salvo nos casos previstos na Constituição, o salário mínimo não pode ser usado como indexador de base de cálculo de vantagem de servidor público ou de empregado, nem ser substituído por decisão judicial." },
  { id: "stf-rg-26", tribunal: "STF", tipo: "Repercussão Geral", numero: "26", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Concessão de aposentadoria especial a policiais civis nos termos da Lei Complementar nº 51/1985.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=26",
    texto: "O inciso I do artigo 1º da Lei complementar 51/1985 foi recepcionado pela Constituição Federal de 1988." },
  { id: "stf-rg-27", tribunal: "STF", tipo: "Repercussão Geral", numero: "27", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Meios de comprovação do estado miserabilidade do idoso para fins de percepção de benefício de assistência continuada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=27",
    texto: "É inconstitucional o § 3º do artigo 20 da Lei 8.742/1993, que estabelece a renda familiar mensal per capita inferior a um quarto do salário mínimo como requisito obrigatório para concessão do benefício assistencial de prestação continuada previsto no artigo 203, V, da Constituição." },
  { id: "stf-rg-28", tribunal: "STF", tipo: "Repercussão Geral", numero: "28", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Fracionamento da execução com expedição de precatório para pagamento de parte incontroversa da condenação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=28",
    texto: "Surge constitucional expedição de precatório ou requisição de pequeno valor para pagamento da parte incontroversa e autônoma do pronunciamento judicial transitada em julgado observada a importância total executada para efeitos de dimensionamento como obrigação de pequeno valor." },
  { id: "stf-rg-29", tribunal: "STF", tipo: "Repercussão Geral", numero: "29", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Vício de iniciativa de lei municipal, proposta pelo Poder Legislativo local, que veda a contratação de parentes de 1º e 2º graus do Prefeito e Vice-Prefeito para ocuparem cargos comissionados.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=29",
    texto: "Leis que tratam dos casos de vedação a nepotismo não são de iniciativa exclusiva do Chefe do Poder Executivo." },
  { id: "stf-rg-30", tribunal: "STF", tipo: "Repercussão Geral", numero: "30", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de servidor comissionado exonerado receber férias não gozadas acrescidas de um terço.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=30",
    texto: "I - O direito individual às férias é adquirido após o período de doze meses trabalhados, sendo devido o pagamento do terço constitucional independente do exercício desse direito; II - A ausência de previsão legal não pode restringir o direito ao pagamento do terço constitucional aos servidores exonerados de cargos comissionados que não usufruíram férias." },
  { id: "stf-rg-31", tribunal: "STF", tipo: "Repercussão Geral", numero: "31", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Exigência de garantia real ou fidejussória para impressão de documentos fiscais de contribuintes inadimplentes.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=31",
    texto: "É inconstitucional o uso de meio indireto coercitivo para pagamento de tributo – “sanção política” –, tal qual ocorre com a exigência, pela Administração Tributária, de fiança, garantia real ou fidejussória como condição para impressão de notas fiscais de contribuintes com débitos tributários." },
  { id: "stf-rg-32", tribunal: "STF", tipo: "Repercussão Geral", numero: "32", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reserva de lei complementar para instituir requisitos à concessão de imunidade tributária às entidades beneficentes de assistência social.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=32",
    texto: "A lei complementar é forma exigível para a definição do modo beneficente de atuação das entidades de assistência social contempladas pelo art. 195, § 7º, da CF, especialmente no que se refere à instituição de contrapartidas a serem por elas observadas." },
  { id: "stf-rg-33", tribunal: "STF", tipo: "Repercussão Geral", numero: "33", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Relevância e urgência da medida provisória nº 2.170-36/2001 que disciplina a capitalização de juros com periodicidade inferior a um ano nas operações realizadas pelas instituições integrantes do Sistema Financeiro Nacional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=33",
    texto: "Os requisitos de relevância e urgência previstos no art. 62 da Constituição Federal estão presentes na Medida Provisória 2.170-36/2001, que autoriza a capitalização de juros com periodicidade inferior a um ano nas operações realizadas pelas instituições integrantes do Sistema Financeiro Nacional." },
  { id: "stf-rg-34", tribunal: "STF", tipo: "Repercussão Geral", numero: "34", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Ampliação da base de cálculo e majoração da alíquota da COFINS pela Lei nº 10.833/2003, resultante da conversão da Medida Provisória nº 135/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=34",
    texto: "É constitucional a previsão em lei ordinária que introduz a sistemática da não-cumulatividade a COFINS dado que observa os princípios da legalidade, isonomia, capacidade contributiva global e não-confisco." },
  { id: "stf-rg-35", tribunal: "STF", tipo: "Repercussão Geral", numero: "35", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "a) Tarifa básica de assinatura do serviço de telefonia fixa. b) Competência para processar e julgar ação em que se discute a legalidade da cobrança da tarifa básica de assinatura do serviço de telefonia fixa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=35",
    texto: "I – Compete à Justiça Estadual processar e julgar ação ajuizada pelo consumidor contra concessionária de serviço público de telefonia na qual não haja interesse jurídico da Anatel em integrar a lide;* II - A questão alusiva à cobrança da tarifa de assinatura básica mensal é unicamente de direito e não apresenta complexidade apta a afastar o seu processamento pelo Juizado Especial; e III – A questão da cobrança de assinatura ou tarifa mensal básica da telefonia fixa tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009. * Exclusivamente quanto a esse ponto, o Tribunal reconheceu a existência de repercussão geral." },
  { id: "stf-rg-36", tribunal: "STF", tipo: "Repercussão Geral", numero: "36", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência da Justiça do Trabalho para execução de contribuições previdenciárias.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=36",
    texto: "A competência da Justiça do Trabalho prevista no art. 114, VIII, da Constituição Federal alcança somente a execução das contribuições previdenciárias relativas ao objeto da condenação constante das sentenças que proferir, não abrangida a execução de contribuições previdenciárias atinentes ao vínculo de trabalho reconhecido na decisão, mas sem condenação ou acordo quanto ao pagamento das verbas salariais que lhe possam servir como base de cálculo." },
  { id: "stf-rg-37", tribunal: "STF", tipo: "Repercussão Geral", numero: "37", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade objetiva do Estado por indenização referente a danos morais decorrentes de emissão de números idênticos de CPF para pessoas distintas, que implicou indevida inscrição em cadastro restritivo de crédito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=37",
    texto: "A questão da responsabilidade civil do Estado por danos morais decorrentes da emissão para mais de uma pessoa de idêntico número no Cadastro de Pessoas Físicas - CPF, ocasionando indevida inscrição de restrição ao crédito pessoal, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-38", tribunal: "STF", tipo: "Repercussão Geral", numero: "38", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Tema cancelado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=38",
    texto: "Em duplicidade com o Tema 37 da repercussão geral." },
  { id: "stf-rg-39", tribunal: "STF", tipo: "Repercussão Geral", numero: "39", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão aos professores inativos da rede pública de ensino do Estado de São Paulo dos benefícios denominados “bônus” e “bônus mérito” concedidos aos professores em atividade.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=39",
    texto: "A questão da extensão aos professores aposentados do ensino público de São Paulo das vantagens pecuniárias denominadas “bônus” e “bônus mérito”, concedidas aos professores em atividade pelas Leis Complementares estaduais ns. 891/2000, 909/2001, 928/2002, 948/2003 e 963/2004, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-40", tribunal: "STF", tipo: "Repercussão Geral", numero: "40", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Cobrança de taxa de matrícula em universidades públicas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=40",
    texto: "A cobrança de taxa de matrícula nas universidades públicas viola o disposto no art. 206, IV, da Constituição Federal." },
  { id: "stf-rg-41", tribunal: "STF", tipo: "Repercussão Geral", numero: "41", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito adquirido à forma de cálculo de parcelas incorporadas à remuneração.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=41",
    texto: "I - Não há direito adquirido a regime jurídico, desde que respeitado o princípio constitucional da irredutibilidade de vencimentos; II - A Lei complementar 203/2001, do Estado do Rio Grande do Norte, no ponto que alterou a forma de cálculo de gratificações e, consequentemente, a composição da remuneração de servidores públicos, não ofende a Constituição da República de 1988, por dar cumprimento ao princípio da irredutibilidade da remuneração." },
  { id: "stf-rg-42", tribunal: "STF", tipo: "Repercussão Geral", numero: "42", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Retenção de parcela do produto da arrecadação do ICMS, pertencente aos Municípios, em razão da concessão de incentivos fiscais pelo Estado-membro.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=42",
    texto: "A retenção da parcela do ICMS constitucionalmente devida aos municípios, a pretexto de concessão de incentivos fiscais, configura indevida interferência do Estado no sistema constitucional de repartição de receitas tributárias." },
  { id: "stf-rg-43", tribunal: "STF", tipo: "Repercussão Geral", numero: "43", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para julgar reclamações de empregados temporários submetidos a regime especial disciplinado em lei local editada antes da Constituição de 1988.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=43",
    texto: "Compete à Justiça comum processar e julgar causas instauradas entre o Poder Público e seus servidores submetidos a regime especial disciplinado por lei local editada antes da Constituição Federal de 1988, com fundamento no artigo 106 da Constituição de 1967, na redação que lhe deu a Emenda Constitucional 1/1969." },
  { id: "stf-rg-44", tribunal: "STF", tipo: "Repercussão Geral", numero: "44", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Constitucionalidade da instituição de contribuição para o custeio do serviço de iluminação pública.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=44",
    texto: "O serviço de iluminação pública não pode ser remunerado mediante taxa." },
  { id: "stf-rg-45", tribunal: "STF", tipo: "Repercussão Geral", numero: "45", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de execução provisória de obrigação de fazer contra a Fazenda Pública.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=45",
    texto: "A execução provisória de obrigação de fazer em face da Fazenda Pública não atrai o regime constitucional dos precatórios." },
  { id: "stf-rg-46", tribunal: "STF", tipo: "Repercussão Geral", numero: "46", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Cobrança do Encargo de Capacidade Emergencial criado pela Lei nº 10.438/2002.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=46",
    texto: "É constitucional a cobrança dos encargos instituídos pela Lei 10.438/2002, os quais não possuem natureza tributária, mas de tarifa ou preço público." },
  { id: "stf-rg-47", tribunal: "STF", tipo: "Repercussão Geral", numero: "47", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Natureza do controle externo exercido pelos Tribunais de Contas Estaduais em relação a atos administrativos dos Municípios.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=47",
    texto: "A competência técnica do Tribunal de Contas do Estado, ao negar registro de admissão de pessoal, não se subordina à revisão pelo Poder Legislativo respectivo." },
  { id: "stf-rg-48", tribunal: "STF", tipo: "Repercussão Geral", numero: "48", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reserva legal para a criação de cargos e reestruturação de órgão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=48",
    texto: "A Constituição da República não oferece guarida à possibilidade de o Governador do Distrito Federal criar cargos e reestruturar órgãos públicos por meio de simples decreto." },
  { id: "stf-rg-49", tribunal: "STF", tipo: "Repercussão Geral", numero: "49", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Creditamento de IPI sobre aquisição de insumos ou produtos intermediários aplicados na fabricação de produtos finais sujeitos à alíquota zero ou isentos, em período anterior à Lei nº 9.779/99.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=49",
    texto: "O direito do contribuinte de utilizar-se de crédito relativo a valores pagos a título de Imposto sobre Produtos Industrializados – IPI, oriundo da aquisição de matéria-prima a ser empregada em produto final beneficiado pela isenção ou tributado à alíquota zero, somente surgiu com a Lei nº 9.779/1999, não se mostrando possível a aplicação retroativa da norma." },
  { id: "stf-rg-50", tribunal: "STF", tipo: "Repercussão Geral", numero: "50", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL MILITAR", titulo: "Possibilidade de substituir-se a formalização de acórdão fundamentado por certidão a qual contenha o resultado de julgamento.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=50",
    texto: "O artigo 118, § 3º, do Regimento Interno do Superior Tribunal Militar — que prevê que o resultado do julgamento de agravo interposto perante aquela Corte será certificado nos autos pela Secretaria do Tribunal Pleno — não pode implicar a ausência de lavratura do acórdão, sob pena de afronta às garantias constitucionais da motivação e da publicidade dos pronunciamentos judiciais." },
  { id: "stf-rg-51", tribunal: "STF", tipo: "Repercussão Geral", numero: "51", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Cobrança da alíquota de 0,38% da CPMF nos noventa dias posteriores à publicação da Emenda Constitucional nº 42/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=51",
    texto: "A Emenda Constitucional 42/2003 não introduziu aumento de alíquota para cobrança da CPMF e, portanto, não violou o princípio da anterioridade nonagesimal." },
  { id: "stf-rg-52", tribunal: "STF", tipo: "Repercussão Geral", numero: "52", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência da Contribuição Provisória sobre Movimentação Financeira – CPMF sobre as receitas oriundas de exportação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=52",
    texto: "A imunidade tributária prevista no art. 149, § 2º, I, da Constituição Federal é restrita às contribuições sociais e de intervenção no domínio econômico incidentes sobre as receitas decorrentes de exportação. Não contempla, assim, a CPMF, cuja hipótese de incidência — movimentações financeiras — não se confunde com receitas." },
  { id: "stf-rg-53", tribunal: "STF", tipo: "Repercussão Geral", numero: "53", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Competência para alterar alíquotas do Imposto de Exportação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=53",
    texto: "É compatível com a Constituição Federal a norma infraconstitucional que atribui a órgão integrante do Poder Executivo da União a faculdade de alterar as alíquotas do Imposto de Exportação." },
  { id: "stf-rg-54", tribunal: "STF", tipo: "Repercussão Geral", numero: "54", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão aos inativos e pensionistas da GDACT em seu grau máximo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=54",
    texto: "I - A Gratificação de Desempenho de Atividade de Ciência e Tecnologia – GDACT, instituída pela Medida Provisória 2.048/2000, apesar de originalmente concebida como gratificação pro labore faciendo, teve caráter geral e foi estendida aos inativos até a sua regulamentação pelo Decreto 3.762/2001, quando passou a constituir gratificação paga em razão do efetivo exercício de cargo; II - É constitucional o art. 60-A acrescentado pela Lei 10.769/2003 à MP 2.229- 43/2001, dado que não implicou redução indevida, visto que, após o Decreto 3.762/2001, deixou de existir o direito dos inativos à percepção da GDACT nas mesmas condições em que concedida aos servidores em atividade." },
  { id: "stf-rg-55", tribunal: "STF", tipo: "Repercussão Geral", numero: "55", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reserva de lei complementar estadual de contribuição compulsória para custeio de assistência médico-hospitalar.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=55",
    texto: "I - Os Estados membros possuem competência apenas para a instituição de contribuição voltada ao custeio do regime de previdência de seus servidores. Falece-lhes, portanto, competência para a criação de contribuição ou qualquer outra espécie tributária destinada ao custeio de serviços médicos, hospitalares, farmacêuticos e odontológicos prestados aos seus servidores; II - Não há óbice constitucional à prestação, pelos Estados, de serviços de saúde a seus servidores, desde que a adesão a esses \"planos\"seja facultativa." },
  { id: "stf-rg-56", tribunal: "STF", tipo: "Repercussão Geral", numero: "56", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade do Ministério Público para propor ação civil pública em que se questiona acordo firmado entre o contribuinte e o Poder Público para pagamento de dívida tributária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=56",
    texto: "O Ministério Público tem legitimidade para propor ação civil pública com o objetivo de anular Termo de Acordo de Regime Especial — TARE firmado entre o Poder Público e contribuinte, em face da legitimação ad causam que o texto constitucional lhe confere para defender o erário." },
  { id: "stf-rg-57", tribunal: "STF", tipo: "Repercussão Geral", numero: "57", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de servidor público militar transferido ingressar em universidade pública, na falta de universidade privada congênere à de origem.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=57",
    texto: "É constitucional a previsão legal que assegure, na hipótese de transferência ex officio de servidor, a matrícula em instituição pública, se inexistir instituição congênere à de origem." },
  { id: "stf-rg-58", tribunal: "STF", tipo: "Repercussão Geral", numero: "58", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Fracionamento de execução contra a Fazenda Pública para pagamento de custas processuais de forma autônoma em relação ao crédito principal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=58",
    texto: "É vedado o fracionamento do valor de precatório em execução de sentença, com o objetivo de efetuar o pagamento das custas processuais por meio de requisição de pequeno valor (RPV)." },
  { id: "stf-rg-59", tribunal: "STF", tipo: "Repercussão Geral", numero: "59", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Progressão de regime em crimes hediondos cometidos antes da vigência da Lei nº 11.464/2007.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=59",
    texto: "A Lei nº 11.464/07, que majorou o tempo necessário para progressão no cumprimento da pena, não se aplica a situações jurídicas que retratem crime hediondo ou equiparado cometido em momento anterior à respectiva vigência." },
  { id: "stf-rg-60", tribunal: "STF", tipo: "Repercussão Geral", numero: "60", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de prisão civil do depositário infiel no ordenamento jurídico-constitucional brasileiro.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=60",
    texto: "É ilícita a prisão civil de depositário infiel, qualquer que seja a modalidade de depósito." },
  { id: "stf-rg-61", tribunal: "STF", tipo: "Repercussão Geral", numero: "61", situacao: "Vigente", tema: "DIREITO ELEITORAL", titulo: "Elegibilidade de ex-cônjuge de ocupante de cargo político quando a dissolução da sociedade conjugal se dá durante o exercício do mandato.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=61",
    texto: "A dissolução da sociedade ou do vínculo conjugal, no curso do mandato, não afasta a inelegibilidade prevista no § 7º do artigo 14 da Constituição Federal." },
  { id: "stf-rg-62", tribunal: "STF", tipo: "Repercussão Geral", numero: "62", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Aplicabilidade do prazo prescricional do art. 7º, XXIX, da Constituição Federal (na redação dada pela Emenda Constitucional nº 28/2000) às ações trabalhistas ajuizadas por trabalhadores rurais cujos contratos de trabalho estavam vigentes à época da publicação da referida Emenda.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=62",
    texto: "A questão da aplicabilidade da prescrição quinquenal do art. 7º, XXIX, da Constituição Federal, na redação da Emenda Constitucional 28/2000, ao direito ao crédito do trabalhador rural que, contratado antes da referida Emenda, tenha ajuizado ação trabalhista após a sua publicação e antes de 29/5/2005 não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-63", tribunal: "STF", tipo: "Repercussão Geral", numero: "63", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Termo final de vigência do crédito-prêmio do IPI instituído pelo Decreto-lei nº 491/69.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=63",
    texto: "O crédito-prêmio de IPI, incentivo fiscal de natureza setorial instituído pelo art. 1º do Decreto-Lei 491/1969, deixou de vigorar em 5/10/1990 ante a ausência de sua confirmação por lei no prazo de dois anos após a publicação da Constituição de 1988, conforme definido no § 1º do art. 41 do Ato das Disposições Constitucionais Transitórias - ADCT." },
  { id: "stf-rg-64", tribunal: "STF", tipo: "Repercussão Geral", numero: "64", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Diferença de tratamento entre empresas públicas e sociedades de economia mista, que exploram atividade econômica, e empresas privadas, no que tange às contribuições para o PIS/PASEP.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=64",
    texto: "Não ofende o art. 173, § 1º, II, da Constituição Federal, a escolha legislativa de reputar não equivalentes a situação das empresas privadas com relação a das sociedades de economia mista, das empresas públicas e respectivas subsidiárias que exploram atividade econômica, para fins de submissão ao regime tributário das contribuições para o PIS e para o PASEP, à luz dos princípios da igualdade tributária e da seletividade no financiamento da Seguridade Social." },
  { id: "stf-rg-65", tribunal: "STF", tipo: "Repercussão Geral", numero: "65", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Acumulação por militar de dois cargos públicos: um de natureza militar e outro de professor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=65",
    texto: "A questão da possibilidade, ou não, de policiais e oficiais militares acumularem cargos públicos – um de natureza militar e outro de magistério – não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-66", tribunal: "STF", tipo: "Repercussão Geral", numero: "66", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reserva de lei para a vedação de nepotismo no âmbito dos Poderes Executivo e Legislativo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=66",
    texto: "A vedação ao nepotismo não exige a edição de lei formal para coibir a prática, dado que essa proibição decorre diretamente dos princípios contidos no art. 37, caput, da Constituição Federal." },
  { id: "stf-rg-67", tribunal: "STF", tipo: "Repercussão Geral", numero: "67", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão aos inativos da GDASST em 60 pontos a partir da Medida Provisória nº 198/94, convertida na Lei nº 10.971/2004.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=67",
    texto: "A Gratificação de Desempenho de Atividade de Seguridade Social e do Trabalho -GDASST deve ser estendida aos inativos nas mesmas condições em que concedida aos servidores em atividade, ou seja, no valor de 60 (sessenta) pontos, a partir do advento da Medida Provisória 198/2004, convertida na Lei 10.971/2004, que alterou a sua base de cálculo. Isso porque, embora de natureza pro labore faciendo, a falta de regulamentação das avaliações de desempenho transmudou a GDASST em uma gratificação de natureza genérica, extensível aos servidores inativos." },
  { id: "stf-rg-68", tribunal: "STF", tipo: "Repercussão Geral", numero: "68", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Validade de contrato de adesão, firmado entre distribuidora e revendedora de combustíveis, que confere exclusividade de fornecimento de produtos derivados de petróleo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=68",
    texto: "A questão da validade de contrato de adesão, firmado entre distribuidora e revendedora de combustíveis, que confere exclusividade de fornecimento de produtos derivados de petróleo, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-69", tribunal: "STF", tipo: "Repercussão Geral", numero: "69", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Inclusão do ICMS na base de cálculo do PIS e da COFINS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=69",
    texto: "O ICMS não compõe a base de cálculo para a incidência do PIS e da COFINS." },
  { id: "stf-rg-70", tribunal: "STF", tipo: "Repercussão Geral", numero: "70", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Possibilidade de conjugar vantagens de dois regimes previdenciários distintos para cálculo do benefício de aposentadoria.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=70",
    texto: "Na sistemática de cálculo dos benefícios previdenciários, não é lícito ao segurado conjugar as vantagens do novo sistema com aquelas aplicáveis ao anterior, porquanto inexiste direito adquirido a determinado regime jurídico." },
  { id: "stf-rg-71", tribunal: "STF", tipo: "Repercussão Geral", numero: "71", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "a) Exigência de reserva de plenário para as situações de não-aplicação do art. 56 da Lei nº 9.430/96, que revogou a isenção da COFINS para as sociedades prestadoras de serviços. b) Necessidade de lei complementar para a revogação da isenção da COFINS para as sociedades prestadoras de serviços.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=71",
    texto: "É legítima a revogação da isenção estabelecida no art. 6º, II, da Lei Complementar 70/1991 pelo art. 56 da Lei 9.430/1996, dado que a LC 70/1991 é apenas formalmente complementar, mas materialmente ordinária com relação aos dispositivos concernentes à contribuição social por ela instituída." },
  { id: "stf-rg-72", tribunal: "STF", tipo: "Repercussão Geral", numero: "72", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Inclusão do salário-maternidade na base de cálculo da Contribuição Previdenciária incidente sobre a remuneração.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=72",
    texto: "É inconstitucional a incidência de contribuição previdenciária a cargo do empregador sobre o salário maternidade." },
  { id: "stf-rg-73", tribunal: "STF", tipo: "Repercussão Geral", numero: "73", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de servidor à diferença de remuneração em virtude de desvio de função.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=73",
    texto: "A questão de o servidor público ter direito ao pagamento de diferenças pecuniárias em virtude de ter exercido trabalho em desvio de função não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-74", tribunal: "STF", tipo: "Repercussão Geral", numero: "74", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para julgamento de ação de interdito proibitório cuja causa de pedir decorre de movimento grevista.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=74",
    texto: "Compete à Justiça do Trabalho o julgamento das ações de interdito proibitório em que se busca garantir o livre acesso de funcionários e de clientes às agências bancárias interditadas em decorrência de movimento grevista." },
  { id: "stf-rg-75", tribunal: "STF", tipo: "Repercussão Geral", numero: "75", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Dedução da CSLL na apuração da sua própria base de cálculo e da base de cálculo do IRPJ.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=75",
    texto: "É constitucional a proibição de deduzir-se o valor da Contribuição Social sobre o Lucro Líquido – CSLL do montante apurado como lucro real, que constitui a base de cálculo do Imposto de Renda de Pessoa Jurídica – IRPJ." },
  { id: "stf-rg-76", tribunal: "STF", tipo: "Repercussão Geral", numero: "76", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Teto da renda mensal dos benefícios previdenciários concedidos anteriormente à vigência das Emendas Constitucionais nos 20/98 e 41/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=76",
    texto: "Não ofende o ato jurídico perfeito a aplicação imediata do art. 14 da Emenda Constitucional 20/1998 e do art. 5º da Emenda Constitucional 41/2003 aos benefícios previdenciários limitados a teto do regime geral de previdência estabelecido antes da vigência dessas normas, de modo a que passem a observar o novo teto constitucional." },
  { id: "stf-rg-77", tribunal: "STF", tipo: "Repercussão Geral", numero: "77", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Cabimento do mandado de segurança contra decisões interlocutórias exaradas em processos submetidos ao rito da Lei nº 9.099/95.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=77",
    texto: "Não cabe mandado de segurança das decisões interlocutórias exaradas em processos submetidos ao rito da Lei 9.099/1995." },
  { id: "stf-rg-78", tribunal: "STF", tipo: "Repercussão Geral", numero: "78", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Observância de simetria federativa por decisão do Tribunal de Justiça que declarou a inconstitucionalidade de Emendas à Lei Orgânica do Distrito Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=78",
    texto: "A questão da declaração de inconstitucionalidade das Emendas distritais n. 13/1996 e n. 17/1997 pelo Tribunal de Justiça, no que ofenderam normas da Lei Orgânica do Distrito Federal, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-80", tribunal: "STF", tipo: "Repercussão Geral", numero: "80", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Majoração da alíquota do IPI para o açúcar.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=80",
    texto: "Surge constitucional, sob o ângulo do caráter seletivo, em função da essencialidade do produto e do tratamento isonômico, o artigo 2º da Lei nº 8.393/1991, a revelar alíquota máxima de Imposto sobre Produtos Industrializados - IPI de 18%, assegurada isenção, quanto aos contribuintes situados na área de atuação da Superintendência de Desenvolvimento do Nordeste - SUDENE e da Superintendência de Desenvolvimento da Amazônia - SUDAM, e autorização para redução de até 50% da alíquota, presentes contribuintes situados nos Estados do Espírito Santo e do Rio de Janeiro." },
  { id: "stf-rg-81", tribunal: "STF", tipo: "Repercussão Geral", numero: "81", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Estorno na remuneração de auditores fiscais do Estado de Rondônia com base no subsídio do Governador.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=81",
    texto: "A questão do teto remuneratório dos auditores fiscais de Rondônia, calculado com base no subsídio do Governador e não no de Desembargador, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-82", tribunal: "STF", tipo: "Repercussão Geral", numero: "82", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de execução de título judicial, decorrente de ação ordinária coletiva ajuizada por entidade associativa, por aqueles que não conferiram autorização individual à associação, não obstante haja previsão genérica de representação dos associados em cláusula do estatuto.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=82",
    texto: "I – A previsão estatutária genérica não é suficiente para legitimar a atuação, em Juízo, de associações na defesa de direitos dos filiados, sendo indispensável autorização expressa, ainda que deliberada em assembleia, nos termos do artigo 5º, inciso XXI, da Constituição Federal; II – As balizas subjetivas do título judicial, formalizado em ação proposta por associação, são definidas pela representação no processo de conhecimento, limitada a execução aos associados apontados na inicial." },
  { id: "stf-rg-83", tribunal: "STF", tipo: "Repercussão Geral", numero: "83", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade civil do Estado por indenização em virtude de demora excessiva e injustificada na apreciação do pedido de aposentadoria de servidor público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=83",
    texto: "A questão da responsabilidade civil do Estado por indenização em virtude de demora excessiva e injustificada na apreciação do pedido de aposentadoria de servidor público não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-84", tribunal: "STF", tipo: "Repercussão Geral", numero: "84", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Exclusão do valor dos descontos incondicionais da base de cálculo do IPI.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=84",
    texto: "É formalmente inconstitucional, por ofensa ao artigo 146, inciso III, alínea “a”, da Constituição Federal, o § 2º do artigo 14 da Lei nº 4.502/1964, com a redação dada pelo artigo 15 da Lei nº 7.798/1989, no ponto em que prevê a inclusão de descontos incondicionais na base de cálculo do Imposto sobre Produtos Industrializados – IPI, em descompasso com a disciplina da matéria no artigo 47, inciso II, alínea “a”, do Código Tributário Nacional." },
  { id: "stf-rg-85", tribunal: "STF", tipo: "Repercussão Geral", numero: "85", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Delegação ao Ministro da Fazenda da competência para instituir taxa destinada ao ressarcimento de custos de selo de controle do IPI.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=85",
    texto: "A questão da recepção, pela Constituição Federal de 1988, do art. 3º do Decreto-Lei n. 1.437/1975, que permite ao Ministro da Fazenda instituir taxa destinada ao ressarcimento dos custos e demais encargos de selo de controle do Imposto sobre Produto Industrializado - IPI, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-86", tribunal: "STF", tipo: "Repercussão Geral", numero: "86", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito adquirido à validação automática de diploma de curso superior obtido no exterior.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=86",
    texto: "A questão do direito adquirido ao registro automático, independente de processo de revalidação, de diploma de curso superior concluído nos países signatários da Convenção Regional sobre o Reconhecimento de Estudos, Títulos e Diplomas de Ensino Superior na América Latina e Caribe, inserida no ordenamento jurídico brasileiro pelo Decreto 80.419/1977, quando o pedido de registro ocorrera após a revogação da referida legislação (Decreto 3.007/1999), não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-87", tribunal: "STF", tipo: "Repercussão Geral", numero: "87", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Exigibilidade do PIS e da COFINS sobre os valores das vendas a prazo inadimplidas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=87",
    texto: "As vendas inadimplidas não podem ser excluídas da base de cálculo da contribuição ao PIS e da COFINS, visto que integram a receita da pessoa jurídica." },
  { id: "stf-rg-88", tribunal: "STF", tipo: "Repercussão Geral", numero: "88", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Aplicação do art. 29 da Lei nº 8.213/91, com a redação dada pela Lei nº 9.876/99, a benefícios concedidos antes da respectiva vigência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=88",
    texto: "Em razão do caráter contributivo do regime geral de previdência (CF/1988, art. 201, caput), o art. 29, § 5º, da Lei nº 8.213/1991 não se aplica à transformação de auxílio-doença em aposentadoria por invalidez, mas apenas a aposentadorias por invalidez precedidas de períodos de auxílio-doença intercalados com intervalos de atividade, sendo válido o art. 36, § 7º, do Decreto nº 3.048/1999, mesmo após a Lei nº 9.876/1999." },
  { id: "stf-rg-89", tribunal: "STF", tipo: "Repercussão Geral", numero: "89", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Renda a ser usada como parâmetro para a concessão do auxílio-reclusão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=89",
    texto: "Segundo decorre do art. 201, IV, da Constituição Federal, a renda do segurado preso é a que deve ser utilizada como parâmetro para a concessão do auxílio-reclusão e não a de seus dependentes." },
  { id: "stf-rg-90", tribunal: "STF", tipo: "Repercussão Geral", numero: "90", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar a execução de créditos trabalhistas no caso de empresa em fase de recuperação judicial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=90",
    texto: "Compete ao juízo comum falimentar processar e julgar a execução dos créditos trabalhistas no caso de empresa em fase de recuperação judicial." },
  { id: "stf-rg-91", tribunal: "STF", tipo: "Repercussão Geral", numero: "91", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Aplicação do prazo nonagesimal previsto no art. 150, III, c, da Constituição Federal relativamente à Lei paulista nº 11.813/2004.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=91",
    texto: "O prazo nonagesimal previsto no art. 150, III, c, da Constituição Federal somente deve ser utilizado nos casos de criação ou majoração de tributos, não nas situações, como a prevista na Lei paulista 11.813/04, de simples prorrogação de alíquota já aplicada anteriormente." },
  { id: "stf-rg-92", tribunal: "STF", tipo: "Repercussão Geral", numero: "92", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Vinculação de receita proveniente de majoração de alíquota do ICMS pela Lei paulista nº 9.903/97.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=92",
    texto: "Não viola o art. 167, IV, da Constituição Federal lei estadual que, ao prever o aumento da alíquota do Imposto sobre Circulação de Mercadorias e Serviços – ICMS, impõe ao Chefe do Executivo a divulgação da aplicação dos recursos provenientes desse aumento." },
  { id: "stf-rg-93", tribunal: "STF", tipo: "Repercussão Geral", numero: "93", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Exigência de reserva de plenário para as situações de não-aplicabilidade do art. 4º da Lei Complementar nº 118/2005 às ações ajuizadas anteriormente à sua vigência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=93",
    texto: "Viola a cláusula de reserva de plenário (CF, art. 97) a decisão de órgão fracionário de Tribunal que, embora não declare expressamente a inconstitucionalidade de lei ou ato normativo do poder público, afasta sua incidência, no todo ou em parte." },
  { id: "stf-rg-94", tribunal: "STF", tipo: "Repercussão Geral", numero: "94", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Exigência de reserva de plenário para as situações em que a Emenda Constitucional nº 29/2000 deixa de ser aplicada em face da incidência da versão primitiva da norma constitucional por ela modificada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=94",
    texto: "É constitucional a Emenda Constitucional nº 29, de 2000, no que estabeleceu a possibilidade de previsão legal de alíquotas progressivas para o IPTU de acordo com o valor do imóvel." },
  { id: "stf-rg-95", tribunal: "STF", tipo: "Repercussão Geral", numero: "95", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Majoração da alíquota da COFINS de 2% para 3% pela Lei nº 9.718/98.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=95",
    texto: "É constitucional a majoração da alíquota da Cofins de 2% para 3%, instituída no artigo 8º da Lei nº 9.718/1998." },
  { id: "stf-rg-96", tribunal: "STF", tipo: "Repercussão Geral", numero: "96", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Incidência de juros de mora no período compreendido entre a data da conta de liquidação e a expedição do requisitório.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=96",
    texto: "Incidem os juros da mora no período compreendido entre a data da realização dos cálculos e a da requisição ou do precatório." },
  { id: "stf-rg-98", tribunal: "STF", tipo: "Repercussão Geral", numero: "98", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Auto-aplicabilidade do art. 192, § 3º, da Constituição Federal, na redação anterior à Emenda Constitucional nº 40/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=98",
    texto: "A norma do § 3º do artigo 192 da Constituição, revogada pela Emenda Constitucional nº 40/2003, que limitava a taxa de juros reais a 12% ao ano, tinha sua aplicação condicionada à edição de lei complementar." },
  { id: "stf-rg-99", tribunal: "STF", tipo: "Repercussão Geral", numero: "99", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Extensão da forma de cálculo da COFINS e do PIS, fixada para as empresas que realizam a comercialização de veículos usados, para as pessoas jurídicas que atuam no ramo industrial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=99",
    texto: "A questão da possibilidade de estender, às pessoas jurídicas que atuam no ramo industrial, as deduções da base de cálculo da Contribuição para o Financiamento da Seguridade Social - COFINS e da Contribuição ao Programa de Integração Social - PIS, fixadas para as instituições financeiras e revendedoras de veículos usados pelas Leis n. 9.716/1998 e n. 9.718/1998, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-101", tribunal: "STF", tipo: "Repercussão Geral", numero: "101", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Validade e eficácia de acordo constante do termo de adesão instituído pela Lei Complementar nº 110/2001.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=101",
    texto: "Ofende a garantia constitucional do ato jurídico perfeito a decisão que, sem ponderar as circunstâncias do caso concreto, desconsidera a validez e a eficácia de acordo constante de termo de adesão instituído pela Lei complementar nº 110/2001." },
  { id: "stf-rg-102", tribunal: "STF", tipo: "Repercussão Geral", numero: "102", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do IOF sobre transmissão de ações de companhias abertas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=102",
    texto: "É constitucional o art. 1º, IV, da Lei 8.033/1990, uma vez que a incidência de IOF sobre o negócio jurídico de transmissão de títulos e valores mobiliários, tais como ações de companhias abertas e respectivas bonificações, encontra respaldo no art. 153, V, da Constituição Federal, sem ofender os princípios tributários da anterioridade e da irretroatividade, nem demandar a reserva de lei complementar." },
  { id: "stf-rg-103", tribunal: "STF", tipo: "Repercussão Geral", numero: "103", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Exigência da comprovação de insuficiência econômico-financeira para a concessão de assistência judiciária gratuita a pessoas jurídicas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=103",
    texto: "A questão sobre o preenchimento dos requisitos exigidos para a assistência jurídica gratuita às pessoas jurídicas, quanto à comprovação do estado de hipossuficiência, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-105", tribunal: "STF", tipo: "Repercussão Geral", numero: "105", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de servidor público federal cedido a Município, nos termos da Lei nº 8.270/91, receber gratificação instituída por lei municipal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=105",
    texto: "A questão de o servidor público federal, cedido a Município, nos termos do art. 20 da Lei n. 8.270/1991, em razão da municipalização da saúde, receber vantagem pecuniária instituída por lei municipal e devida pelo exercício efetivo em unidade sanitária, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-107", tribunal: "STF", tipo: "Repercussão Geral", numero: "107", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Majoração da alíquota da CSLL pela Emenda Constitucional nº 10/96.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=107",
    texto: "A Emenda Constitucional 10/1996, especialmente quanto ao inciso III do art. 72 do ADCT, é um novo texto e veicula nova norma, não sendo mera prorrogação da Emenda Constitucional de Revisão 1/1994, devendo, portanto, observância ao princípio da anterioridade nonagesimal, porquanto majorou a alíquota da CSLL para as pessoas jurídicas referidas no § 1º do art. 22 da Lei nº 8.212/1991." },
  { id: "stf-rg-108", tribunal: "STF", tipo: "Repercussão Geral", numero: "108", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Exigibilidade de contribuição social, destinada ao INCRA, das empresas urbanas. Atenção: desde 2011 este tema tem repercussão geral reconhecida, por proposta de revisão de tese apresentada pelo relator do tema 495.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=108",
    texto: "Este tema, relativo à exigibilidade de contribuição social das empresas urbanas ao INCRA, até então sem repercussão geral, foi objeto de proposta de revisão de tese, pelo Relator do RE 630.898/RS, no tema 495. Neste (tema 495) a repercussão geral foi reconhecida. Vide \"Pesquisa Avançada\"." },
  { id: "stf-rg-109", tribunal: "STF", tipo: "Repercussão Geral", numero: "109", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Adoção pelo Poder Judiciário de critérios normativos estaduais como fundamento para extinguir ações de execução fiscal ajuizadas pelo Município.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=109",
    texto: "Lei estadual autorizadora da não inscrição em dívida ativa e do não ajuizamento de débitos de pequeno valor é insuscetível de aplicação a Município e, consequentemente, não serve de fundamento para a extinção das execuções fiscais que promova, sob pena de violação à sua competência tributária." },
  { id: "stf-rg-110", tribunal: "STF", tipo: "Repercussão Geral", numero: "110", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Ampliação da base de cálculo da COFINS", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=110",
    texto: "É inconstitucional a ampliação da base de cálculo da contribuição ao PIS e da COFINS prevista no art. 3º, § 1º, da Lei 9.718/98." },
  { id: "stf-rg-112", tribunal: "STF", tipo: "Repercussão Geral", numero: "112", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Conversão de precatórios expedidos antes da Emenda Constitucional nº 37/2002 em requisições de pequeno valor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=112",
    texto: "É harmônica com a normatividade constitucional a previsão no artigo 86 do ADCT na dicção da EC 32/2002 de um regime de transição para tratar dos precatórios reputados de pequeno valor, já expedidos antes de sua promulgação." },
  { id: "stf-rg-113", tribunal: "STF", tipo: "Repercussão Geral", numero: "113", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Revogação do art. 25 da Lei de Contravenções Penais pela Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=113",
    texto: "O art. 25 da Lei de Contravenções Penais (Decreto-lei 3.688/1941) não foi recepcionado pela Constituição de 1988, por violar os princípios da dignidade da pessoa humana (CF, art. 1º, III) e da isonomia (CF, art. 5º, caput e I)." },
  { id: "stf-rg-114", tribunal: "STF", tipo: "Repercussão Geral", numero: "114", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Agravamento da pena por reincidência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=114",
    texto: "Surge harmônico com o princípio constitucional da individualização da pena o inciso I do artigo 61 do Código Penal, no que prevê, como agravante, a reincidência." },
  { id: "stf-rg-115", tribunal: "STF", tipo: "Repercussão Geral", numero: "115", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Aplicação da imunidade tributária recíproca às sociedades de economia mista que prestam serviços de saúde exclusivamente pelo SUS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=115",
    texto: "Não foi fixada tese de repercussão geral, visto que a decisão de mérito do RE 580.264 vale apenas para o caso concreto, em razão de suas peculiaridades." },
  { id: "stf-rg-116", tribunal: "STF", tipo: "Repercussão Geral", numero: "116", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Direito a honorários advocatícios nas ações que visam obter expurgos inflacionários de FGTS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=116",
    texto: "É inconstitucional o art. 29-C da Lei 8.036/1990, introduzido pelo art. 9º da MP 2.164-41/2001, que veda a condenação em honorários advocatícios nas ações entre o FGTS e os titulares de contas vinculadas, bem como naquelas em que figuram os respectivos representantes ou substitutos processuais." },
  { id: "stf-rg-117", tribunal: "STF", tipo: "Repercussão Geral", numero: "117", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Limitação do direito de compensação de prejuízos fiscais do IRPJ e da base de cálculo negativa da CSLL.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=117",
    texto: "É constitucional a limitação do direito de compensação de prejuízos fiscais do IRPJ e da base de cálculo negativa da CSLL." },
  { id: "stf-rg-119", tribunal: "STF", tipo: "Repercussão Geral", numero: "119", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Acumulação por militar de dois cargos públicos na área de saúde.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=119",
    texto: "A questão da possibilidade de os militares acumularem dois cargos públicos na área de saúde, um de natureza militar e outro municipal, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-120", tribunal: "STF", tipo: "Repercussão Geral", numero: "120", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Contribuições sociais criadas para o pagamento dos expurgos inflacionários das contas vinculadas ao FGTS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=120",
    texto: "A questão da exigibilidade das contribuições sociais criadas pelos arts. 1º e 2º da Lei Complementar n. 110/2001, destinadas ao pagamento dos expurgos inflacionários das contas vinculadas ao Fundo de Garantia do Tempo de Serviço - FGTS, decorrentes da aplicação de índice de correção monetária dessas contas abaixo da inflação real, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-121", tribunal: "STF", tipo: "Repercussão Geral", numero: "121", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reserva legal para fixação de limite de idade para ingresso nas Forças Armadas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=121",
    texto: "Não foi recepcionada pela Constituição da República de 1988 a expressão “nos regulamentos da Marinha, do Exército e da Aeronáutica” do art. 10 da Lei 6.880/1980, dado que apenas lei pode definir os requisitos para ingresso nas Forças Armadas, notadamente o requisito de idade, nos termos do art. 142, § 3º, X, da Constituição de 1988. Descabe, portanto, a regulamentação por outra espécie normativa, ainda que por delegação legal." },
  { id: "stf-rg-122", tribunal: "STF", tipo: "Repercussão Geral", numero: "122", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de servidor, que teve regime jurídico alterado de celetista para estatutário, à contagem como tempo de serviço em dobro, o período correspondente à licença especial não-gozada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=122",
    texto: "A questão de o servidor, cujo regime jurídico fora alterado de celetista para o estatutário, ter direito à contagem em dobro do período de licença especial não usufruída como tempo de serviço público não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-125", tribunal: "STF", tipo: "Repercussão Geral", numero: "125", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do ISS sobre operações de arrendamento mercantil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=125",
    texto: "É constitucional a incidência do Imposto sobre Serviços de Qualquer Natureza - ISS sobre as operações de arrendamento mercantil (leasing financeiro)." },
  { id: "stf-rg-127", tribunal: "STF", tipo: "Repercussão Geral", numero: "127", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Limitação temporal dos efeitos da condenação ao reajuste salarial de 84,32% aos servidores do Distrito Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=127",
    texto: "A questão da aplicação do limite temporal de vigência da Lei Distrital 38/1989, revogada pela Lei Distrital 117/1990, aos efeitos da condenação do Distrito Federal ao reajuste salarial de 84,32% (Plano Collor) devido aos seus servidores não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-128", tribunal: "STF", tipo: "Repercussão Geral", numero: "128", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para dirimir conflito de competência entre Juizado Especial e Juízo Federal de primeiro grau de uma mesma Seção Judiciária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=128",
    texto: "Cabe ao respectivo Tribunal Regional Federal dirimir conflitos de competência entre Juizado Especial e Juízo Federal de primeira instância que pertençam a uma mesma Seção Judiciária." },
  { id: "stf-rg-129", tribunal: "STF", tipo: "Repercussão Geral", numero: "129", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Consideração de ações penais em curso como maus antecedentes para fins de dosimetria da pena.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=129",
    texto: "A existência de inquéritos policiais ou de ações penais sem trânsito em julgado não pode ser considerada como maus antecedentes para fins de dosimetria da pena." },
  { id: "stf-rg-130", tribunal: "STF", tipo: "Repercussão Geral", numero: "130", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Responsabilidade objetiva do Estado em caso de responsabilidade civil da pessoa jurídica de direito privado prestadora de serviço público em relação a terceiros não-usuários do serviço.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=130",
    texto: "A responsabilidade civil das pessoas jurídicas de direito privado prestadoras de serviço público é objetiva relativamente a terceiros usuários e não usuários do serviço, segundo decorre do art. 37, § 6º, da Constituição Federal." },
  { id: "stf-rg-131", tribunal: "STF", tipo: "Repercussão Geral", numero: "131", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Despedida imotivada de empregados de Empresa Pública.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=131",
    texto: "A Empresa Brasileira de Correios e Telégrafos - ECT tem o dever jurídico de motivar, em ato formal, a demissão de seus empregados." },
  { id: "stf-rg-132", tribunal: "STF", tipo: "Repercussão Geral", numero: "132", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Incidência de juros moratórios e compensatórios durante o período de parcelamento previsto no art. 78 do ADCT.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=132",
    texto: "O art. 78 do Ato das Disposições Constitucionais Transitórias possui a mesma mens legis que o art. 33 desse Ato, razão pela qual, uma vez calculado o precatório pelo valor real do débito, acrescido de juros legais, não há mais falar em incidência desses nas parcelas anuais, iguais e sucessivas em que é fracionado, desde que adimplidas a tempo e corrigidas monetariamente." },
  { id: "stf-rg-133", tribunal: "STF", tipo: "Repercussão Geral", numero: "133", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Alíquota do Imposto de Renda de Pessoa Física aplicável aos valores recebidos em atraso e de forma acumulada pelo beneficiário, por culpa exclusiva da autarquia federal. Atenção: desde 2014 este tema teve a repercussão geral reconhecida e o mérito julgado, por proposta de revisão de tese apresentada pelo relator do tema 368. \"", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=133",
    texto: "Este tema, até então sem repercussão geral, foi objeto de proposta de revisão de tese, pelo relator do RE n. 614 406 (tema 368), fixada nos seguintes termos: \"O Imposto de Renda incidente sobre verbas recebidas acumuladamente deve observar o regime de competência, aplicável a alíquota correspondente ao valor recebido mês a mês, e não a relativa ao total satisfeito de uma única vez\"." },
  { id: "stf-rg-134", tribunal: "STF", tipo: "Repercussão Geral", numero: "134", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Direito a honorários advocatícios quando a Defensoria Pública Estadual representa vencedor em demanda ajuizada contra o Estado ao qual é vinculada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=134",
    texto: "A questão de a Defensoria Pública, representando o vencedor da demanda judicial, receber honorários advocatícios sucumbenciais nas causas ajuizadas contra o ente federativo ao qual aquela está vinculada não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-135", tribunal: "STF", tipo: "Repercussão Geral", numero: "135", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Exigibilidade do porte de remessa e retorno de autos de autarquia federal no âmbito da Justiça Estadual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=135",
    texto: "Aplica-se o § 1º do art. 511 do Código de Processo Civil para dispensa de porte de remessa e retorno ao exonerar o seu respectivo recolhimento por parte do INSS." },
  { id: "stf-rg-136", tribunal: "STF", tipo: "Repercussão Geral", numero: "136", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "a) Cabimento de ação rescisória que visa desconstituir julgado com base em nova orientação da Corte; b) Creditamento de IPI pela aquisição de insumos isentos, não tributados ou sujeitos à alíquota zero.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=136",
    texto: "Não cabe ação rescisória quando o julgado estiver em harmonia com o entendimento firmado pelo Plenário do Supremo à época da formalização do acórdão rescindendo, ainda que ocorra posterior superação do precedente." },
  { id: "stf-rg-137", tribunal: "STF", tipo: "Repercussão Geral", numero: "137", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Prazo para a Fazenda Pública opor embargos à execução.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=137",
    texto: "É compatível com a Constituição da República de 1988 a ampliação para 30 (trinta) dias do prazo de oposição de embargos à execução pela Fazenda Pública." },
  { id: "stf-rg-138", tribunal: "STF", tipo: "Repercussão Geral", numero: "138", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Anulação de ato administrativo pela Administração, com reflexo em interesses individuais, sem a instauração de procedimento administrativo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=138",
    texto: "Ao Estado é facultada a revogação de atos que repute ilegalmente praticados; porém, se de tais atos já tiverem decorrido efeitos concretos, seu desfazimento deve ser precedido de regular processo administrativo." },
  { id: "stf-rg-139", tribunal: "STF", tipo: "Repercussão Geral", numero: "139", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão da Gratificação por Atividade de Magistério aos servidores inativos que ingressaram no serviço público até a publicação da Emenda Constitucional nº 41/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=139",
    texto: "Os servidores que ingressaram no serviço público antes da EC 41/2003, mas que se aposentaram após a referida emenda, possuem direito à paridade remuneratória e à integralidade no cálculo de seus proventos, desde que observadas as regras de transição especificadas nos arts. 2º e 3º da EC 47/2005." },
  { id: "stf-rg-140", tribunal: "STF", tipo: "Repercussão Geral", numero: "140", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão da Gratificação de Atividade Institucional Autônoma – GAIA, concedida aos Procuradores do Estado de Minas Gerais, aos Procuradores da Fazenda Estadual, referente a período anterior à unificação das carreiras.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=140",
    texto: "A questão do direito de os Procuradores da Fazenda do Estado de Minas Gerais receberem a Gratificação de Atividade Institucional Autônoma – GAIA, paga aos procuradores daquele Estado, no período anterior à unificação das carreiras, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-141", tribunal: "STF", tipo: "Repercussão Geral", numero: "141", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Cálculo de vantagens pessoais incidentes sobre o abono garantidor da percepção de um salário-mínimo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=141",
    texto: "O cálculo de gratificações e outras vantagens do servidor público não incide sobre o abono utilizado para se atingir o salário mínimo." },
  { id: "stf-rg-142", tribunal: "STF", tipo: "Repercussão Geral", numero: "142", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Pagamento a servidor público de salário-base inferior ao mínimo constitucional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=142",
    texto: "Os artigos 7º, IV, e 39, § 3º (redação da EC 19/1998), da Constituição referem-se ao total da remuneração percebida pelo servidor público." },
  { id: "stf-rg-143", tribunal: "STF", tipo: "Repercussão Geral", numero: "143", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Cancelamento de descontos em folha de pagamento por posterior desinteresse do mutuário no seu prosseguimento.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=143",
    texto: "A questão do direito ao cancelamento de autorização expressa de desconto em folha de pagamento pelo posterior desinteresse do mutuário na sua continuidade não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-144", tribunal: "STF", tipo: "Repercussão Geral", numero: "144", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "a) Termo inicial da prescrição para ação de cobrança da diferença decorrente da incidência dos expurgos inflacionários reconhecidos pela Lei Complementar nº 110/2001 na multa de 40% sobre os depósitos do FGTS; b) Responsabilidade do empregador pelo pagamento dessa diferença.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=144",
    texto: "I - A questão da definição do termo inicial da prescrição da ação de cobrança das diferenças dos expurgos inflacionários reconhecidos pela Lei Complementar n. 110/2001, para atualização monetária do Fundo de Garantia por Tempo de Serviço - FGTS, incidentes na multa de 40% (quarenta por cento) sobre os depósitos dessa conta vinculada tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral; II - A questão da responsabilidade do empregador pelo pagamento das diferenças de expurgos inflacionários reconhecidos pela Lei Complementar n. 110/2001, para atualização monetária do Fundo de Garantia por Tempo de Serviço - FGTS, incidentes na multa de 40% (quarenta por cento) sobre os depósitos dessa conta vinculada, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral." },
  { id: "stf-rg-145", tribunal: "STF", tipo: "Repercussão Geral", numero: "145", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "a) Competência do Município para legislar sobre meio ambiente; b) Competência dos Tribunais de Justiça para exercer controle de constitucionalidade de norma municipal em face da Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=145",
    texto: "O município é competente para legislar sobre o meio ambiente com a União e o Estado, no limite do seu interesse local e desde que tal regramento seja harmônico com a disciplina estabelecida pelos demais entes federados (art. 24, VI, c/c 30, I e II, da Constituição Federal)." },
  { id: "stf-rg-146", tribunal: "STF", tipo: "Repercussão Geral", numero: "146", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "a) Cobrança de taxa em razão de serviços públicos de limpeza; b) Adoção de um ou mais elementos que compõem a base de cálculo própria de imposto para apuração do valor de taxa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=146",
    texto: "I - A taxa cobrada exclusivamente em razão dos serviços públicos de coleta, remoção e tratamento ou destinação de lixo ou resíduos provenientes de imóveis não viola o artigo 145, II, da Constituição Federal; II - A taxa cobrada em razão dos serviços de conservação e limpeza de logradouros e bens públicos ofende o art. 145, II, da Constituição Federal; III - É constitucional a adoção, no cálculo do valor de taxa, de um ou mais elementos da base de cálculo própria de determinado imposto, desde que não haja integral identidade entre uma base e outra." },
  { id: "stf-rg-147", tribunal: "STF", tipo: "Repercussão Geral", numero: "147", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Incidência de juros de mora durante o prazo previsto na Constituição Federal para o pagamento de precatório.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=147",
    texto: "Durante o período previsto no parágrafo 1º do artigo 100 (redação original e redação da EC 30/2000) da Constituição, não incidem juros de mora sobre os precatórios que nele sejam pagos." },
  { id: "stf-rg-148", tribunal: "STF", tipo: "Repercussão Geral", numero: "148", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Individualização de créditos de litisconsortes para efeito de fracionamento do valor principal da execução contra a Fazenda Pública.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=148",
    texto: "A interpretação do § 4º do art. 100, alterado e hoje § 8º do art. 100 da Constituição da República, permite o pagamento dos débitos em execução nos casos de litisconsórcio facultativo." },
  { id: "stf-rg-149", tribunal: "STF", tipo: "Repercussão Geral", numero: "149", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar causa que envolve contribuição previdenciária instituída pelo Estado membro incidente sobre complementação de proventos e de pensões por ele paga.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=149",
    texto: "Compete à Justiça comum o julgamento de conflito de interesses a envolver a incidência de contribuição previdenciária, considerada a complementação de proventos." },
  { id: "stf-rg-150", tribunal: "STF", tipo: "Repercussão Geral", numero: "150", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Consideração de condenações transitadas em julgado há mais de cinco anos como maus antecedentes para efeito de fixação da pena-base.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=150",
    texto: "Não se aplica para o reconhecimento dos maus antecedentes o prazo quinquenal de prescrição da reincidência, previsto no art. 64, I, do Código Penal." },
  { id: "stf-rg-151", tribunal: "STF", tipo: "Repercussão Geral", numero: "151", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Decretação de ofício da prescrição de crédito tributário sem a manifestação da Fazenda Pública.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=151",
    texto: "É infraconstitucional, a ela se atribuindo os efeitos da ausência de repercussão geral, a controvérsia relativa à possibilidade de o juízo decretar, de ofício, a prescrição do crédito tributário cobrado na execução fiscal sem a prévia manifestação da Fazenda Pública." },
  { id: "stf-rg-152", tribunal: "STF", tipo: "Repercussão Geral", numero: "152", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Renúncia genérica a direitos mediante adesão a plano de demissão voluntária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=152",
    texto: "A transação extrajudicial que importa rescisão do contrato de trabalho, em razão de adesão voluntária do empregado a plano de dispensa incentivada, enseja quitação ampla e irrestrita de todas as parcelas objeto do contrato de emprego, caso essa condição tenha constado expressamente do acordo coletivo que aprovou o plano, bem como dos demais instrumentos celebrados com o empregado." },
  { id: "stf-rg-153", tribunal: "STF", tipo: "Repercussão Geral", numero: "153", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão, em relação aos servidores inativos, dos critérios de cálculo da GDATA e da GDASST estabelecidos para os servidores em atividade.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=153",
    texto: "A fixação da GDATA e da GDASST em relação aos servidores inativos deve obedecer aos critérios a que estão submetidos os servidores em atividade de acordo com a sucessão de leis de regência." },
  { id: "stf-rg-154", tribunal: "STF", tipo: "Repercussão Geral", numero: "154", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Trancamento da ação penal, em habeas corpus, por falta de justa causa, sem a submissão de acusados de crime doloso contra a vida ao Tribunal do Júri.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=154",
    texto: "Qualquer decisão do Poder Judiciário que rejeite denúncia, que impronuncie ou absolva, sumariamente, os réus ou, ainda, que ordene a extinção, em sede de “habeas corpus”, de procedimentos penais não transgride o monopólio constitucional da ação penal pública (CF, art. 129, I) nem ofende os postulados do juiz natural (CF, art. 5º, inciso LIII) e da soberania do veredicto do Júri (CF, art. 5º, inciso XXXVIII, “c”)." },
  { id: "stf-rg-155", tribunal: "STF", tipo: "Repercussão Geral", numero: "155", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Progressividade do IPTU antes da Emenda Constitucional nº 29/2000.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=155",
    texto: "É inconstitucional a lei municipal que tenha estabelecido, antes da Emenda Constitucional 29/2000, alíquotas progressivas para o IPTU, salvo se destinada a assegurar o cumprimento da função social da propriedade urbana." },
  { id: "stf-rg-156", tribunal: "STF", tipo: "Repercussão Geral", numero: "156", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão da verba de incentivo de aprimoramento à docência prevista no art. 3º da Lei Complementar nº 159/2004 do Estado de Mato Grosso a professores inativos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=156",
    texto: "I - As vantagens remuneratórias legítimas e de caráter geral conferidas a determinada categoria, carreira ou, indistintamente, a servidores públicos, por serem vantagens genéricas, são extensíveis aos servidores inativos e pensionistas; II - Nesses casos, a extensão alcança os servidores que tenham ingressado no serviço público antes da publicação das Emendas Constitucionais 20/1998 e 41/2003 e se aposentado ou adquirido o direito à aposentadoria antes da EC 41/2003; III - Com relação àqueles servidores que se aposentaram após a EC 41/2003, deverão ser observados os requisitos estabelecidos na regra de transição contida no seu art. 7º, em virtude da extinção da paridade integral entre ativos e inativos contida no art. 40, § 8º, da CF para os servidores que ingressaram no serviço público após a publicação da referida emenda; IV - Por fim, com relação aos servidores que ingressaram no serviço público antes da EC 41/2003 e se aposentaram ou adquiriram o direito à aposentadoria após a sua edição, é necessário observar a incidência das regras de transição fixadas pela EC 47/2005, a qual estabeleceu efeitos retroativos à data de vigência da EC 41/2003, conforme decidido nos autos do RE 590.260/SP, Plenário, Rel. MIN. RICARDO LEWANDOWSKI, julgado em 24/6/2009." },
  { id: "stf-rg-157", tribunal: "STF", tipo: "Repercussão Geral", numero: "157", situacao: "Vigente", tema: "DIREITO ELEITORAL E PROCESSO ELEITORAL", titulo: "Competência exclusiva da Câmara Municipal para o julgamento das contas de Prefeito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=157",
    texto: "O parecer técnico elaborado pelo Tribunal de Contas tem natureza meramente opinativa, competindo exclusivamente à Câmara de Vereadores o julgamento das contas anuais do Chefe do Poder Executivo local, sendo incabível o julgamento ficto das contas por decurso de prazo." },
  { id: "stf-rg-158", tribunal: "STF", tipo: "Repercussão Geral", numero: "158", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Fixação de pena aquém do mínimo legal, em face da incidência de circunstância genérica atenuante.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=158",
    texto: "Circunstância atenuante genérica não pode conduzir à redução da pena abaixo do mínimo legal." },
  { id: "stf-rg-159", tribunal: "STF", tipo: "Repercussão Geral", numero: "159", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar mandado de segurança contra decisão de juiz federal no exercício de jurisdição de juizado especial federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=159",
    texto: "Compete às Turmas Recursais o julgamento de mandado de segurança utilizado como substitutivo recursal contra decisão de juiz federal no exercício de jurisdição do Juizado Especial Federal." },
  { id: "stf-rg-160", tribunal: "STF", tipo: "Repercussão Geral", numero: "160", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Contribuição previdenciária sobre pensões e proventos e militares inativos entre a Emenda Constitucional nº 20/98 e a Emenda Constitucional nº 41/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=160",
    texto: "É constitucional a cobrança de contribuições sobre os proventos dos militares inativos, aqui compreendidos os Policiais Militares e o Corpo de Bombeiros dos Estados e do Distrito Federal e os integrantes das Forças Armadas, entre o período de vigência da Emenda Constitucional 20/98 e da Emenda Constitucional 41/03, por serem titulares de regimes jurídicos distintos dos servidores públicos civis e porque a eles não se estende a interpretação integrativa dos textos dos artigos 40, §§ 8º e 12, e artigo 195, II, da Constituição da República." },
  { id: "stf-rg-161", tribunal: "STF", tipo: "Repercussão Geral", numero: "161", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Nomeação de candidato classificado entre as vagas previstas no edital de concurso público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=161",
    texto: "O candidato aprovado em concurso público dentro do número de vagas previsto no edital possui direito subjetivo à nomeação." },
  { id: "stf-rg-162", tribunal: "STF", tipo: "Repercussão Geral", numero: "162", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Acumulação de pensões por morte, no caso de o servidor aposentado ter reingressado no serviço público, por meio de concurso, antes da edição da Emenda Constitucional nº 20/98, e ter falecido em data posterior ao seu advento.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=162",
    texto: "É inconstitucional a percepção cumulativa de duas pensões estatutárias pela morte de servidor aposentado que reingressara no serviço público, por meio de concurso, antes da edição da EC 20/1998 e falecera após o seu advento." },
  { id: "stf-rg-163", tribunal: "STF", tipo: "Repercussão Geral", numero: "163", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Contribuição previdenciária sobre o terço constitucional de férias, a gratificação natalina, os serviços extraordinários, o adicional noturno e o adicional de insalubridade.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=163",
    texto: "Não incide contribuição previdenciária sobre verba não incorporável aos proventos de aposentadoria do servidor público, tais como terço de férias, serviços extraordinários, adicional noturno e adicional de insalubridade." },
  { id: "stf-rg-164", tribunal: "STF", tipo: "Repercussão Geral", numero: "164", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Contribuição social, a cargo das cooperativas de trabalho, sobre as importâncias pagas, distribuídas ou creditadas aos seus cooperados, a título de remuneração por serviços prestados a pessoas jurídicas por intermédio delas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=164",
    texto: "A questão acerca da constitucionalidade do art. 1°, II, da Lei Complementar 84/1996, que instituiu, a cargo das cooperativas de trabalho, a contribuição social sobre as importâncias pagas, distribuídas ou creditadas a seus cooperados, a título de remuneração ou retribuição pelos serviços que prestem a pessoas jurídicas por intermédio da cooperativa, no período em que a referida lei produziu efeitos, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-165", tribunal: "STF", tipo: "Repercussão Geral", numero: "165", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Revisão da pensão por morte concedida antes do advento da Lei nº 9.032/95.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=165",
    texto: "A revisão de pensão por morte e demais benefícios, constituídos antes da entrada em vigor da Lei 9.032/1995, não pode ser realizada com base em novo coeficiente de cálculo estabelecido no referido diploma legal." },
  { id: "stf-rg-166", tribunal: "STF", tipo: "Repercussão Geral", numero: "166", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Contribuição, a cargo da empresa, incidente sobre 15% do valor bruto da nota fiscal ou fatura de prestação de serviços desenvolvidos por cooperativas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=166",
    texto: "É inconstitucional a contribuição previdenciária prevista no art. 22, IV, da Lei 8.212/1991, com redação dada pela Lei 9.876/1999, que incide sobre o valor bruto da nota fiscal ou fatura referente a serviços prestados por cooperados por intermédio de cooperativas de trabalho." },
  { id: "stf-rg-168", tribunal: "STF", tipo: "Repercussão Geral", numero: "168", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Aplicação de lei que majorou alíquota do imposto de renda sobre fatos ocorridos no mesmo ano em que publicada, para pagamento do tributo com relação ao exercício seguinte.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=168",
    texto: "É inconstitucional a aplicação retroativa de lei que majora a alíquota incidente sobre o lucro proveniente de operações incentivadas ocorridas no passado, ainda que no mesmo ano-base, tendo em vista que o fato gerador se consolida no momento em que ocorre cada operação de exportação, à luz da extrafiscalidade da tributação na espécie." },
  { id: "stf-rg-169", tribunal: "STF", tipo: "Repercussão Geral", numero: "169", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Aplicação retroativa do § 4º do art. 33 da Lei nº 11.343/2006 sobre pena cominada com base na Lei nº 6.368/76.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=169",
    texto: "I – É inadmissível a aplicação da causa de diminuição prevista no art. 33, § 4º, da Lei 11.343/2006 à pena relativa à condenação por crime cometido na vigência da Lei 6.368/1976; II – Não é possível a conjugação de partes mais benéficas das referidas normas, para criar-se uma terceira lei, sob pena de violação aos princípios da legalidade e da separação de Poderes; III – O juiz, contudo, deverá, no caso concreto, avaliar qual das mencionadas leis é mais favorável ao réu e aplicá-la em sua integralidade." },
  { id: "stf-rg-170", tribunal: "STF", tipo: "Repercussão Geral", numero: "170", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Julgamento proferido por órgão fracionário de tribunal composto majoritariamente por juízes convocados.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=170",
    texto: "Não viola o postulado constitucional do juiz natural o julgamento de apelação por órgão composto majoritariamente por juízes convocados, autorizado no âmbito da Justiça Federal pela Lei 9.788/1999." },
  { id: "stf-rg-171", tribunal: "STF", tipo: "Repercussão Geral", numero: "171", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de ICMS na importação de equipamento médico por sociedade civil não contribuinte do referido imposto.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=171",
    texto: "Após a Emenda Constitucional 33/2001, é constitucional a incidência de ICMS sobre operações de importação efetuadas por pessoa, física ou jurídica, que não se dedica habitualmente ao comércio ou à prestação de serviços." },
  { id: "stf-rg-172", tribunal: "STF", tipo: "Repercussão Geral", numero: "172", situacao: "Vigente", tema: "DIREITO ELEITORAL E PROCESSO ELEITORAL", titulo: "Reeleição de membro do Ministério Público para o exercício de atividade político-partidária após a Emenda Constitucional nº 45/2004.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=172",
    texto: "Membro do Ministério Público possui direito a concorrer à nova eleição a ser reeleito, nos termos do art. 14, § 5º da Constituição Federal, desde que já ocupe cargo eletivo à época do advento da EC 45/2004." },
  { id: "stf-rg-173", tribunal: "STF", tipo: "Repercussão Geral", numero: "173", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Concessão de benefício assistencial a estrangeiros residentes no Brasil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=173",
    texto: "Os estrangeiros residentes no País são beneficiários da assistência social prevista no artigo 203, inciso V, da Constituição Federal, uma vez atendidos os requisitos constitucionais e legais." },
  { id: "stf-rg-174", tribunal: "STF", tipo: "Repercussão Geral", numero: "174", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Índice de correção monetária incidente sobre verba a ser restituída a associados que se desligam de plano de previdência privada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=174",
    texto: "A questão do índice de correção monetária aplicável sobre as parcelas de contribuição a serem restituídas aos associados que se desligam de plano de previdência privada tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-175", tribunal: "STF", tipo: "Repercussão Geral", numero: "175", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Modulação dos efeitos de declaração incidental de inconstitucionalidade de lei municipal que instituiu a cobrança de IPTU com alíquotas progressivas, TIP e TCLL.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=175",
    texto: "A questão constitucional sobre a modulação dos efeitos de declaração incidental de inconstitucionalidade de leis municipais que instituam cobrança do Imposto Predial e Territorial Urbano - IPTU, com alíquotas progressivas, de Taxa de Iluminação Pública - TIP e de Taxa de Coleta de Lixo e Limpeza Pública - TCLL não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-176", tribunal: "STF", tipo: "Repercussão Geral", numero: "176", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Inclusão dos valores pagos a título de “demanda contratada” na base de cálculo do ICMS sobre operações envolvendo energia elétrica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=176",
    texto: "A demanda de potência elétrica não é passível, por si só, de tributação via ICMS, porquanto somente integram a base de cálculo desse imposto os valores referentes àquelas operações em que haja efetivo consumo de energia elétrica pelo consumidor." },
  { id: "stf-rg-177", tribunal: "STF", tipo: "Repercussão Geral", numero: "177", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Revogação, por medida provisória, da isenção da contribuição para o PIS e para a COFINS concedida às sociedades cooperativas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=177",
    texto: "São legítimas as alterações introduzidas pela Medida Provisória 1.858/1999, no que revogou a isenção da COFINS e da contribuição para o PIS concedidas às sociedades cooperativas." },
  { id: "stf-rg-178", tribunal: "STF", tipo: "Repercussão Geral", numero: "178", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Cálculo da quantidade de ações em que dividido o capital subscrito em uma sociedade anônima, referente aos contratos de participação financeira e subscrição de ações de telefonia, com complementação dos títulos acionários.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=178",
    texto: "A questão da forma de apuração do valor patrimonial das ações subscritas e integralizadas, pelo adquirente de linha telefônica fixa, em contratos de participação financeira com aquisição de título acionário, firmado com a Brasil Telecom S/A, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-179", tribunal: "STF", tipo: "Repercussão Geral", numero: "179", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Compensação de créditos calculados com base nos valores dos bens e mercadorias em estoque, no momento da transição da sistemática cumulativa para a não-cumulativa da contribuição para o PIS e da COFINS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=179",
    texto: "Em relação às contribuições ao PIS/COFINS, não viola o princípio da não-cumulatividade a impossibilidade de creditamento de despesas ocorridas no sistema cumulativo, pois os créditos são presumidos e o direito ao desconto somente surge com as despesas incorridas em momento posterior ao início da vigência do regime não-cumulativo." },
  { id: "stf-rg-180", tribunal: "STF", tipo: "Repercussão Geral", numero: "180", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Restituição de valores descontados da remuneração de servidores públicos estaduais mediante aplicação de redutor salarial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=180",
    texto: "A questão do direito à restituição de valores descontados da remuneração de servidores públicos estaduais mediante aplicação de redutor salarial, nos termos da Lei Complementar de Sergipe nº 61/2001, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-181", tribunal: "STF", tipo: "Repercussão Geral", numero: "181", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Pressupostos de admissibilidade de recursos da competência de outros Tribunais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=181",
    texto: "A questão do preenchimento dos pressupostos de admissibilidade de recursos da competência de outros Tribunais tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-182", tribunal: "STF", tipo: "Repercussão Geral", numero: "182", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Valoração das circunstâncias judiciais previstas no art. 59 do Código Penal na fundamentação da fixação da pena-base pelo juízo sentenciante.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=182",
    texto: "A questão da adequada valoração das circunstâncias judiciais previstas no art. 59 do Código Penal, na fundamentação da fixação da pena-base pelo juízo sentenciante, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-183", tribunal: "STF", tipo: "Repercussão Geral", numero: "183", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Aplicação do princípio da insignificância a crime de posse de substância entorpecente para uso próprio.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=183",
    texto: "A questão da aplicação do princípio da insignificância a crime de posse de substância entorpecente para uso próprio tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-184", tribunal: "STF", tipo: "Repercussão Geral", numero: "184", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Poder de investigação do Ministério Público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=184",
    texto: "O Ministério Público dispõe de competência para promover, por autoridade própria, e por prazo razoável, investigações de natureza penal, desde que respeitados os direitos e garantias que assistem a qualquer indiciado ou a qualquer pessoa sob investigação do Estado, observadas, sempre, por seus agentes, as hipóteses de reserva constitucional de jurisdição e, também, as prerrogativas profissionais de que se acham investidos, em nosso País, os Advogados (Lei 8.906/1994, art. 7º, notadamente os incisos I, II, III, XI, XIII, XIV e XIX), sem prejuízo da possibilidade – sempre presente no Estado democrático de Direito – do permanente controle jurisdicional dos atos, necessariamente documentados (Súmula Vinculante 14), praticados pelos membros dessa Instituição." },
  { id: "stf-rg-186", tribunal: "STF", tipo: "Repercussão Geral", numero: "186", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Fixação de honorários advocatícios em execução de sentença proferida em ação coletiva não-embargada pela Fazenda Pública.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=186",
    texto: "A questão da fixação de honorários advocatícios no cumprimento de sentença proferida em ações coletivas, não embargadas pela Fazenda Pública, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-187", tribunal: "STF", tipo: "Repercussão Geral", numero: "187", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Imposição de efeitos próprios de sentença penal condenatória à transação penal prevista na Lei nº 9.099/95.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=187",
    texto: "As consequências jurídicas extra penais previstas no art. 91 do Código Penal são decorrentes de sentença penal condenatória. Tal não ocorre, portanto, quando há transação penal (art. 76 da Lei 9.099/1995), cuja sentença tem natureza meramente homologatória, sem qualquer juízo sobre a responsabilidade criminal do aceitante. As consequências geradas pela transação penal são essencialmente aquelas estipuladas por modo consensual no respectivo instrumento de acordo." },
  { id: "stf-rg-188", tribunal: "STF", tipo: "Repercussão Geral", numero: "188", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Declaração de hipossuficiência para obtenção de gratuidade de justiça.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=188",
    texto: "A questão sobre o preenchimento dos requisitos para assistência jurídica gratuita às pessoas naturais quanto à comprovação do estado de hipossuficiência tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-189", tribunal: "STF", tipo: "Repercussão Geral", numero: "189", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Pensão decorrente de morte de servidor que, apesar de contratado pelo regime da Consolidação das Leis do Trabalho, faleceu após o advento da Lei nº 8.112/90.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=189",
    texto: "A questão do regime jurídico aplicável à pensão por morte de servidor contratado por conselho de fiscalização profissional pelas normas da Consolidação das Leis do Trabalho - CLT e falecido após a vigência do Regime Jurídico Único instituído pela Lei n. 8.112/1990 tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-190", tribunal: "STF", tipo: "Repercussão Geral", numero: "190", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar causas que envolvam complementação de aposentadoria por entidades de previdência privada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=190",
    texto: "Compete à Justiça comum o processamento de demandas ajuizadas contra entidades privadas de previdência com o propósito de obter complementação de aposentadoria, mantendo-se na Justiça Federal do Trabalho, até o trânsito em julgado e correspondente execução, todas as causas dessa espécie em que houver sido proferida sentença de mérito até 20/2/2013." },
  { id: "stf-rg-191", tribunal: "STF", tipo: "Repercussão Geral", numero: "191", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Recolhimento de FGTS na contratação de servidor público sem a prévia aprovação em concurso público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=191",
    texto: "É constitucional o art. 19-A da Lei 8.036/1990, que dispõe ser devido o depósito do Fundo de Garantia do Tempo de Serviço - FGTS na conta de trabalhador cujo contrato com a Administração Pública seja declarado nulo por ausência de prévia aprovação em concurso público, desde que mantido o direito ao salário." },
  { id: "stf-rg-193", tribunal: "STF", tipo: "Repercussão Geral", numero: "193", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Incorporação a contrato individual de trabalho de cláusulas normativas pactuadas em acordos coletivos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=193",
    texto: "A questão da ultratividade de cláusulas normativas pactuadas em acordo ou convenção coletivos para incorporação de vantagens nos contratos individuais de trabalho de forma definitiva tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-194", tribunal: "STF", tipo: "Repercussão Geral", numero: "194", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reajuste da vantagem pecuniária denominada “indenização de campo” no mesmo percentual pago a título de reajuste de diárias.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=194",
    texto: "A questão da possibilidade de o reajuste da vantagem pecuniária denominada “indenização de campo” ser calculado no mesmo percentual do pago a título de diárias tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-195", tribunal: "STF", tipo: "Repercussão Geral", numero: "195", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Publicação de editais de notificação do lançamento da contribuição sindical rural por órgão da imprensa oficial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=195",
    texto: "A questão da validade da publicação de editais de notificação do lançamento da contribuição sindical rural somente em órgão da imprensa oficial tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-196", tribunal: "STF", tipo: "Repercussão Geral", numero: "196", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Responsabilidade subsidiária de tomador de serviços, em decorrência do não-pagamento de verbas trabalhistas devidas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=196",
    texto: "A questão, no âmbito privado, da responsabilidade subsidiária do tomador de serviços por obrigações trabalhistas não pagas pelo prestador de serviços tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-197", tribunal: "STF", tipo: "Repercussão Geral", numero: "197", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Cobrança de contribuição assistencial, instituída por assembleia, de trabalhadores não filiados a sindicato, bem como a aplicação de multa em julgamento de embargos de declaração tidos por protelatórios.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=197",
    texto: "I - A questão da cobrança de contribuição assistencial, instituída por assembleia de trabalhadores não filiados ao sindicato da categoria tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009. II - A questão da aplicação de multa pela oposição de embargos de declaração julgados protelatórios tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-198", tribunal: "STF", tipo: "Repercussão Geral", numero: "198", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Prazo prescricional relativo às atualizações monetárias de contas fundiárias do PIS/PASEP.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=198",
    texto: "A questão do prazo prescricional aplicável ao pedido de pagamento de correção monetária das contas vinculadas ao Programas de Integração Social e ao de Formação do Patrimônio do Servidor - PIS/PASEP, em razão dos expurgos inflacionários gerados por planos econômicos do Governo Federal, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-199", tribunal: "STF", tipo: "Repercussão Geral", numero: "199", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de descontos previdenciários sobre vencimentos de servidor que se afastou regularmente do serviço, após haver formulado pedido de sua aposentadoria.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=199",
    texto: "A questão do pagamento da contribuição previdenciária durante o período do regular afastamento do servidor do cargo, após formular pedido de aposentadoria, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-200", tribunal: "STF", tipo: "Repercussão Geral", numero: "200", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Critério de reajuste de saldo devedor de contrato de mútuo firmado no âmbito do Sistema Financeiro da Habitação para posterior amortização.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=200",
    texto: "A questão do critério de reajuste de saldo devedor de contrato de mútuo firmado no âmbito do Sistema Financeiro da Habitação para posterior amortização tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-201", tribunal: "STF", tipo: "Repercussão Geral", numero: "201", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Restituição da diferença de ICMS pago a mais no regime de substituição tributária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=201",
    texto: "É devida a restituição da diferença do Imposto sobre Circulação de Mercadorias e Serviços (ICMS) pago a mais no regime de substituição tributária para a frente se a base de cálculo efetiva da operação for inferior à presumida." },
  { id: "stf-rg-202", tribunal: "STF", tipo: "Repercussão Geral", numero: "202", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Cobrança de contribuição a ser recolhida pelo empregador rural pessoa física sobre receita bruta proveniente da comercialização de sua produção.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=202",
    texto: "É inconstitucional a contribuição, a ser recolhida pelo empregador rural pessoa física, incidente sobre a receita bruta proveniente da comercialização de sua produção, prevista no art. 25 da Lei 8.212/1991, com a redação dada pelo art. 1º da Lei 8.540/1992." },
  { id: "stf-rg-203", tribunal: "STF", tipo: "Repercussão Geral", numero: "203", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Sistema de reserva de vagas, como forma de ação afirmativa de inclusão social, estabelecido por universidade.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=203",
    texto: "É constitucional o uso de ações afirmativas, tal como a utilização do sistema de reserva de vagas (\"cotas\") por critério étnico-racial, na seleção para ingresso no ensino superior público." },
  { id: "stf-rg-204", tribunal: "STF", tipo: "Repercussão Geral", numero: "204", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Contribuição adicional de 2,5% sobre a folha de salários de instituições financeiras instituída pela Lei nº 8.212/91.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=204",
    texto: "É constitucional a previsão legal de diferenciação de alíquotas em relação às contribuições previdenciárias incidentes sobre a folha de salários de instituições financeiras ou de entidades a elas legalmente equiparáveis, após a edição da Emenda Constitucional nº 20/1998." },
  { id: "stf-rg-205", tribunal: "STF", tipo: "Repercussão Geral", numero: "205", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Requisitos para a concessão de progressão de regime à luz da nova redação dada ao art. 112 da Lei de Execução Penal pela Lei nº 10.792/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=205",
    texto: "A questão do preenchimento dos requisitos para a concessão de progressão de regime carcerário, nos termos do art. 112 da Lei de Execução Penal, na redação da Lei nº 10.792/2003, em especial com relação à realização de exame criminológico (exigência de avaliação social e psicológica do apenado), tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-207", tribunal: "STF", tipo: "Repercussão Geral", numero: "207", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reconhecimento a contribuinte optante pelo SIMPLES das imunidades tributárias previstas nos artigos 149, § 2º, I e 153, § 3º, III, da Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=207",
    texto: "As imunidades previstas nos artigos 149, § 2º, I, e 153, § 3º, III, da Constituição Federal são aplicáveis às empresas optantes pelo Simples Nacional." },
  { id: "stf-rg-209", tribunal: "STF", tipo: "Repercussão Geral", numero: "209", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade tributária de livros, jornais e periódicos do FINSOCIAL.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=209",
    texto: "A contribuição para o Finsocial, incidente sobre o faturamento das empresas, não está abrangida pela imunidade objetiva prevista no art. 150, VI, d, da Constituição Federal de 1988, anterior art. 19. III, d, da Carta de 1967/1969." },
  { id: "stf-rg-210", tribunal: "STF", tipo: "Repercussão Geral", numero: "210", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Limitação de indenizações por danos decorrentes de extravio de bagagem com fundamento na Convenção de Varsóvia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=210",
    texto: "Nos termos do art. 178 da Constituição da República, as normas e os tratados internacionais limitadores da responsabilidade das transportadoras aéreas de passageiros, especialmente as Convenções de Varsóvia e Montreal, têm prevalência em relação ao Código de Defesa do Consumidor." },
  { id: "stf-rg-211", tribunal: "STF", tipo: "Repercussão Geral", numero: "211", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Necessidade de lei em sentido formal para a atualização do valor venal de imóveis.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=211",
    texto: "A majoração do valor venal dos imóveis para efeito da cobrança de IPTU não prescinde da edição de lei em sentido formal, exigência que somente se pode afastar quando a atualização não excede os índices inflacionários anuais de correção monetária." },
  { id: "stf-rg-212", tribunal: "STF", tipo: "Repercussão Geral", numero: "212", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do ISS sobre locação de bens móveis.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=212",
    texto: "É inconstitucional a incidência do Imposto sobre Serviços de Qualquer Natureza- ISS sobre operações de locação de bens móveis, dissociada da prestação de serviços." },
  { id: "stf-rg-213", tribunal: "STF", tipo: "Repercussão Geral", numero: "213", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar ação que visa compelir os entes políticos das três esferas do governo a fornecer medicamentos à pessoa carente, quando o valor da causa é inferior ao limite de sessenta salários mínimos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=213",
    texto: "A questão do reconhecimento da competência do Juizado Especial Federal para processar e julgar as causas que visam compelir os entes políticos federal, estadual e municipal a fornecer medicamentos à pessoa carente, limitada essa competência ao limite de sessenta salários mínimos, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-214", tribunal: "STF", tipo: "Repercussão Geral", numero: "214", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "a) Inclusão do ICMS em sua própria base de cálculo; b) Emprego da taxa SELIC para fins tributários; c) Natureza de multa moratória fixada em 20% do valor do tributo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=214",
    texto: "I - É constitucional a inclusão do valor do Imposto sobre Circulação de Mercadorias e Serviços - ICMS na sua própria base de cálculo; II - É legítima a utilização, por lei, da taxa SELIC como índice de atualização de débitos tributários; III- Não é confiscatória a multa moratória no patamar de 20%." },
  { id: "stf-rg-215", tribunal: "STF", tipo: "Repercussão Geral", numero: "215", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Forma de cálculo de contribuição previdenciária incidente sobre o 13º salário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=215",
    texto: "A questão da forma de cálculo, mediante a aplicação, em separado, da tabela de alíquotas, para a cobrança de contribuição social previdenciária sobre a Gratificação Natalina (décimo terceiro salário) tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-216", tribunal: "STF", tipo: "Repercussão Geral", numero: "216", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do ICMS sobre venda de veículos salvados de sinistros.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=216",
    texto: "O ICMS não incide sobre alienação de salvados de sinistro pelas seguradoras." },
  { id: "stf-rg-217", tribunal: "STF", tipo: "Repercussão Geral", numero: "217", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Comprovação do poder de polícia para cobrança de taxa de localização e funcionamento.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=217",
    texto: "É constitucional taxa de renovação de funcionamento e localização municipal, desde que efetivo o exercício do poder de polícia, demonstrado pela existência de órgão e estrutura competentes para o respectivo exercício." },
  { id: "stf-rg-219", tribunal: "STF", tipo: "Repercussão Geral", numero: "219", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Extensão a beneficiários de plano de previdência privada complementar de vantagem outorgada a empregados ativos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=219",
    texto: "A questão da extensão de vantagem pecuniária paga aos empregados em atividade aos beneficiários da previdência complementar privada tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-220", tribunal: "STF", tipo: "Repercussão Geral", numero: "220", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência do Poder Judiciário para determinar ao Poder Executivo a realização de obras em estabelecimentos prisionais com o objetivo de assegurar a observância de direitos fundamentais dos presos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=220",
    texto: "É lícito ao Judiciário impor à Administração Pública obrigação de fazer, consistente na promoção de medidas ou na execução de obras emergenciais em estabelecimentos prisionais para dar efetividade ao postulado da dignidade da pessoa humana e assegurar aos detentos o respeito à sua integridade física e moral, nos termos do que preceitua o art. 5º, XLIX, da Constituição Federal, não sendo oponível à decisão o argumento da reserva do possível nem o princípio da separação dos poderes." },
  { id: "stf-rg-222", tribunal: "STF", tipo: "Repercussão Geral", numero: "222", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Extensão do adicional de risco portuário ao trabalhador portuário avulso.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=222",
    texto: "Sempre que for pago ao trabalhador com vínculo permanente, o adicional de riscos é devido, nos mesmos termos, ao trabalhador portuário avulso." },
  { id: "stf-rg-223", tribunal: "STF", tipo: "Repercussão Geral", numero: "223", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência do Poder Legislativo municipal para estabelecer vantagens, benefícios e adicionais em favor de servidores municipais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=223",
    texto: "É inconstitucional, por afrontar a iniciativa privativa do Chefe do Poder Executivo, a normatização de direitos dos servidores públicos em lei orgânica do Município." },
  { id: "stf-rg-224", tribunal: "STF", tipo: "Repercussão Geral", numero: "224", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade tributária recíproca do responsável tributário por sucessão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=224",
    texto: "A imunidade tributária recíproca não exonera o sucessor das obrigações tributárias relativas aos fatos jurídicos tributários ocorridos antes da sucessão." },
  { id: "stf-rg-225", tribunal: "STF", tipo: "Repercussão Geral", numero: "225", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "a) Fornecimento de informações sobre movimentações financeiras ao Fisco sem autorização judicial, nos termos do art. 6º da Lei Complementar nº 105/2001; b) Aplicação retroativa da Lei nº 10.174/2001 para apuração de créditos tributários referentes a exercícios anteriores ao de sua vigência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=225",
    texto: "I - O art. 6º da Lei Complementar 105/01 não ofende o direito ao sigilo bancário, pois realiza a igualdade em relação aos cidadãos, por meio do princípio da capacidade contributiva, bem como estabelece requisitos objetivos e o translado do dever de sigilo da esfera bancária para a fiscal; II - A Lei 10.174/01 não atrai a aplicação do princípio da irretroatividade das leis tributárias, tendo em vista o caráter instrumental da norma, nos termos do artigo 144, § 1º, do CTN." },
  { id: "stf-rg-226", tribunal: "STF", tipo: "Repercussão Geral", numero: "226", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Cobrança do IPTU pela alíquota mínima nos casos de declaração da inconstitucionalidade da sua progressividade.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=226",
    texto: "Declarada inconstitucional a progressividade de alíquota tributária, é devido o tributo calculado pela alíquota mínima correspondente, de acordo com a destinação do imóvel." },
  { id: "stf-rg-227", tribunal: "STF", tipo: "Repercussão Geral", numero: "227", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reserva de lei complementar para instituir contribuição destinada ao SEBRAE.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=227",
    texto: "A contribuição destinada ao Serviço Brasileiro de Apoio às Micro e Pequenas Empresas - Sebrae possui natureza de contribuição de intervenção no domínio econômico e não necessita de edição de lei complementar para ser instituída." },
  { id: "stf-rg-228", tribunal: "STF", tipo: "Repercussão Geral", numero: "228", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Restituição de valores recolhidos a maior a título de PIS e COFINS mediante o regime de substituição tributária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=228",
    texto: "É devida a restituição da diferença das contribuições para o Programa de Integração Social - PIS e para o Financiamento da Seguridade Social - Cofins recolhidas a mais, no regime de substituição tributária, se a base de cálculo efetiva das operações for inferior à presumida." },
  { id: "stf-rg-229", tribunal: "STF", tipo: "Repercussão Geral", numero: "229", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Isonomia quanto ao enquadramento como beneficiário do regime público de previdência complementar instituído por lei estadual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=229",
    texto: "A questão do preenchimento dos requisitos para concessão de complementação de aposentadoria, nos termos das Leis paulistas n. 4.819/1958 e n. 200/1974, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-230", tribunal: "STF", tipo: "Repercussão Geral", numero: "230", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Exigibilidade da contribuição para o Fundo de Saúde dos Militares.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=230",
    texto: "A questão da exigibilidade de contribuição para manutenção e custeio dos Fundos de Saúde dos militares das Forças Armadas, até março de 2001 (Medida Provisória n. 2.131/2000), tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-232", tribunal: "STF", tipo: "Repercussão Geral", numero: "232", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Indenização por danos morais decorrentes de inscrição indevida em cadastro de inadimplentes.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=232",
    texto: "A questão do direito à indenização por danos morais pela indevida inscrição em cadastro de inadimplentes tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-233", tribunal: "STF", tipo: "Repercussão Geral", numero: "233", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "a) Indenização por danos morais decorrentes de vazamento de produtos químicos em um dos afluentes do Rio Paraíba do Sul; b) Competência dos Juizados Especiais para as causas respectivas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=233",
    texto: "I - A questão do direito à indenização por danos morais pelo vazamento de produtos químicos em um dos afluentes do Rio Paraíba do Sul tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009; II - A questão da complexidade da causa para fixação da competência dos Juizados Especiais tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-234", tribunal: "STF", tipo: "Repercussão Geral", numero: "234", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reajuste das tabelas dos serviços prestados ao SUS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=234",
    texto: "A questão relativa ao reajuste das tabelas dos serviços prestados ao Sistema Único de Saúde - SUS, em virtude da implantação do Plano Real, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-235", tribunal: "STF", tipo: "Repercussão Geral", numero: "235", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade tributária das atividades exercidas pela Empresa Brasileira de Correios e Telégrafos - ECT.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=235",
    texto: "Os serviços prestados pela Empresa Brasileira de Correios e Telégrafos - ECT, inclusive aqueles em que a empresa não age em regime de monopólio, estão abrangidos pela imunidade tributária recíproca (CF, art. 150, VI,a e §§ 2º e 3º)." },
  { id: "stf-rg-236", tribunal: "STF", tipo: "Repercussão Geral", numero: "236", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Natureza jurídica de verbas rescisórias para fins de incidência do imposto de renda.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=236",
    texto: "A questão da exigibilidade do Imposto de Renda de Pessoa Física - IRPF, sobre verbas rescisórias recebidas nos planos de demissão voluntária ou incentivadas, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-237", tribunal: "STF", tipo: "Repercussão Geral", numero: "237", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Gravação ambiental realizada por um dos interlocutores sem conhecimento do outro.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=237",
    texto: "É lícita a prova consistente em gravação ambiental realizada por um dos interlocutores sem conhecimento do outro." },
  { id: "stf-rg-238", tribunal: "STF", tipo: "Repercussão Geral", numero: "238", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Propositura de ação penal por descumprimento das condições estabelecidas em transação penal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=238",
    texto: "A homologação da transação penal prevista no artigo 76 da Lei 9.099/1995 não faz coisa julgada material e, descumpridas suas cláusulas, retoma-se a situação anterior, possibilitando-se ao Ministério Público a continuidade da persecução penal mediante oferecimento de denúncia ou requisição de inquérito policial." },
  { id: "stf-rg-239", tribunal: "STF", tipo: "Repercussão Geral", numero: "239", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Extinção da punibilidade em virtude de prescrição da pretensão punitiva em perspectiva.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=239",
    texto: "É inadmissível a extinção da punibilidade em virtude da decretação da prescrição \"em perspectiva, projetada ou antecipada\", isto é, com base em previsão da pena que hipoteticamente seria aplicada, independentemente da existência ou sorte do processo criminal." },
  { id: "stf-rg-240", tribunal: "STF", tipo: "Repercussão Geral", numero: "240", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Nulidade do processo pela falta de requisição do réu preso, por meio de carta precatória, para comparecer à audiência de oitiva de testemunhas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=240",
    texto: "Inexiste nulidade pela ausência, em oitiva de testemunha por carta precatória, de réu preso que não manifestou expressamente intenção de participar da audiência." },
  { id: "stf-rg-241", tribunal: "STF", tipo: "Repercussão Geral", numero: "241", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Exigência da prévia aprovação no exame da OAB para exercício da advocacia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=241",
    texto: "O Exame, inicialmente previsto no artigo 48, inciso III, da Lei nº 4.215/63 e hoje no artigo 8º, inciso IV, da Lei nº 8.906/94, mostra-se consentâneo com a Constituição Federal. Com ela é compatível a prerrogativa conferida à Ordem dos Advogados do Brasil para aplicação do exame de suficiência relativo ao acesso à advocacia." },
  { id: "stf-rg-242", tribunal: "STF", tipo: "Repercussão Geral", numero: "242", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar ações indenizatórias decorrentes de acidente do trabalho propostas por sucessores do trabalhador falecido.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=242",
    texto: "Compete à Justiça do Trabalho processar e julgar as ações de indenização por danos morais e patrimoniais decorrentes de acidentes de trabalho propostas por empregado contra empregador, inclusive as propostas pelos sucessores do trabalhador falecido, salvo quando a sentença de mérito for anterior à promulgação da EC nº 45/04, hipótese em que, até o trânsito em julgado e a sua execução, a competência continuará a ser da Justiça Comum." },
  { id: "stf-rg-243", tribunal: "STF", tipo: "Repercussão Geral", numero: "243", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Termo inicial dos juros moratórios nas ações de repetição de indébito tributário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=243",
    texto: "A questão da definição do termo inicial dos juros moratórios nas ações de repetição de indébito tributário tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-244", tribunal: "STF", tipo: "Repercussão Geral", numero: "244", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Limitação temporal para o aproveitamento de créditos de PIS E COFINS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=244",
    texto: "Surge inconstitucional, por ofensa aos princípios da não cumulatividade e da isonomia, o artigo 31, cabeça, da Lei nº 10.865/2004, no que vedou o creditamento da contribuição para o PIS e da COFINS, relativamente ao ativo imobilizado adquirido até 30 de abril de 2004" },
  { id: "stf-rg-245", tribunal: "STF", tipo: "Repercussão Geral", numero: "245", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Base de cálculo do adicional de periculosidade dos empregados do setor de energia elétrica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=245",
    texto: "A questão da base de cálculo do adicional de periculosidade dos empregados do setor de energia elétrica (Lei n. 7.369/1985) tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-246", tribunal: "STF", tipo: "Repercussão Geral", numero: "246", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Responsabilidade subsidiária da Administração Pública por encargos trabalhistas gerados pelo inadimplemento de empresa prestadora de serviço.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=246",
    texto: "O inadimplemento dos encargos trabalhistas dos empregados do contratado não transfere automaticamente ao Poder Público contratante a responsabilidade pelo seu pagamento, seja em caráter solidário ou subsidiário, nos termos do art. 71, § 1º, da Lei nº 8.666/93." },
  { id: "stf-rg-247", tribunal: "STF", tipo: "Repercussão Geral", numero: "247", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do ISS sobre materiais empregados na construção civil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=247",
    texto: "O art. 9º, § 2º, do DL nº 406/1968 foi recepcionado pela ordem jurídica inaugurada pela Constituição de 1988." },
  { id: "stf-rg-248", tribunal: "STF", tipo: "Repercussão Geral", numero: "248", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Pressupostos de admissibilidade de ação rescisória no âmbito da Justiça do Trabalho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=248",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa ao preenchimento dos pressupostos de admissibilidade de ação rescisória no âmbito da Justiça do Trabalho." },
  { id: "stf-rg-250", tribunal: "STF", tipo: "Repercussão Geral", numero: "250", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão de regra mais benéfica concernente a férias prevista no Estatuto do Magistério estadual a professores contratados sob o regime temporário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=250",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à possibilidade de extensão de regra mais benéfica prevista no estatuto do magistério público estadual - referente a férias - aos professores contratados temporariamente quando não há regramento específico sobre o caso." },
  { id: "stf-rg-251", tribunal: "STF", tipo: "Repercussão Geral", numero: "251", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Suspensão ou devolução de prazos processuais da União em decorrência de movimento grevista deflagrado pelos membros das carreiras da AGU.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=251",
    texto: "A questão da necessidade de suspensão ou devolução de prazos processuais da União em face da greve deflagrada pelos membros das carreiras da AGU tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-252", tribunal: "STF", tipo: "Repercussão Geral", numero: "252", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão de Gratificação Especial a cargos equivalentes ao de técnico de nível superior.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=252",
    texto: "A questão da extensão do direito ao recebimento da gratificação especial das Leis estaduais n. 6.371/1993, n. 6.568/1994 e n. 6.615/1994 aos assessores jurídicos do Rio Grande do Norte, até a incorporação da parcela única remuneratória, nos termos da Lei Complementar Estadual n. 229/2002, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-253", tribunal: "STF", tipo: "Repercussão Geral", numero: "253", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aplicabilidade do regime de precatórios às entidades da Administração Indireta prestadoras de serviços públicos essenciais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=253",
    texto: "Sociedades de economia mista que desenvolvem atividade econômica em regime concorrencial não se beneficiam do regime de precatórios, previsto no art. 100 da Constituição da República." },
  { id: "stf-rg-255", tribunal: "STF", tipo: "Repercussão Geral", numero: "255", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Prazo prescricional para a execução contra o Estado de débitos oriundos da extinta Minascaixa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=255",
    texto: "A questão da definição do prazo prescricional para a execução contra o Estado, de débitos da extinta Caixa Econômica do Estado de Minas Gerais - Minascaixa, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-256", tribunal: "STF", tipo: "Repercussão Geral", numero: "256", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Complementação de aposentadoria de ex-empregado da FEPASA.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=256",
    texto: "Afronta o art. 7º, inciso IV, da Constituição Federal a adoção do salário mínimo como base de cálculo para a fixação de piso salarial." },
  { id: "stf-rg-257", tribunal: "STF", tipo: "Repercussão Geral", numero: "257", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Inclusão das vantagens pessoais no teto remuneratório estadual após a Emenda Constitucional nº 41/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=257",
    texto: "Computam-se, para efeito de observância do teto remuneratório do art. 37, XI, da Constituição da República, também os valores percebidos anteriormente à vigência da Emenda Constitucional 41/2003 a título de vantagens pessoais pelo servidor público, dispensada a restituição dos valores recebidos em excesso e de boa-fé até o dia 18 de novembro de 2015." },
  { id: "stf-rg-258", tribunal: "STF", tipo: "Repercussão Geral", numero: "258", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência para processar e julgar execuções ajuizadas pela OAB contra advogados inadimplentes quanto ao pagamento de anuidades.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=258",
    texto: "Compete à Justiça Federal processar e julgar ações em que a Ordem dos Advogados do Brasil, quer mediante o Conselho Federal, quer seccional, figure na relação processual." },
  { id: "stf-rg-259", tribunal: "STF", tipo: "Repercussão Geral", numero: "259", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Tributação da importação de pequenos componentes eletrônicos que acompanham material didático de curso de montagem de computadores.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=259",
    texto: "A imunidade da alínea d do inciso VI do artigo 150 da Constituição Federal alcança componentes eletrônicos destinados, exclusivamente, a integrar unidade didática com fascículos." },
  { id: "stf-rg-260", tribunal: "STF", tipo: "Repercussão Geral", numero: "260", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão aos inativos da Gratificação de Desempenho de Atividade Jurídica - GDAJ.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=260",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à possibilidade de extensão aos inativos do direito ao recebimento da Gratificação de Desempenho de Atividade Jurídica (GDAJ), paga aos servidores em atividade até a edição da Medida Provisória nº 305/2006, convertida na Lei nº 11.358/2006." },
  { id: "stf-rg-261", tribunal: "STF", tipo: "Repercussão Geral", numero: "261", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Cobrança de taxa de ocupação do solo e do espaço aéreo por poste de transmissão de energia elétrica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=261",
    texto: "É inconstitucional a cobrança de taxa, espécie tributária, pelo uso de espaços públicos dos municípios por concessionárias prestadoras do serviço público de fornecimento de energia elétrica." },
  { id: "stf-rg-262", tribunal: "STF", tipo: "Repercussão Geral", numero: "262", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade do Ministério Público para ajuizar ação civil pública que tem por objetivo compelir entes federados a entregar medicamentos a portadores de certas doenças.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=262",
    texto: "O Ministério Público é parte legítima para ajuizamento de ação civil pública que vise o fornecimento de remédios a portadores de certa doença." },
  { id: "stf-rg-263", tribunal: "STF", tipo: "Repercussão Geral", numero: "263", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de ICMS sobre os serviços prestados pelos provedores de acesso à internet.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=263",
    texto: "A questão da incidência do Imposto sobre Circulação de Mercadorias e Serviços - ICMS sobre os serviços prestados pelos provedores de acesso à internet tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-267", tribunal: "STF", tipo: "Repercussão Geral", numero: "267", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Fixação de multa por descumprimento de ordem judicial de pagamento de precatório no prazo legal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=267",
    texto: "A questão da possibilidade de fixação de multa pelo atraso no pagamento de precatório, com fundamento nos arts. 14, inc. V, 600, inc. III, e 601 - atuais arts. 77, § 2º, 774 e parágrafo único - do Código de Processo Civil, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-268", tribunal: "STF", tipo: "Repercussão Geral", numero: "268", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Majorações de tarifas de energia elétrica durante o período de congelamento de preços denominado Plano Cruzado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=268",
    texto: "A questão do reajuste das tarifas de energia elétrica durante o congelamento de preços, quando vigente o denominado Plano Cruzado (Decretos-Leis n. 2.283 e n. 2.284, ambos de 1986), tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-269", tribunal: "STF", tipo: "Repercussão Geral", numero: "269", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de militar mineiro reformado do Estado de Minas Gerais receber o adicional trintenário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=269",
    texto: "A questão do direito do militar reformado do Estado de Minas Gerais ao recebimento da vantagem pecuniária “Adicional Trintenário” tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-270", tribunal: "STF", tipo: "Repercussão Geral", numero: "270", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reserva de lei para instituir punição disciplinar imposta a militar.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=270",
    texto: "A questão da legalidade das punições previstas no Regulamento Disciplinar da Brigada Militar do Rio Grande do Sul tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-271", tribunal: "STF", tipo: "Repercussão Geral", numero: "271", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de filha de ex-servidor, solteira e maior de 21 anos, receber pensão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=271",
    texto: "A questão do direito ao recebimento de pensão previdenciária por morte de servidor estadual pela filha solteira, maior de 21 anos de idade, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 84.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-272", tribunal: "STF", tipo: "Repercussão Geral", numero: "272", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência dos Municípios para legislar sobre tempo máximo de espera de clientes em filas de bancos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=272",
    texto: "Compete aos Municípios legislar sobre assuntos de interesse local, notadamente sobre a definição do tempo máximo de espera de clientes em filas de instituições bancárias." },
  { id: "stf-rg-273", tribunal: "STF", tipo: "Repercussão Geral", numero: "273", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de servidores inativos da extinta FEPASA à extensão de vantagens salariais concedidas em dissídios e acordos coletivos aos ferroviários em atividade.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=273",
    texto: "A questão do direito ao recebimento de vantagens salariais concedidas em dissídios e acordos coletivos aos ferroviários em atividade, pelos servidores aposentados e pensionistas da extinta Ferrovia Paulista S.A. - FEPASA, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-274", tribunal: "STF", tipo: "Repercussão Geral", numero: "274", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Cobrança de pulsos além da franquia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=274",
    texto: "A questão da legalidade da cobrança, sem a respectiva discriminação, dos pulsos excedentes à franquia mensal do contrato de prestação de serviço de telefonia fixa tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-275", tribunal: "STF", tipo: "Repercussão Geral", numero: "275", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de servidores públicos do Poder Judiciário do Estado do Rio Grande do Norte à Gratificação Especial de Técnico de Nível Superior - GTNS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=275",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa ao direito ao recebimento da Gratificação Especial de Técnico de Nível Superior (GTNS), vantagem pecuniária instituída pela Lei nº 6.371/1993 e mantida por suas sucessivas alterações, pelos servidores técnicos do Poder Judiciário do Estado do Rio Grande do Norte." },
  { id: "stf-rg-276", tribunal: "STF", tipo: "Repercussão Geral", numero: "276", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Adicional noturno para policiais civis que trabalham sob o regime de plantão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=276",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa ao direito ao recebimento da vantagem pecuniária Adicional Noturno pelos policiais civis que trabalham sob o regime de plantão." },
  { id: "stf-rg-277", tribunal: "STF", tipo: "Repercussão Geral", numero: "277", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Desvinculação do produto de arrecadação de contribuições sociais da União por Emenda Constitucional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=277",
    texto: "I - A eventual inconstitucionalidade de desvinculação de receita de contribuições sociais não acarreta a devolução ao contribuinte do montante correspondente ao percentual desvinculado, pois a tributação não seria inconstitucional ou ilegal, única hipótese autorizadora da repetição do indébito tributário; II - Não é inconstitucional a desvinculação, ainda que parcial, do produto da arrecadação das contribuições sociais instituídas pelo art. 76 do ADCT, seja em sua redação original, seja naquela resultante das Emendas Constitucionais 27/2000, 42/2003, 56/2007, 59/2009 e 68/2011." },
  { id: "stf-rg-278", tribunal: "STF", tipo: "Repercussão Geral", numero: "278", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "a) Sujeição da contribuição ao PIS ao princípio da anterioridade nonagesimal; b) Contagem do prazo nonagesimal para fins de majoração de alíquota estabelecida por ocasião da conversão de medida provisória em lei.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=278",
    texto: "I - A contribuição para o PIS está sujeita ao princípio da anterioridade nonagesimal previsto no art. 195, § 6º, da Constituição Federal; II - Nos casos em que a majoração de alíquota tenha sido estabelecida somente na conversão de medida provisória em lei, a contribuição apenas poderá ser exigida após noventa dias da publicação da lei de conversão." },
  { id: "stf-rg-279", tribunal: "STF", tipo: "Repercussão Geral", numero: "279", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Natureza das leis n. 2.123/93 e 4.069/62 que garantem aos procuradores federais direito a férias de sessenta dias por ano.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=279",
    texto: "Os procuradores federais têm o direito às férias de 30 dias, por força do que dispõe o art. 5º da Lei 9.527/1997, porquanto não recepcionados com natureza de leis complementares o art. 1º da Lei 2.123/1953 e o art. 17, parágrafo único, da Lei 4.069/1962." },
  { id: "stf-rg-280", tribunal: "STF", tipo: "Repercussão Geral", numero: "280", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Provas obtidas mediante invasão de domicílio por policiais sem mandado de busca e apreensão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=280",
    texto: "A entrada forçada em domicílio sem mandado judicial só é lícita, mesmo em período noturno, quando amparada em fundadas razões, devidamente justificadas a posteriori, que indiquem que dentro da casa ocorre situação de flagrante delito, sob pena de responsabilidade disciplinar, civil e penal do agente ou da autoridade, e de nulidade dos atos praticados." },
  { id: "stf-rg-282", tribunal: "STF", tipo: "Repercussão Geral", numero: "282", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Subsistência, após a Emenda Constitucional nº 19/98, dos subtetos salariais criados com amparo na redação original do art. 37, XI, da Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=282",
    texto: "A eficácia do inciso XI do artigo 37 da Constituição Federal, decorrente da redação da Emenda Constitucional nº 19/1998, condiciona-se à fixação do subsídio, mediante lei de iniciativa conjunta do Presidente da República, do Presidente do Supremo, do Presidente da Câmara e do Presidente do Senado, persistindo a vigência do texto primitivo da Carta, no que definido o teto por Poder, consideradas as esferas federal e estadual." },
  { id: "stf-rg-283", tribunal: "STF", tipo: "Repercussão Geral", numero: "283", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do PIS e da COFINS não-cumulativos sobre valores recebidos a título de transferência de ICMS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=283",
    texto: "É inconstitucional a incidência da contribuição ao PIS e da COFINS não cumulativas sobre os valores recebidos por empresa exportadora em razão da transferência a terceiros de créditos de ICMS." },
  { id: "stf-rg-286", tribunal: "STF", tipo: "Repercussão Geral", numero: "286", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Responsabilidade civil de banco por danos decorrentes de indevida utilização de cartão de crédito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=286",
    texto: "A questão da responsabilidade civil de instituição financeira, bancária ou de crédito pelo lançamento indevido de débito no cartão de crédito enviado ao titular do contrato bancário firmado, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-287", tribunal: "STF", tipo: "Repercussão Geral", numero: "287", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Sujeito ativo competente para cobrança do ISS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=287",
    texto: "A questão da definição do sujeito ativo para cobrança do Imposto sobre Serviços - ISS, quando o local de prestação do serviço ocorra em unidade da Federação distinta da sede do contribuinte, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-288", tribunal: "STF", tipo: "Repercussão Geral", numero: "288", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Interrupção do prazo prescricional na execução fiscal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=288",
    texto: "A questão da causa de interrupção do prazo prescricional na execução fiscal, antes da alteração do art. 174, parágrafo único, inc. I, do Código Tributário Nacional - CTN, pela Lei Complementar n. 118/2005, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-290", tribunal: "STF", tipo: "Repercussão Geral", numero: "290", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Pagamento de diferenças em razão de reenquadramento de servidor público do Município de Santos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=290",
    texto: "A questão do direito ao pagamento de diferenças pelo reenquadramento de servidor público do Município de Santos, nos termos do Plano de Cargos, Carreiras e Salários (PCCS) e no Plano de Avaliação de Desempenho (PAV), previsto na legislação municipal pertinente, tem natureza nfraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-291", tribunal: "STF", tipo: "Repercussão Geral", numero: "291", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Notificação pessoal de contribuinte para exclusão do REFIS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=291",
    texto: "A questão da validade do meio pelo qual intima-se o contribuinte sobre a exclusão do Programa de Recuperação Fiscal - Refis tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-292", tribunal: "STF", tipo: "Repercussão Geral", numero: "292", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Extinção de execução fiscal da União por falta de interesse de agir, em razão do valor irrisório do débito, com base em legislação federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=292",
    texto: "A questão da extinção de execuções fiscais, por falta de interesse de agir do ente político credor, em razão do valor do débito executado ser irrisório, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-294", tribunal: "STF", tipo: "Repercussão Geral", numero: "294", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Cabimento de agravo interno contra decisão monocrática proferida no âmbito dos Juizados Especiais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=294",
    texto: "Cabe o julgamento monocrático no âmbito dos Juizados Especiais, desde que possível sua revisão pelo Órgão Colegiado." },
  { id: "stf-rg-295", tribunal: "STF", tipo: "Repercussão Geral", numero: "295", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Penhorabilidade de bem de família de fiador de contrato de locação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=295",
    texto: "É constitucional a penhora de bem de família pertencente a fiador de contrato de locação, em virtude da compatibilidade da exceção prevista no art. 3°, VII, da Lei 8.009/1990 com o direito à moradia consagrado no art. 6° da Constituição Federal, com redação da EC 26/2000." },
  { id: "stf-rg-296", tribunal: "STF", tipo: "Repercussão Geral", numero: "296", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Caráter taxativo da lista de serviços sujeitos ao ISS a que se refere o art. 156, III, da Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=296",
    texto: "É taxativa a lista de serviços sujeitos ao ISS a que se refere o art. 156, III, da Constituição Federal, admitindo-se, contudo, a incidência do tributo sobre as atividades inerentes aos serviços elencados em lei em razão da interpretação extensiva." },
  { id: "stf-rg-297", tribunal: "STF", tipo: "Repercussão Geral", numero: "297", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do ICMS na importação de mercadoria por meio de arrendamento mercantil internacional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=297",
    texto: "Não incide o ICMS na operação de arrendamento mercantil internacional, salvo na hipótese de antecipação da opção de compra, quando configurada a transferência da titularidade do bem." },
  { id: "stf-rg-298", tribunal: "STF", tipo: "Repercussão Geral", numero: "298", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Diferimento da compensação tributária advinda da correção monetária das demonstrações financeiras no período-base de 1990.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=298",
    texto: "É constitucional a sistemática estabelecida no artigo 3º, inciso I, da Lei 8.200/1991 para a compensação tributária decorrente da correção monetária das demonstrações financeiras de pessoas jurídicas no ano-base 1990." },
  { id: "stf-rg-299", tribunal: "STF", tipo: "Repercussão Geral", numero: "299", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Aproveitamento integral de créditos do ICMS pago na operação antecedente em hipóteses de redução parcial da base de cálculo na operação subsequente.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=299",
    texto: "A redução da base de cálculo de ICMS equivale à isenção parcial, o que acarreta a anulação proporcional de crédito relativo às operações anteriores, salvo disposição em lei estadual em sentido contrário." },
  { id: "stf-rg-300", tribunal: "STF", tipo: "Repercussão Geral", numero: "300", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do ISS sobre os contratos de franquia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=300",
    texto: "É constitucional a incidência de Imposto sobre Serviços de Qualquer Natureza (ISS) sobre contratos de franquia (franchising) (itens 10.04 e 17.08 da lista de serviços prevista no Anexo da Lei Complementar 116/2003)." },
  { id: "stf-rg-301", tribunal: "STF", tipo: "Repercussão Geral", numero: "301", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Cobrança de ICMS sobre serviço de habilitação de celular.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=301",
    texto: "A questão da exigibilidade do Imposto sobre Circulação de Mercadorias e Serviços - ICMS sobre serviço de habilitação de celular tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-302", tribunal: "STF", tipo: "Repercussão Geral", numero: "302", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Natureza jurídica da retenção de 11% sobre os valores brutos dos contratos de prestação de serviço por empresas tomadoras de serviços.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=302",
    texto: "É constitucional a substituição tributária prevista no art. 31 da Lei 8.212/1991, com redação dada pela Lei 9.711/98, que determinou a retenção de 11% do valor bruto da nota fiscal ou fatura de prestação de serviço." },
  { id: "stf-rg-305", tribunal: "STF", tipo: "Repercussão Geral", numero: "305", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar ações de cobrança de honorários advocatícios arbitrados em favor de advogado dativo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=305",
    texto: "Compete à Justiça comum estadual processar e julgar as ações de cobrança ou os feitos executivos de honorários advocatícios arbitrados em favor de advogado dativo em ações cíveis e criminais." },
  { id: "stf-rg-306", tribunal: "STF", tipo: "Repercussão Geral", numero: "306", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Natureza jurídica dos juros, em reclamatória trabalhista, para fins de incidência de Imposto de Renda.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=306",
    texto: "A questão da exigibilidade de Imposto de Renda de Pessoa Física - IRPF sobre os juros moratórios recebidos em reclamatória trabalhista tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-307", tribunal: "STF", tipo: "Repercussão Geral", numero: "307", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Efeito suspensivo a embargos do devedor em execução fiscal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=307",
    texto: "A questão da concessão de efeito suspensivo aos embargos de devedor opostos na execução fiscal tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-308", tribunal: "STF", tipo: "Repercussão Geral", numero: "308", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Efeitos trabalhistas decorrentes de contratação pela Administração Pública de empregado não submetido à prévia aprovação em concurso público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=308",
    texto: "A Constituição de 1988 comina de nulidade as contratações de pessoal pela Administração Pública sem a observância das normas referentes à indispensabilidade da prévia aprovação em concurso público (CF, art. 37, § 2º), não gerando, essas contratações, quaisquer efeitos jurídicos válidos em relação aos empregados contratados, a não ser o direito à percepção dos salários referentes ao período trabalhado e, nos termos do art. 19-A da Lei 8.036/90, ao levantamento dos depósitos efetuados no Fundo de Garantia por Tempo de Serviço - FGTS." },
  { id: "stf-rg-310", tribunal: "STF", tipo: "Repercussão Geral", numero: "310", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Alteração judicial, ao patamar de 12% ao ano, de juros contratados após a Emenda Constitucional nº 40/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=310",
    texto: "A questão da limitação da taxa dos juros remuneratórios a 12% a.a. (doze por cento ao ano), nos contratos firmados junto ao Sistema Financeiro Nacional, após a Emenda Constitucional n. 40, de 29/5/2003, que revogou o § 3º do art. 192 da Constituição Federal, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-311", tribunal: "STF", tipo: "Repercussão Geral", numero: "311", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Índice para correção monetária das demonstrações financeiras das pessoas jurídicas no ano-base de 1990.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=311",
    texto: "São inconstitucionais o § 1º do artigo 30 da Lei nº 7.730/1989 e o artigo 30 da Lei nº 7.799/1989." },
  { id: "stf-rg-312", tribunal: "STF", tipo: "Repercussão Geral", numero: "312", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Interpretação extensiva ao parágrafo único do art. 34 da Lei nº 10.741/2003 para fins do cálculo da renda familiar de que trata o art. 20, §3º, da Lei nº 8.742/93.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=312",
    texto: "É inconstitucional, por omissão parcial, o parágrafo único do art. 34 da Lei 10.741/2003 (Estatuto do Idoso)." },
  { id: "stf-rg-313", tribunal: "STF", tipo: "Repercussão Geral", numero: "313", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Aplicação do prazo decadencial previsto na Medida Provisória nº 1.523/97 a benefícios concedidos antes da sua edição.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=313",
    texto: "I – Inexiste prazo decadencial para a concessão inicial do benefício previdenciário; II – Aplica-se o prazo decadencial de dez anos para a revisão de benefícios concedidos, inclusive os anteriores ao advento da Medida Provisória 1.523/1997, hipótese em que a contagem do prazo deve iniciar-se em 1º de agosto de 1997." },
  { id: "stf-rg-314", tribunal: "STF", tipo: "Repercussão Geral", numero: "314", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Exigência de depósito prévio como requisito de admissibilidade de recurso administrativo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=314",
    texto: "É inconstitucional a exigência de depósito prévio como requisito de admissibilidade de recurso administrativo." },
  { id: "stf-rg-315", tribunal: "STF", tipo: "Repercussão Geral", numero: "315", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aumento de vencimentos e extensão de vantagens e gratificações pelo Poder Judiciário e pela Administração Pública.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=315",
    texto: "Não cabe, ao Poder Judiciário, que não tem a função legislativa, aumentar vencimentos de servidores públicos sob o fundamento de isonomia." },
  { id: "stf-rg-316", tribunal: "STF", tipo: "Repercussão Geral", numero: "316", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão da vantagem denominada Prêmio de Incentivo à Qualidade – PIQ a servidores inativos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=316",
    texto: "A questão do direito dos servidores públicos aposentados e pensionistas ao recebimento do Prêmio de Incentivo à Qualidade - PIQ, instituído pela Lei 8.975/1994 do Estado de São Paulo, pago aos servidores públicos estaduais em atividade, tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-318", tribunal: "STF", tipo: "Repercussão Geral", numero: "318", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Requisitos do mandado de segurança.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=318",
    texto: "A questão do preenchimento dos pressupostos de admissibilidade do mandado de segurança tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-319", tribunal: "STF", tipo: "Repercussão Geral", numero: "319", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Critérios de correção monetária para a devolução de empréstimo compulsório de energia elétrica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=319",
    texto: "A questão da incidência e dos índices de correção monetária para a devolução de empréstimo compulsório sobre o consumo de energia elétrica tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-320", tribunal: "STF", tipo: "Repercussão Geral", numero: "320", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Reconhecimento da condição de ex-combatente para fins de recebimento de benefício de pensão especial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=320",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa ao preenchimento dos requisitos para o reconhecimento da condição de ex-combatente da Segunda Guerra mundial e a consequente concessão do benefício de pensão especial." },
  { id: "stf-rg-322", tribunal: "STF", tipo: "Repercussão Geral", numero: "322", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Creditamento de IPI na entrada de insumos provenientes da Zona Franca de Manaus.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=322",
    texto: "Há direito ao creditamento de IPI na entrada de insumos, matéria-prima e material de embalagem adquiridos junto à Zona Franca de Manaus sob o regime de isenção, considerada a previsão de incentivos regionais constante do art. 43, § 2º, III, da Constituição Federal, combinada com o comando do art. 40 do ADCT." },
  { id: "stf-rg-323", tribunal: "STF", tipo: "Repercussão Geral", numero: "323", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do PIS sobre os atos cooperativos próprios.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=323",
    texto: "A receita auferida pelas cooperativas de trabalho decorrentes dos atos (negócios jurídicos) firmados com terceiros se insere na materialidade da contribuição ao PIS/PASEP." },
  { id: "stf-rg-324", tribunal: "STF", tipo: "Repercussão Geral", numero: "324", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reserva de lei complementar para estabelecimento de valores pré-fixados para o cálculo do IPI.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=324",
    texto: "É constitucional o artigo 3º da Lei 7.798/1989, que estabelece valores pré-fixados para o IPI." },
  { id: "stf-rg-326", tribunal: "STF", tipo: "Repercussão Geral", numero: "326", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de ICMS sobre o fornecimento de água encanada por concessionárias.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=326",
    texto: "O ICMS não incide sobre o fornecimento de água tratada por concessionária de serviço público, dado que esse serviço não caracteriza uma operação de circulação de mercadoria." },
  { id: "stf-rg-329", tribunal: "STF", tipo: "Repercussão Geral", numero: "329", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do PIS e da COFINS sobre a receita decorrente da variação cambial positiva.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=329",
    texto: "É inconstitucional a incidência da contribuição ao PIS e da COFINS sobre a receita decorrente da variação cambial positiva obtida nas operações de exportação de produtos." },
  { id: "stf-rg-330", tribunal: "STF", tipo: "Repercussão Geral", numero: "330", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do IRPF sobre os benefícios recebidos de entidade de previdência privada e as importâncias correspondentes ao resgate de contribuições.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=330",
    texto: "A questão da incidência de Imposto de Renda das Pessoas Físicas - IRPF sobre os benefícios recebidos de entidade de previdência privada e as importâncias correspondentes ao resgate de contribuições, após 31/12/1995, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-331", tribunal: "STF", tipo: "Repercussão Geral", numero: "331", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência de juros progressivos sobre o FGTS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=331",
    texto: "A questão da aplicação de taxa de juros progressivos sobre conta vinculada de Fundo de Garantia por Tempo de Serviço - FGTS tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-332", tribunal: "STF", tipo: "Repercussão Geral", numero: "332", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Restituição dos valores pagos a consórcio em razão de desistência do consorciado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=332",
    texto: "A questão da possibilidade de devolução das parcelas pagas em consórcio, no caso de desistência do consorciado antes do encerramento do grupo, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-333", tribunal: "STF", tipo: "Repercussão Geral", numero: "333", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Responsabilização do empregador no caso de sucessão de empresa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=333",
    texto: "A questão da responsabilidade solidária do empregador pelos créditos trabalhistas, no caso de cisão parcial ou sucessão de empresas, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-334", tribunal: "STF", tipo: "Repercussão Geral", numero: "334", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Direito a cálculo de benefício de aposentadoria de acordo com legislação vigente à época do preenchimento dos requisitos exigidos para sua concessão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=334",
    texto: "Para o cálculo da renda mensal inicial, cumpre observar o quadro mais favorável ao beneficiário, pouco importando o decesso remuneratório ocorrido em data posterior ao implemento das condições legais para a aposentadoria, respeitadas a decadência do direito à revisão e a prescrição quanto às prestações vencidas." },
  { id: "stf-rg-335", tribunal: "STF", tipo: "Repercussão Geral", numero: "335", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Remarcação de teste de aptidão física em concurso público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=335",
    texto: "Inexiste direito dos candidatos em concurso público à prova de segunda chamada nos teste de aptidão física, salvo contrária disposição editalícia, em razão de circunstâncias pessoais, ainda que de caráter fisiológico ou de força maior, mantida a validade das provas de segunda chamada realizadas até 15/5/2013, em nome da segurança jurídica." },
  { id: "stf-rg-337", tribunal: "STF", tipo: "Repercussão Geral", numero: "337", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Majoração da alíquota de contribuição para o PIS mediante medida provisória.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=337",
    texto: "Não obstante as Leis nº 10.637/02 e 10.833/03 estejam em processo de inconstitucionalização, é ainda constitucional o modelo legal de coexistência dos regimes cumulativo e não cumulativo, na apuração do PIS/Cofins das empresas prestadoras de serviços." },
  { id: "stf-rg-338", tribunal: "STF", tipo: "Repercussão Geral", numero: "338", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Exigência do exame psicotécnico em concurso público, sem previsão em lei, e critérios de avaliação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=338",
    texto: "A exigência do exame psicotécnico em concurso depende de previsão em lei e no edital, e deve seguir critérios objetivos." },
  { id: "stf-rg-339", tribunal: "STF", tipo: "Repercussão Geral", numero: "339", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Obrigatoriedade de fundamentação das decisões judiciais", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=339",
    texto: "O art. 93, IX, da Constituição Federal exige que o acórdão ou decisão sejam fundamentados, ainda que sucintamente, sem determinar, contudo, o exame pormenorizado de cada uma das alegações ou provas." },
  { id: "stf-rg-340", tribunal: "STF", tipo: "Repercussão Geral", numero: "340", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão do índice de reajuste de 28,86% aos militares.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=340",
    texto: "Estende-se o reajuste de 28,86% aos servidores militares contemplados com índices inferiores pelas Leis 8.622/1993 e 8.627/1993, já que se trata de revisão geral dos servidores públicos, observadas, entretanto, as compensações dos reajustes concedidos e a limitação temporal da Medida Provisória 2.131/2000, atual Medida Provisória 2.215-10/2001." },
  { id: "stf-rg-341", tribunal: "STF", tipo: "Repercussão Geral", numero: "341", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Plano de carreira de servidores públicos instituído por lei municipal sem norma regulamentadora.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=341",
    texto: "A questão do direito à progressão funcional na carreira do Magistério municipal, cumpridos os requisitos legais, independente da edição de decreto regulamentar do Poder Executivo, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-342", tribunal: "STF", tipo: "Repercussão Geral", numero: "342", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade de ICMS sobre produtos e serviços adquiridos por entidade filantrópica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=342",
    texto: "A imunidade tributária subjetiva aplica-se a seus beneficiários na posição de contribuinte de direito, mas não na de simples contribuinte de fato, sendo irrelevante para a verificação da existência do beneplácito constitucional a repercussão econômica do tributo envolvido." },
  { id: "stf-rg-343", tribunal: "STF", tipo: "Repercussão Geral", numero: "343", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Devolução de contribuição previdenciária cobrada de servidor inativo ou pensionista, no período compreendido entre a EC 20/98 e a EC 41/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=343",
    texto: "É devida a devolução aos pensionistas e inativos, perante o Juízo competente para a execução, da contribuição previdenciária indevidamente recolhida no período entre a EC 20/1998 e a EC 41/2003, sob pena de enriquecimento ilícito do ente estatal." },
  { id: "stf-rg-344", tribunal: "STF", tipo: "Repercussão Geral", numero: "344", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de contribuição previdenciária sobre a participação nos lucros da empresa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=344",
    texto: "Incide contribuição previdenciária sobre as parcelas pagas a título de participação nos lucros no período que antecede a entrada em vigor da Medida Provisória 794/1994, que regulamentou o art. 7º, XI, da Constituição Federal de 1988." },
  { id: "stf-rg-345", tribunal: "STF", tipo: "Repercussão Geral", numero: "345", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Ressarcimento ao Sistema Único de Saúde – SUS das despesas com atendimento a beneficiários de planos privados de saúde.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=345",
    texto: "É constitucional o ressarcimento previsto no art. 32 da Lei 9.656/98, o qual é aplicável aos procedimentos médicos, hospitalares ou ambulatoriais custeados pelo SUS e posteriores a 1.9.1998, assegurados o contraditório e a ampla defesa, no âmbito administrativo, em todos os marcos jurídicos." },
  { id: "stf-rg-346", tribunal: "STF", tipo: "Repercussão Geral", numero: "346", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reserva de norma constitucional para dispor sobre direito à compensação de créditos do ICMS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=346",
    texto: "(i) Não viola o princípio da não cumulatividade (art. 155, §2º, incisos I e XII, alínea c, da CF/1988) lei complementar que prorroga a compensação de créditos de ICMS relativos a bens adquiridos para uso e consumo no próprio estabelecimento do contribuinte; (ii) Conforme o artigo 150, III, c, da CF/1988, o princípio da anterioridade nonagesimal aplica-se somente para leis que instituem ou majoram tributos, não incidindo relativamente às normas que prorrogam a data de início da compensação de crédito tributário." },
  { id: "stf-rg-347", tribunal: "STF", tipo: "Repercussão Geral", numero: "347", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito à atualização monetária do vale-refeição dos servidores públicos do Estado do Rio Grande do Sul por decisão judicial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=347",
    texto: "A discussão relativa ao reajuste de vale-refeição concedido a servidores públicos do Estado do Rio Grande do Sul é infraconstitucional, não ensejando o conhecimento do recurso extraordinário." },
  { id: "stf-rg-348", tribunal: "STF", tipo: "Repercussão Geral", numero: "348", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Plano diretor como instrumento básico da política de desenvolvimento e de expansão urbana.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=348",
    texto: "Os municípios com mais de vinte mil habitantes e o Distrito Federal podem legislar sobre programas e projetos específicos de ordenamento do espaço urbano por meio de leis que sejam compatíveis com as diretrizes fixadas no plano diretor." },
  { id: "stf-rg-349", tribunal: "STF", tipo: "Repercussão Geral", numero: "349", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Registro prévio do contrato de alienação fiduciária em garantia de veículo automotor perante o órgão competente para o licenciamento.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=349",
    texto: "É constitucional o § 1º do artigo 1.361 do Código Civil no que revela a possibilidade de ter-se como constituída a propriedade fiduciária de veículos com o registro do contrato na repartição competente para o licenciamento do bem." },
  { id: "stf-rg-350", tribunal: "STF", tipo: "Repercussão Geral", numero: "350", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Prévio requerimento administrativo como condição para o acesso ao Judiciário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=350",
    texto: "I - A concessão de benefícios previdenciários depende de requerimento do interessado, não se caracterizando ameaça ou lesão a direito antes de sua apreciação e indeferimento pelo INSS, ou se excedido o prazo legal para sua análise. É bem de ver, no entanto, que a exigência de prévio requerimento não se confunde com o exaurimento das vias administrativas; II – A exigência de prévio requerimento administrativo não deve prevalecer quando o entendimento da Administração for notória e reiteradamente contrário à postulação do segurado; III – Na hipótese de pretensão de revisão, restabelecimento ou manutenção de benefício anteriormente concedido, considerando que o INSS tem o dever legal de conceder a prestação mais vantajosa possível, o pedido poderá ser formulado diretamente em juízo – salvo se depender da análise de matéria de fato ainda não levada ao conhecimento da Administração –, uma vez que, nesses casos, a conduta do INSS já configura o não acolhimento ao menos tácito da pretensão; IV – Nas ações ajuizadas antes da conclusão do julgamento do RE 631.240/MG (03/09/2014) que não tenham sido instruídas por prova do prévio requerimento administrativo, nas hipóteses em que exigível, será observado o seguinte: (a) caso a ação tenha sido ajuizada no âmbito de Juizado Itinerante, a ausência de anterior pedido administrativo não deverá implicar a extinção do feito; (b) caso o INSS já tenha apresentado contestação de mérito, está caracterizado o interesse em agir pela resistência à pretensão; e (c) as demais ações que não se enquadrem nos itens (a) e (b) serão sobrestadas e baixadas ao juiz de primeiro grau, que deverá intimar o autor a dar entrada no pedido administrativo em até 30 dias, sob pena de extinção do processo por falta de interesse em agir. Comprovada a postulação administrativa, o juiz intimará o INSS para se manifestar acerca do pedido em até 90 dias. Se o pedido for acolhido administrativamente ou não puder ter o seu mérito analisado devido a razões imputáveis ao próprio requerente, extingue-se a ação. Do contrário, estará caracterizado o interesse em agir e o feito deverá prosseguir; V – Em todos os casos acima – itens (a), (b) e (c) –, tanto a análise administrativa quanto a judicial deverão levar em conta a data do início da ação como data de entrada do requerimento, para todos os efeitos legais." },
  { id: "stf-rg-351", tribunal: "STF", tipo: "Repercussão Geral", numero: "351", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão a inativos e pensionistas da Gratificação de Desempenho do Plano Geral de Cargos do Poder Executivo – GDPGPE.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=351",
    texto: "A Gratificação de Desempenho do Plano Geral de Cargos do Poder Executivo — GDPGPE, prevista na Lei nº 11.357/2006, estende-se aos inativos e pensionistas, no patamar de oitenta pontos, até o implemento da avaliação dos servidores em atividade." },
  { id: "stf-rg-353", tribunal: "STF", tipo: "Repercussão Geral", numero: "353", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Enquadramento de pessoas jurídicas da área de saúde na qualidade de prestadoras de serviço hospitalar para fins de obtenção do benefício de recolhimento da Contribuição Social sobre o Lucro líquido (CSLL) e do Imposto de Renda de Pessoa Jurídica (IRPJ) com base de cálculo reduzida.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=353",
    texto: "A questão do enquadramento da sociedade empresária como prestadora de serviços tipicamente hospitalar ou assemelhado, para o reconhecimento do direito ao recolhimento da Contribuição Social sobre o Lucro Líquido (CSLL) e do Imposto de Renda de Pessoa Jurídica (IRPJ) com alíquota reduzida, nos termos da exceção do art. 15, § 1º, inc. III, da Lei n. 9.249/1995, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-354", tribunal: "STF", tipo: "Repercussão Geral", numero: "354", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Cabimento de ação rescisória contra decisão dos Juizados Especiais Federais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=354",
    texto: "A questão do cabimento de ação rescisória contra decisão de Turma Recursal dos Juizados Especiais Federais tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-355", tribunal: "STF", tipo: "Repercussão Geral", numero: "355", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "a) Penhora de bens da Rede Ferroviária S.A. realizada anteriormente à sucessão pela União; b) Possibilidade de execução, pelo regime de precatório, dos bens da Rede Ferroviária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=355",
    texto: "É válida a penhora em bens de pessoa jurídica de direito privado, realizada anteriormente à sucessão desta pela União, não devendo a execução prosseguir mediante precatório." },
  { id: "stf-rg-356", tribunal: "STF", tipo: "Repercussão Geral", numero: "356", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Adicional de periculosidade em decorrência de armazenamento de agentes inflamáveis em prédio vertical.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=356",
    texto: "A questão do direito ao recebimento da vantagem pecuniária “Adicional de Periculosidade” pelo empregado que labora em prédio vertical onde está armazenado inflamável, líquido ou gasoso, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-357", tribunal: "STF", tipo: "Repercussão Geral", numero: "357", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Redução do intervalo intrajornada e majoração da jornada de trabalho, no regime de turnos ininterruptos de revezamento, por negociação coletiva.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=357",
    texto: "A questão da validade de norma de acordo ou convenção coletiva de trabalho que estabelece ampliação da jornada dos trabalhadores em turnos ininterruptos de revezamento e a redução de intervalo intrajornada tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009" },
  { id: "stf-rg-358", tribunal: "STF", tipo: "Repercussão Geral", numero: "358", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Competência dos Tribunais de Justiça dos Estados e do Distrito Federal para decidir sobre questão previdenciária, no bojo de processo autônomo de perda de posto e patente de militar.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=358",
    texto: "A competência constitucional do tribunal para decidir sobre a perda do posto e da patente dos oficiais e da graduação das praças é específica, nos termos do artigo 125, § 4º, não autorizando a concessão de reforma de policial militar julgado inapto a permanecer nas fileiras da corporação." },
  { id: "stf-rg-359", tribunal: "STF", tipo: "Repercussão Geral", numero: "359", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência do teto constitucional remuneratório sobre o montante decorrente da acumulação de proventos e pensão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=359",
    texto: "Ocorrida a morte do instituidor da pensão em momento posterior ao da Emenda Constitucional nº 19/1998, o teto constitucional previsto no inciso XI do artigo 37 da Constituição Federal incide sobre o somatório de remuneração ou provento e pensão percebida por servidor." },
  { id: "stf-rg-360", tribunal: "STF", tipo: "Repercussão Geral", numero: "360", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Desconstituição de título executivo judicial mediante aplicação do parágrafo único do art. 741 do Código de Processo Civil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=360",
    texto: "São constitucionais as disposições normativas do parágrafo único do art. 741 do CPC, do § 1º do art. 475-L, ambos do CPC/73, bem como os correspondentes dispositivos do CPC/15, o art. 525, § 1º, III e §§ 12 e 14, o art. 535, § 5º. São dispositivos que, buscando harmonizar a garantia da coisa julgada com o primado da Constituição, vieram agregar ao sistema processual brasileiro um mecanismo com eficácia rescisória de sentenças revestidas de vício de inconstitucionalidade qualificado, assim caracterizado nas hipóteses em que (a) a sentença exequenda esteja fundada em norma reconhecidamente inconstitucional, seja por aplicar norma inconstitucional, seja por aplicar norma em situação ou com um sentido inconstitucionais; ou (b) a sentença exequenda tenha deixado de aplicar norma reconhecidamente constitucional; e (c) desde que, em qualquer dos casos, o reconhecimento dessa constitucionalidade ou a inconstitucionalidade tenha decorrido de julgamento do STF realizado em data anterior ao trânsito em julgado da sentença exequenda." },
  { id: "stf-rg-361", tribunal: "STF", tipo: "Repercussão Geral", numero: "361", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Transmudação da natureza de precatório alimentar em normal em virtude de cessão do direito nele estampado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=361",
    texto: "A cessão de crédito alimentício não implica a alteração da natureza." },
  { id: "stf-rg-363", tribunal: "STF", tipo: "Repercussão Geral", numero: "363", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Impedimento à adesão ao regime tributário do Simples Nacional de microempresas ou empresas de pequeno porte com pendências tributárias ou previdenciárias.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=363",
    texto: "É constitucional o art. 17, V, da Lei Complementar 123/2006, que veda a adesão ao Simples Nacional à microempresa ou à empresa de pequeno porte que possua débito com o Instituto Nacional do Seguro Social - INSS ou com as Fazendas Públicas Federal, Estadual ou Municipal, cuja exigibilidade não esteja suspensa." },
  { id: "stf-rg-365", tribunal: "STF", tipo: "Repercussão Geral", numero: "365", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade do Estado por danos morais decorrentes de superlotação carcerária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=365",
    texto: "Considerando que é dever do Estado, imposto pelo sistema normativo, manter em seus presídios os padrões mínimos de humanidade previstos no ordenamento jurídico, é de sua responsabilidade, nos termos do art. 37, § 6º, da Constituição, a obrigação de ressarcir os danos, inclusive morais, comprovadamente causados aos detentos em decorrência da falta ou insuficiência das condições legais de encarceramento." },
  { id: "stf-rg-366", tribunal: "STF", tipo: "Repercussão Geral", numero: "366", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade civil do Estado por danos decorrentes de omissão do dever de fiscalizar comércio de fogos de artifício em residência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=366",
    texto: "Para que fique caracterizada a responsabilidade civil do Estado por danos decorrentes do comércio de fogos de artifício, é necessário que exista a violação de um dever jurídico específico de agir, que ocorrerá quando for concedida a licença para funcionamento sem as cautelas legais ou quando for de conhecimento do poder público eventuais irregularidades praticadas pelo particular." },
  { id: "stf-rg-367", tribunal: "STF", tipo: "Repercussão Geral", numero: "367", situacao: "Vigente", tema: "DIREITO ELEITORAL E PROCESSO ELEITORAL", titulo: "Inelegibilidade em razão de renúncia a mandato.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=367",
    texto: "A Lei Complementar 135/2010 não é aplicável às eleições gerais de 2010, em face do princípio da anterioridade eleitoral (art. 16 da Constituição Federal)." },
  { id: "stf-rg-368", tribunal: "STF", tipo: "Repercussão Geral", numero: "368", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do imposto de renda de pessoa física sobre rendimentos percebidos acumuladamente. Obs.: revisão de tese do tema 133, o qual não tinha repercussão geral.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=368",
    texto: "O Imposto de Renda incidente sobre verbas recebidas acumuladamente deve observar o regime de competência, aplicável a alíquota correspondente ao valor recebido mês a mês, e não a relativa ao total satisfeito de uma única vez." },
  { id: "stf-rg-370", tribunal: "STF", tipo: "Repercussão Geral", numero: "370", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Suspensão dos direitos políticos de condenado a pena privativa de liberdade substituída por pena restritiva de direito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=370",
    texto: "A suspensão de direitos políticos prevista no art. 15, inc. III, da Constituição Federal aplica-se no caso de substituição da pena privativa de liberdade pela restritiva de direitos." },
  { id: "stf-rg-371", tribunal: "STF", tipo: "Repercussão Geral", numero: "371", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Concessão de indulto a pessoa submetida a medida de segurança.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=371",
    texto: "Reveste-se de legitimidade jurídica a concessão, pelo Presidente da República, do benefício constitucional do indulto (CF, art. 84, XII), que traduz expressão do poder de graça do Estado, mesmo se se tratar de indulgência destinada a favorecer pessoa que, em razão de sua inimputabilidade ou semi-imputabilidade, sofre medida de segurança, ainda que de caráter pessoal e detentivo." },
  { id: "stf-rg-373", tribunal: "STF", tipo: "Repercussão Geral", numero: "373", situacao: "Vigente", tema: "DIREITO INTERNACIONAL", titulo: "Expulsão de estrangeiro cuja prole brasileira foi concebida posteriormente ao fato motivador do ato expulsório.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=373",
    texto: "O § 1º do artigo 75 da Lei nº 6.815/1980 não foi recepcionado pela Constituição Federal de 1988, sendo vedada a expulsão de estrangeiro cujo filho brasileiro foi reconhecido ou adotado posteriormente ao fato ensejador do ato expulsório, uma vez comprovado estar a criança sob a guarda do estrangeiro e deste depender economicamente." },
  { id: "stf-rg-374", tribunal: "STF", tipo: "Repercussão Geral", numero: "374", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Aplicação do art. 109, § 2º, da Constituição Federal aos entes da Administração Indireta", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=374",
    texto: "A regra prevista no § 2º do art. 109 da Constituição Federal também se aplica às ações movidas em face de autarquias federais." },
  { id: "stf-rg-375", tribunal: "STF", tipo: "Repercussão Geral", numero: "375", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Condições para a promoção de policial militar.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=375",
    texto: "A questão do preenchimento dos requisitos legais para promoção de policial militar à graduação superior tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-376", tribunal: "STF", tipo: "Repercussão Geral", numero: "376", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Cláusulas de barreira ou afunilamento em concurso público", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=376",
    texto: "É constitucional a regra inserida no edital de concurso público, denominada cláusula de barreira, com o intuito de selecionar apenas os candidatos mais bem classificados para prosseguir no certame." },
  { id: "stf-rg-377", tribunal: "STF", tipo: "Repercussão Geral", numero: "377", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência do teto remuneratório no caso de acumulação de cargos públicos", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=377",
    texto: "Nos casos autorizados constitucionalmente de acumulação de cargos, empregos e funções, a incidência do art. 37, inciso XI, da Constituição Federal pressupõe consideração de cada um dos vínculos formalizados, afastada a observância do teto remuneratório quanto ao somatório dos ganhos do agente público. (A mesma tese foi fixada para o Tema 384)" },
  { id: "stf-rg-378", tribunal: "STF", tipo: "Repercussão Geral", numero: "378", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reajustes de vencimentos de servidores públicos do Município de São Paulo com base em leis municipais", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=378",
    texto: "A questão dos percentuais aplicáveis aos reajustes quadrimestrais devidos aos servidores públicos do Município de São Paulo, conforme as normas municipais pertinentes, tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-379", tribunal: "STF", tipo: "Repercussão Geral", numero: "379", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imposto a incidir em operações mistas realizadas por farmácias de manipulação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=379",
    texto: "No tocante às farmácias de manipulação, incide o ISS sobre as operações envolvendo o preparo e o fornecimento de medicamentos encomendados para posterior entrega aos fregueses, em caráter pessoal, para consumo; incide o ICMS sobre os medicamentos de prateleira por elas produzidos, ofertados ao público consumidor." },
  { id: "stf-rg-380", tribunal: "STF", tipo: "Repercussão Geral", numero: "380", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aplicação do art. 17 do ADCT a vantagens protegidas pela garantia da coisa julgada", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=380",
    texto: "O art. 17 do ADCT alcança as situações jurídicas cobertas pela coisa julgada." },
  { id: "stf-rg-382", tribunal: "STF", tipo: "Repercussão Geral", numero: "382", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Sujeição da Lei Complementar 122/2006 a prazo nonagesimal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=382",
    texto: "A postergação do direito do contribuinte do ICMS de usufruir de novas hipóteses de creditamento, por não representar aumento do tributo, não se sujeita à anterioridade nonagesimal prevista no art. 150, III, c, da Constituição." },
  { id: "stf-rg-384", tribunal: "STF", tipo: "Repercussão Geral", numero: "384", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência do teto remuneratório a servidores já ocupantes de dois cargos públicos antes da vigência da Emenda Constitucional 41/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=384",
    texto: "Nos casos autorizados constitucionalmente de acumulação de cargos, empregos e funções, a incidência do art. 37, inciso XI, da Constituição Federal pressupõe consideração de cada um dos vínculos formalizados, afastada a observância do teto remuneratório quanto ao somatório dos ganhos do agente público. (A mesma tese foi fixada para o Tema 377)" },
  { id: "stf-rg-385", tribunal: "STF", tipo: "Repercussão Geral", numero: "385", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reconhecimento de imunidade tributária recíproca a sociedade de economia mista ocupante de bem público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=385",
    texto: "A imunidade recíproca, prevista no art. 150, VI, a, da Constituição não se estende a empresa privada arrendatária de imóvel público, quando seja ela exploradora de atividade econômica com fins lucrativos. Nessa hipótese é constitucional a cobrança do IPTU pelo Município." },
  { id: "stf-rg-387", tribunal: "STF", tipo: "Repercussão Geral", numero: "387", situacao: "Vigente", tema: "DIREITO ELEITORAL E PROCESSO ELEITORAL", titulo: "Aplicabilidade imediata da Lei Complementar nº 135/2010, que prevê novas hipóteses de inelegibilidade, às eleições de 2010.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=387",
    texto: "A Lei Complementar 135/2010 não é aplicável às eleições gerais de 2010, em face do princípio da anterioridade eleitoral (art. 16 da Constituição Federal)." },
  { id: "stf-rg-388", tribunal: "STF", tipo: "Repercussão Geral", numero: "388", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Revisão de auxílio-acidente concedido antes do advento da Lei nº 9.032/95.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=388",
    texto: "É inviável a aplicação retroativa da majoração prevista na Lei nº 9.032/1995 aos benefícios de auxílio-acidente concedidos em data anterior à sua vigência." },
  { id: "stf-rg-389", tribunal: "STF", tipo: "Repercussão Geral", numero: "389", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Âmbito de incidência de isenção de taxas judiciárias, custas e emolumentos concedida por lei estadual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=389",
    texto: "A questão da revogação de isenção do pagamento de emolumentos, taxas e custas judiciais, concedida por lei estadual ao ente político federado, quando vencido em demandas judicias, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-391", tribunal: "STF", tipo: "Repercussão Geral", numero: "391", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do PIS e da COFINS nas importações realizadas por conta e ordem de terceiros no contexto do Sistema Fundap.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=391",
    texto: "É infraconstitucional e incide a Súmula 279/STF, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa a base de cálculo da COFINS e do PIS, na importação feita no âmbito do sistema FUNDAP, quando fundada na análise do fatos e provas que originaram o negócio jurídico subjacente à importação e no enquadramento como operação de importação por conta e ordem de terceiro de que trata a MP nº 2.158-35/2001." },
  { id: "stf-rg-392", tribunal: "STF", tipo: "Repercussão Geral", numero: "392", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Superação da coisa julgada para possibilitar nova ação de investigação de paternidade em face de viabilidade de realização de exame de DNA.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=392",
    texto: "I - É possível a repropositura de ação de investigação de paternidade, quando anterior demanda idêntica, entre as mesmas partes, foi julgada improcedente, por falta de provas, em razão da parte interessada não dispor de condições econômicas para realizar o exame de DNA e o Estado não ter custeado a produção dessa prova; II - Deve ser relativizada a coisa julgada estabelecida em ações de investigação de paternidade em que não foi possível determinar-se a efetiva existência de vínculo genético a unir as partes, em decorrência da não realização do exame de DNA, meio de prova que pode fornecer segurança quase absoluta quanto à existência de tal vínculo." },
  { id: "stf-rg-393", tribunal: "STF", tipo: "Repercussão Geral", numero: "393", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Competência para processar e julgar suposto crime de publicação, na internet, de imagens com conteúdo pornográfico envolvendo criança ou adolescente.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=393",
    texto: "Compete à Justiça Federal processar e julgar os crimes consistentes em disponibilizar ou adquirir material pornográfico, acessível transnacionalmente, envolvendo criança ou adolescente, quando praticados por meio da rede mundial de computadores (arts. 241, 241-A e 241-B da Lei nº 8.069/1990)." },
  { id: "stf-rg-394", tribunal: "STF", tipo: "Repercussão Geral", numero: "394", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Pagamento imediato de reparação econômica a anistiados políticos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=394",
    texto: "1) - Reconhecido o direito à anistia política, a falta de cumprimento de requisição ou determinação de providências por parte da União, por intermédio do órgão competente, no prazo previsto nos arts. 12, § 4º, e 18, caput e parágrafo único, da Lei nº 10.599/02, caracteriza ilegalidade e violação de direito líquido e certo; 2) - Havendo rubricas no orçamento destinadas ao pagamento das indenizações devidas aos anistiados políticos e não demonstrada a ausência de disponibilidade de caixa, a União há de promover o pagamento do valor ao anistiado no prazo de 60 dias; 3) - Na ausência ou na insuficiência de disponibilidade orçamentária no exercício em curso, cumpre à União promover sua previsão no projeto de lei orçamentária imediatamente seguinte." },
  { id: "stf-rg-395", tribunal: "STF", tipo: "Repercussão Geral", numero: "395", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incorporação de quintos decorrentes do exercício de funções comissionadas e/ou gratificadas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=395",
    texto: "Ofende o princípio da legalidade a decisão que concede a incorporação de quintos pelo exercício de função comissionada no período de 8/4/1998 até 4/9/2001, ante a carência de fundamento legal." },
  { id: "stf-rg-396", tribunal: "STF", tipo: "Repercussão Geral", numero: "396", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito adquirido aos critérios da paridade e integralidade no pagamento de pensão por morte de servidor aposentado antes do advento da Emenda Constitucional nº 41/2003, mas falecido durante sua vigência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=396",
    texto: "Os pensionistas de servidor falecido posteriormente à EC 41/2003 têm direito à paridade com servidores em atividade (EC 41/2003, art. 7º), caso se enquadrem na regra de transição prevista no art. 3º da EC 47/2005. Não tem, contudo, direito à integralidade (CF, art. 40, § 7º, inciso I)." },
  { id: "stf-rg-397", tribunal: "STF", tipo: "Repercussão Geral", numero: "397", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Cobrança de contribuição previdenciária dos servidores estaduais ativos de São Paulo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=397",
    texto: "A questão constitucional da exigibilidade de contribuição previdenciária, instituída pala Lei Complementar estadual n. 943/2003, paga pelos servidores públicos estaduais em atividade, no que diz respeito ao preenchimento dos pressupostos de validade da criação de tributos, não tem repercussão geral, pois não atingido quórum mínimo de oito votos para reconhecimento do tema como matéria infraconstitucional (Regimento Interno do Supremo Tribunal Federal - RISTF, art. 324, § 2º)." },
  { id: "stf-rg-398", tribunal: "STF", tipo: "Repercussão Geral", numero: "398", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Anulação de sentença por contradição e incoerência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=398",
    texto: "A questão das causas legais de anulação de decisão judicial tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-399", tribunal: "STF", tipo: "Repercussão Geral", numero: "399", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Natureza da responsabilidade do proprietário de terras com cultivo ilegal de plantas psicotrópicas para fins de expropriação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=399",
    texto: "A expropriação prevista no art. 243 da Constituição Federal pode ser afastada, desde que o proprietário comprove que não incorreu em culpa, ainda que \"in vigilando\" ou \"in eligendo\"." },
  { id: "stf-rg-400", tribunal: "STF", tipo: "Repercussão Geral", numero: "400", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Legitimidade ativa para cobrar IPTU referente à área de município em que se controverte acerca da observância do artigo 18, § 4º, da Constituição Federal no processo de desmembramento.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=400",
    texto: "A exigência da realização de plebiscito, conforme se determina no § 4º do art. 18 da Constituição da República, não foi afastada pelo art. 96, inserido no Ato das Disposições Constitucionais Transitórias da Constituição da República pela Emenda Constitucional n. 57/2008, sendo ilegítimo o município ocupante para cobrar o Imposto sobre a Propriedade Predial e Territorial Urbana - IPTU nos territórios indevidamente incorporados." },
  { id: "stf-rg-401", tribunal: "STF", tipo: "Repercussão Geral", numero: "401", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Multa por litigância de má-fé.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=401",
    texto: "A questão da caracterização de situações justificadoras da imposição de multa por litigância de má-fé tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-402", tribunal: "STF", tipo: "Repercussão Geral", numero: "402", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade tributária recíproca quanto à incidência de ICMS sobre o transporte de encomendas pela Empresa Brasileira de Correios e Telégrafos - ECT.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=402",
    texto: "Não incide o ICMS sobre o serviço de transporte de encomendas realizado pela Empresa Brasileira de Correios e Telégrafos - ECT, tendo em vista a imunidade recíproca prevista no art. 150, VI, a, da Constituição Federal." },
  { id: "stf-rg-403", tribunal: "STF", tipo: "Repercussão Geral", numero: "403", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Requisitos para contratação de professor substituto no âmbito de instituições federais de ensino superior.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=403",
    texto: "É compatível com a Constituição Federal a previsão legal que exija o transcurso de 24 (vinte e quatro) meses, contados do término do contrato, antes de nova admissão de professor temporário anteriormente contratado." },
  { id: "stf-rg-404", tribunal: "STF", tipo: "Repercussão Geral", numero: "404", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Recebimento de vale-refeição, por servidor público, durante o período de férias.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=404",
    texto: "A questão do direito ao recebimento da vantagem pecuniária “vale-refeição” pelos servidores militares do Rio Grande do Sul, durante o período de férias, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-405", tribunal: "STF", tipo: "Repercussão Geral", numero: "405", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Cômputo do tempo de serviço exercido em condições especiais para efeito de aposentadoria.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=405",
    texto: "A questão constitucional do direito à conversão de tempo de serviço especial em comum, para concessão de aposentadoria especial, por tempo de serviço, após 28.5.1998, não tem repercussão geral, pois não atingido quórum mínimo de oito para reconhecimento do tema como matéria infraconstitucional (Regimento Interno do Supremo Tribunal Federal - RISTF, art. 324, § 2º)." },
  { id: "stf-rg-406", tribunal: "STF", tipo: "Repercussão Geral", numero: "406", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Critérios para o cálculo da renda mensal inicial de benefício previdenciário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=406",
    texto: "A questão constitucional do direito ao recálculo da média aritmética simples, considerados os quarenta e oito (48) maiores salários de contribuição que compõem o período básico de cálculo, com renúncia aos de menor expressão econômica, não tem repercussão geral, pois não atingido quórum mínimo de oito votos para reconhecimento do tema como matéria infraconstitucional (Regimento Interno do Supremo Tribunal Federal - RISTF, art. 324, § 2º)." },
  { id: "stf-rg-407", tribunal: "STF", tipo: "Repercussão Geral", numero: "407", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Restituição de valores descontados compulsoriamente a título de contribuição previdenciária declarada inconstitucional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=407",
    texto: "A questão do direito à restituição da parcela da contribuição previdenciária destinada ao custeio da assistência médico-hospitalar, descontada compulsoriamente de servidores públicos, tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-408", tribunal: "STF", tipo: "Repercussão Geral", numero: "408", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Cabimento de apelação em caso de execução fiscal com valor inferior a 50 ORTN.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=408",
    texto: "É compatível com a Constituição o art. 34 da Lei 6.830/1980, que afirma incabível apelação em casos de execução fiscal cujo valor seja inferior a 50 ORTN." },
  { id: "stf-rg-409", tribunal: "STF", tipo: "Repercussão Geral", numero: "409", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão, em relação aos servidores inativos, dos critérios de cálculo da GDPST estabelecidos para os servidores em atividade.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=409",
    texto: "É compatível com a Constituição a extensão, aos servidores públicos inativos, dos critérios de cálculo da Gratificação de Desempenho da Carreira da Previdência, Saúde e Trabalho — GDPST estabelecidos para os servidores públicos em atividade." },
  { id: "stf-rg-410", tribunal: "STF", tipo: "Repercussão Geral", numero: "410", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão, em relação aos servidores inativos, dos critérios de cálculo da GDPGTAS estabelecidos para os servidores em atividade.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=410",
    texto: "É compatível com a Constituição a extensão, aos servidores públicos inativos, dos critérios de cálculo da Gratificação de Desempenho de Atividade Técnico-Administrativa e de Suporte – GDPGTAS estabelecidos para os servidores públicos em atividade." },
  { id: "stf-rg-411", tribunal: "STF", tipo: "Repercussão Geral", numero: "411", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Rito da execução de decisões que condenem entidades paraestatais, pessoas jurídicas de direito privado, a quantia em dinheiro.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=411",
    texto: "É incompatível com a Constituição o reconhecimento às entidades paraestatais dos privilégios processuais concedidos à Fazenda Pública em execução de pagamento de quantia em dinheiro." },
  { id: "stf-rg-412", tribunal: "STF", tipo: "Repercussão Geral", numero: "412", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Extensão da imunidade tributária recíproca às empresas públicas prestadoras de serviços públicos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=412",
    texto: "A Empresa Brasileira de Infraestrutura Aeroportuária - INFRAERO, empresa pública prestadora de serviço público, faz jus à imunidade recíproca prevista no art. 150, VI, a, da Constituição Federal." },
  { id: "stf-rg-413", tribunal: "STF", tipo: "Repercussão Geral", numero: "413", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Quantum indenizatório de condenação por danos morais e materiais decorrentes da relação entre concessionária de serviço público e consumidor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=413",
    texto: "A questão dos critérios utilizados pelo juízo competente para quantificar o valor devido a título de indenização por dano moral em decorrência da relação de consumo entre a concessionária fornecedora de energia elétrica e o consumidor tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-414", tribunal: "STF", tipo: "Repercussão Geral", numero: "414", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar ação em que se discute a prestação de benefícios previdenciários decorrentes de acidentes de trabalho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=414",
    texto: "Compete à Justiça Comum Estadual julgar as ações acidentárias que, propostas pelo segurado contra o Instituto Nacional do Seguro Social (INSS), visem à prestação de benefícios relativos a acidentes de trabalho." },
  { id: "stf-rg-415", tribunal: "STF", tipo: "Repercussão Geral", numero: "415", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reserva de Lei Complementar para repasse do PIS e da COFINS ao consumidor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=415",
    texto: "Não há reserva de lei complementar para o repasse do PIS e COFINS ao usuário de serviços públicos concedidos, tais como telefonia e energia elétrica, cobrado nas respectivas faturas." },
  { id: "stf-rg-417", tribunal: "STF", tipo: "Repercussão Geral", numero: "417", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Responsabilidade civil por dano material em face de relações contratuais e extracontratuais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=417",
    texto: "A questão da responsabilidade civil de instituição financeira por dano material causado ao titular do contrato pela utilização fraudulenta do cartão de crédito por terceiros tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-418", tribunal: "STF", tipo: "Repercussão Geral", numero: "418", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Compensação do reajuste de 28,86% sobre a RAV com as reposições salariais posteriores ao reajustamento concedido pelas Leis 8.622/1993 e 8.627/1993.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=418",
    texto: "A questão da ofensa aos limites objetivos da coisa julgada pela compensação do reajuste de 28,86% sobre a vantagem pecuniária “Retribuição Adicional Variável – RAV”, paga aos servidores públicos civis e militares, com as reposições salariais das Leis n. 8.622/1993 e n. 8.627/1993 tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-419", tribunal: "STF", tipo: "Repercussão Geral", numero: "419", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Dever de as concessionárias de serviços públicos cumprirem suas obrigações contratuais mesmo que em área de risco à integridade física de seus funcionários.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=419",
    texto: "A questão de estarem as concessionárias de serviços públicos obrigadas ao cumprimento do contrato, ainda que o local de execução esteja em área de risco à integridade física de seus funcionários, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-420", tribunal: "STF", tipo: "Repercussão Geral", numero: "420", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão de progressão salarial a servidores efetivados por Lei Estadual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=420",
    texto: "A questão do direito à progressão salarial concedida pela Lei estadual n. 10.961/1992, regulamentada pelo Decreto n. 36.033/94, a servidores do Departamento de Estradas de Rodagem do Estado de Minas Gerais – DER efetivados pela Lei estadual n. 10.254/1990 tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-421", tribunal: "STF", tipo: "Repercussão Geral", numero: "421", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Aplicação do artigo 1º da Lei de Usura, que limita a taxa de juros a 12% ao ano, aos contratos bancários.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=421",
    texto: "A questão da aplicação do art. 1º do Decreto n. 22.262/1933 (Lei de Usura), que limita a taxa de juros remuneratórios a 12% (doze por cento) ao ano, aos contratos bancários regidos pelo Código de Defesa do Consumidor - CDC tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-422", tribunal: "STF", tipo: "Repercussão Geral", numero: "422", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Cálculo do valor mínimo nacional por aluno (VMNA) a ser repassado ao Fundo de Manutenção e Desenvolvimento do Ensino Fundamental e de Valorização do Magistério (FUNDEF)", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=422",
    texto: "A questão da fórmula usada pela União para calcular a verba denominada Valor Mínimo Nacional por Aluno (VMNA) a ser repassada a título de complementação ao Fundo de Manutenção e Desenvolvimento do Ensino Fundamental e de Valorização do Magistério (FUNDEF), tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-423", tribunal: "STF", tipo: "Repercussão Geral", numero: "423", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Cumprimento de pena em regime menos gravoso ante a falta de vagas em estabelecimento penitenciário adequado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=423",
    texto: "I - A falta de estabelecimento penal adequado não autoriza a manutenção do condenado em regime prisional mais gravoso; II - Os juízes da execução penal poderão avaliar os estabelecimentos destinados aos regimes semiaberto e aberto, para qualificação como adequados a tais regimes. São aceitáveis estabelecimentos que não se qualifiquem como “colônia agrícola, industrial” (regime semiaberto) ou “casa de albergado ou estabelecimento adequado” (regime aberto) (art. 33, §1º, alíneas “b” e “c”); III - Havendo déficit de vagas, deverá determinar-se: (i) a saída antecipada de sentenciado no regime com falta de vagas; (ii) a liberdade eletronicamente monitorada ao sentenciado que sai antecipadamente ou é posto em prisão domiciliar por falta de vagas; (iii) o cumprimento de penas restritivas de direito e/ou estudo ao sentenciado que progride ao regime aberto. Até que sejam estruturadas as medidas alternativas propostas, poderá ser deferida a prisão domiciliar ao sentenciado." },
  { id: "stf-rg-424", tribunal: "STF", tipo: "Repercussão Geral", numero: "424", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Indeferimento de produção de provas no âmbito de processo judicial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=424",
    texto: "A questão do indeferimento de produção de provas no âmbito de processo judicial tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-425", tribunal: "STF", tipo: "Repercussão Geral", numero: "425", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Restituição de verbas de natureza alimentar pagas indevidamente pela Administração Pública a beneficiário de boa-fé.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=425",
    texto: "A questão do dever de restituir valores de natureza alimentar, pagas indevidamente pela Administração Pública a beneficiário de boa-fé tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-426", tribunal: "STF", tipo: "Repercussão Geral", numero: "426", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência do adicional de “sexta parte” sobre a integralidade dos vencimentos de servidor estadual celetista.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=426",
    texto: "A questão de a base de cálculo de vantagem pecuniária - Adicional de “Sexta Parte” - ser a integralidade dos vencimentos de servidor público estadual celetista tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-427", tribunal: "STF", tipo: "Repercussão Geral", numero: "427", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão do reajuste de 10% concedido pelo Decreto Estadual nº 36.829/1995 aos servidores da FUNED.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=427",
    texto: "A questão do direito ao reajuste de 10% (dez por cento) concedido pelo Decreto estadual n. 36.829/1995 aos servidores lotados na Fundação Ezequiel Dias - FUNED tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-428", tribunal: "STF", tipo: "Repercussão Geral", numero: "428", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão a outros servidores públicos militares em atividade da Gratificação de Encargos Especiais-GEE", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=428",
    texto: "A questão do direito à extensão aos demais servidores públicos militares em atividade da vantagem pecuniária “Gratificação de Encargos Especiais – GEE”, paga aos Coronéis da Polícia Militar e Corpo de Bombeiros, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-429", tribunal: "STF", tipo: "Repercussão Geral", numero: "429", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão a servidor público inativo do Adicional de Local de Exercício - ALE definido como vantagem de caráter geral.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=429",
    texto: "A questão do direito à extensão aos aposentados e pensionistas ao recebimento da vantagem pecuniária “Adicional de Local de Exercício – ALE”, paga aos policiais militares de São Paulo em atividade, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-430", tribunal: "STF", tipo: "Repercussão Geral", numero: "430", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência privativa da União para legislar sobre trânsito e transporte.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=430",
    texto: "É incompatível com a Constituição lei municipal que impõe sanção mais gravosa que a prevista no Código de Trânsito Brasileiro, por extrapolar a competência legislativa do município." },
  { id: "stf-rg-431", tribunal: "STF", tipo: "Repercussão Geral", numero: "431", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Contribuição para assistência à saúde incidente sobre proventos e pensões dos servidores públicos no interregno das EC n. 20/98 e n. 41/03.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=431",
    texto: "É incompatível com a Constituição norma que institui contribuição à saúde incidente sobre o valor de proventos e pensões de servidores públicos, no interregno das Emendas Constitucionais 20/1998 e 41/2003." },
  { id: "stf-rg-432", tribunal: "STF", tipo: "Repercussão Geral", numero: "432", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade tributária das entidades filantrópicas em relação à contribuição para o PIS", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=432",
    texto: "A imunidade tributária prevista no art. 195, § 7º, da Constituição Federal abrange a contribuição para o PIS." },
  { id: "stf-rg-433", tribunal: "STF", tipo: "Repercussão Geral", numero: "433", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência de juizados especiais face à alegação de complexidade da prova.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=433",
    texto: "A questão da alegada necessidade de produção de prova complexa afastar a competência dos Juizados Especiais Cíveis tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-434", tribunal: "STF", tipo: "Repercussão Geral", numero: "434", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Alteração do cálculo da Gratificação por Produção Suplementar – GPS por lei específica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=434",
    texto: "É compatível com a Constituição lei específica que altera o cálculo da Gratificação por Produção Suplementar - GPS, desde que não haja redução da remuneração na sua totalidade." },
  { id: "stf-rg-435", tribunal: "STF", tipo: "Repercussão Geral", numero: "435", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Aplicação do artigo 1º-F da Lei 9.494/97 nas ações ajuizadas anteriormente à sua vigência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=435",
    texto: "É compatível com a Constituição a aplicabilidade imediata do art. 1º-F da Lei 9.494/97, com alteração pela Medida Provisória nº 2.180-35/2001, ainda que em relação às ações ajuizadas antes de sua entrada em vigor." },
  { id: "stf-rg-436", tribunal: "STF", tipo: "Repercussão Geral", numero: "436", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Alteração de prazo prescricional por legislação infraconstitucional superveniente.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=436",
    texto: "A questão do termo inicial da prescrição da ação de cobrança de diferença do valor da indenização referente ao Seguro de Danos Pessoais Causados por Veículos Automotores de Vias Terrestres - DPVAT tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-437", tribunal: "STF", tipo: "Repercussão Geral", numero: "437", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reconhecimento de imunidade tributária recíproca a empresa privada ocupante de bem público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=437",
    texto: "Incide o IPTU, considerado imóvel de pessoa jurídica de direito público cedido a pessoa jurídica de direito privado, devedora do tributo." },
  { id: "stf-rg-439", tribunal: "STF", tipo: "Repercussão Geral", numero: "439", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito adquirido de servidores públicos estaduais aposentados à permanência em determinada classe, não obstante o advento de lei estadual que, ao promover a reclassificação de cargos, reenquadra-os em classe inferior.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=439",
    texto: "Desde que mantida a irredutibilidade, não tem o servidor inativo, embora aposentado na última classe da carreira anterior, o direito de perceber proventos correspondentes aos da última classe da nova carreira, reestruturada por lei superveniente." },
  { id: "stf-rg-440", tribunal: "STF", tipo: "Repercussão Geral", numero: "440", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Redução legal do valor de gratificação para servidores que ingressaram, ou reingressaram no quadro, após a entrada em vigor da lei redutora.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=440",
    texto: "A redução da Gratificação Especial de Retorno à Atividade - GERA não implica violação ao princípio da irredutibilidade de vencimentos, se o ingresso ou o reingresso aos quadros do Corpo Voluntário de Militares Estaduais Inativos (CVMI) se deu após a edição da Lei Estadual 10.916/1997." },
  { id: "stf-rg-442", tribunal: "STF", tipo: "Repercussão Geral", numero: "442", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Inexigibilidade de título judicial cujo fundamento contraria decisão superveniente do Superior Tribunal de Justiça sobre tema declarado de natureza infraconstitucional pelo Supremo Tribunal Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=442",
    texto: "A questão da inexigibilidade de título judicial cujo fundamento contraria decisão superveniente do Superior Tribunal de Justiça tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-443", tribunal: "STF", tipo: "Repercussão Geral", numero: "443", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Exigência de atualização, no final de cada exercício, da ajuda de custo instituída pela Lei Municipal 4.823/1996.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=443",
    texto: "A questão do direito ao reajuste da vantagem pecuniária “Ajuda de Custo”, instituída a título de ressarcimento pela Lei municipal n. 4.823/1996, com base nos parâmetros do Decreto municipal n. 19.844/1997 tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-444", tribunal: "STF", tipo: "Repercussão Geral", numero: "444", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reflexos na base de cálculo do décimo terceiro salário e do terço de férias da verba decorrente de plantão na área da saúde.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=444",
    texto: "A questão da inclusão do valor recebido por servidor municipal da área de saúde, a título de plantões, na base de cálculo das vantagens pecuniárias “Gratificação Natalina” (13º salário) e terço de férias, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-445", tribunal: "STF", tipo: "Repercussão Geral", numero: "445", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência do prazo decadencial previsto no art. 54 da Lei 9.784/1999 para a Administração anular ato de concessão de aposentadoria.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=445",
    texto: "Em atenção aos princípios da segurança jurídica e da confiança legítima, os Tribunais de Contas estão sujeitos ao prazo de 5 anos para o julgamento da legalidade do ato de concessão inicial de aposentadoria, reforma ou pensão, a contar da chegada do processo à respectiva Corte de Contas." },
  { id: "stf-rg-446", tribunal: "STF", tipo: "Repercussão Geral", numero: "446", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Destinação de parte do valor das astreintes a fundo estadual de defesa do consumidor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=446",
    texto: "A questão da legitimidade de destinar parte do valor das astreintes recebidas pelo descumprimento de ordem judicial que determina o restabelecimento de serviço de telefonia a fundo estadual de defesa do consumidor tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-447", tribunal: "STF", tipo: "Repercussão Geral", numero: "447", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão, em relação aos servidores inativos e pensionistas, dos critérios de cálculo da GDAMB estabelecidos para os servidores em atividade.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=447",
    texto: "É compatível com a Constituição a extensão, aos servidores públicos inativos e pensionistas, dos critérios de cálculo da Gratificação de Desempenho de Atividade Técnico-Administrativa do Meio Ambiente – GDAMB estabelecidos para os servidores públicos em atividade." },
  { id: "stf-rg-448", tribunal: "STF", tipo: "Repercussão Geral", numero: "448", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão do adicional de insalubridade aos policiais militares inativos em razão de previsão em Lei Complementar Estadual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=448",
    texto: "É incompatível com a Constituição a extensão, aos policiais militares inativos e pensionistas, do adicional de insalubridade instituído pela Lei Complementar 432/1985 do Estado de São Paulo." },
  { id: "stf-rg-450", tribunal: "STF", tipo: "Repercussão Geral", numero: "450", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Incidência de correção monetária no período compreendido entre a data do cálculo e a do efetivo pagamento da requisição de pequeno valor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=450",
    texto: "É devida correção monetária no período compreendido entre a data de elaboração do cálculo da requisição de pequeno valor – RPV e sua expedição para pagamento." },
  { id: "stf-rg-451", tribunal: "STF", tipo: "Repercussão Geral", numero: "451", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Remissão aos fundamentos adotados na sentença impugnada nos termos do § 5º do art. 82 da Lei nº 9.099/95.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=451",
    texto: "Não afronta a exigência constitucional de motivação dos atos decisórios a decisão de Turma Recursal de Juizados Especiais que, em consonância com a Lei 9.099/1995, adota como razões de decidir os fundamentos contidos na sentença recorrida." },
  { id: "stf-rg-452", tribunal: "STF", tipo: "Repercussão Geral", numero: "452", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Cláusula de plano de previdência complementar que estabelece valor inferior de complementação de benefício para mulheres em virtude de seu tempo de contribuição.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=452",
    texto: "É inconstitucional, por violação ao princípio da isonomia (art. 5º, I, da Constituição da República), cláusula de contrato de previdência complementar que, ao prever regras distintas entre homens e mulheres para cálculo e concessão de complementação de aposentadoria, estabelece valor inferior do benefício para as mulheres, tendo em conta o seu menor tempo de contribuição." },
  { id: "stf-rg-453", tribunal: "STF", tipo: "Repercussão Geral", numero: "453", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Manutenção de prerrogativa de foro a magistrados aposentados.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=453",
    texto: "O foro especial por prerrogativa de função não se estende a magistrados aposentados." },
  { id: "stf-rg-454", tribunal: "STF", tipo: "Repercussão Geral", numero: "454", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito à promoção funcional, independentemente de apuração própria ao estágio probatório, quando reconhecida eficácia retroativa do direito à nomeação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=454",
    texto: "A nomeação tardia de candidatos aprovados em concurso público, por meio de ato judicial, à qual atribuída eficácia retroativa, não gera direito às promoções ou progressões funcionais que alcançariam houvesse ocorrido, a tempo e modo, a nomeação." },
  { id: "stf-rg-458", tribunal: "STF", tipo: "Repercussão Geral", numero: "458", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Direito do consumidor à exibição de documentos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=458",
    texto: "A questão da obrigatoriedade de as instituições financeiras entregarem os extratos de conta poupança aos respectivos titulares, quando solicitados, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-459", tribunal: "STF", tipo: "Repercussão Geral", numero: "459", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Requisitos legais para enquadramento de pessoa jurídica como entidade beneficente de assistência social para fins de imunidade tributária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=459",
    texto: "A questão do preenchimento dos requisitos legais para enquadramento de pessoa jurídica como entidade beneficente de assistência social, para fins de imunidade tributária, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-460", tribunal: "STF", tipo: "Repercussão Geral", numero: "460", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Prosseguimento de Execução Fiscal lastreada em Certidão de Dívida Ativa supostamente ilíquida.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=460",
    texto: "A questão da possibilidade de prosseguimento de execução fiscal com base em certidão de dívida ativa ilíquida tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-461", tribunal: "STF", tipo: "Repercussão Geral", numero: "461", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Ilegalidade de cláusulas previstas em contratos regidos pelo Código de Defesa do Consumidor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=461",
    texto: "A questão da legalidade de decisão judicial declarar a abusividade do percentual cobrado a título de taxa de administração, previsto em contrato de consórcio, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-462", tribunal: "STF", tipo: "Repercussão Geral", numero: "462", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão, em relação aos servidores inativos e pensionistas, da Gratificação de Atividade Policial Militar – GAPM.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=462",
    texto: "A questão da extensão aos aposentados e pensionistas da vantagem pecuniária “Gratificação de Atividade Policial Militar – GAPM”, paga aos policiais militares em atividade, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-463", tribunal: "STF", tipo: "Repercussão Geral", numero: "463", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Violação à coisa julgada em decorrência de preclusão referente à juntada de acordo apenas por ocasião dos embargos à execução.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=463",
    texto: "A questão da ofensa à coisa julgada pela homologação, na fase executória do processo, do termo de acordo de adesão da Lei Complementar n. 110/2001, firmado com a Caixa Econômica Federal - CEF e o titular da conta vinculada ao Fundo de Garantia do Tempo de Serviço - FGTS, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-464", tribunal: "STF", tipo: "Repercussão Geral", numero: "464", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão aos inativos do Prêmio de Produção concedido aos servidores ativos do Quadro Permanente de Tributação, Fiscalização e Arrecadação do Estado de Minas Gerais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=464",
    texto: "A questão do direito à extensão aos aposentados e pensionistas da vantagem pecuniária “Prêmio de Produção”, paga aos servidores do Quadro Permanente de Tributação, Fiscalização e Arrecadação de Minas Gerais em atividade, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-466", tribunal: "STF", tipo: "Repercussão Geral", numero: "466", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Revisão de contrato celebrado com entidade fechada de previdência complementar.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=466",
    texto: "A questão da obrigatoriedade da revisão de contrato celebrado com entidade fechada de previdência complementar para recalcular os benefícios de seus associados, com base nos mesmos índices utilizados para reajustar os benefícios pagos pelo Regime Geral de Previdência Social – RGPS, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-467", tribunal: "STF", tipo: "Repercussão Geral", numero: "467", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Descontos previdenciários de militares estaduais ativos com base na Lei nº 7.672/82.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=467",
    texto: "A questão da exigibilidade de contribuição previdenciários de servidores militares estaduais em atividade, com base na Lei gaúcha n. 7.672/1982, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-468", tribunal: "STF", tipo: "Repercussão Geral", numero: "468", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Termo inicial da prescrição para ação de cobrança da diferença decorrente da incidência dos expurgos inflacionários reconhecidos pela Lei Complementar nº 110/2001 na multa de 40% sobre os depósitos do FGTS (reafirmação do entendimento fixado no tema 144).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=468",
    texto: "A questão da definição do termo inicial da prescrição da ação de cobrança das diferenças dos expurgos inflacionários reconhecidos pela Lei Complementar n. 110/2001, para atualização monetária do Fundo de Garantia por Tempo de Serviço - FGTS, incidentes na multa de 40% (quarenta por cento) sobre os depósitos dessa conta vinculada tem natureza infraconstitucional e a ela são atribuídos os efeitos da ausência de repercussão geral (reafirmação da mesma tese constante no tema 144)." },
  { id: "stf-rg-469", tribunal: "STF", tipo: "Repercussão Geral", numero: "469", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Alcance da imunidade material concedida aos vereadores por suas opiniões, palavras e votos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=469",
    texto: "Nos limites da circunscrição do município e havendo pertinência com o exercício do mandato, garante-se a imunidade ao vereador." },
  { id: "stf-rg-470", tribunal: "STF", tipo: "Repercussão Geral", numero: "470", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Contribuição adicional de 2,5% sobre a folha de salários de instituições financeiras estabelecida antes da EC 20/98.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=470",
    texto: "É constitucional a contribuição adicional de 2,5% (dois e meio por cento) sobre a folha de salários instituída para as instituições financeiras e assemelhadas pelo art. 3º, § 2º, da Lei 7.787/1989, mesmo considerado o período anterior à Emenda Constitucional 20/1998." },
  { id: "stf-rg-471", tribunal: "STF", tipo: "Repercussão Geral", numero: "471", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade do Ministério Público para propor ação civil pública em defesa de interesses de beneficiários do DPVAT.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=471",
    texto: "Com fundamento no art. 127 da Constituição Federal, o Ministério Público está legitimado a promover a tutela coletiva de direitos individuais homogêneos, mesmo de natureza disponível, quando a lesão a tais direitos, visualizada em seu conjunto, em forma coletiva e impessoal, transcender a esfera de interesses puramente particulares, passando a comprometer relevantes interesses sociais." },
  { id: "stf-rg-472", tribunal: "STF", tipo: "Repercussão Geral", numero: "472", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência de guarda municipal para lavrar auto de infração de trânsito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=472",
    texto: "É constitucional a atribuição às guardas municipais do exercício de poder de polícia de trânsito, inclusive para imposição de sanções administrativas legalmente previstas." },
  { id: "stf-rg-473", tribunal: "STF", tipo: "Repercussão Geral", numero: "473", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incorporação de quintos por exercício de função comissionada anteriormente ao ingresso na magistratura.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=473",
    texto: "Não encontra amparo constitucional a pretensão de acumular, no cargo de magistrado ou em qualquer outro, a vantagem correspondente a “quintos”, a que o titular fazia jus quando no exercício de cargo diverso." },
  { id: "stf-rg-475", tribunal: "STF", tipo: "Repercussão Geral", numero: "475", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Extensão da imunidade relativa ao ICMS para a comercialização de embalagens fabricadas para produtos destinados à exportação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=475",
    texto: "A imunidade a que se refere o art. 155, § 2º, X, \"a\", da CF não alcança operações ou prestações anteriores à operação de exportação." },
  { id: "stf-rg-476", tribunal: "STF", tipo: "Repercussão Geral", numero: "476", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Manutenção de candidato investido em cargo público por força de decisão judicial de caráter provisório pela aplicação da teoria do fato consumado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=476",
    texto: "Não é compatível com o regime constitucional de acesso aos cargos públicos a manutenção no cargo, sob fundamento de fato consumado, de candidato não aprovado que nele tomou posse em decorrência de execução provisória de medida liminar ou outro provimento judicial de natureza precária, supervenientemente revogado ou modificado." },
  { id: "stf-rg-478", tribunal: "STF", tipo: "Repercussão Geral", numero: "478", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Alcance do princípio da autodefesa frente ao crime de falsa identidade", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=478",
    texto: "O princípio constitucional da autodefesa (art. 5º, LXIII, da CF/88) não alcança aquele que atribui falsa identidade perante autoridade policial com o intento de ocultar maus antecedentes, sendo, portanto, típica a conduta praticada pelo agente (art. 307 do CP)." },
  { id: "stf-rg-479", tribunal: "STF", tipo: "Repercussão Geral", numero: "479", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Imposição de obrigação de fazer à concessionária de serviço público para que observe padrão internacional de segurança.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=479",
    texto: "No atual estágio do conhecimento científico, que indica ser incerta a existência de efeitos nocivos da exposição ocupacional e da população em geral a campos elétricos, magnéticos e eletromagnéticos gerados por sistemas de energia elétrica, não existem impedimentos, por ora, a que sejam adotados os parâmetros propostos pela Organização Mundial de Saúde, conforme estabelece a Lei nº 11.934/2009." },
  { id: "stf-rg-480", tribunal: "STF", tipo: "Repercussão Geral", numero: "480", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência do teto constitucional remuneratório sobre proventos percebidos em desacordo com o disposto no art. 37, XI, da Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=480",
    texto: "O teto de retribuição estabelecido pela Emenda Constitucional 41/03 possui eficácia imediata, submetendo às referências de valor máximo nele discriminadas todas as verbas de natureza remuneratória percebidas pelos servidores públicos da União, Estados, Distrito Federal e Municípios, ainda que adquiridas de acordo com regime legal anterior. Os valores que ultrapassam os limites estabelecidos para cada nível federativo na Constituição Federal constituem excesso cujo pagamento não pode ser reclamado com amparo na garantia da irredutibilidade de vencimentos." },
  { id: "stf-rg-482", tribunal: "STF", tipo: "Repercussão Geral", numero: "482", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Incidência de contribuição previdenciária sobre os valores pagos pelo empregador ao empregado nos primeiros quinze dias de auxílio-doença.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=482",
    texto: "A questão da incidência de contribuição previdenciária sobre os valores pagos pelo empregador ao empregado nos primeiros quinze dias de auxílio-doença tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-483", tribunal: "STF", tipo: "Repercussão Geral", numero: "483", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Divulgação, em sítio eletrônico oficial, de informações alusivas a servidores públicos, inclusive seus nomes e correspondentes remunerações.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=483",
    texto: "É legítima a publicação, inclusive em sítio eletrônico mantido pela Administração Pública, dos nomes dos seus servidores e do valor dos correspondentes vencimentos e vantagens pecuniárias." },
  { id: "stf-rg-484", tribunal: "STF", tipo: "Repercussão Geral", numero: "484", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "a) Legitimidade de tribunal de justiça para atuar em controle concentrado de constitucionalidade de lei municipal contestada em face da Constituição Federal; b) Possibilidade de concessão de gratificação natalina, ou de outras espécies remuneratórias, a detentor de mandato eletivo remunerado por subsídio.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=484",
    texto: "1) Tribunais de Justiça podem exercer controle abstrato de constitucionalidade de leis municipais utilizando como parâmetro normas da Constituição Federal, desde que se trate de normas de reprodução obrigatória pelos Estados; e 2) O art. 39, § 4º, da Constituição Federal não é incompatível com o pagamento de terço de férias e décimo terceiro salário." },
  { id: "stf-rg-485", tribunal: "STF", tipo: "Repercussão Geral", numero: "485", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Controle jurisdicional do ato administrativo que avalia questões em concurso público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=485",
    texto: "Não compete ao Poder Judiciário substituir a banca examinadora para reexaminar o conteúdo das questões e os critérios de correção utilizados, salvo ocorrência de ilegalidade ou de inconstitucionalidade." },
  { id: "stf-rg-486", tribunal: "STF", tipo: "Repercussão Geral", numero: "486", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Suspensão de habilitação para dirigir de motorista profissional condenado por homicídio culposo na direção de veículo automotor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=486",
    texto: "É constitucional a imposição da pena de suspensão de habilitação para dirigir veículo automotor ao motorista profissional condenado por homicídio culposo no trânsito." },
  { id: "stf-rg-489", tribunal: "STF", tipo: "Repercussão Geral", numero: "489", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Responsabilidade solidária da União pelo pagamento de correção monetária integral referente a crédito oriundo de devolução de empréstimo compulsório sobre o consumo de energia elétrica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=489",
    texto: "A questão da responsabilidade solidária da União pelo pagamento de correção monetária integral referente a crédito pela devolução de empréstimo compulsório sobre o consumo de energia elétrica tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-490", tribunal: "STF", tipo: "Repercussão Geral", numero: "490", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Creditamento de ICMS incidente em operação oriunda de outro ente federado que concede, unilateralmente, benefício fiscal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=490",
    texto: "O estorno proporcional de crédito de ICMS efetuado pelo Estado de destino, em razão de crédito fiscal presumido concedido pelo Estado de origem sem autorização do Conselho Nacional de Política Fazendária (CONFAZ), não viola o princípio constitucional da não cumulatividade." },
  { id: "stf-rg-494", tribunal: "STF", tipo: "Repercussão Geral", numero: "494", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Limites objetivos da coisa julgada em sede de execução.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=494",
    texto: "A sentença que reconhece ao trabalhador ou servidor o direito a determinado percentual de acréscimo remuneratório deixa de ter eficácia a partir da superveniente incorporação definitiva do referido percentual nos seus ganhos." },
  { id: "stf-rg-497", tribunal: "STF", tipo: "Repercussão Geral", numero: "497", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Proteção objetiva da estabilidade de empregada gestante, em virtude de rescisão imotivada do contrato de trabalho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=497",
    texto: "A incidência da estabilidade prevista no art. 10, inc. II, do ADCT, somente exige a anterioridade da gravidez à dispensa sem justa causa." },
  { id: "stf-rg-498", tribunal: "STF", tipo: "Repercussão Geral", numero: "498", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Alcance do direito sucessório em face de união estável homoafetiva.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=498",
    texto: "É inconstitucional a distinção de regimes sucessórios entre cônjuges e companheiros prevista no art. 1.790 do CC/2002, devendo ser aplicado, tanto nas hipóteses de casamento quanto nas de união estável, o regime do art. 1.829 do CC/2002. (A mesma tese foi fixada para o Tema 809)." },
  { id: "stf-rg-499", tribunal: "STF", tipo: "Repercussão Geral", numero: "499", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Limites subjetivos da coisa julgada referente à ação coletiva proposta por entidade associativa de caráter civil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=499",
    texto: "A eficácia subjetiva da coisa julgada formada a partir de ação coletiva, de rito ordinário, ajuizada por associação civil na defesa de interesses dos associados, somente alcança os filiados, residentes no âmbito da jurisdição do órgão julgador, que o fossem em momento anterior ou até a data da propositura da demanda, constantes da relação jurídica juntada à inicial do processo de conhecimento." },
  { id: "stf-rg-500", tribunal: "STF", tipo: "Repercussão Geral", numero: "500", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Dever do Estado de fornecer medicamento não registrado pela ANVISA.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=500",
    texto: "1. O Estado não pode ser obrigado a fornecer medicamentos experimentais. 2. A ausência de registro na ANVISA impede, como regra geral, o fornecimento de medicamento por decisão judicial. 3. É possível, excepcionalmente, a concessão judicial de medicamento sem registro sanitário, em caso de mora irrazoável da ANVISA em apreciar o pedido (prazo superior ao previsto na Lei nº 13.411/2016), quando preenchidos três requisitos: (i) a existência de pedido de registro do medicamento no Brasil (salvo no caso de medicamentos órfãos para doenças raras e ultrarraras);(ii) a existência de registro do medicamento em renomadas agências de regulação no exterior; e (iii) a inexistência de substituto terapêutico com registro no Brasil. 4. As ações que demandem fornecimento de medicamentos sem registro na ANVISA deverão necessariamente ser propostas em face da União." },
  { id: "stf-rg-503", tribunal: "STF", tipo: "Repercussão Geral", numero: "503", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Conversão de aposentadoria proporcional em aposentadoria integral por meio do instituto da desaposentação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=503",
    texto: "No âmbito do Regime Geral de Previdência Social - RGPS, somente lei pode criar benefícios e vantagens previdenciárias, não havendo, por ora, previsão legal do direito à 'desaposentação' ou à ‘reaposentação’, sendo constitucional a regra do art. 18, § 2º, da Lei nº 8.213/91." },
  { id: "stf-rg-505", tribunal: "STF", tipo: "Repercussão Geral", numero: "505", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Aplicação imediata EC nº 20/98 quanto à competência da Justiça do Trabalho para execução de contribuições previdenciárias decorrentes de sentenças anteriores à sua promulgação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=505",
    texto: "A Justiça do Trabalho é competente para executar, de ofício, as contribuições previstas no artigo 195, incisos I, alínea a, e II, da Carta da República, relativamente a títulos executivos judiciais por si formalizados em data anterior à promulgação da Emenda Constitucional nº 20/1998." },
  { id: "stf-rg-508", tribunal: "STF", tipo: "Repercussão Geral", numero: "508", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade tributária recíproca para sociedade de economia mista com participação acionária negociada em bolsa de valores.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=508",
    texto: "Sociedade de economia mista, cuja participação acionária é negociada em Bolsas de Valores, e que, inequivocamente, está voltada à remuneração do capital de seus controladores ou acionistas, não está abrangida pela regra de imunidade tributária prevista no art. 150, VI, ‘a’, da Constituição, unicamente em razão das atividades desempenhadas." },
  { id: "stf-rg-509", tribunal: "STF", tipo: "Repercussão Geral", numero: "509", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Momento de comprovação do triênio de atividade jurídica para ingresso no cargo de juiz substituto.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=509",
    texto: "A comprovação do triênio de atividade jurídica exigida para o ingresso no cargo de juiz substituto, nos termos do inciso I do art. 93 da Constituição Federal, deve ocorrer no momento da inscrição definitiva no concurso público." },
  { id: "stf-rg-510", tribunal: "STF", tipo: "Repercussão Geral", numero: "510", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Teto remuneratório de procuradores municipais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=510",
    texto: "A expressão \"Procuradores\", contida na parte final do inciso XI do art. 37 da Constituição da República, compreende os Procuradores Municipais, uma vez que estes se inserem nas funções essenciais à Justiça, estando, portanto, submetidos ao teto de noventa inteiros e vinte e cinco centésimos por cento do subsídio mensal, em espécie, dos Ministros do Supremo Tribunal Federal." },
  { id: "stf-rg-511", tribunal: "STF", tipo: "Repercussão Geral", numero: "511", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Compensação de débitos tributários com requisições de pequeno valor – RPV.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=511",
    texto: "É constitucionalmente vedada a compensação unilateral de débitos em proveito exclusivo da Fazenda Pública ainda que os valores envolvidos não estejam sujeitos ao regime de precatórios, mas apenas à sistemática da requisição de pequeno valor." },
  { id: "stf-rg-512", tribunal: "STF", tipo: "Repercussão Geral", numero: "512", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade civil do Estado por danos materiais causados a candidatos inscritos em concurso público em face do cancelamento da prova do certame por suspeita de fraude.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=512",
    texto: "O Estado responde subsidiariamente por danos materiais causados a candidatos em concurso público organizado por pessoa jurídica de direito privado (art. 37, § 6º, da CRFB/88), quando os exames são cancelados por indícios de fraude." },
  { id: "stf-rg-514", tribunal: "STF", tipo: "Repercussão Geral", numero: "514", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aumento da carga horária de servidores públicos, sem a devida contraprestação remuneratória.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=514",
    texto: "I - A ampliação de jornada de trabalho sem alteração da remuneração do servidor consiste em violação da regra constitucional da irredutibilidade de vencimentos; II - No caso concreto, o § 1º do art. 1º do Decreto estadual 4.345, de 14 de fevereiro de 2005, do Estado do Paraná não se aplica aos servidores elencados em seu caput que, antes de sua edição, estavam legitimamente submetidos a carga horária semanal inferior a quarenta horas." },
  { id: "stf-rg-515", tribunal: "STF", tipo: "Repercussão Geral", numero: "515", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reserva de lei para a majoração da alíquota da COFINS de 3% para 4% pela Lei 10.684/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=515",
    texto: "É constitucional a majoração diferenciada de alíquotas em relação às contribuições sociais incidentes sobre o faturamento ou a receita de instituições financeiras ou de entidades a elas legalmente equiparáveis." },
  { id: "stf-rg-518", tribunal: "STF", tipo: "Repercussão Geral", numero: "518", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Compatibilidade da contribuição destinada ao custeio da educação básica com as Constituições de 1969 e de 1988.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=518",
    texto: "Nos termos da Súmula 732 do STF, é constitucional a cobrança da contribuição do salário-educação." },
  { id: "stf-rg-520", tribunal: "STF", tipo: "Repercussão Geral", numero: "520", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Sujeito ativo do ICMS a incidir sobre circulação de mercadorias importadas por um estado da federação, industrializadas em outro estado da federação e que retorna ao primeiro para comercialização.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=520",
    texto: "O sujeito ativo da obrigação tributária de ICMS incidente sobre mercadoria importada é o Estado-membro no qual está domiciliado ou estabelecido o destinatário legal da operação que deu causa à circulação da mercadoria, com a transferência de domínio." },
  { id: "stf-rg-521", tribunal: "STF", tipo: "Repercussão Geral", numero: "521", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Quebra da ordem cronológica do pagamento de precatórios alimentares para fins de sequestro de recursos públicos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=521",
    texto: "O pagamento parcelado dos créditos não alimentares, na forma do art. 78 do ADCT, não caracteriza preterição indevida de precatórios alimentares, desde que os primeiros tenham sido inscritos em exercício anterior ao da apresentação dos segundos, uma vez que, ressalvados os créditos de que trata o art. 100, § 2º, da Constituição, o pagamento dos precatórios deve observar as seguintes diretrizes: (1) a divisão e a organização das classes ocorrem segundo o ano de inscrição; (2) inicia-se o pagamento pelo exercício mais antigo em que há débitos pendentes; (3) quitam-se primeiramente os créditos alimentares; depois, os não alimentares do mesmo ano; (4) passa-se, então, ao ano seguinte da ordem cronológica, repetindo-se o esquema de pagamento; e assim sucessivamente." },
  { id: "stf-rg-522", tribunal: "STF", tipo: "Repercussão Geral", numero: "522", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Contagem recíproca do tempo de contribuição na administração pública e na atividade privada para fins de concessão de aposentadoria.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=522",
    texto: "A imposição de restrições, por legislação local, à contagem recíproca do tempo de contribuição na administração pública e na atividade privada para fins de concessão de aposentadoria viola o art. 202, § 2º, da Constituição Federal, com redação anterior à EC 20/98." },
  { id: "stf-rg-523", tribunal: "STF", tipo: "Repercussão Geral", numero: "523", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Seletividade de IPTU antes da Emenda Constitucional nº 29/2000", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=523",
    texto: "São constitucionais as leis municipais anteriores à Emenda Constitucional n° 29/2000, que instituíram alíquotas diferenciadas de IPTU para imóveis edificados e não edificados, residenciais e não residenciais." },
  { id: "stf-rg-524", tribunal: "STF", tipo: "Repercussão Geral", numero: "524", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aposentadoria integral de servidor portador de doença grave não especificada em lei.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=524",
    texto: "A concessão de aposentadoria de servidor público por invalidez com proventos integrais exige que a doença incapacitante esteja prevista em rol taxativo da legislação de regência." },
  { id: "stf-rg-525", tribunal: "STF", tipo: "Repercussão Geral", numero: "525", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência legislativa municipal para dispor sobre a obrigatoriedade de prestação de serviços de acondicionamento ou embalagem de compras por supermercados ou similares.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=525",
    texto: "São inconstitucionais as leis que obrigam os supermercados ou similares à prestação de serviços de acondicionamento ou embalagem das compras, por violação ao princípio da livre iniciativa (arts. 1º, IV, e 170 da Constituição)." },
  { id: "stf-rg-530", tribunal: "STF", tipo: "Repercussão Geral", numero: "530", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Desistência em mandado de segurança, sem aquiescência da parte contrária, após prolação de sentença de mérito, ainda que favorável ao impetrante.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=530",
    texto: "É lícito ao impetrante desistir da ação de mandado de segurança, independentemente de aquiescência da autoridade apontada como coatora ou da entidade estatal interessada ou, ainda, quando for o caso, dos litisconsortes passivos necessários, a qualquer momento antes do término do julgamento, mesmo após eventual sentença concessiva do ‘writ’ constitucional, não se aplicando, em tal hipótese, a norma inscrita no art. 267, § 4º, do CPC/1973." },
  { id: "stf-rg-531", tribunal: "STF", tipo: "Repercussão Geral", numero: "531", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Desconto nos vencimentos dos servidores públicos dos dias não trabalhados em virtude de greve.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=531",
    texto: "A administração pública deve proceder ao desconto dos dias de paralisação decorrentes do exercício do direito de greve pelos servidores públicos, em virtude da suspensão do vínculo funcional que dela decorre, permitida a compensação em caso de acordo. O desconto será, contudo, incabível se ficar demonstrado que a greve foi provocada por conduta ilícita do Poder Público." },
  { id: "stf-rg-535", tribunal: "STF", tipo: "Repercussão Geral", numero: "535", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Cobrança de mensalidade em curso de pós-graduação lato sensu por instituição pública de ensino.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=535",
    texto: "A garantia constitucional da gratuidade de ensino não obsta a cobrança por universidades públicas de mensalidade em cursos de especialização." },
  { id: "stf-rg-537", tribunal: "STF", tipo: "Repercussão Geral", numero: "537", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Momento de disponibilização de renda de pessoas jurídicas sediadas no Brasil com participação nos lucros de suas empresas coligadas ou controladas no estrangeiro para fins de IR.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=537",
    texto: "O art. 74 da MP 2.158-35 aplica-se às empresas nacionais controladoras de pessoas jurídicas sediadas em países de tributação favorecida ou desprovidos de controles societários e fiscais adequados, sendo inconstitucional o parágrafo único do mesmo dispositivo legal, o qual não incide sobre os lucros apurados até 31.12.2001." },
  { id: "stf-rg-538", tribunal: "STF", tipo: "Repercussão Geral", numero: "538", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência para processar e julgar ação em que se discute pagamento de adicional de insalubridade a servidor público de ex-Território Federal ante a existência de convênio firmado entre a União e o Estado-membro para o qual cedido.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=538",
    texto: "Não tem repercussão geral a questão constitucional sobre a competência da Justiça estadual para processar e julgar ação relacionada ao pagamento de adicional de insalubridade a servidor público de ex-Território cedido a Estado-membro por convênio firmado com a União." },
  { id: "stf-rg-539", tribunal: "STF", tipo: "Repercussão Geral", numero: "539", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Conversão monetária de vencimentos de servidores públicos estaduais, sem intermédio de URV.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=539",
    texto: "A questão da legitimidade de conversão da remuneração dos servidores públicos do Rio Grande do Sul, expressos no padrão monetário Cruzeiro Real para a nova moeda denominada Real, sem intermédio da Unidade Real de Valor - URV, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-540", tribunal: "STF", tipo: "Repercussão Geral", numero: "540", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Fixação de anuidade por conselhos de fiscalização profissional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=540",
    texto: "É inconstitucional, por ofensa ao princípio da legalidade tributária, lei que delega aos conselhos de fiscalização de profissões regulamentadas a competência de fixar ou majorar, sem parâmetro legal, o valor das contribuições de interesse das categorias profissionais e econômicas, usualmente cobradas sob o título de anuidades, vedada, ademais, a atualização desse valor pelos conselhos em percentual superior aos índices legalmente previstos." },
  { id: "stf-rg-541", tribunal: "STF", tipo: "Repercussão Geral", numero: "541", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Exercício do direito de greve por policiais civis.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=541",
    texto: "1 - O exercício do direito de greve, sob qualquer forma ou modalidade, é vedado aos policiais civis e a todos os servidores públicos que atuem diretamente na área de segurança pública. 2 - É obrigatória a participação do Poder Público em mediação instaurada pelos órgãos classistas das carreiras de segurança pública, nos termos do art. 165 do CPC, para vocalização dos interesses da categoria" },
  { id: "stf-rg-543", tribunal: "STF", tipo: "Repercussão Geral", numero: "543", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito adquirido ao recebimento de salário-família em face de alteração promovida pela EC 20/98.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=543",
    texto: "A alteração de regência constitucional do salário-família não repercute nas relações jurídicas existentes na data em que promulgada a Emenda Constitucional nº 20/1998." },
  { id: "stf-rg-544", tribunal: "STF", tipo: "Repercussão Geral", numero: "544", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Competência para julgamento de abusividade de greve de servidores públicos celetistas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=544",
    texto: "A justiça comum, federal ou estadual, é competente para julgar a abusividade de greve de servidores públicos celetistas da Administração pública direta, autarquias e fundações públicas." },
  { id: "stf-rg-545", tribunal: "STF", tipo: "Repercussão Geral", numero: "545", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Extensão da estabilidade excepcional do art. 19 do ADCT a empregados de fundação privada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=545",
    texto: "1. A qualificação de uma fundação instituída pelo Estado como sujeita ao regime público ou privado depende (i) do estatuto de sua criação ou autorização e (ii) das atividades por ela prestadas. As atividades de conteúdo econômico e as passíveis de delegação, quando definidas como objetos de dada fundação, ainda que essa seja instituída ou mantida pelo Poder público, podem-se submeter ao regime jurídico de direito privado. 2. A estabilidade especial do art. 19 do ADCT não se estende aos empregados das fundações públicas de direito privado, aplicando-se tão somente aos servidores das pessoas jurídicas de direito público." },
  { id: "stf-rg-546", tribunal: "STF", tipo: "Repercussão Geral", numero: "546", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Competência legislativa para dispor sobre o transporte irregular de passageiros e a aplicação da penalidade de apreensão de veículos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=546",
    texto: "Surge constitucional previsão normativa local voltada a coibir fraude considerado o serviço público de transporte coletivo e inconstitucional condicionar a liberação de veículo apreendido ao pagamento de multas, preços públicos e demais encargos decorrentes de infração." },
  { id: "stf-rg-549", tribunal: "STF", tipo: "Repercussão Geral", numero: "549", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Obrigatoriedade de intimação pessoal de procuradores federais no âmbito dos Juizados Especiais Federais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=549",
    texto: "A prerrogativa processual da Fazenda Pública Federal de receber intimações pessoais, nos termos do art. 17 da Lei 10.910/2004, não tem aplicação no âmbito do procedimento dos Juizados Especiais Federais." },
  { id: "stf-rg-551", tribunal: "STF", tipo: "Repercussão Geral", numero: "551", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão de direitos dos servidores públicos efetivos aos servidores e empregados públicos contratados para atender necessidade temporária e excepcional do setor público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=551",
    texto: "Servidores temporários não fazem jus a décimo terceiro salário e férias remuneradas acrescidas do terço constitucional, salvo (I) expressa previsão legal e/ou contratual em sentido contrário, ou (II) comprovado desvirtuamento da contratação temporária pela Administração Pública, em razão de sucessivas e reiteradas renovações e/ou prorrogações." },
  { id: "stf-rg-552", tribunal: "STF", tipo: "Repercussão Geral", numero: "552", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Participação de escrivão de paz em concurso de remoção para serventias notariais ou registrais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=552",
    texto: "A questão da possibilidade de remoção de escrivão de paz para serventias registrais e notariais tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-555", tribunal: "STF", tipo: "Repercussão Geral", numero: "555", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Fornecimento de Equipamento de Proteção Individual - EPI como fator de descaracterização do tempo de serviço especial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=555",
    texto: "I - O direito à aposentadoria especial pressupõe a efetiva exposição do trabalhador a agente nocivo à sua saúde, de modo que, se o EPI for realmente capaz de neutralizar a nocividade não haverá respaldo constitucional à aposentadoria especial; II - Na hipótese de exposição do trabalhador a ruído acima dos limites legais de tolerância, a declaração do empregador, no âmbito do Perfil Profissiográfico Previdenciário (PPP), no sentido da eficácia do Equipamento de Proteção Individual – EPI, não descaracteriza o tempo de serviço especial para aposentadoria." },
  { id: "stf-rg-557", tribunal: "STF", tipo: "Repercussão Geral", numero: "557", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Contagem de pontos por tempo de gerenciamento de equipes decorrente de designação formal como critério para promoção de servidores públicos municipais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=557",
    texto: "A questão de o tempo de gerenciamento de equipes decorrente de designação formal ser um dos critérios específicos para a promoção na carreira de servidor público municipal, conforme previsto na Lei 11.000/2004 do Município de Curitiba, tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-560", tribunal: "STF", tipo: "Repercussão Geral", numero: "560", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Ausência de coabitação dos cônjuges como prova da separação de fato.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=560",
    texto: "A questão da necessidade de ausência de coabitação para comprovar a separação de fato, requisito necessário para a dissolução do casamento civil pelo divórcio direto, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-561", tribunal: "STF", tipo: "Repercussão Geral", numero: "561", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade do Ministério Público para ajuizamento de ação civil pública que visa a anular ato administrativo com fundamento na defesa do patrimônio público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=561",
    texto: "O Ministério Público é parte legítima para o ajuizamento de ação coletiva que visa anular ato administrativo de aposentadoria que importe em lesão ao patrimônio público." },
  { id: "stf-rg-562", tribunal: "STF", tipo: "Repercussão Geral", numero: "562", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Indenização por dano moral decorrente de declarações públicas, supostamente ofensivas à honra, proferidas por Ministro de Estado no âmbito de sua atuação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=562",
    texto: "Ante conflito entre a liberdade de expressão de agente político, na defesa da coisa pública, e honra de terceiro, há de prevalecer o interesse coletivo." },
  { id: "stf-rg-563", tribunal: "STF", tipo: "Repercussão Geral", numero: "563", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência do adicional de “sexta parte” sobre a integralidade dos vencimentos de servidor público estadual estatutário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=563",
    texto: "A questão de a base de cálculo da vantagem pecuniária “Adicional de Sexta Parte” ser a integralidade dos vencimentos de servidor público estadual estatutário tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-564", tribunal: "STF", tipo: "Repercussão Geral", numero: "564", situacao: "Vigente", tema: "DIREITO ELEITORAL E PROCESSO ELEITORAL", titulo: "Candidatura de prefeito reeleito à chefia do Poder Executivo em Municipalidade diversa e aplicação imediata de modificação jurisprudencial da Justiça Eleitoral", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=564",
    texto: "I - O art. 14, § 5º, da Constituição deve ser interpretado no sentido de que a proibição da segunda reeleição é absoluta e torna inelegível para determinado cargo de Chefe do Poder Executivo o cidadão que já exerceu dois mandatos consecutivos (reeleito uma única vez) em cargo da mesma natureza, ainda que em ente da Federação diverso; II - As decisões do Tribunal Superior Eleitoral - TSE que, no curso do pleito eleitoral ou logo após o seu encerramento, impliquem mudança de jurisprudência não têm aplicabilidade imediata." },
  { id: "stf-rg-565", tribunal: "STF", tipo: "Repercussão Geral", numero: "565", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de exclusão de policial militar da corporação mediante processo administrativo", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=565",
    texto: "É possível a exclusão, em processo administrativo, de policial militar que comete faltas disciplinares, independentemente do curso de ação penal instaurada em razão da mesma conduta." },
  { id: "stf-rg-566", tribunal: "STF", tipo: "Repercussão Geral", numero: "566", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Realinhamento salarial de servidores públicos inativos, em face de modificações no regime próprio de previdência social.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=566",
    texto: "A questão do direito ao realinhamento salarial da Lei gaúcha n. 12.201/2004, que institui o fator de recomposição para o vencimento básico dos servidores da Secretaria da Justiça e Segurança, pelos inativos, em face de modificações no regime próprio de previdência social, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-567", tribunal: "STF", tipo: "Repercussão Geral", numero: "567", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Preenchimento de requisitos exigidos em edital de concurso para provimento de cargo público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=567",
    texto: "A questão de a qualificação superior à prevista no edital de concurso público apresentada pela candidata nomeada satisfazer a habilitação específica para provimento de cargo no Magistério tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-568", tribunal: "STF", tipo: "Repercussão Geral", numero: "568", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Reconhecimento, por via judicial, do direito à equivalência entre o limite máximo do salário-de-contribuição e a renda mensal inicial dos benefícios previdenciários.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=568",
    texto: "A questão do direito à revisão da renda mensal do benefício previdenciário em equivalência aos índices de reajuste aplicados aos limites máximos, ou tetos, dos salários-de-contribuição, disciplinados nas Emendas Constitucionais ns. 20/1998 e 41/2003, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-569", tribunal: "STF", tipo: "Repercussão Geral", numero: "569", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Concurso público para a contratação de empregados por pessoa jurídica que integra o chamado “Sistema S”.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=569",
    texto: "Os serviços sociais autônomos integrantes do denominado Sistema \"S\" não estão submetidos à exigência de concurso público para contratação de pessoal, nos moldes do art. 37, II, da Constituição Federal." },
  { id: "stf-rg-570", tribunal: "STF", tipo: "Repercussão Geral", numero: "570", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Equiparação dos valores recebidos a título de Adicional de Local de Exercício (ALE) ou Operacional de Localidade (AOL) entre todos os policiais civis e militares da ativa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=570",
    texto: "A questão do direito à equiparação dos valores recebidos a título de Adicional de Local de Exercício (ALE) ou Adicional Operacional de Localidade (AOL), entre todos os policiais civis e militares em atividade no Estado de São Paulo, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-571", tribunal: "STF", tipo: "Repercussão Geral", numero: "571", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aposentadoria compulsória de titular de serventia judicial não estatizada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=571",
    texto: "Não se aplica a aposentadoria compulsória prevista no artigo 40, parágrafo 1º, inciso II, da Constituição Federal aos titulares de serventias judiciais não estatizadas, desde que não sejam ocupantes de cargo público efetivo e não recebam remuneração proveniente dos cofres públicos." },
  { id: "stf-rg-572", tribunal: "STF", tipo: "Repercussão Geral", numero: "572", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar causas alusivas à parcela do imposto de renda retido na fonte pertencente ao Estado-membro.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=572",
    texto: "Compete à Justiça comum estadual processar e julgar causas alusivas à parcela do imposto de renda retido na fonte pertencente ao Estado-membro, porque ausente o interesse da União." },
  { id: "stf-rg-573", tribunal: "STF", tipo: "Repercussão Geral", numero: "573", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Ofensa aos princípios da isonomia e do livre acesso à Justiça pela Portaria 655/93, do Ministério da Fazenda.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=573",
    texto: "Não viola o princípio da isonomia e o livre acesso à jurisdição a restrição de ingresso no parcelamento de dívida relativa à Contribuição para Financiamento da Seguridade Social - COFINS, instituída pela Portaria nº 655/93, dos contribuintes que questionaram o tributo em juízo com depósito judicial dos débitos tributários." },
  { id: "stf-rg-575", tribunal: "STF", tipo: "Repercussão Geral", numero: "575", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Comprovação do recolhimento da contribuição previdenciária como requisito para o recebimento do seguro defeso.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=575",
    texto: "A questão da necessidade de comprovação do recolhimento da contribuição previdenciária, como requisito para o recebimento do seguro-defeso, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-576", tribunal: "STF", tipo: "Repercussão Geral", numero: "576", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Processamento e julgamento de prefeitos, por atos de improbidade administrativa, com base na Lei 8.429/92.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=576",
    texto: "O processo e julgamento de prefeito municipal por crime de responsabilidade (Decreto-lei 201/67) não impede sua responsabilização por atos de improbidade administrativa previstos na Lei 8.429/1992, em virtude da autonomia das instâncias." },
  { id: "stf-rg-577", tribunal: "STF", tipo: "Repercussão Geral", numero: "577", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Ajuizamento de ação individual autônoma para pleitear o direito aos juros remuneratórios de caderneta, reconhecido em ação coletiva transitada em julgado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=577",
    texto: "A questão da ofensa aos limites à coisa julgada pela propositura de ação individual autônoma para o recebimento de juros remuneratórios mensais e capitalizados da poupança, tendo em vista tratar-se de pedido não compreendido em título executivo decorrente de ação civil pública anteriormente ajuizada, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-578", tribunal: "STF", tipo: "Repercussão Geral", numero: "578", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aplicação do lapso temporal da Emenda Constitucional 20/98 a integrante de carreira pública escalonada em classes que pleiteia aposentadoria, com proventos relativos ao cargo ao qual promovido, ante o implemento dos requisitos, no cargo originalmente ocupado, antes do advento da emenda em questão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=578",
    texto: "(i) Ressalvado o direito de opção, a regra de transição do art. 8º, inciso II da Emenda Constitucional nº 20/98, somente se aplica aos servidores que, quando da sua publicação, ainda não reuniam os requisitos necessários para a aposentadoria; (ii) em se tratando de carreira pública escalonada em classes, a exigência instituída pelo art. 8º, inciso II da Emenda Constitucional n.º 20/98, de cinco anos de efetivo exercício no cargo no qual se dará a aposentadoria, deverá ser compreendida como cinco anos de efetivo exercício na carreira a que pertencente o servidor." },
  { id: "stf-rg-579", tribunal: "STF", tipo: "Repercussão Geral", numero: "579", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Melhoria do tipo de acomodação de paciente internado pelo Sistema Único de Saúde - SUS mediante o pagamento da diferença respectiva.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=579",
    texto: "É constitucional a regra que veda, no âmbito do Sistema Único de Saúde, a internação em acomodações superiores, bem como o atendimento diferenciado por médico do próprio Sistema Único de Saúde, ou por médico conveniado, mediante o pagamento da diferença dos valores correspondentes." },
  { id: "stf-rg-581", tribunal: "STF", tipo: "Repercussão Geral", numero: "581", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do ISS sobre atividades desenvolvidas por operadoras de planos de saúde.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=581",
    texto: "As operadoras de planos de saúde realizam prestação de serviço sujeita ao Imposto sobre Serviços de Qualquer Natureza - ISSQN, previsto no art. 156, III, da CRFB/88." },
  { id: "stf-rg-582", tribunal: "STF", tipo: "Repercussão Geral", numero: "582", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Cabimento de habeas data para fins de acesso a informações incluídas em banco de dados denominado SINCOR – Sistema de Conta-Corrente de Pessoa Jurídica, da Receita Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=582",
    texto: "O habeas data é a garantia constitucional adequada para a obtenção, pelo próprio contribuinte, dos dados concernentes ao pagamento de tributos constantes de sistemas informatizados de apoio à arrecadação dos órgãos da administração fazendária dos entes estatais." },
  { id: "stf-rg-583", tribunal: "STF", tipo: "Repercussão Geral", numero: "583", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Prescrição aplicável (total ou parcial) no âmbito da Justiça do Trabalho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=583",
    texto: "A questão de a prescrição ser total ou parcial, no Direito do Trabalho, quando se discute, a título de complementação, o pagamento de parcelas nunca recebidas, provenientes de norma regulamentar revogada antes da aposentadoria, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-584", tribunal: "STF", tipo: "Repercussão Geral", numero: "584", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de ingresso da Aneel e da Eletrobrás no polo passivo de ação de restituição de valores, com o deslocamento da competência para a Justiça Federal, e análise de eventual prescrição da ação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=584",
    texto: "A questão da possibilidade de inclusão das Centrais Elétricas Brasileiras S.A. - Eletrobrás e da Agência Nacional de Energia Elétrica - ANEEL no polo passivo da ação, com o deslocamento da competência para a Justiça Federal, bem como da prescrição da pretensão de repetição de indébito ajuizada pelo recorrido, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-585", tribunal: "STF", tipo: "Repercussão Geral", numero: "585", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Diminuição da base de cálculo de contribuições previdenciárias em decorrência de acordo celebrado em execução trabalhista.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=585",
    texto: "A questão acerca da possibilidade de acordo firmado na fase de execução da sentença trabalhista condenatória transitada em julgado resultar em diminuição da base de cálculo das contribuições previdenciárias tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-586", tribunal: "STF", tipo: "Repercussão Geral", numero: "586", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Necessidade de lei em sentido formal para a fixação do valor de gratificações mensais pagas a chefes de cartório e escrivães eleitorais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=586",
    texto: "A questão sobre a necessidade de lei em sentido formal para a fixação do valor das gratificações mensais pagas a chefes de cartório e escrivães eleitorais tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-587", tribunal: "STF", tipo: "Repercussão Geral", numero: "587", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Excesso de execução decorrente de eventual erro de cálculo em processo alusivo a diferenças de correção monetária em cadernetas de poupança, por alegados expurgos inflacionários.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=587",
    texto: "A questão da caracterização de excesso de execução pelo erro de cálculo nos processos em que se discute a cobrança dos expurgos inflacionários relativos aos planos econômicos tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-588", tribunal: "STF", tipo: "Repercussão Geral", numero: "588", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Modificação ou revogação de lei municipal mediante decreto, por alegada contrariedade a lei federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=588",
    texto: "A questão da validade de o ato administrativo normativo (decreto municipal) modificar ou revogar lei municipal, contestada em face da legislação federal, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-589", tribunal: "STF", tipo: "Repercussão Geral", numero: "589", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Revisão de renda mensal de benefício previdenciário mediante aplicação dos mesmos índices utilizados para reajuste do teto do salário-de-contribuição, relativamente aos meses de junho de 1999 e maio de 2004.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=589",
    texto: "A questão da adoção, para fins de revisão da renda mensal de benefício previdenciário, dos mesmos índices aplicados para o reajuste do teto do salário-de-contribuição, relativamente aos meses de junho de 1999 (Portaria n. 5.188/1999) e maio de 2004 (Decreto n. 5.061/2004), conforme o disposto nas Emendas Constitucionais n. 20/1998 e n. 41/2003, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-591", tribunal: "STF", tipo: "Repercussão Geral", numero: "591", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Extensão, às complementações de aposentadoria, de benefício concedido indistintamente aos empregados ativos em razão de acordo coletivo de trabalho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=591",
    texto: "A questão do direito ao recebimento pelos aposentados e pensionistas, a título de complementação de aposentadoria, das vantagens concedidas em acordo coletivo de trabalho, aos empregados em atividade, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-592", tribunal: "STF", tipo: "Repercussão Geral", numero: "592", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade civil objetiva do Estado por morte de detento.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=592",
    texto: "Em caso de inobservância do seu dever específico de proteção previsto no art. 5º, inciso XLIX, da Constituição Federal, o Estado é responsável pela morte de detento." },
  { id: "stf-rg-593", tribunal: "STF", tipo: "Repercussão Geral", numero: "593", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade tributária de livro eletrônico (e-book) gravado em CD-ROM.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=593",
    texto: "A imunidade tributária constante do art. 150, VI, d, da CF/88 aplica-se ao livro eletrônico (e-book), inclusive aos suportes exclusivamente utilizados para fixá-lo." },
  { id: "stf-rg-594", tribunal: "STF", tipo: "Repercussão Geral", numero: "594", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aplicação das regras previstas nos §§ 4º e 5º do art. 40 da Constituição Federal (redação originária) a servidor celetista aposentado ou falecido antes do advento da Lei 8.112/90.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=594",
    texto: "As regras dos parágrafos 4º e 5º do artigo 40 da Constituição Federal, na redação anterior à EC 20/1998, não se aplicam ao servidor submetido ao regime da Consolidação das Leis do Trabalho que se aposentou ou faleceu antes do advento da Lei nº 8.112/1990." },
  { id: "stf-rg-595", tribunal: "STF", tipo: "Repercussão Geral", numero: "595", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Promulgação, pelo Chefe do Poder Executivo, de parte de projeto de lei que não foi vetada, antes da manifestação do Poder Legislativo pela manutenção ou pela rejeição do veto.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=595",
    texto: "É constitucional a promulgação, pelo Chefe do Poder Executivo, de parte incontroversa de projeto da lei que não foi vetada, antes da manifestação do Poder Legislativo pela manutenção ou pela rejeição do veto, inexistindo vício de inconstitucionalidade dessa parte inicialmente publicada pela ausência de promulgação da derrubada dos vetos." },
  { id: "stf-rg-596", tribunal: "STF", tipo: "Repercussão Geral", numero: "596", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aplicação dos critérios de reajuste do vale-refeição dos servidores do Estado do Rio Grande do Sul aos integrantes do quadro especial decorrente da transformação da antiga CEERGS - Caixa Econômica Estadual do Rio Grande do Sul em sociedade anônima de economia mista.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=596",
    texto: "A questão do direito dos servidores públicos do Quadro Especial da extinta Caixa Econômica Estadual do Rio Grande do Sul - CEERGS ao reajuste da vantagem pecuniária “Vale-Refeição”, paga aos servidores do Poder Executivo gaúcho, nos termos da Lei estadual n. 10.002/1993, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-597", tribunal: "STF", tipo: "Repercussão Geral", numero: "597", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Imposição ao INSS, nos processos em que figure como parte ré, do ônus de apresentar cálculos de liquidação do seu próprio débito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=597",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à imposição ao Instituto Nacional do Seguro Social (INSS) do ônus de apresentar cálculo de liquidação de seus próprios débitos nos processos em que figure como réu." },
  { id: "stf-rg-601", tribunal: "STF", tipo: "Repercussão Geral", numero: "601", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Fixação de soldo em valor inferior a vencimento básico de referência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=601",
    texto: "A questão referente à determinação do valor do soldo dos integrantes da carreira militar do Estado de Pernambuco, em face do escalonamento vertical previsto na Lei Estadual 10.426/1990 e da estipulação do Vencimento Básico de Referência – VBR pela Lei Pernambucana 11.216/1995, bem como a questão acerca das consequências da edição da Lei Complementar Estadual 32/2001 na disciplina remuneratória dos militares daquele Estado têm natureza infraconstitucional e a elas atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-602", tribunal: "STF", tipo: "Repercussão Geral", numero: "602", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão, a servidores aposentados e pensionistas, dos efeitos financeiros decorrentes do enquadramento de servidores ativos do extinto DNER no Plano Especial de Cargos do DNIT.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=602",
    texto: "Os servidores aposentados e pensionistas do extinto DNER fazem jus aos efeitos financeiros decorrentes do enquadramento de servidores ativos que, provindos deste órgão, passaram a gozar dos benefícios e vantagens resultantes do Pleno Especial de Cargos do DNIT, instituído pela Lei 11.171/2005." },
  { id: "stf-rg-604", tribunal: "STF", tipo: "Repercussão Geral", numero: "604", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Restituição de valores despendidos por consumidor para a implantação de rede elétrica em propriedade rural.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=604",
    texto: "A questão do direito à restituição de valores gastos por proprietários rurais com a instalação de rede elétrica pela antecipação do programa de universalização de energia da Centrais Elétricas Brasileiras S.A. - Eletrobrás e da Agência Nacional de Energia Elétrica - ANEEL tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-605", tribunal: "STF", tipo: "Repercussão Geral", numero: "605", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Percepção da Gratificação de Atividade e da Gratificação de Habilitação pelos Policiais Militares do Estado da Bahia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=605",
    texto: "A questão do direito ao recebimento das vantagens pecuniárias “Gratificação de Atividade” e “Gratificação de Habilitação” pelos Policiais Militares da Bahia tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-607", tribunal: "STF", tipo: "Repercussão Geral", numero: "607", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade da Defensoria Pública para propor ação civil pública em defesa de interesses difusos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=607",
    texto: "A Defensoria Pública tem legitimidade para a propositura de ação civil pública que vise a promover a tutela judicial de direitos difusos ou coletivos de que sejam titulares, em tese, pessoas necessitadas." },
  { id: "stf-rg-608", tribunal: "STF", tipo: "Repercussão Geral", numero: "608", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Prazo prescricional aplicável à cobrança de valores não depositados no Fundo de Garantia por Tempo de Serviço - FGTS", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=608",
    texto: "O prazo prescricional aplicável à cobrança de valores não depositados no Fundo de Garantia por Tempo de Serviço (FGTS) é quinquenal, nos termos do art. 7º, XXIX, da Constituição Federal." },
  { id: "stf-rg-609", tribunal: "STF", tipo: "Repercussão Geral", numero: "609", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Valor do auxílio-acidente inferior ao salário mínimo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=609",
    texto: "A questão do pagamento de auxílio-acidente em valor não inferior ao salário mínimo tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-610", tribunal: "STF", tipo: "Repercussão Geral", numero: "610", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Incorporação de gratificação de função à remuneração de empregados públicos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=610",
    texto: "A questão do direito à incorporação da vantagem pecuniária “função comissionada” aos vencimentos dos empregados públicos tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-611", tribunal: "STF", tipo: "Repercussão Geral", numero: "611", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Responsabilidade civil por danos morais e materiais decorrentes da negativa de cobertura por operadora de plano de saúde.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=611",
    texto: "A questão da responsabilidade civil por danos morais e materiais pela negativa de cobertura de atendimento por operadora de plano de saúde tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-612", tribunal: "STF", tipo: "Repercussão Geral", numero: "612", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Constitucionalidade de lei municipal que dispõe sobre as hipóteses de contratação temporária servidores públicos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=612",
    texto: "Nos termos do art. 37, IX, da Constituição Federal, para que se considere válida a contratação temporária de servidores públicos, é preciso que: a) os casos excepcionais estejam previstos em lei; b) o prazo de contratação seja predeterminado; c) a necessidade seja temporária; d) o interesse público seja excepcional; e) a contratação seja indispensável, sendo vedada para os serviços ordinários permanentes do Estado que estejam sob o espectro das contingências normais da Administração." },
  { id: "stf-rg-613", tribunal: "STF", tipo: "Repercussão Geral", numero: "613", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Constitucionalidade do art. 362 do Código de Processo Penal (dispositivo que trata da citação por hora certa).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=613",
    texto: "1. É constitucional a citação por hora certa, prevista no art. 362, do Código de Processo Penal. 2. A ocultação do réu para ser citado infringe cláusulas constitucionais do devido processo legal e viola as garantias constitucionais do acesso à justiça e da razoável duração do processo." },
  { id: "stf-rg-614", tribunal: "STF", tipo: "Repercussão Geral", numero: "614", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Cobrança de tarifas e taxas acessórias, vinculadas a contratos bancários (como, por exemplo, “de abertura de crédito”, “de retorno”, “de emissão de boleto” e “de cadastro”).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=614",
    texto: "A questão da legitimidade de cobrança de tarifas, taxas administrativas acessórias e de serviços de terceiros, incluídas em contrato de financiamento bancário, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-615", tribunal: "STF", tipo: "Repercussão Geral", numero: "615", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Constitucionalidade da cobrança de ICMS, pelo Estado de destino, com base no Protocolo ICMS 21/2011 do CONFAZ, nas operações interestaduais de vendas de mercadorias a consumidor final, realizadas de forma não presencial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=615",
    texto: "É inconstitucional a cobrança de ICMS pelo Estado de destino, com fundamento no Protocolo ICMS 21/2011 do CONFAZ, nas operações interestaduais de venda de mercadoria ou bem realizadas de forma não presencial a consumidor final não contribuinte do imposto." },
  { id: "stf-rg-617", tribunal: "STF", tipo: "Repercussão Geral", numero: "617", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Revisão judicial do ato de denegação de concessão de licença ambiental de pescador artesanal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=617",
    texto: "A questão da validade de concessão judicial de licença ambiental para pescador artesanal, negada pelo Instituto Brasileiro do Meio Ambiente e dos Recursos Naturais Renováveis - IBAMA, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-618", tribunal: "STF", tipo: "Repercussão Geral", numero: "618", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Cobrança das denominadas tarifas de demanda e de ultrapassagem, nos termos em que previstas na Resolução 456/2000, da Agência nacional de Energia Elétrica - ANEEL.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=618",
    texto: "A questão da legitimidade da cobrança das tarifas de demanda e de ultrapassagem, nos termos da Resolução 456/2000 da Agência Nacional de Energia Elétrica - ANEEL, tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-620", tribunal: "STF", tipo: "Repercussão Geral", numero: "620", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito ao processamento de requerimento de revalidação de diploma de graduação obtido em instituição de ensino superior estrangeira.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=620",
    texto: "A questão do direito ao processamento do requerimento de revalidação de diploma de graduação obtido em instituição de ensino superior estrangeira tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-621", tribunal: "STF", tipo: "Repercussão Geral", numero: "621", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Revogação da multa prevista no art. 600 da Consolidação das Leis do Trabalho, bem como sua aplicabilidade em razão do atraso no pagamento da contribuição sindical rural.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=621",
    texto: "A questão da subsistência da multa do art. 600 da Consolidação das Leis do Trabalho - CLT, pelo recolhimento da contribuição sindical rural em atraso, após a edição da Lei n. 8.022/1990, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-622", tribunal: "STF", tipo: "Repercussão Geral", numero: "622", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Prevalência da paternidade socioafetiva em detrimento da paternidade biológica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=622",
    texto: "A paternidade socioafetiva, declarada ou não em registro público, não impede o reconhecimento do vínculo de filiação concomitante baseado na origem biológica, com os efeitos jurídicos próprios." },
  { id: "stf-rg-623", tribunal: "STF", tipo: "Repercussão Geral", numero: "623", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Direito à indenização por danos morais e materiais decorrentes da espera excessiva em fila de instituição financeira.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=623",
    texto: "A questão da responsabilidade por danos morais e materiais decorrentes da espera excessiva em fila de instituição financeira, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-625", tribunal: "STF", tipo: "Repercussão Geral", numero: "625", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Aplicabilidade dos juros de mora previstos no art. 1º-F da Lei 9.494/1997 aos casos em que a Fazenda Pública é condenada subsidiariamente pelas obrigações trabalhistas inadimplidas pelo empregador principal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=625",
    texto: "A questão da aplicabilidade dos juros de mora previstos no art. 1º-F da Lei 9.494/1997 na hipótese em que a Fazenda Pública for condenada subsidiariamente pelas obrigações trabalhistas inadimplidas pelo empregador principal tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-626", tribunal: "STF", tipo: "Repercussão Geral", numero: "626", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Constitucionalidade da vedação à conversão da pena privativa de liberdade em pena restritiva de direitos, prevista nos artigos 33, § 4º, e 44, caput, da Lei 11.343/2006.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=626",
    texto: "É inconstitucional a vedação à conversão da pena privativa de liberdade em restritiva de direitos, prevista nos artigos 33, § 4º, e 44, caput, da Lei 11.343/2006." },
  { id: "stf-rg-628", tribunal: "STF", tipo: "Repercussão Geral", numero: "628", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Modificação, pela Administração Pública, de critérios técnicos ou econômicos estabelecidos no instrumento convocatório, no curso de procedimento licitatório.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=628",
    texto: "A questão da validade de modificação, pela Administração Pública, dos critérios técnicos ou econômicos estabelecidos no instrumento convocatório, no curso de procedimento licitatório, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-629", tribunal: "STF", tipo: "Repercussão Geral", numero: "629", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Equiparação salarial de empregados de sociedade de economia mista integrantes de quadro de carreira cuja reestruturação não foi homologada pelo Ministério do Trabalho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=629",
    texto: "A questão do direito à equiparação salarial dos empregados da sociedade de economia mista, integrantes de quadro de carreira cuja reestruturação não foi homologada pelo Ministério do Trabalho, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral." },
  { id: "stf-rg-631", tribunal: "STF", tipo: "Repercussão Geral", numero: "631", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Desnecessidade de comprovação do prévio exaurimento das vias extrajudiciais de busca de bens para o deferimento de penhora eletrônica pelo denominado sistema Bacen Jud, requerida após a Lei 11.382/2006.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=631",
    texto: "A questão da legitimidade da penhora de dinheiro ou outros ativos financeiros pelo sistema eletrônico do denominado Bacen-Jud, independentemente do prévio esgotamento das vias extrajudiciais para localização de outros bens penhoráveis, e após a vigência da Lei n. 11.382/2006, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-634", tribunal: "STF", tipo: "Repercussão Geral", numero: "634", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Isonomia de gênero quanto ao critério de expectativa de vida adotado no cálculo do fator previdenciário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=634",
    texto: "A questão da isonomia de gênero quanto ao critério de expectativa de vida adotado no cálculo do fator previdenciário, na aposentadoria por tempo de contribuição, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-635", tribunal: "STF", tipo: "Repercussão Geral", numero: "635", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de servidores públicos ativos à conversão de férias não gozadas em indenização pecuniária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=635",
    texto: "É assegurada ao servidor público inativo a conversão de férias não gozadas, ou de outros direitos de natureza remuneratória, em indenização pecuniária, dada a responsabilidade objetiva da Administração Pública em virtude da vedação ao enriquecimento sem causa. Obs.: após a oposição de embargos de declaração o STF decidiu permitir o processamento do recurso extraordinário para julgar a questão em relação aos servidores públicos em atividade." },
  { id: "stf-rg-636", tribunal: "STF", tipo: "Repercussão Geral", numero: "636", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Conversão de direito de uso de linha telefônica, adquirido antes da privatização do Sistema Telebrás, em direito acionário da nova sociedade de economia mista criada pelo Município de Londrina.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=636",
    texto: "A questão da validade da conversão do direito de uso de linha telefônica fixa, adquirido antes da privatização do Sistema Telebrás, em direito acionário de nova sociedade de economia mista, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-637", tribunal: "STF", tipo: "Repercussão Geral", numero: "637", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Prazo prescricional relativo às ações de indenização por danos morais e materiais decorrentes de acidente de trabalho antes do advento da Emenda Constitucional 45/2004.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=637",
    texto: "A questão do prazo prescricional aplicável às ações de reparação de danos decorrentes de acidente de trabalho reconhecido antes do advento da Emenda Constitucional 45/2004 tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-639", tribunal: "STF", tipo: "Repercussão Geral", numero: "639", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Definição do montante remuneratório recebido por servidores públicos, para fins de incidência do teto constitucional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=639",
    texto: "Subtraído o montante que exceder o teto e o subteto previsto no art. 37, inciso XI, da Constituição, tem-se o valor para base de cálculo para a incidência do imposto de renda e da contribuição previdenciária." },
  { id: "stf-rg-640", tribunal: "STF", tipo: "Repercussão Geral", numero: "640", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Incidência dos juros de mora previstos no art. 1º-F da Lei 9.494/1997, nas ações em que a União figura como sucessora da Rede Ferroviária Federal S.A., em período anterior à referida sucessão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=640",
    texto: "A questão do momento de incidência dos juros de mora previstos no art. 1º-F da Lei 9.494/1997 nas ações em que a União figura como sucessora da Rede Ferroviária Federal S.A. - RFFSA tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-641", tribunal: "STF", tipo: "Repercussão Geral", numero: "641", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Delimitação da base de cálculo do Imposto sobre Serviços de Qualquer Natureza – ISSQN devido pela prestação de serviços de registros públicos, cartorários e notariais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=641",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa ao enquadramento da prestação dos serviços de registros públicos, cartorários e notariais na sistemática de recolhimento do ISS prevista no art. 9º, § 1º, do Decreto-Lei nº 406/1968." },
  { id: "stf-rg-643", tribunal: "STF", tipo: "Repercussão Geral", numero: "643", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do Imposto sobre Produtos Industrializados – IPI nas operações de importação de veículos automotores por pessoa natural para uso próprio.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=643",
    texto: "Incide o imposto de produtos industrializados na importação de veículo automotor por pessoa natural, ainda que não desempenhe atividade empresarial e o faça para uso próprio." },
  { id: "stf-rg-644", tribunal: "STF", tipo: "Repercussão Geral", numero: "644", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade tributária recíproca quanto ao Imposto sobre Propriedade Territorial Urbana – IPTU incidente sobre imóveis de propriedade da Empresa Brasileira de Correios e Telégrafos – ECT.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=644",
    texto: "A imunidade tributária recíproca reconhecida à Empresa Brasileira de Correios e Telégrafos — ECT alcança o IPTU incidente sobre imóveis de sua propriedade e por ela utilizados, não se podendo estabelecer, a priori, nenhuma distinção entre os imóveis afetados ao serviço postal e aqueles afetados à atividade econômica." },
  { id: "stf-rg-645", tribunal: "STF", tipo: "Repercussão Geral", numero: "645", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade processual ativa do Ministério Público para deduzir, em ação civil pública, pretensão de natureza tributária em defesa dos contribuintes.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=645",
    texto: "O Ministério Público não possui legitimidade ativa ad causam para, em ação civil pública, deduzir em juízo pretensão de natureza tributária em defesa dos contribuintes, que vise questionar a constitucionalidade/legalidade de tributo." },
  { id: "stf-rg-646", tribunal: "STF", tipo: "Repercussão Geral", numero: "646", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Estabelecimento de limite de idade para inscrição em concurso público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=646",
    texto: "O estabelecimento de limite de idade para inscrição em concurso público apenas é legítimo quando justificado pela natureza das atribuições do cargo a ser preenchido." },
  { id: "stf-rg-647", tribunal: "STF", tipo: "Repercussão Geral", numero: "647", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Possibilidade da decretação de perdimento de bem apreendido em decorrência do tráfico ilícito de entorpecentes e drogas afins, quando não comprovada sua utilização habitual ou sua adulteração para o cometimento do crime.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=647",
    texto: "É possível o confisco de todo e qualquer bem de valor econômico apreendido em decorrência do tráfico de drogas, sem a necessidade de se perquirir a habitualidade, reiteração do uso do bem para tal finalidade, a sua modificação para dificultar a descoberta do local do acondicionamento da droga ou qualquer outro requisito além daqueles previstos expressamente no art. 243, parágrafo único, da Constituição Federal." },
  { id: "stf-rg-648", tribunal: "STF", tipo: "Repercussão Geral", numero: "648", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Competência da Justiça Federal para processar e julgar crimes ambientais transnacionais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=648",
    texto: "Compete à Justiça Federal processar e julgar o crime ambiental de caráter transnacional que envolva animais silvestres, ameaçados de extinção e espécimes exóticas ou protegidas por compromissos internacionais assumidos pelo Brasil." },
  { id: "stf-rg-650", tribunal: "STF", tipo: "Repercussão Geral", numero: "650", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Extinção da punibilidade do delito de posse irregular de arma de fogo de uso permitido, pela aplicabilidade retroativa de lei que concedeu novo prazo para registro de armas ainda não registradas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=650",
    texto: "É incabível a aplicação retroativa do art. 30 da Lei 10.826/2003, inserido pela Medida Provisória 417/2008, para extinguir a punibilidade do delito de posse de arma de fogo de uso permitido cometido antes da sua entrada em vigor." },
  { id: "stf-rg-652", tribunal: "STF", tipo: "Repercussão Geral", numero: "652", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de nomeação de membro do Ministério Público Especial para o cargo de Conselheiro do Tribunal de Contas estadual, ainda que a vaga devesse ser reservada à escolha da Assembleia Legislativa, a fim de se garantir a representatividade do Ministério Público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=652",
    texto: "É inconstitucional a nomeação, pelo Chefe do Executivo, de membro do Ministério Público especial para preenchimento de cargo vago de Conselheiro de Tribunal de Contas local quando se tratar de vaga reservada à escolha da Assembleia Legislativa, devendo-se observar a regra constitucional de divisão proporcional das indicações entre os Poderes Legislativo e Executivo." },
  { id: "stf-rg-653", tribunal: "STF", tipo: "Repercussão Geral", numero: "653", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Valor devido pela União ao Fundo de Participação dos Municípios, relativamente aos impostos sobre a renda e proventos de qualquer natureza e sobre produtos industrializados, em face de benefícios e incentivos fiscais concedidos em relação a esses mesmos impostos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=653",
    texto: "É constitucional a concessão regular de incentivos, benefícios e isenções fiscais relativos ao Imposto de Renda e Imposto sobre Produtos Industrializados por parte da União em relação ao Fundo de Participação de Municípios e respectivas quotas devidas às Municipalidades." },
  { id: "stf-rg-654", tribunal: "STF", tipo: "Repercussão Geral", numero: "654", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Base de cálculo das horas extras e do adicional noturno prestados por policial civil do Estado de Santa Catarina.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=654",
    texto: "A questão da determinação da base de cálculo das horas extras e do adicional noturno devidos aos policiais civis do Estado de Santa Catarina, bem como a questão acerca da definição da lei local aplicável ao caso têm natureza infraconstitucional e a elas atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-655", tribunal: "STF", tipo: "Repercussão Geral", numero: "655", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Modificação do valor fixado a título de indenização por danos morais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=655",
    texto: "A questão da razoabilidade e da proporcionalidade do valor fixado a título de indenização por danos morais tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-657", tribunal: "STF", tipo: "Repercussão Geral", numero: "657", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Responsabilidade civil por danos morais em razão de ofensa à imagem.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=657",
    texto: "A questão da responsabilidade por danos morais decorrentes da suposta ofensa aos valores da personalidade, passíveis de ressarcimento, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-658", tribunal: "STF", tipo: "Repercussão Geral", numero: "658", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de a Fazenda Pública recusar a nomeação de precatórios à penhora, em razão da ordem de preferências estabelecida na legislação processual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=658",
    texto: "A questão referente à necessidade de a nomeação de precatórios à penhora observar a ordem de preferência descrita no Código de Processo Civil e na Lei de Execuções Fiscais tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-659", tribunal: "STF", tipo: "Repercussão Geral", numero: "659", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de membro do Ministério Público da União ao recebimento de ajuda de custo nos casos de remoção a pedido.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=659",
    texto: "A questão do direito de membro do Ministério Público ao pagamento de ajuda de custo na hipótese de remoção a pedido tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-660", tribunal: "STF", tipo: "Repercussão Geral", numero: "660", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Violação dos princípios do contraditório e da ampla defesa quando o julgamento da causa depender de prévia análise da adequada aplicação das normas infraconstitucionais. Extensão do entendimento ao princípio do devido processo legal e aos limites da coisa julgada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=660",
    texto: "A questão da ofensa aos princípios do contraditório, da ampla defesa, do devido processo legal e dos limites à coisa julgada, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-662", tribunal: "STF", tipo: "Repercussão Geral", numero: "662", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Direito adquirido ao recebimento de complementação de aposentadoria calculada de acordo com as normas vigentes à época da adesão a contrato de plano de previdência privada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=662",
    texto: "A questão do direito adquirido ao recebimento de complementação de benefício previdenciário de acordo com as regras vigentes no período de adesão ao plano de previdência privada tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-663", tribunal: "STF", tipo: "Repercussão Geral", numero: "663", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Incidência do fator previdenciário sobre período trabalhado em condições especiais convertido em tempo de serviço comum para o cálculo de aposentadoria por tempo de contribuição.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=663",
    texto: "A questão da incidência do fator previdenciário sobre período exercido em atividade especial convertido em tempo de serviço comum, para fins do cálculo do benefício de aposentadoria por tempo de contribuição, tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-664", tribunal: "STF", tipo: "Repercussão Geral", numero: "664", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão da GDATFA aos servidores inativos no mesmo patamar pago aos servidores em atividade. Fixação do termo final dessa equiparação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=664",
    texto: "O termo inicial do pagamento diferenciado das gratificações de desempenho entre servidores ativos e inativos é o da data da homologação do resultado das avaliações, após a conclusão do primeiro ciclo de avaliações, não podendo a Administração retroagir os efeitos financeiros a data anterior." },
  { id: "stf-rg-665", tribunal: "STF", tipo: "Repercussão Geral", numero: "665", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Constitucionalidade das modificações efetuadas na base de cálculo e na alíquota da contribuição ao PIS, destinada à composição do Fundo Social de Emergência e devida pelos contribuintes a que se refere o § 1º do art. 22 da Lei 8.212/1991, no período de vigência do art. 72, V, do ADCT.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=665",
    texto: "São constitucionais a alíquota e a base de cálculo da contribuição ao PIS, previstas no art. 72, V, do ADCT, destinada à composição do Fundo Social de Emergência, nas redações da ECR 1/94 e das EC 10/96 e 17/97, observados os princípios da anterioridade nonagesimal e da irretroatividade tributária." },
  { id: "stf-rg-666", tribunal: "STF", tipo: "Repercussão Geral", numero: "666", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Imprescritibilidade das ações de ressarcimento por danos causados ao erário, ainda que o prejuízo não decorra de ato de improbidade administrativa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=666",
    texto: "É prescritível a ação de reparação de danos à Fazenda Pública decorrente de ilícito civil." },
  { id: "stf-rg-667", tribunal: "STF", tipo: "Repercussão Geral", numero: "667", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade da reestruturação de quadro funcional por meio de aglutinação, em uma única carreira, de cargos anteriormente providos em carreiras diferenciadas, sem a observância do concurso público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=667",
    texto: "É inconstitucional, por dispensar o concurso público, a reestruturação de quadro funcional por meio de aglutinação, em uma única carreira, de cargos diversos, quando a nova carreira tiver atribuições e responsabilidades diferentes dos cargos originais." },
  { id: "stf-rg-669", tribunal: "STF", tipo: "Repercussão Geral", numero: "669", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Validade da contribuição a ser recolhida pelo empregador rural pessoa física sobre a receita bruta proveniente da comercialização de sua produção, nos termos do art. 1º da Lei 10.256/2001.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=669",
    texto: "É constitucional formal e materialmente a contribuição social do empregador rural pessoa física, instituída pela Lei 10.256/2001, incidente sobre a receita bruta obtida com a comercialização de sua produção." },
  { id: "stf-rg-671", tribunal: "STF", tipo: "Repercussão Geral", numero: "671", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de candidatos aprovados em concurso público a indenização por danos materiais em razão de alegada demora na nomeação, efetivada apenas após o trânsito em julgado de decisão judicial que reconheceu o direito à investidura.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=671",
    texto: "Na hipótese de posse em cargo público determinada por decisão judicial, o servidor não faz jus a indenização, sob fundamento de que deveria ter sido investido em momento anterior, salvo situação de arbitrariedade flagrante." },
  { id: "stf-rg-672", tribunal: "STF", tipo: "Repercussão Geral", numero: "672", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Recebimento, por ex-vereadores, de pensão vitalícia estabelecida por lei municipal anterior à Constituição de 1988.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=672",
    texto: "Lei municipal a versar a percepção, mensal e vitalícia, de 'subsídio' por ex-vereador e a consequente pensão em caso de morte não é harmônica com a Constituição Federal de 1988." },
  { id: "stf-rg-673", tribunal: "STF", tipo: "Repercussão Geral", numero: "673", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Prazo prescricional aplicável às execuções individuais de sentença prolatada em processo coletivo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=673",
    texto: "A questão do prazo prescricional aplicável às execuções individuais de sentença proferida em ação coletiva já transitada em julgado tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-674", tribunal: "STF", tipo: "Repercussão Geral", numero: "674", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Aplicabilidade da imunidade referente às contribuições sociais sobre as receitas decorrentes de exportação intermediada por empresas comerciais exportadoras (“trading companies”).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=674",
    texto: "A norma imunizante contida no inciso I do § 2º do art. 149 da Constituição da República alcança as receitas decorrentes de operações indiretas de exportação caracterizadas por haver participação negocial de sociedade exportadora intermediária." },
  { id: "stf-rg-675", tribunal: "STF", tipo: "Repercussão Geral", numero: "675", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Suspensão de ação individual em razão da existência de ação coletiva.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=675",
    texto: "A questão da suspensão de ação individual pelo ajuizamento de ação civil pública com a mesma finalidade tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-676", tribunal: "STF", tipo: "Repercussão Geral", numero: "676", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Situação dos terrenos de marinha localizados em ilhas costeiras com sede de município, após o advento da Emenda Constitucional 46/2005.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=676",
    texto: "A Emenda Constitucional nº 46/2005 não interferiu na propriedade da União, nos moldes do art. 20, VII, da Constituição da República, sobre os terrenos de marinha e seus acrescidos situados em ilhas costeiras sede de Municípios." },
  { id: "stf-rg-677", tribunal: "STF", tipo: "Repercussão Geral", numero: "677", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do imposto de renda sobre os valores recebidos por servidor público a título de abono de permanência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=677",
    texto: "A questão da exigibilidade de Imposto de Renda da Pessoa Física - IRPF sobre valores recebidos por servidor público a título de abono de permanência tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-678", tribunal: "STF", tipo: "Repercussão Geral", numero: "678", situacao: "Vigente", tema: "DIREITO ELEITORAL E PROCESSO ELEITORAL", titulo: "Incidência da inelegibilidade prevista no art. 14, § 7º, da Constituição federal e na Súmula Vinculante 18, nos casos em que a dissolução da sociedade conjugal ocorre em razão da morte, durante o curso do mandato, do cônjuge anteriormente eleito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=678",
    texto: "A Súmula Vinculante 18 do STF (“A dissolução da sociedade ou do vínculo conjugal, no curso do mandato, não afasta a inelegibilidade prevista no § 7º do artigo 14 da Constituição Federal”) não se aplica aos casos de extinção do vínculo conjugal pela morte de um dos cônjuges." },
  { id: "stf-rg-679", tribunal: "STF", tipo: "Repercussão Geral", numero: "679", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Validade da exigência do depósito recursal como pressuposto de admissibilidade do recurso extraordinário na Justiça do Trabalho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=679",
    texto: "Surge incompatível com a Constituição Federal exigência de depósito prévio como condição de admissibilidade do recurso extraordinário, no que não recepcionada a previsão constante do § 1º do artigo 899 da Consolidação das Leis do Trabalho, sendo inconstitucional a contida na cabeça do artigo 40 da Lei nº 8.177 e, por arrastamento, no inciso II da Instrução Normativa nº 3/1993 do Tribunal Superior do Trabalho." },
  { id: "stf-rg-680", tribunal: "STF", tipo: "Repercussão Geral", numero: "680", situacao: "Vigente", tema: "DIREITO ELEITORAL E PROCESSO ELEITORAL", titulo: "Legitimidade do Ministério Público Eleitoral para recorrer de decisão que defere registro de candidatura, ainda que não haja apresentado impugnação ao pedido inicial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=680",
    texto: "A partir das eleições de 2014, inclusive, o Ministério Público Eleitoral tem legitimidade para recorrer da decisão que julga o pedido de registro de candidatura, ainda que não tenha apresentado impugnação." },
  { id: "stf-rg-681", tribunal: "STF", tipo: "Repercussão Geral", numero: "681", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Utilização do salário mínimo como indexador para fins de correção monetária no período anterior ao advento da Lei 4.357/1964.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=681",
    texto: "A questão relativa à utilização do salário mínimo como parâmetro para a correção monetária do período anterior à edição da Lei 4.357/1964 não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-682", tribunal: "STF", tipo: "Repercussão Geral", numero: "682", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Reserva de iniciativa de leis que impliquem redução ou extinção de tributos ao Chefe do Poder Executivo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=682",
    texto: "Inexiste, na Constituição Federal de 1988, reserva de iniciativa para leis de natureza tributária, inclusive para as que concedem renúncia fiscal." },
  { id: "stf-rg-685", tribunal: "STF", tipo: "Repercussão Geral", numero: "685", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Extensão da imunidade tributária recíproca ao IPVA de veículos adquiridos por município no regime da alienação fiduciária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=685",
    texto: "Não incide IPVA sobre veículo automotor adquirido, mediante alienação fiduciária, por pessoa jurídica de direito público." },
  { id: "stf-rg-686", tribunal: "STF", tipo: "Repercussão Geral", numero: "686", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Emenda parlamentar que implica aumento de despesa em projeto de iniciativa privativa do chefe do Poder Executivo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=686",
    texto: "I - Há reserva de iniciativa do Chefe do Poder Executivo para edição de normas que alterem o padrão remuneratório dos servidores públicos (art. 61, § 1º, II, a, da CF); II - São formalmente inconstitucionais emendas parlamentares que impliquem aumento de despesa em projeto de lei de iniciativa reservada do Chefe do Poder Executivo (art. 63, I, da CF)." },
  { id: "stf-rg-687", tribunal: "STF", tipo: "Repercussão Geral", numero: "687", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Promoção de policiais militares ao grau hierarquicamente superior quando transferidos para a reserva remunerada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=687",
    texto: "A questão da possibilidade de os militares fazerem jus aos proventos da classe hierarquicamente superior na carreira ao se transferirem para a inatividade tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-688", tribunal: "STF", tipo: "Repercussão Geral", numero: "688", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do Imposto Sobre Serviços de Qualquer Natureza – ISSQN sobre serviços de registro público, cartorários e notariais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=688",
    texto: "É constitucional a incidência do ISS sobre a prestação de serviços de registros públicos, cartorários e notariais, devidamente previstos em legislação tributária municipal." },
  { id: "stf-rg-689", tribunal: "STF", tipo: "Repercussão Geral", numero: "689", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Possibilidade de o estado de origem cobrar ICMS sobre a operação interestadual de fornecimento de energia elétrica a consumidor final, para emprego em processo de industrialização.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=689",
    texto: "Segundo o artigo 155, § 2º, X, b, da CF/1988, cabe ao Estado de destino, em sua totalidade, o ICMS sobre a operação interestadual de fornecimento de energia elétrica a consumidor final, para emprego em processo de industrialização, não podendo o Estado de origem cobrar o referido imposto." },
  { id: "stf-rg-691", tribunal: "STF", tipo: "Repercussão Geral", numero: "691", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Submissão dos entes federativos ao pagamento de contribuição previdenciária patronal incidente sobre a remuneração dos agentes políticos não vinculados a regime próprio de previdência social, após o advento da Lei 10.887/2004.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=691",
    texto: "Incide contribuição previdenciária sobre os rendimentos pagos aos exercentes de mandato eletivo, decorrentes da prestação de serviços à União, a estados e ao Distrito Federal ou a municípios, após o advento da Lei nº 10.887/2004, desde que não vinculados a regime próprio de previdência" },
  { id: "stf-rg-692", tribunal: "STF", tipo: "Repercussão Geral", numero: "692", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Possibilidade de o Conselho Federal de Engenharia, Arquitetura e Agronomia (CONFEA) fixar por resolução os valores das taxas pela expedição de Anotação de Responsabilidade Técnica (ART).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=692",
    texto: "A Anotação de Responsabilidade Técnica, instituída pela Lei 6.496/1977, cobrada pelos Conselhos Regionais de Engenharia, Arquitetura e Agronomia, tem natureza jurídica de taxa, sendo, portanto, necessária a observância do princípio da legalidade tributária previsto no art. 150, I, da Constituição Federal." },
  { id: "stf-rg-693", tribunal: "STF", tipo: "Repercussão Geral", numero: "693", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do IPTU sobre lotes vagos de propriedade de instituições de educação e de assistência social sem fins lucrativos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=693",
    texto: "A imunidade tributária prevista no art. 150, VI, c, da CF/88 aplica-se aos bens imóveis, temporariamente ociosos, de propriedade das instituições de educação e de assistência social sem fins lucrativos que atendam os requisitos legais." },
  { id: "stf-rg-695", tribunal: "STF", tipo: "Repercussão Geral", numero: "695", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Inclusão do décimo terceiro salário no cálculo do salário de benefício para apuração da Renda Mensal Inicial (RMI).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=695",
    texto: "A questão relativa à inclusão, ou não, da gratificação natalina (décimo terceiro salário) no cálculo do salário de benefício para apuração da Renda Mensal Inicial (RMI) tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-696", tribunal: "STF", tipo: "Repercussão Geral", numero: "696", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Validade da destinação de recursos advindos da contribuição para o custeio do serviço de iluminação pública também ao melhoramento e à expansão da rede.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=696",
    texto: "É constitucional a aplicação dos recursos arrecadados por meio de contribuição para o custeio da iluminação pública na expansão e aprimoramento da rede." },
  { id: "stf-rg-700", tribunal: "STF", tipo: "Repercussão Geral", numero: "700", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Constitucionalidade da incidência do Imposto sobre Serviços de Qualquer Natureza (ISSQN) sobre a atividade de exploração de jogos e apostas — tais como a venda de bilhetes, de pules ou de cupons de apostas — e a validade da base de cálculo utilizada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=700",
    texto: "É constitucional a incidência de ISS sobre serviços de distribuição e venda de bilhetes e demais produtos de loteria, bingos, cartões, pules ou cupons de apostas, sorteios e prêmios (item 19 da Lista de Serviços Anexa à Lei Complementar 116/2003). Nesta situação, a base de cálculo do ISS é o valor a ser remunerado pela prestação do serviço, independentemente da cobrança de ingresso, não podendo corresponder ao valor total da aposta." },
  { id: "stf-rg-701", tribunal: "STF", tipo: "Repercussão Geral", numero: "701", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de extensão, aos trabalhadores rurais, do seguro-desemprego concedido aos pescadores artesanais pela Lei federal 10.779/2003 (seguro-defeso).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=701",
    texto: "A questão do direito dos trabalhadores rurais ao pagamento do benefício previdenciário denominado “Seguro-Desemprego Defeso”, pago aos pescadores artesanais no período de proibição da atividade pesqueira, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-702", tribunal: "STF", tipo: "Repercussão Geral", numero: "702", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência do adicional por tempo de serviço (quinquênio) sobre a integralidade dos vencimentos de servidor público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=702",
    texto: "A questão de a base de cálculo da vantagem pecuniária denominada “Quinquênios” ser a integralidade dos vencimentos de servidor público estadual tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-706", tribunal: "STF", tipo: "Repercussão Geral", numero: "706", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de concessão da Gratificação de Atividade de Ensino Especial (GAEE), prevista na Lei distrital 4.075/2007, aos professores da rede pública que lecionam disciplinas para turmas mistas, que incluem um ou alguns alunos portadores de necessidades educativas especiais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=706",
    texto: "A questão do direito ao recebimento da vantagem pecuniária denominada “Gratificação de Atividade de Ensino Especial – GAEE” pelos professores do Distrito Federal, que lecionam para turmas com um ou mais alunos portadores de necessidades especiais, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-707", tribunal: "STF", tipo: "Repercussão Geral", numero: "707", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Validade da restrição do direito a créditos da contribuição ao PIS apenas quanto aos bens, serviços, custos e despesas relacionados a negócios jurídicos contratados com pessoas jurídicas domiciliadas no Brasil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=707",
    texto: "Revela-se constitucional o artigo 3º, § 3º, incisos I e II, da Lei nº 10.637/2003, no que veda o creditamento da contribuição para o Programa de Integração Social, no regime não cumulativo, em relação às operações com pessoas jurídicas domiciliadas no exterior." },
  { id: "stf-rg-709", tribunal: "STF", tipo: "Repercussão Geral", numero: "709", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Possibilidade de percepção do benefício da aposentadoria especial na hipótese em que o segurado permanece no exercício de atividades laborais nocivas à saúde.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=709",
    texto: "I) É constitucional a vedação de continuidade da percepção de aposentadoria especial se o beneficiário permanece laborando em atividade especial ou a ela retorna, seja essa atividade especial aquela que ensejou a aposentação precoce ou não. II) Nas hipóteses em que o segurado solicitar a aposentadoria e continuar a exercer o labor especial, a data de início do benefício será a data de entrada do requerimento, remontando a esse marco, inclusive, os efeitos financeiros. Efetivada, contudo, seja na via administrativa, seja na judicial a implantação do benefício, uma vez verificado o retorno ao labor nocivo ou sua continuidade, cessará o benefício previdenciário em questão." },
  { id: "stf-rg-710", tribunal: "STF", tipo: "Repercussão Geral", numero: "710", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de o Poder Judiciário determinar o cumprimento de lei complementar estadual que, sem prévia dotação orçamentária, concedeu reajuste salarial a servidores públicos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=710",
    texto: "A questão do direito ao reajuste de vencimentos dos servidores públicos do Rio Grande do Norte, concedido com base em Lei Complementar Estadual, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-711", tribunal: "STF", tipo: "Repercussão Geral", numero: "711", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de percepção, por servidor público de universidade estadual, da denominada Vantagem Promoção (VPRO), referente a período retroativo no qual a regulamentação da gratificação permaneceu suspensa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=711",
    texto: "A questão do pagamento retroativo da Vantagem Promocional (VPRO) aos servidores estaduais autárquicos da Universidade Estadual Paulista Júlio Mesquita Filho - UNESP tem natureza infraconstitucional e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-712", tribunal: "STF", tipo: "Repercussão Geral", numero: "712", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Possibilidade, em caso de condenação pelo delito de tráfico de drogas, de valoração da quantidade e da natureza da droga apreendida, tanto para a fixação da pena-base quanto para a modulação da causa de diminuição prevista no art. 33, § 4º, da Lei 11.343/2006.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=712",
    texto: "As circunstâncias da natureza e da quantidade da droga apreendida devem ser levadas em consideração apenas em uma das fases do cálculo da pena." },
  { id: "stf-rg-713", tribunal: "STF", tipo: "Repercussão Geral", numero: "713", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Necessidade de representação da ofendida, como condição de procedibilidade da ação penal, em caso de crime de lesão corporal praticado contra a mulher no âmbito doméstico e familiar.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=713",
    texto: "Os crimes de lesão corporal praticados contra a mulher no âmbito doméstico e familiar são de ação penal pública incondicionada." },
  { id: "stf-rg-714", tribunal: "STF", tipo: "Repercussão Geral", numero: "714", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Concessão de isenção do Imposto sobre a Circulação de Mercadorias e Serviços (ICMS) na aquisição de veículos automotores por portadores de deficiência física não elencada na legislação estadual correlata.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=714",
    texto: "A questão da isenção do Imposto sobre a Circulação de Mercadorias e Serviços - ICMS, na aquisição de veículo automotor por pessoa com deficiência física, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-715", tribunal: "STF", tipo: "Repercussão Geral", numero: "715", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Limites territoriais da eficácia de decisão prolatada em ação coletiva.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=715",
    texto: "A questão da limitação territorial da eficácia da decisão proferida em ação coletiva tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-716", tribunal: "STF", tipo: "Repercussão Geral", numero: "716", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de limitação à liberdade de expressão artística e de imprensa, no tocante às publicações destinadas ao público adulto, em face do princípio do sentimento religioso.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=716",
    texto: "A questão constitucional da harmonia entre os princípios da liberdade de imprensa, expressão artística e o sentimento religioso pela publicação, em revista voltada para o público adulto, de ensaio fotográfico em que modelo posou portando símbolo cristão não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda ao interesse das partes." },
  { id: "stf-rg-717", tribunal: "STF", tipo: "Repercussão Geral", numero: "717", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de regularização da situação funcional de servidor da Polícia Federal nomeado por força de decisão judicial e após aprovação em curso de formação, independentemente do resultado final da ação judicial que lhe garantiu continuidade no certame público, tendo em vista a existência de decisão administrativa que assegurou a nomeação e a posse de outros candidatos em situação similar.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=717",
    texto: "A questão da confirmação da nomeação e posse de candidatos sub judice no cargo de Delegado da Polícia Federal que, por força de despacho do Ministro de Estado da Justiça, datado de 9/7/2002, tiveram a situação administrativa regularizada por ato do Diretor-Geral do Departamento de Polícia Federal, desde que concluíssem com êxito o curso de formação profissional da Academia Nacional de Polícia, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-718", tribunal: "STF", tipo: "Repercussão Geral", numero: "718", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Controvérsia acerca da natureza jurídica de reajuste concedido a servidores públicos, se revisão geral anual ou reestruturação da carreira, para fins de repercussão sobre as vantagens pessoais nominalmente identificadas – VPNI.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=718",
    texto: "A questão do direito ao reajuste de 15,8% (quinze inteiros e oito décimos por cento) sobre vantagem pessoal nominalmente identificada - VPNI, paga a servidor público do Poder Judiciário, considerada a natureza jurídica de revisão geral anual, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-719", tribunal: "STF", tipo: "Repercussão Geral", numero: "719", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Viabilidade de recurso extraordinário contra acórdão que nega o caráter de revisão geral anual à vantagem pecuniária individual concedida a servidores públicos federais pela Lei n. 10.698/2003. Obs.: Título aperfeiçoado pelo Relator quando da publicação da tese, em 10/04/2018 (conforme Processo STF/SEI 010927/2017). Redação original: Possibilidade de se emprestar o caráter de revisão geral anual à vantagem pecuniária individual concedida a servidores públicos federais pela Lei 10.698/2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=719",
    texto: "Restringe-se ao âmbito infraconstitucional e, portanto, não deve ser conhecido, o recurso extraordinário contra acórdão que nega o caráter de revisão geral anual à vantagem pecuniária individual concedida a servidores públicos federais pela Lei 10.698/2003, e a ele se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-720", tribunal: "STF", tipo: "Repercussão Geral", numero: "720", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do imposto de renda sobre os valores recebidos por servidor público a título de horas de sobreaviso.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=720",
    texto: "A questão da exigibilidade do Imposto de Renda de Pessoa Física - IRPF, sobre os valores recebidos por servidor público a título de horas de sobreaviso, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-721", tribunal: "STF", tipo: "Repercussão Geral", numero: "721", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Constitucionalidade de taxa cobrada em razão da expedição de guias de recolhimento de tributos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=721",
    texto: "São inconstitucionais a instituição e a cobrança de taxas por emissão ou remessa de carnês/guias de recolhimento de tributos." },
  { id: "stf-rg-722", tribunal: "STF", tipo: "Repercussão Geral", numero: "722", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para julgar mandado de segurança impetrado contra ato de dirigente de sociedade de economia mista federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=722",
    texto: "Compete à justiça federal comum processar e julgar mandado de segurança quando a autoridade apontada como coatora for autoridade federal, considerando-se como tal também os dirigentes de pessoa jurídica de direito privado investidos de delegação concedida pela União." },
  { id: "stf-rg-723", tribunal: "STF", tipo: "Repercussão Geral", numero: "723", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Validade da contribuição a ser recolhida pelo produtor rural pessoa física que desempenha suas atividades em regime de economia familiar, sem empregados permanentes, sobre a receita bruta proveniente da comercialização de sua produção.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=723",
    texto: "É constitucional, formal e materialmente, a contribuição social do segurado especial prevista no art. 25 da Lei 8.212/1991." },
  { id: "stf-rg-724", tribunal: "STF", tipo: "Repercussão Geral", numero: "724", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Promoção ao oficialato dos militares anistiados que integraram os quadros de praças.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=724",
    texto: "As promoções dos anistiados se restringem ao quadro a que pertencia o militar na ativa." },
  { id: "stf-rg-725", tribunal: "STF", tipo: "Repercussão Geral", numero: "725", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Terceirização de serviços para a consecução da atividade-fim da empresa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=725",
    texto: "É lícita a terceirização ou qualquer outra forma de divisão do trabalho entre pessoas jurídicas distintas, independentemente do objeto social das empresas envolvidas, mantida a responsabilidade subsidiária da empresa contratante." },
  { id: "stf-rg-726", tribunal: "STF", tipo: "Repercussão Geral", numero: "726", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Montante da complementação de pensão devida aos pensionistas de ex-ferroviários da extinta Rede Ferroviária Federal – RFFSA.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=726",
    texto: "A questão do direito ao recebimento da complementação de pensão devida aos pensionistas de ex-ferroviários da extinta Rede Ferroviária Federal S.A. - RFFSA, nos termos da Lei 8.186/1991, que determina a paridade de valores relativos à aposentadoria com o vencimento da ativa, tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-727", tribunal: "STF", tipo: "Repercussão Geral", numero: "727", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Definição da legitimidade passiva ad causam e, portanto, da competência para julgar o mandado de injunção impetrado por servidores públicos municipais, estaduais e distritais em que se pretende a declaração de mora legislativa para edição da lei complementar relativa à disciplina da aposentadoria especial de servidor público, a que alude o § 4º do art. 40 da Constituição federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=727",
    texto: "Compete ao Supremo Tribunal Federal julgar mandado de injunção referente à omissão quanto à edição da lei complementar prevista no art. 40, § 4º, da Constituição de 1988." },
  { id: "stf-rg-728", tribunal: "STF", tipo: "Repercussão Geral", numero: "728", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Constitucionalidade dos índices de correção monetária aplicados para reajustar os benefícios previdenciários nos anos de 1999, 2000, 2001, 2002 e 2003.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=728",
    texto: "São constitucionais os índices de correção monetária adotados pelo INSS para reajustar os benefícios previdenciários nos anos de 1997, 1999, 2000, 2001, 2002 e 2003." },
  { id: "stf-rg-729", tribunal: "STF", tipo: "Repercussão Geral", numero: "729", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incidência do imposto de renda sobre os valores recebidos a título de Gratificação de Atividade de Combate e Controle de Endemias (GACEN).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=729",
    texto: "A questão da exigibilidade do Imposto de Renda de Pessoa Física - IRPF sobre os valores recebidos a título de Gratificação de Atividade de Combate e Controle de Endemias - GACEN tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-730", tribunal: "STF", tipo: "Repercussão Geral", numero: "730", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Base de cálculo de vantagem devida a servidores públicos em razão da prestação de serviços em regime de plantão e de sobreaviso.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=730",
    texto: "A questão da composição da base de cálculo de vantagem pecuniária paga a servidores públicos pela prestação de serviços em regime de plantão e de sobreaviso tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-731", tribunal: "STF", tipo: "Repercussão Geral", numero: "731", situacao: "Vigente", tema: "DIREITO ELEITORAL E PROCESSO ELEITORAL", titulo: "Possibilidade de obtenção de quitação eleitoral mediante mera apresentação das contas de campanha, ainda que não aprovadas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=731",
    texto: "A questão do preenchimento dos requisitos necessários para obtenção de certidão de quitação eleitoral pela mera apresentação das contas de campanha, ainda que rejeitadas, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-732", tribunal: "STF", tipo: "Repercussão Geral", numero: "732", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Constitucionalidade de dispositivo legal que prevê sanção disciplinar de suspensão do exercício profissional em razão do inadimplemento de anuidades devidas à entidade de classe.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=732",
    texto: "É inconstitucional a suspensão realizada por conselho de fiscalização profissional do exercício laboral de seus inscritos por inadimplência de anuidades, pois a medida consiste em sanção política em matéria tributária." },
  { id: "stf-rg-733", tribunal: "STF", tipo: "Repercussão Geral", numero: "733", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Eficácia temporal de sentença transitada em julgado fundada em norma supervenientemente declarada inconstitucional pelo Supremo Tribunal Federal em sede de controle concentrado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=733",
    texto: "A decisão do Supremo Tribunal Federal declarando a constitucionalidade ou a inconstitucionalidade de preceito normativo não produz a automática reforma ou rescisão das decisões anteriores que tenham adotado entendimento diferente. Para que tal ocorra, será indispensável a interposição de recurso próprio ou, se for o caso, a propositura de ação rescisória própria, nos termos do art. 485 do CPC, observado o respectivo prazo decadencial (CPC, art. 495)." },
  { id: "stf-rg-734", tribunal: "STF", tipo: "Repercussão Geral", numero: "734", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Retroatividade de lei posterior mais benéfica quanto à sanção de natureza administrativa aplicada em decorrência da prática de infração de trânsito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=734",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à aplicação retroativa de lei mais benéfica referente à sanção de natureza administrativa decorrente do cometimento de infração de trânsito." },
  { id: "stf-rg-735", tribunal: "STF", tipo: "Repercussão Geral", numero: "735", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito à nomeação de candidato aprovado em concurso público em face de posteriores contratações temporárias, nas hipóteses em que não fica comprovada a preterição.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=735",
    texto: "A questão do direito à nomeação de candidato aprovado em concurso público em face de posteriores contratações temporárias, quando não comprovada a preterição, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-737", tribunal: "STF", tipo: "Repercussão Geral", numero: "737", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de vinculação de pensões e de proventos de aposentadoria de servidores públicos efetivos com subsídios de agentes políticos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=737",
    texto: "É inconstitucional norma que vincula pensões e proventos de aposentadoria de servidores públicos efetivos a subsídios de agentes políticos." },
  { id: "stf-rg-738", tribunal: "STF", tipo: "Repercussão Geral", numero: "738", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Necessidade de registro na Ordem dos Músicos do Brasil – OMB e do pagamento de anuidades à referida autarquia para o exercício da profissão de músico.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=738",
    texto: "É incompatível com a Constituição a exigência de inscrição na Ordem dos Músicos do Brasil, bem como de pagamento de anuidade, para o exercício da profissão." },
  { id: "stf-rg-739", tribunal: "STF", tipo: "Repercussão Geral", numero: "739", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Possibilidade de recusa de aplicação do art. 94, II, da Lei 9.472/1997 em razão da invocação da Súmula 331 do Tribunal Superior do Trabalho, sem observância da regra de reserva de plenário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=739",
    texto: "É nula a decisão de órgão fracionário que se recusa a aplicar o art. 94, II, da Lei 9.472/1997, sem observar a cláusula de reserva de Plenário (CF, art. 97), observado o art. 949 do Código de Processo Civil." },
  { id: "stf-rg-740", tribunal: "STF", tipo: "Repercussão Geral", numero: "740", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar causas relativas a prestações por parte da Assistência Multidisciplinar de Saúde – AMS, oferecida pela Petrobras a seus empregados e respectivos dependentes.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=740",
    texto: "A questão da definição da Justiça competente para processar e julgar ações relativas à cobertura de saúde oferecida pela Petróleo Brasileiro S/A – Petrobras a seus empregados e respectivos dependentes, por intermédio da Assistência Multidisciplinar de Saúde – AMS, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-741", tribunal: "STF", tipo: "Repercussão Geral", numero: "741", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Validade da exigência do INSS de prévio agendamento para o atendimento de advogados e da restrição a um único requerimento de benefício previdenciário por atendimento.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=741",
    texto: "A questão da validade da exigência do prévio agendamento para o atendimento de advogados e da restrição a um único requerimento de benefício previdenciário por atendimento feita pelo Instituto Nacional do Seguro Social - INSS tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-742", tribunal: "STF", tipo: "Repercussão Geral", numero: "742", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Estipulação legal de valor mínimo para a propositura de execuções fiscais referentes a contribuições devidas aos conselhos profissionais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=742",
    texto: "A questão da aplicação imediata do art. 8º da Lei federal n. 12.514/2011, que vedou aos conselhos profissionais a cobrança judicial de dívidas, referentes a anuidades, inferiores a quatro vezes o valor cobrado anualmente da pessoa física ou jurídica inadimplente, atraindo a extinção da execução fiscal em curso, por carência de ação, em função do valor irrisório do débito executado, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-743", tribunal: "STF", tipo: "Repercussão Geral", numero: "743", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Possibilidade de município cuja Câmara Municipal está em débito com a Fazenda Nacional obter certidão positiva de débito com efeito de negativa – CPDEN.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=743",
    texto: "É possível ao Município obter certidão positiva de débitos com efeito de negativa quando a Câmara Municipal do mesmo ente possui débitos com a Fazenda Nacional, tendo em conta o princípio da intranscendência subjetiva das sanções financeiras." },
  { id: "stf-rg-746", tribunal: "STF", tipo: "Repercussão Geral", numero: "746", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Equiparação do valor do auxílio-alimentação pago aos servidores públicos da Justiça Federal de Santa Catarina ao valor percebido por outros servidores públicos federais, tomados como paradigma.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=746",
    texto: "A questão sobre o direito ao recebimento do auxílio-alimentação pelos servidores públicos da Justiça Federal de Santa Catarina nos mesmos valores pagos para outros servidores públicos federais, tomados como paradigma, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-747", tribunal: "STF", tipo: "Repercussão Geral", numero: "747", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Cabimento de reclamação para o Superior Tribunal de Justiça por alegada usurpação de sua competência por Tribunal de Justiça estadual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=747",
    texto: "A questão sobre o cabimento de reclamação ao Superior Tribunal de Justiça por alegada usurpação de sua competência pelo Tribunal de Justiça que examina liminar em mandado de segurança impetrado contra acórdão proferido por Conselho da Magistratura, em processo de dúvida registral, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-748", tribunal: "STF", tipo: "Repercussão Geral", numero: "748", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Constitucionalidade do art. 31 da Lei 8.880/1994, que previu indenização adicional equivalente a cinquenta por cento da última remuneração recebida pelo empregado no caso de demissão sem justa causa durante o período de vigência da URV.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=748",
    texto: "É constitucional o art. 31 da Lei 8.880/1994, que prevê indenização adicional equivalente a 50% da última remuneração recebida na hipótese de demissão imotivada de empregado durante a vigência da Unidade Real de Valor (URV)." },
  { id: "stf-rg-749", tribunal: "STF", tipo: "Repercussão Geral", numero: "749", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de aplicação de índices negativos para fins de correção monetária do valor devido a título de verba salarial.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=749",
    texto: "A questão do critério de atualização que considera, no cálculo da correção monetária de débito judicial, a aplicação de índices negativos (deflação) tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-750", tribunal: "STF", tipo: "Repercussão Geral", numero: "750", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incorporação do Adicional de Local de Exercício – ALE aos vencimentos dos policiais militares do Estado de São Paulo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=750",
    texto: "A questão do direito à incorporação da vantagem pecuniária denominada “Adicional de Local de Exercício – ALE” ao vencimento dos policiais militares de São Paulo tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-751", tribunal: "STF", tipo: "Repercussão Geral", numero: "751", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de cálculo proporcional do valor da Gratificação de Desempenho de Atividade de Seguridade Social e do Trabalho – GDASST nos casos de aposentadoria proporcional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=751",
    texto: "A questão da forma de cálculo da Gratificação de Desempenho de Atividade de Seguridade Social e do Trabalho – GDASST, paga aos servidores inativos, nos casos de aposentadoria proporcional, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-752", tribunal: "STF", tipo: "Repercussão Geral", numero: "752", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade do consumidor final para propor ação de repetição de indébito tributário relativo a valores do ICMS incidente sobre a demanda contratada de energia elétrica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=752",
    texto: "A questão da legitimidade do consumidor final (contribuinte de fato) para ajuizar ação de repetição de indébito tributário relativo a valores do Imposto sobre Circulação de Mercadorias e Prestação de Serviços - ICMS incidente sobre a demanda contratada de energia elétrica tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-753", tribunal: "STF", tipo: "Repercussão Geral", numero: "753", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incorporação do valor integral da Gratificação de Atividade Policial – GAP ao salário-base dos policiais militares do Estado de São Paulo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=753",
    texto: "A questão do direito à incorporação do valor integral da vantagem pecuniária denominada “Gratificação de Atividade Policial – GAP” ao salário-base dos policiais militares do Estado de São Paulo tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-754", tribunal: "STF", tipo: "Repercussão Geral", numero: "754", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Eficácia temporal do art. 6º-A da Emenda Constitucional 41/2003, incluído pela Emenda Constitucional 70/2012, que reestabeleceu a integralidade e a paridade de proventos para os servidores públicos aposentados por invalidez permanente decorrente de doença grave.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=754",
    texto: "Os efeitos financeiros das revisões de aposentadoria concedidas com base no art. 6º-A da Emenda Constitucional nº 41/2003, introduzido pela Emenda Constitucional nº 70/2012, somente se produzirão a partir da data de sua promulgação (30.3.2012)." },
  { id: "stf-rg-755", tribunal: "STF", tipo: "Repercussão Geral", numero: "755", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de fracionamento da execução pecuniária contra a Fazenda Pública para que parte do valor devido seja pago antes do trânsito em julgado, mediante complemento positivo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=755",
    texto: "É vedado o fracionamento da execução pecuniária contra a Fazenda Pública para que uma parte seja paga antes do trânsito em julgado, por meio de Complemento Positivo, e outra depois do trânsito, mediante Precatório ou Requisição de Pequeno Valor." },
  { id: "stf-rg-757", tribunal: "STF", tipo: "Repercussão Geral", numero: "757", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de cancelamento automático da inscrição em conselho profissional em decorrência de inadimplência da anuidade, sem prévio processo administrativo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=757",
    texto: "É inconstitucional o artigo 64 da Lei nº 5.194/1966, considerada a previsão de cancelamento automático, ante a inadimplência da anuidade por dois anos consecutivos, do registro em conselho profissional, sem prévia manifestação do profissional ou da pessoa jurídica, por violar o devido processo legal." },
  { id: "stf-rg-759", tribunal: "STF", tipo: "Repercussão Geral", numero: "759", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de contribuição previdenciária sobre a verba recebida por empregado a título de aviso prévio indenizado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=759",
    texto: "A questão da exigibilidade de contribuição previdenciária sobre a parcela do aviso prévio indenizado, recebida pelo empregado, no caso de desligamento imediato do trabalho, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-760", tribunal: "STF", tipo: "Repercussão Geral", numero: "760", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência da Justiça Federal comum para processar e julgar causas em que se discute o direito de servidores estatutários do extinto Departamento de Correios e Telégrafos optantes pelo regime celetista à percepção de quinquênios completados anteriormente à opção.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=760",
    texto: "A questão sobre a competência da Justiça Federal para processar e julgar causas em que se discute o direito de servidores estatutários do extinto Departamento de Correios e Telégrafos optantes pelo regime celetista, que requerem o pagamento de quinquênios completados anteriormente à opção, não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-761", tribunal: "STF", tipo: "Repercussão Geral", numero: "761", situacao: "Vigente", tema: "REGISTROS PÚBLICOS", titulo: "Possibilidade de alteração de gênero no assento de registro civil de transexual, mesmo sem a realização de procedimento cirúrgico de redesignação de sexo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=761",
    texto: "I) O transgênero tem direito fundamental subjetivo à alteração de seu prenome e de sua classificação de gênero no registro civil, não se exigindo, para tanto, nada além da manifestação de vontade do indivíduo, o qual poderá exercer tal faculdade tanto pela via judicial como diretamente pela via administrativa; II) Essa alteração deve ser averbada à margem do assento de nascimento, vedada a inclusão do termo 'transgênero'; III) Nas certidões do registro não constará nenhuma observação sobre a origem do ato, vedada a expedição de certidão de inteiro teor, salvo a requerimento do próprio interessado ou por determinação judicial; IV) Efetuando-se o procedimento pela via judicial, caberá ao magistrado determinar de ofício ou a requerimento do interessado a expedição de mandados específicos para a alteração dos demais registros nos órgãos públicos ou privados pertinentes, os quais deverão preservar o sigilo sobre a origem dos atos." },
  { id: "stf-rg-762", tribunal: "STF", tipo: "Repercussão Geral", numero: "762", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Validade de norma coletiva de trabalho que fixa limite ao pagamento de horas in itinere inferior à metade do que seria devido em relação ao tempo efetivamente gasto pelo trabalhador no trajeto até o local do serviço.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=762",
    texto: "A questão da validade de norma coletiva de trabalho que fixa limite de horas in itinere inferior à metade do tempo efetivamente gasto pelo trabalhador no seu trajeto até o local do serviço tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-763", tribunal: "STF", tipo: "Repercussão Geral", numero: "763", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de aplicação da aposentadoria compulsória ao servidor público ocupante exclusivamente de cargo em comissão, assim como a possibilidade de o servidor efetivo aposentado compulsoriamente vir a assumir cargos ou funções comissionadas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=763",
    texto: "1. Os servidores ocupantes de cargo exclusivamente em comissão não se submetem à regra da aposentadoria compulsória prevista no art. 40, § 1º, II, da Constituição Federal, a qual atinge apenas os ocupantes de cargo de provimento efetivo, inexistindo, também, qualquer idade limite para fins de nomeação a cargo em comissão; 2. Ressalvados impedimentos de ordem infraconstitucional, não há óbice constitucional a que o servidor efetivo aposentado compulsoriamente permaneça no cargo comissionado que já desempenhava ou a que seja nomeado para cargo de livre nomeação e exoneração, uma vez que não se trata de continuidade ou criação de vínculo efetivo com a Administração." },
  { id: "stf-rg-764", tribunal: "STF", tipo: "Repercussão Geral", numero: "764", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de servidores que passaram a integrar quadro especial em extinção receberem reajustes remuneratórios de acordo a Lei estadual 13.444/2010.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=764",
    texto: "Não tem repercussão geral a controvérsia sobre o direito de servidores públicos do extinto Departamento de Pesquisa e de Pesca do Rio Grande do Sul ao reajuste concedido pela Lei nº 13.444/2010." },
  { id: "stf-rg-765", tribunal: "STF", tipo: "Repercussão Geral", numero: "765", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Absorção da parcela remuneratória denominada Vencimento Básico Complementar – VBC, prevista na Lei 11.091/2005, que estruturou o Plano de Carreira dos Cargos Técnico-Administrativos da Educação – PCCTAE.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=765",
    texto: "A questão da absorção da parcela remuneratória complementar denominada “Vencimento Básico Complementar – VBC”, prevista na Lei n. 11.091/2005, que estruturou a Carreira dos servidores técnico-administrativos da Educação, no âmbito das Instituições Federais de Ensino vinculadas ao Ministério da Educação (PCCTAE), tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-766", tribunal: "STF", tipo: "Repercussão Geral", numero: "766", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Verificação dos requisitos legais necessários para concessão de benefício previdenciário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=766",
    texto: "Não tem repercussão geral a controvérsia relativa ao preenchimento de requisitos para a concessão do benefício previdenciário do auxílio-doença." },
  { id: "stf-rg-767", tribunal: "STF", tipo: "Repercussão Geral", numero: "767", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão do adicional noturno a professores públicos estaduais, na forma em que foi previsto no estatuto dos servidores públicos civis do estado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=767",
    texto: "Não tem repercussão geral a controvérsia sobre a aplicação de Estatuto dos Servidores Públicos Civis do Estado para o pagamento de vantagem pecuniária denominada “Adicional Noturno” ao magistério público estadual." },
  { id: "stf-rg-768", tribunal: "STF", tipo: "Repercussão Geral", numero: "768", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de execução das decisões de condenação patrimonial proferidas pelos Tribunais de Contas por iniciativa do Ministério Público, atuante ou não junto às Cortes de Contas, seja federal, seja estadual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=768",
    texto: "Somente o ente público beneficiário possui legitimidade ativa para a propositura de ação executiva decorrente de condenação patrimonial imposta por Tribunais de Contas (CF, art. 71, § 3º)." },
  { id: "stf-rg-769", tribunal: "STF", tipo: "Repercussão Geral", numero: "769", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Restituição de valores referentes à parcela denominada comissão de corretagem cobrada de consumidor que adquire imóvel diretamente de construtora ou de incorporadora.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=769",
    texto: "A questão da obrigação de devolver valores referentes à parcela denominada comissão de corretagem cobrada de consumidor que adquire imóvel diretamente de construtora ou de incorporadora tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-770", tribunal: "STF", tipo: "Repercussão Geral", numero: "770", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de condenação da Fazenda Pública em honorários advocatícios nas execuções não embargadas, nos casos em que a parte exequente renuncia aos valores excedentes a quarenta salários mínimos, a fim de possibilitar o pagamento por meio de requisição de pequeno valor – RPV.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=770",
    texto: "A questão do cabimento da condenação da Fazenda Pública em honorários advocatícios nas execuções não embargadas, nos casos em que a parte exequente renuncia aos valores excedentes a quarenta salários mínimos, a fim de possibilitar o pagamento por meio de requisição de pequeno valor – RPV, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-771", tribunal: "STF", tipo: "Repercussão Geral", numero: "771", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Constitucionalidade da redução dos valores de indenização do Seguro DPVAT pela Medida Provisória 340/2006, convertida na Lei 11.482/2007.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=771",
    texto: "São constitucionais as alterações procedidas pelo art. 8º da Lei 11.482/2007 no art. 3º da Lei 6.194/1974, que ensejaram a redução dos valores das indenizações pagas a título de seguro obrigatório por danos pessoais causados por veículos automotores de via terrestre (DPVAT)." },
  { id: "stf-rg-772", tribunal: "STF", tipo: "Repercussão Geral", numero: "772", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Possibilidade de conversão de tempo de serviço especial prestado na atividade de magistério em tempo de serviço comum, após a Emenda Constitucional 18/1981.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=772",
    texto: "É vedada a conversão de tempo de serviço especial em comum na função de magistério após a EC 18/1981." },
  { id: "stf-rg-773", tribunal: "STF", tipo: "Repercussão Geral", numero: "773", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de contribuição previdenciária sobre a Gratificação Especial de Localidade – GEL, transformada em Vantagem Pessoal Nominalmente Identificada – VPNI.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=773",
    texto: "A questão da exigibilidade de contribuição previdenciária sobre a Gratificação Especial de Localidade – GEL, transformada em Vantagem Pessoal Nominalmente Identificada – VPNI, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-774", tribunal: "STF", tipo: "Repercussão Geral", numero: "774", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência legislativa, se privativa da União ou concorrente, para adoção de política pública dirigida a compelir concessionária de energia elétrica a promover investimentos, com recursos de parcela da receita operacional auferida, voltados à proteção e à preservação ambiental de mananciais hídricos em que ocorrer a exploração.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=774",
    texto: "A norma estadual que impõe à concessionária de geração de energia elétrica a promoção de investimentos, com recursos identificados como parcela da receita que aufere, voltados à proteção e à preservação de mananciais hídricos é inconstitucional por configurar intervenção indevida do Estado no contrato de concessão da exploração do aproveitamento energético dos cursos de água, atividade de competência da União, conforme art. 21, XII, 'b', da Constituição Federal." },
  { id: "stf-rg-776", tribunal: "STF", tipo: "Repercussão Geral", numero: "776", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Regulamentação do pagamento de adicional noturno para servidor público estadual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=776",
    texto: "A questão da configuração do direito e a regulamentação do pagamento da vantagem pecuniária denominada “Adicional Noturno” aos servidores públicos de Pernambuco tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-777", tribunal: "STF", tipo: "Repercussão Geral", numero: "777", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade civil do Estado em decorrência de danos causados a terceiros por tabeliães e oficiais de registro no exercício de suas funções.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=777",
    texto: "O Estado responde, objetivamente, pelos atos dos tabeliães e registradores oficiais que, no exercício de suas funções, causem dano a terceiros, assentado o dever de regresso contra o responsável, nos casos de dolo ou culpa, sob pena de improbidade administrativa." },
  { id: "stf-rg-779", tribunal: "STF", tipo: "Repercussão Geral", numero: "779", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aplicabilidade do teto constitucional à remuneração de substitutos (interinos) designados para o exercício de função notarial e registral em serventias extrajudiciais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=779",
    texto: "Os substitutos ou interinos designados para o exercício de função delegada não se equiparam aos titulares de serventias extrajudiciais, visto não atenderem aos requisitos estabelecidos nos arts. 37, inciso II, e 236, § 3º, da Constituição Federal para o provimento originário da função, inserindo-se na categoria dos agentes estatais, razão pela qual se aplica a eles o teto remuneratório do art. 37, inciso XI, da Carta da República." },
  { id: "stf-rg-780", tribunal: "STF", tipo: "Repercussão Geral", numero: "780", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade do conhecimento de ofício da incompetência para o julgamento de execução fiscal na hipótese de inobservância do art. 578 do Código de Processo Civil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=780",
    texto: "A questão do conhecimento, de ofício, da incompetência para processar execução fiscal ajuizada em local diverso do foro do domicílio do réu, nos termos do artigo 578, V, do CPC/1973, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-781", tribunal: "STF", tipo: "Repercussão Geral", numero: "781", situacao: "Vigente", tema: "DIREITO ELEITORAL", titulo: "Aplicabilidade do prazo de desincompatibilização de 6 meses previsto no art. 14, § 7º, da Constituição Federal às eleições suplementares.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=781",
    texto: "As hipóteses de inelegibilidade previstas no art. 14, § 7º, da Constituição Federal, inclusive quanto ao prazo de seis meses, são aplicáveis às eleições suplementares." },
  { id: "stf-rg-782", tribunal: "STF", tipo: "Repercussão Geral", numero: "782", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de lei instituir prazos diferenciados de licença-maternidade às servidoras gestantes e às adotantes.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=782",
    texto: "Os prazos da licença adotante não podem ser inferiores aos prazos da licença gestante, o mesmo valendo para as respectivas prorrogações. Em relação à licença adotante, não é possível fixar prazos diversos em função da idade da criança adotada." },
  { id: "stf-rg-783", tribunal: "STF", tipo: "Repercussão Geral", numero: "783", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de arbitramento de honorários advocatícios no curso de execução provisória.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=783",
    texto: "A questão do arbitramento de honorários advocatícios na execução provisória, em benefício do exequente, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-784", tribunal: "STF", tipo: "Repercussão Geral", numero: "784", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito à nomeação de candidatos aprovados fora do número de vagas previstas no edital de concurso público no caso de surgimento de novas vagas durante o prazo de validade do certame.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=784",
    texto: "O surgimento de novas vagas ou a abertura de novo concurso para o mesmo cargo, durante o prazo de validade do certame anterior, não gera automaticamente o direito à nomeação dos candidatos aprovados fora das vagas previstas no edital, ressalvadas as hipóteses de preterição arbitrária e imotivada por parte da administração, caracterizada por comportamento tácito ou expresso do Poder Público capaz de revelar a inequívoca necessidade de nomeação do aprovado durante o período de validade do certame, a ser demonstrada de forma cabal pelo candidato. Assim, o direito subjetivo à nomeação do candidato aprovado em concurso público exsurge nas seguintes hipóteses: I – Quando a aprovação ocorrer dentro do número de vagas dentro do edital; II – Quando houver preterição na nomeação por não observância da ordem de classificação; III – Quando surgirem novas vagas, ou for aberto novo concurso durante a validade do certame anterior, e ocorrer a preterição de candidatos de forma arbitrária e imotivada por parte da administração nos termos acima." },
  { id: "stf-rg-785", tribunal: "STF", tipo: "Repercussão Geral", numero: "785", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de adesão ao Fundo de Garantia de Operações de Crédito Educativo (FGEDUC) após a formalização de contrato de financiamento estudantil com o FIES (Fundo de Financiamento ao Estudante de Ensino Superior).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=785",
    texto: "A questão da possibilidade de adesão ao Fundo de Garantia de Operações de Crédito Educativo (FGEDUC), após a formalização de contrato de financiamento estudantil com o FIES (Fundo de Financiamento ao Estudante de Ensino Superior), quando firmado sem garantia fidejussória, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-787", tribunal: "STF", tipo: "Repercussão Geral", numero: "787", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Validade da aplicação da Taxa Referencial - TR como índice de correção monetária dos depósitos efetuados na conta vinculada ao Fundo de Garantia por Tempo de Serviço - FGTS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=787",
    texto: "Não tem repercussão geral a questão da aplicação da Taxa Referencial - TR como índice de correção monetária dos depósitos efetuados nas contas vinculadas ao Fundo de Garantia por Tempo de Serviço - FGTS." },
  { id: "stf-rg-789", tribunal: "STF", tipo: "Repercussão Geral", numero: "789", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incorporação do percentual de 50% da parcela autônoma ao vencimento básico de professores estaduais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=789",
    texto: "A questão da incorporação do índice de 50% (cinquenta por cento) da parcela autônoma do Magistério, nos termos da Lei estadual n. 13.733/2011, ao vencimento básico dos professores do Rio Grande do Sul, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-790", tribunal: "STF", tipo: "Repercussão Geral", numero: "790", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de o abono variável, deferido a membros da magistratura federal, compor a base de cálculo da gratificação eleitoral devida a membros do Ministério Público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=790",
    texto: "A questão relativa à possibilidade de inclusão do abono variável, pago a membros da magistratura federal, na base de cálculo da gratificação eleitoral devida aos membros do Ministério Público tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-791", tribunal: "STF", tipo: "Repercussão Geral", numero: "791", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Isenção da Taxa de Coleta de Lixo de imóveis do Programa de Arrendamento Residencial (PAR).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=791",
    texto: "A questão da isenção de pagamento da Taxa de Coleta de Lixo de imóveis do Programa de Arrendamento Residencial (PAR) tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-792", tribunal: "STF", tipo: "Repercussão Geral", numero: "792", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de aplicação da Lei distrital 3.624/2005, que reduziu para 10 salários mínimos o teto para expedição de requisição de pequeno valor, às execuções em curso.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=792",
    texto: "Lei disciplinadora da submissão de crédito ao sistema de execução via precatório possui natureza material e processual, sendo inaplicável a situação jurídica constituída em data que a anteceda." },
  { id: "stf-rg-793", tribunal: "STF", tipo: "Repercussão Geral", numero: "793", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade solidária dos entes federados pelo dever de prestar assistência à saúde.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=793",
    texto: "Os entes da federação, em decorrência da competência comum, são solidariamente responsáveis nas demandas prestacionais na área da saúde, e diante dos critérios constitucionais de descentralização e hierarquização, compete à autoridade judicial direcionar o cumprimento conforme as regras de repartição de competências e determinar o ressarcimento a quem suportou o ônus financeiro." },
  { id: "stf-rg-795", tribunal: "STF", tipo: "Repercussão Geral", numero: "795", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Validade do cálculo do valor da verba denominada Complemento de Remuneração Mínima por Nível e Regime paga aos empregados da Petrobrás, descrita na Cláusula 35ª do Acordo Coletivo de Trabalho de 2007/2009, mediante a subtração, no valor desse complemento, dos adicionais inerentes ao trabalho em condições especiais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=795",
    texto: "A questão da validade do cálculo do valor da verba denominada Complemento de Remuneração Mínima por Nível e Regime (RMNR) paga aos empregados da Petróleo Brasileiro S/A - Petrobrás, nos termos da Cláusula 35ª do Acordo Coletivo de Trabalho de 2007/2009, mediante a subtração, no valor desse complemento, dos adicionais inerentes ao trabalho em condições especiais, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-796", tribunal: "STF", tipo: "Repercussão Geral", numero: "796", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Alcance da imunidade tributária do ITBI, prevista no art. 156, § 2º, I, da Constituição, sobre imóveis incorporados ao patrimônio de pessoa jurídica, quando o valor total desses bens excederem o limite do capital social a ser integralizado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=796",
    texto: "A imunidade em relação ITBI, prevista no inciso I do § 2º do art. 156 da Constituição Federal, não alcança o valor dos bens que exceder o limite do capital social a ser integralizado." },
  { id: "stf-rg-797", tribunal: "STF", tipo: "Repercussão Geral", numero: "797", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Presunção relativa de inexistência de repercussão geral dos recursos extraordinários interpostos nas causas processadas nos Juizados Especiais Cíveis da Lei 9.099/1995. Obs.: Título aperfeiçoado pelo Relator quando da publicação da tese, em 10/04/2018 (conforme Processo STF/SEI 010927/2017). Redação original: Viabilidade de recurso extraordinário contra acórdão proferido por Juizado Especial Cível da Lei 9.099/1995 em matéria de indenização decorrente de acidente de trânsito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=797",
    texto: "A admissão de recurso extraordinário interposto em causa processada nos Juizados Especiais Cíveis da Lei 9.099/1995 exige o preenchimento, por parte do recorrente, de dois requisitos adicionais: (a) demonstração específica e objetiva do prequestionamento, mediante a indicação clara da parte do acórdão recorrido em que tangenciada a matéria constitucional, e (b) fundamentação acerca da relevância calcada em dados concretos que revertam a presunção de inexistência de repercussão geral das lides processadas nesses Juizados. Obs.: unificação da tese para os Temas 797, 798 e 800." },
  { id: "stf-rg-798", tribunal: "STF", tipo: "Repercussão Geral", numero: "798", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Presunção relativa de inexistência de repercussão geral dos recursos extraordinários interpostos nas causas processadas nos Juizados Especiais Cíveis da Lei 9.099/1995. Obs.: Título aperfeiçoado pelo Relator quando da publicação da tese, em 10/04/2018 (conforme Processo STF/SEI 010927/2017). Redação original: Viabilidade de recurso extraordinário contra acórdão de Juizado Especial Cível da Lei 9.099/1995 em matéria de revisão contratual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=798",
    texto: "A admissão de recurso extraordinário interposto em causa processada nos Juizados Especiais Cíveis da Lei 9.099/1995 exige o preenchimento, por parte do recorrente, de dois requisitos adicionais: (a) demonstração específica e objetiva do prequestionamento, mediante a indicação clara da parte do acórdão recorrido em que tangenciada a matéria constitucional, e (b) fundamentação acerca da relevância calcada em dados concretos que revertam a presunção de inexistência de repercussão geral das lides processadas nesses Juizados. Obs.: unificação da tese para os Temas 797, 798 e 800." },
  { id: "stf-rg-799", tribunal: "STF", tipo: "Repercussão Geral", numero: "799", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Possibilidade da devolução de valores recebidos em virtude de tutela antecipada posteriormente revogada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=799",
    texto: "A questão acerca da devolução de valores recebidos em virtude de concessão de antecipação de tutela posteriormente revogada tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-800", tribunal: "STF", tipo: "Repercussão Geral", numero: "800", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Presunção relativa de inexistência de repercussão geral dos recursos extraordinários interpostos nas causas processadas nos Juizados Especiais Cíveis da Lei 9.099/1995. Obs.: Título aperfeiçoado pelo Relator quando da publicação da tese, em 10/04/2018 (conforme Processo STF/SEI 010927/2017). Redação original: Viabilidade de recurso extraordinário contra acórdão proferido por Juizado Especial Cível da Lei 9.099/1995 em matéria de responsabilidade pelo adimplemento de obrigação assumida em contrato de direito privado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=800",
    texto: "A admissão de recurso extraordinário interposto em causa processada nos Juizados Especiais Cíveis da Lei 9.099/1995 exige o preenchimento, por parte do recorrente, de dois requisitos adicionais: (a) demonstração específica e objetiva do prequestionamento, mediante a indicação clara da parte do acórdão recorrido em que tangenciada a matéria constitucional, e (b) fundamentação acerca da relevância calcada em dados concretos que revertam a presunção de inexistência de repercussão geral das lides processadas nesses Juizados. Obs.: unificação da tese para os Temas 797, 798 e 800." },
  { id: "stf-rg-802", tribunal: "STF", tipo: "Repercussão Geral", numero: "802", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Indenização por danos morais decorrentes da inscrição de consumidor em sistema de avaliação de crédito denominado \"Concentre Scoring\" (ou \"Credit Scoring\" ou \"Credscore\"), instituído e mantido pelo SERASA.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=802",
    texto: "A questão do direito à indenização por danos morais decorrentes da inscrição de consumidor em sistema de avaliação de crédito denominado concentre scoring, credit scoring ou credscore, instituído e mantido pela SERASA, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-803", tribunal: "STF", tipo: "Repercussão Geral", numero: "803", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Paridade remuneratória entre os militares do antigo e do atual Distrito Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=803",
    texto: "A questão do direito ao recebimento dos valores remuneratórios pagos aos policiais militares do atual Distrito Federal, pelos militares inativos e pensionistas dos servidores que ingressaram nos quadros da Polícia Militar do Rio de Janeiro antes da transferência da Capital federal para Brasília, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-804", tribunal: "STF", tipo: "Repercussão Geral", numero: "804", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Natureza jurídica do aumento remuneratório conferido pela Lei 8.369/2006 do Estado do Maranhão: se de revisão geral anual ou não.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=804",
    texto: "A questão da definição da natureza jurídica dos reajustes remuneratórios concedidos pela Lei maranhense n. 8.369/2006 aos servidores públicos estaduais, civis e militares (se recomposição ou revisão geral anual) tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-805", tribunal: "STF", tipo: "Repercussão Geral", numero: "805", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Legitimidade da definição da data de entrada do requerimento administrativo como marco temporal dos efeitos financeiros da revisão de benefício previdenciário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=805",
    texto: "A questão da validade de o termo inicial dos efeitos financeiros da concessão ou da revisão de benefício previdenciário ser a data de entrada do requerimento administrativo no Instituto Nacional do Seguro Social - INSS tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-806", tribunal: "STF", tipo: "Repercussão Geral", numero: "806", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Equiparação de vencimentos entre militares das Forças Armadas e policiais e bombeiros militares do Distrito Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=806",
    texto: "É vedada a equiparação remuneratória entre militares das Forças Armadas e policiais e bombeiros militares do Distrito Federal, visto que a Constituição Federal de 1988, em seu art. 37, XIII, coíbe a vinculação ou equiparação de quaisquer espécies remuneratórias no âmbito do serviço público." },
  { id: "stf-rg-807", tribunal: "STF", tipo: "Repercussão Geral", numero: "807", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Preenchimento dos requisitos para concessão do benefício assistencial previsto no art. 203, V, da Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=807",
    texto: "A questão do preenchimento dos requisitos para concessão do benefício assistencial de prestação continuada tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-809", tribunal: "STF", tipo: "Repercussão Geral", numero: "809", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Validade de dispositivos do Código Civil que atribuem direitos sucessórios distintos ao cônjuge e ao companheiro.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=809",
    texto: "É inconstitucional a distinção de regimes sucessórios entre cônjuges e companheiros prevista no art. 1.790 do CC/2002, devendo ser aplicado, tanto nas hipóteses de casamento quanto nas de união estável, o regime do art. 1.829 do CC/2002. (A mesma tese foi fixada para o Tema 498)" },
  { id: "stf-rg-810", tribunal: "STF", tipo: "Repercussão Geral", numero: "810", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Validade da correção monetária e dos juros moratórios incidentes sobre as condenações impostas à Fazenda Pública, conforme previstos no art. 1º-F da Lei 9.494/1997, com a redação dada pela Lei 11.960/2009.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=810",
    texto: "1) O art. 1º-F da Lei nº 9.494/97, com a redação dada pela Lei nº 11.960/09, na parte em que disciplina os juros moratórios aplicáveis a condenações da Fazenda Pública, é inconstitucional ao incidir sobre débitos oriundos de relação jurídico-tributária, aos quais devem ser aplicados os mesmos juros de mora pelos quais a Fazenda Pública remunera seu crédito tributário, em respeito ao princípio constitucional da isonomia (CRFB, art. 5º, caput); quanto às condenações oriundas de relação jurídica não-tributária, a fixação dos juros moratórios segundo o índice de remuneração da caderneta de poupança é constitucional, permanecendo hígido, nesta extensão, o disposto no art. 1º-F da Lei nº 9.494/97 com a redação dada pela Lei nº 11.960/09; e 2) O art. 1º-F da Lei nº 9.494/97, com a redação dada pela Lei nº 11.960/09, na parte em que disciplina a atualização monetária das condenações impostas à Fazenda Pública segundo a remuneração oficial da caderneta de poupança, revela-se inconstitucional ao impor restrição desproporcional ao direito de propriedade (CRFB, art. 5º, XXII), uma vez que não se qualifica como medida adequada a capturar a variação de preços da economia, sendo inidônea a promover os fins a que se destina." },
  { id: "stf-rg-811", tribunal: "STF", tipo: "Repercussão Geral", numero: "811", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "a) Cabimento de ação penal privada subsidiária da pública após o decurso do prazo previsto no art. 46 do Código de Processo Penal, na hipótese de o Ministério Público não oferecer denúncia, promover o arquivamento ou requisitar diligências externas no prazo legal; b) Ocorrência de prejudicialidade da queixa quando o Ministério Público, após o prazo legal para propositura da ação penal (art. 46 do CPP), oferecer denúncia, promover o arquivamento do inquérito ou determinar a realização de diligências externas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=811",
    texto: "I - O ajuizamento da ação penal privada pode ocorrer após o decurso do prazo legal, sem que seja oferecida denúncia, ou promovido o arquivamento, ou requisitadas diligências externas ao Ministério Público. Diligências internas à instituição são irrelevantes; II - A conduta do Ministério Público posterior ao surgimento do direito de queixa não prejudica sua propositura. Assim, o oferecimento de denúncia, a promoção do arquivamento ou a requisição de diligências externas ao Ministério Público, posterior ao decurso do prazo legal para a propositura da ação penal não afastam o direito de queixa. Nem mesmo a ciência da vítima ou da família quanto a tais diligências afasta esse direito, por não representar concordância com a falta de iniciativa da ação penal pública." },
  { id: "stf-rg-812", tribunal: "STF", tipo: "Repercussão Geral", numero: "812", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Quantificação da condenação em honorários advocatícios nas ações previdenciárias: incidência ou não de verba honorária sobre as prestações vencidas após a prolação da sentença.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=812",
    texto: "A questão acerca da apuração do valor da condenação em honorários advocatícios nas ações previdenciárias – notadamente quanto à incidência, ou não, de verba honorária sobre as prestações vencidas após a sentença – tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-813", tribunal: "STF", tipo: "Repercussão Geral", numero: "813", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Ocorrência de redução dos proventos de servidor público inativo em virtude da alteração do regime do magistério estadual e do posterior reenquadramento funcional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=813",
    texto: "A questão da preservação do valor dos proventos dos servidores do Magistério estadual que foram reenquadrados em razão da redução da jornada de trabalho do cargo de professor no qual se deu a respectiva aposentadoria tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-814", tribunal: "STF", tipo: "Repercussão Geral", numero: "814", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Base de cálculo da Gratificação de Insalubridade paga aos servidores públicos das universidades estaduais do Paraná.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=814",
    texto: "A questão da composição da base de cálculo da vantagem pecuniária denominada “Gratificação de Insalubridade”, paga aos servidores públicos das universidades estaduais do Paraná, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-815", tribunal: "STF", tipo: "Repercussão Geral", numero: "815", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Possibilidade de legislação infraconstitucional obstar o reconhecimento do direito à usucapião especial urbana, previsto no art. 183 da Constituição Federal, mediante o estabelecimento de módulos urbanos na área em que situado o imóvel.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=815",
    texto: "Preenchidos os requisitos do art. 183 da Constituição Federal, o reconhecimento do direito à usucapião especial urbana não pode ser obstado por legislação infraconstitucional que estabeleça módulos urbanos na respectiva área em que situado o imóvel (dimensão do lote)." },
  { id: "stf-rg-819", tribunal: "STF", tipo: "Repercussão Geral", numero: "819", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Indenização por danos materiais decorrentes da demora do Poder Público em avaliar o desempenho de servidores para o fim de pagamento de gratificação de desempenho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=819",
    texto: "A questão do direito à indenização por danos materiais decorrentes da demora do Poder Público em avaliar o desempenho dos servidores em atividade, com vistas ao pagamento de gratificações, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-821", tribunal: "STF", tipo: "Repercussão Geral", numero: "821", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Possibilidade de fixação de pensão alimentícia com base no salário mínimo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=821",
    texto: "A utilização do salário mínimo como base de cálculo do valor de pensão alimentícia não viola a Constituição Federal." },
  { id: "stf-rg-822", tribunal: "STF", tipo: "Repercussão Geral", numero: "822", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de o ensino domiciliar (homeschooling), ministrado pela família, ser considerado meio lícito de cumprimento do dever de educação, previsto no art. 205 da Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=822",
    texto: "Não existe direito público subjetivo do aluno ou de sua família ao ensino domiciliar, inexistente na legislação brasileira." },
  { id: "stf-rg-823", tribunal: "STF", tipo: "Repercussão Geral", numero: "823", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade dos sindicatos para a execução de título judicial, independentemente de autorização dos sindicalizados.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=823",
    texto: "Os sindicatos possuem ampla legitimidade extraordinária para defender em juízo os direitos e interesses coletivos ou individuais dos integrantes da categoria que representam, inclusive nas liquidações e execuções de sentença, independentemente de autorização dos substituídos." },
  { id: "stf-rg-824", tribunal: "STF", tipo: "Repercussão Geral", numero: "824", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Índice de reajuste aplicável aos benefícios previdenciários a fim de preservar o seu valor real.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=824",
    texto: "A questão relativa ao índice de reajuste aplicável aos benefícios previdenciários a fim de preservar o seu valor real tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-826", tribunal: "STF", tipo: "Repercussão Geral", numero: "826", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Verificação da ocorrência de dano e consequente responsabilidade da União pela eventual fixação de preços dos produtos do setor sucroalcooleiro em valores inferiores ao custo de produção.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=826",
    texto: "É imprescindível para o reconhecimento da responsabilidade civil do Estado em decorrência da fixação de preços no setor sucroalcooleiro a comprovação de efetivo prejuízo econômico, mediante perícia técnica em cada caso concreto." },
  { id: "stf-rg-827", tribunal: "STF", tipo: "Repercussão Geral", numero: "827", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de ICMS sobre o valor pago a título de assinatura básica mensal pelo serviço de telefonia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=827",
    texto: "O Imposto sobre Circulação de Mercadorias e Serviços (ICMS) incide sobre a tarifa de assinatura básica mensal cobrada pelas prestadoras de serviços de telefonia, independentemente da franquia de minutos concedida ou não ao usuário." },
  { id: "stf-rg-828", tribunal: "STF", tipo: "Repercussão Geral", numero: "828", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Obrigatoriedade de inclusão da Caixa Econômica Federal como litisconsorte passiva necessária, e consequente competência da Justiça Federal para julgar a demanda, em ação de indenização por vícios na construção de imóvel adquirido no âmbito do programa governamental Minha Casa, Minha Vida.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=828",
    texto: "A questão da configuração do efetivo interesse da Caixa Econômica Federal - CEF que, se presente, deslocaria a competência para a Justiça Federal, nas ações de indenização por vícios na construção de imóvel adquirido no âmbito do programa governamental “Minha Casa, Minha Vida”, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-829", tribunal: "STF", tipo: "Repercussão Geral", numero: "829", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Validade da exigência da taxa para expedição da Anotação de Responsabilidade Técnica (ART), baseada na Lei 6.994/1982, que estabeleceu limites máximos para a ART.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=829",
    texto: "Não viola a legalidade tributária a lei que, prescrevendo o teto, possibilita o ato normativo infralegal fixar o valor de taxa em proporção razoável com os custos da atuação estatal, valor esse que não pode ser atualizado por ato do próprio conselho de fiscalização em percentual superior aos índices de correção monetária legalmente previstos." },
  { id: "stf-rg-830", tribunal: "STF", tipo: "Repercussão Geral", numero: "830", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Possibilidade de o regime de apuração e recolhimento do ICMS ser disciplinado por decreto.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=830",
    texto: "Somente lei em sentido formal pode instituir o regime de recolhimento do ICMS por estimativa." },
  { id: "stf-rg-831", tribunal: "STF", tipo: "Repercussão Geral", numero: "831", situacao: "Vigente", tema: "DIREITO ELEITORAL", titulo: "Obrigatoriedade de pagamento, mediante o regime de precatórios, dos valores devidos pela Fazenda Pública entre a data da impetração do mandado de segurança e a efetiva implementação da ordem concessiva.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=831",
    texto: "O pagamento dos valores devidos pela Fazenda Pública entre a data da impetração do mandado de segurança e a efetiva implementação da ordem concessiva deve observar o regime de precatórios previsto no artigo 100 da Constituição Federal." },
  { id: "stf-rg-832", tribunal: "STF", tipo: "Repercussão Geral", numero: "832", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de vereador, enquanto parlamentar e cidadão, a obter diretamente do chefe do Poder Executivo informações e documentos sobre a gestão municipal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=832",
    texto: "O parlamentar, na condição de cidadão, pode exercer plenamente seu direito fundamental de acesso a informações de interesse pessoal ou coletivo, nos termos do art. 5º, inciso XXXIII, da CF e das normas de regência desse direito." },
  { id: "stf-rg-834", tribunal: "STF", tipo: "Repercussão Geral", numero: "834", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Validade da cobrança de serviços e comissões, notadamente o Serviço de Assessoria Técnica Imobiliária - SATI, previstos em contrato de compra e venda de imóveis entre consumidores e construtora ou incorporadora.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=834",
    texto: "A questão relativa à validade da cobrança de comissões e serviços previstos em contrato de compra e venda de imóvel entre consumidores e construtora ou incorporadora, notadamente o Serviço de Assessoria Técnica Imobiliária – SATI, tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-835", tribunal: "STF", tipo: "Repercussão Geral", numero: "835", situacao: "Vigente", tema: "DIREITO ELEITORAL", titulo: "Definição do órgão competente, se o Poder Legislativo ou o Tribunal de Contas, para julgar as contas de Chefe do Poder Executivo que age na qualidade de ordenador de despesas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=835",
    texto: "Para os fins do art. 1º, inciso I, alínea \"g\", da Lei Complementar 64, de 18 de maio de 1990, alterado pela Lei Complementar 135, de 4 de junho de 2010, a apreciação das contas de prefeitos, tanto as de governo quanto as de gestão, será exercida pelas Câmaras Municipais, com o auxílio dos Tribunais de Contas competentes, cujo parecer prévio somente deixará de prevalecer por decisão de 2/3 dos vereadores." },
  { id: "stf-rg-836", tribunal: "STF", tipo: "Repercussão Geral", numero: "836", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Exigência de comprovação de prejuízo material aos cofres públicos como condição para a propositura de ação popular.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=836",
    texto: "Não é condição para o cabimento da ação popular a demonstração de prejuízo material aos cofres públicos, dado que o art. 5º, inciso LXXIII, da Constituição Federal estabelece que qualquer cidadão é parte legítima para propor ação popular e impugnar, ainda que separadamente, ato lesivo ao patrimônio material, moral, cultural ou histórico do Estado ou de entidade de que ele participe." },
  { id: "stf-rg-838", tribunal: "STF", tipo: "Repercussão Geral", numero: "838", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Constitucionalidade da proibição, contida em edital de concurso público, de ingresso em cargo, emprego ou função pública para candidatos que tenham certos tipos de tatuagem em seu corpo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=838",
    texto: "Editais de concurso público não podem estabelecer restrição a pessoas com tatuagem, salvo situações excepcionais em razão de conteúdo que viole valores constitucionais." },
  { id: "stf-rg-839", tribunal: "STF", tipo: "Repercussão Geral", numero: "839", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "a) Possibilidade de um ato administrativo, caso evidenciada a violação direta ao texto constitucional, ser anulado pela Administração Pública quando decorrido o prazo decadencial previsto na Lei nº 9.784/1999. b) Saber se portaria que disciplina tempo máximo de serviço de militar atende aos requisitos do art. 8º do ADCT.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=839",
    texto: "No exercício do seu poder de autotutela, poderá a Administração Pública rever os atos de concessão de anistia a cabos da Aeronáutica com fundamento na Portaria nº 1.104/1964, quando se comprovar a ausência de ato com motivação exclusivamente política, assegurando-se ao anistiado, em procedimento administrativo, o devido processo legal e a não devolução das verbas já recebidas." },
  { id: "stf-rg-844", tribunal: "STF", tipo: "Repercussão Geral", numero: "844", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Possibilidade de creditamento de IPI pela aquisição de insumos isentos, não tributados ou sujeitos à alíquota zero.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=844",
    texto: "O princípio da não cumulatividade não assegura direito de crédito presumido de IPI para o contribuinte adquirente de insumos não tributados, isentos ou sujeitos à alíquota zero." },
  { id: "stf-rg-845", tribunal: "STF", tipo: "Repercussão Geral", numero: "845", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Indenização por danos decorrentes da suspensão do fornecimento de energia elétrica por empresa prestadora de serviço público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=845",
    texto: "A questão relativa à ocorrência de dano indenizável em virtude da suspensão do fornecimento de energia elétrica por empresa prestadora de serviço público tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-846", tribunal: "STF", tipo: "Repercussão Geral", numero: "846", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Constitucionalidade da manutenção de contribuição social após atingida a finalidade que motivou a sua instituição.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=846",
    texto: "É constitucional a contribuição social prevista no artigo 1º da Lei Complementar nº 110, de 29 de junho de 2001, tendo em vista a persistência do objeto para a qual foi instituída." },
  { id: "stf-rg-848", tribunal: "STF", tipo: "Repercussão Geral", numero: "848", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Legitimidade para executar sentença em ação coletiva na hipótese em que o título transitado em julgado define explicitamente os titulares do direito. Obs.: Título aperfeiçoado pelo Relator quando da publicação da tese, em 10/04/2018 (conforme Processo STF/SEI 010927/2017). Redação original: Limites subjetivos de sentença condenatória genérica transitada em julgado proferida nos autos de ação civil pública ajuizada por associação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=848",
    texto: "A questão acerca dos legitimados para executar sentença proferida em ação coletiva, na hipótese em que o título transitado em julgado define explicitamente os beneficiários do direito, tem natureza infraconstitucional, pois trata de discussão sobre os limites da coisa julgada (Tema 660), e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-850", tribunal: "STF", tipo: "Repercussão Geral", numero: "850", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Legitimidade do Ministério Público para a propositura de ação civil pública em defesa de direitos relacionados ao FGTS, tendo em vista a vedação contida no art. 1º, parágrafo único, da Lei 7.347/1985.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=850",
    texto: "O Ministério Público tem legitimidade para a propositura de ação civil pública em defesa de direitos sociais relacionados ao FGTS." },
  { id: "stf-rg-851", tribunal: "STF", tipo: "Repercussão Geral", numero: "851", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de servidores estaduais optantes do regime de pagamento anterior à Lei 18.975/2010 do Estado de Minas Gerais ao aumento de 5% conferido aos servidores que optaram pelo regime de subsídio.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=851",
    texto: "A questão do direito ao aumento de 5% (cinco por cento) aos servidores públicos que optaram pelo regime de pagamento anterior à Lei 18.975/2010, por meio de subsídio, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-852", tribunal: "STF", tipo: "Repercussão Geral", numero: "852", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Avaliação judicial de critérios para a caracterização de trabalho especial, para fins de reconhecimento de aposentadoria especial ou de conversão de tempo de serviço, nos termos dos arts. 57 e 58 da Lei 8.213/1991.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=852",
    texto: "A questão da validade do reconhecimento judicial de trabalho em condições especiais, pela efetiva exposição aos agentes nocivos à saúde ou integridade física, para fins de concessão ou revisão de aposentadoria especial ou para converter tempo de serviço, nos termos dos arts. 57 e 58 da Lei n. 8.213/1991, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-853", tribunal: "STF", tipo: "Repercussão Geral", numero: "853", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Competência da Justiça do Trabalho para processar e julgar reclamação trabalhista, fundada em contrato de trabalho regido pela CLT, na qual figura o Poder Público no polo passivo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=853",
    texto: "Compete à Justiça do Trabalho processar e julgar demandas visando a obter prestações de natureza trabalhista, ajuizadas contra órgãos da Administração Pública por servidores que ingressaram em seus quadros, sem concurso público, antes do advento da CF/88, sob regime da Consolidação das Leis do Trabalho - CLT." },
  { id: "stf-rg-854", tribunal: "STF", tipo: "Repercussão Geral", numero: "854", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de implementação da prestação de serviço público de transporte coletivo, considerado o art. 175 da Constituição Federal, mediante simples credenciamento, sem licitação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=854",
    texto: "Salvo em situações excepcionais devidamente comprovadas, serviço público de transporte coletivo pressupõe prévia licitação." },
  { id: "stf-rg-856", tribunal: "STF", tipo: "Repercussão Geral", numero: "856", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "a) Necessidade de submissão de demanda judicial à regra da reserva de plenário na hipótese em que a decisão judicial estiver fundada em jurisprudência do Plenário do Supremo Tribunal Federal ou em Súmula deste Tribunal; b) Constitucionalidade de restrições impostas pelo Estado ao livre exercício de atividade econômica ou profissional, quando aquelas forem utilizadas como meio de cobrança indireta de tributos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=856",
    texto: "I - É desnecessária a submissão à regra da reserva de plenário quando a decisão judicial estiver fundada em jurisprudência do Plenário ou em Súmula deste Supremo Tribunal Federal; II - É inconstitucional a restrição ilegítima ao livre exercício de atividade econômica ou profissional, quando imposta como meio de cobrança indireta de tributos." },
  { id: "stf-rg-860", tribunal: "STF", tipo: "Repercussão Geral", numero: "860", situacao: "Vigente", tema: "DIREITO ELEITORAL", titulo: "Possibilidade de aplicação do prazo de 8 anos de inelegibilidade por abuso de poder previsto na Lei Complementar 135/2010 às situações anteriores à referida lei em que, por força de decisão transitada em julgado, o prazo de inelegibilidade de 3 anos aplicado com base na redação original do art. 1º, I, d, da Lei Complementar 64/1990 houver sido integralmente cumprido.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=860",
    texto: "A condenação por abuso de poder econômico ou político em ação de investigação judicial eleitoral transitada em julgado, ex vi do art. 22, XIV, da Lei Complementar n. 64/90, em sua redação primitiva, é apta a atrair a incidência da inelegibilidade do art. 1º, inciso I, alínea d, na redação dada pela Lei Complementar n. 135/2010, aplicando-se a todos os processos de registro de candidatura em trâmite." },
  { id: "stf-rg-861", tribunal: "STF", tipo: "Repercussão Geral", numero: "861", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Natureza jurídica de direitos: se individuais homogêneos ou heterogêneos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=861",
    texto: "A questão da definição da natureza jurídica dos direitos controvertidos, se individuais homogêneos ou individuais heterogêneos, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-862", tribunal: "STF", tipo: "Repercussão Geral", numero: "862", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Termo inicial da contagem do prazo para apresentação de defesa no âmbito dos Juizados Especiais Cíveis.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=862",
    texto: "A questão da definição do termo inicial do prazo para apresentação de defesa nas causas dos Juizados Especiais Cíveis tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-864", tribunal: "STF", tipo: "Repercussão Geral", numero: "864", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Existência, ou não, de direito subjetivo a revisão geral da remuneração dos servidores públicos por índice previsto apenas na Lei de Diretrizes Orçamentárias, sem correspondente dotação orçamentária na Lei Orçamentária do respectivo ano.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=864",
    texto: "A revisão geral anual da remuneração dos servidores públicos depende, cumulativamente, de dotação na Lei Orçamentária Anual e de previsão na Lei de Diretrizes Orçamentárias." },
  { id: "stf-rg-866", tribunal: "STF", tipo: "Repercussão Geral", numero: "866", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Legitimidade da revisão de contrato já extinto.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=866",
    texto: "A questão da validade de revisão do índice de correção monetária aplicado ao saldo devedor de contrato extinto ou quitado tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-867", tribunal: "STF", tipo: "Repercussão Geral", numero: "867", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Pagamento de férias fora do prazo do art. 145 da Consolidação das Leis do Trabalho: direito ou não à remuneração de férias em dobro.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=867",
    texto: "A questão da obrigatoriedade do pagamento em dobro de férias pagas fora do prazo do art. 145 da Consolidação das Leis do Trabalho tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-868", tribunal: "STF", tipo: "Repercussão Geral", numero: "868", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Obrigatoriedade, ou não, de o Estado do Rio de Janeiro prestar assistência médico-hospitalar aos militares do estado, independentemente de contribuição.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=868",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à obrigatoriedade de manutenção da prestação de serviços médicos, hospitalares, odontológico e farmacêuticos aos servidores militares, independentemente de contribuição destinada ao custeio dos serviços." },
  { id: "stf-rg-869", tribunal: "STF", tipo: "Repercussão Geral", numero: "869", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Indenização por dano moral em virtude de inadimplemento de cláusula contratual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=869",
    texto: "A questão do direito à indenização por danos morais pelo inadimplemento de cláusula contratual, representado pelo atraso na entrega de imóvel residencial, comprado ainda na planta, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-870", tribunal: "STF", tipo: "Repercussão Geral", numero: "870", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Legitimidade do Município de Mossoró/RN para figurar no polo passivo de demanda visando à complementação de aposentadoria.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=870",
    texto: "A questão da legitimidade do Município de Mossoró - RN para figurar no polo passivo nas causas cujo pedido é a complementação de aposentadoria concedida com base na Lei municipal 311/1991 tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-871", tribunal: "STF", tipo: "Repercussão Geral", numero: "871", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Base de cálculo da Gratificação de Difícil Acesso devida aos servidores públicos estaduais do quadro da Secretaria de Educação do Estado do Rio Grande do Sul que preencham os requisitos legais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=871",
    texto: "A questão da composição da base de cálculo da vantagem pecuniária denominada “Gratificação de Difícil Acesso”, paga aos servidores públicos estaduais do quadro da Secretaria de Educação do Rio Grande do Sul, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-872", tribunal: "STF", tipo: "Repercussão Geral", numero: "872", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Constitucionalidade da exigência de multa por ausência ou atraso na entrega de Declaração de Débitos e Créditos Tributários Federais – DCTF, prevista no art. 7º, II, da Lei 10.426/2002, apurada mediante percentual a incidir, mês a mês, sobre os valores dos tributos a serem informados.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=872",
    texto: "Revela-se constitucional a sanção prevista no artigo 7º, inciso II, da Lei nº 10.426/2002, ante a ausência de ofensa aos princípios da proporcionalidade e da vedação de tributo com efeito confiscatório." },
  { id: "stf-rg-873", tribunal: "STF", tipo: "Repercussão Geral", numero: "873", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Compatibilidade da execução individual de sentença condenatória genérica proferida em ação coletiva com o art. 100, § 8º, da Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=873",
    texto: "Não viola o art. 100, § 8º, da Constituição Federal a execução individual de sentença condenatória genérica proferida contra a Fazenda Pública em ação coletiva visando à tutela de direitos individuais homogêneos." },
  { id: "stf-rg-874", tribunal: "STF", tipo: "Repercussão Geral", numero: "874", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Constitucionalidade do parágrafo único do art. 73 da Lei 9.430/1996, com a redação dada pela Lei 12.844/2013, que prevê a possibilidade de o Fisco, aproveitando o ensejo da restituição ou do ressarcimento de tributos administrados pela Secretaria da Receita Federal do Brasil, proceder à compensação, de ofício, com débitos não parcelados ou parcelados sem garantia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=874",
    texto: "É inconstitucional, por afronta ao art. 146, III, b, da CF, a expressão “ou parcelados sem garantia”, constante do parágrafo único do art. 73, da Lei nº 9.430/96, incluído pela Lei nº 12.844/13, na medida em que retira os efeitos da suspensão da exigibilidade do crédito tributário prevista no CTN." },
  { id: "stf-rg-875", tribunal: "STF", tipo: "Repercussão Geral", numero: "875", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Natureza jurídica do auxílio-alimentação concedido a servidor público estadual pela Lei 794/1998 do Estado de Rondônia: se indenizatória ou remuneratória.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=875",
    texto: "A questão da definição da natureza jurídica do “auxílio-alimentação”, pago aos servidores públicos do Tribunal de Justiça de Rondônia, se indenizatória ou remuneratória, e estendida aos demais servidores da Administração Direta, Autárquica e Fundacional daquele Estado pela Lei estadual n. 794/1998, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-876", tribunal: "STF", tipo: "Repercussão Geral", numero: "876", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Indenização por danos morais e materiais em razão do lapso temporal decorrido entre a publicação do Decreto 1.499/1995 e o efetivo retorno do anistiado ao serviço.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=876",
    texto: "A questão do direito à indenização por danos morais e materiais em razão do lapso temporal decorrido entre a publicação do Decreto n. 1.499/1995 e o efetivo retorno do anistiado ao serviço tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-877", tribunal: "STF", tipo: "Repercussão Geral", numero: "877", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Submissão dos conselhos de fiscalização profissional à execução pelo regime de precatórios.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=877",
    texto: "Os pagamentos devidos, em razão de pronunciamento judicial, pelos Conselhos de Fiscalização não se submetem ao regime de precatórios." },
  { id: "stf-rg-878", tribunal: "STF", tipo: "Repercussão Geral", numero: "878", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Legitimidade da execução na Justiça do Trabalho de bens que, a despeito de não integrarem a massa falida, pertencem a pessoa jurídica do mesmo grupo econômico de sociedade submetida a procedimento falimentar.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=878",
    texto: "A questão da legitimidade do bloqueio de bens de pessoa jurídica do mesmo grupo econômico, porém não integrantes da massa falida, pelo Juízo Trabalhista, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-879", tribunal: "STF", tipo: "Repercussão Geral", numero: "879", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "a) Prescrição de obrigação reconhecida como de trato sucessivo; b) Reposição salarial concedida pela Lei 1.329/2000 do Município de Arvorezinha/RS e sua eventual derrogação pela Lei 1.394/2001 do mesmo município.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=879",
    texto: "As questões da ocorrência da prescrição de obrigação de trato sucessivo e do direito à reposição salarial da Lei 1.329/2000 do Município de Arvorezinha/RS e sua eventual derrogação pela Lei 1.394/2001, do mesmo município, têm natureza infraconstitucional, e a elas se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-880", tribunal: "STF", tipo: "Repercussão Geral", numero: "880", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Indenização por dano moral decorrente de responsabilidade civil extracontratual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=880",
    texto: "A questão do direito à indenização por dano moral decorrente de responsabilidade civil extracontratual tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-882", tribunal: "STF", tipo: "Repercussão Geral", numero: "882", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Natureza da Gratificação de Risco de Policiamento Ostensivo prevista na Lei Complementar 59/2004 do Estado de Pernambuco: se geral ou propter laborem.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=882",
    texto: "A questão da definição da natureza jurídica da vantagem pecuniária denominada “Gratificação de Risco de Policiamento Ostensivo”, instituída pela Lei Complementar estadual 59/2004, paga aos servidores militares de Pernambuco, se indenizatória ou remuneratória, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-883", tribunal: "STF", tipo: "Repercussão Geral", numero: "883", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito a férias relativas a período de participação em curso de formação de soldados da polícia militar do Estado de São Paulo.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=883",
    texto: "A questão do direito a férias relativas a período de participação em curso de formação de soldados da polícia militar estadual tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-884", tribunal: "STF", tipo: "Repercussão Geral", numero: "884", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Imunidade tributária recíproca em relação ao IPTU incidente sobre bens imóveis mantidos sob a propriedade fiduciária da Caixa Econômica Federal, mas que não se comunicam com o patrimônio desta, porque integrados ao Programa de Arrendamento Residencial – PAR, criado e mantido pela União, nos termos da Lei 10.188/2001.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=884",
    texto: "Os bens e direitos que integram o patrimônio do fundo vinculado ao Programa de Arrendamento Residencial - PAR, criado pela Lei 10.188/2001, beneficiam-se da imunidade tributária prevista no art. 150, VI, a, da Constituição Federal." },
  { id: "stf-rg-886", tribunal: "STF", tipo: "Repercussão Geral", numero: "886", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência para remover ex officio servidor público municipal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=886",
    texto: "A questão da definição da autoridade competente para remover, ex officio, servidor público municipal tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-887", tribunal: "STF", tipo: "Repercussão Geral", numero: "887", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Inclusão da Gratificação de Incentivo à Eficientização dos Serviços – GIEFS nas bases de cálculo do décimo terceiro salário e do adicional de férias devidos a servidor público estadual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=887",
    texto: "A questão da inclusão da Gratificação de Incentivo à Eficiência dos Serviços (GIEFS) na base de cálculo do décimo terceiro salário e do terço constitucional de férias, a servidor público lotado em Fundação estadual, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-888", tribunal: "STF", tipo: "Repercussão Geral", numero: "888", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de servidores públicos abrangidos pela aposentadoria especial ao abono de permanência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=888",
    texto: "É legítimo o pagamento do abono de permanência previsto no art. 40, § 19, da Constituição Federal ao servidor público que opte por permanecer em atividade após o preenchimento dos requisitos para a concessão da aposentadoria voluntária especial (art. 40, § 4º, da Carta Magna)." },
  { id: "stf-rg-889", tribunal: "STF", tipo: "Repercussão Geral", numero: "889", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Direito à correção monetária da indenização do Seguro DPVAT no período entre o advento da MP 340/2006 e a ocorrência do sinistro.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=889",
    texto: "A questão do direito à correção monetária da indenização do Seguro de Danos Pessoais Causados por Veículos Automotores de Vias Terrestres – DPVAT, no período entre o advento da Medida Provisória 340/2006 e a ocorrência do sinistro, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-890", tribunal: "STF", tipo: "Repercussão Geral", numero: "890", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Ofensa aos princípios constitucionais da dignidade da pessoa humana, da legalidade, da propriedade e sua função social, do devido processo legal e do acesso à Justiça em decorrência de rescisão contratual.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=890",
    texto: "A questão da ofensa aos princípios da dignidade da pessoa humana, da legalidade, da propriedade e sua função social, do devido processo legal e do acesso à Justiça, quando decorrente de relação contratual, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-891", tribunal: "STF", tipo: "Repercussão Geral", numero: "891", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Constitucionalidade da Taxa de Serviços Administrativos - TSA prevista no art. 1º da Lei 9.960/2000.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=891",
    texto: "É inconstitucional o art. 1º da Lei 9.960/2000, que instituiu a Taxa de Serviços Administrativos - TSA, por não definir de forma específica o fato gerador da exação." },
  { id: "stf-rg-892", tribunal: "STF", tipo: "Repercussão Geral", numero: "892", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Marco prescricional para a interposição de ação para exigir contribuição sindical rural no âmbito da Justiça do Trabalho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=892",
    texto: "A questão da definição do marco prescricional para a cobrança de valores devidos a título de contribuição sindical rural, na Justiça do Trabalho, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-893", tribunal: "STF", tipo: "Repercussão Geral", numero: "893", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Validade do critério de cálculo da aposentadoria proporcional previsto no art. 53, I e II, da Lei 8.213/1991.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=893",
    texto: "A questão relativa à validade do critério de cálculo da aposentadoria proporcional previsto no art. 53, I e II, da Lei 8.213/1991 tem natureza infraconstitucional e a ela atribuem-se os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, Relatora a Ministra Ellen Gracie, DJe 13/3/2009." },
  { id: "stf-rg-894", tribunal: "STF", tipo: "Repercussão Geral", numero: "894", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Aplicabilidade do princípio da anterioridade nonagesimal à contribuição ao PIS instituída pelo art. 2º da EC 17/1997.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=894",
    texto: "A contribuição ao PIS só pode ser exigida, na forma estabelecida pelo art. 2º da EC 17/1997, após decorridos noventa dias da data da publicação da referida emenda constitucional." },
  { id: "stf-rg-895", tribunal: "STF", tipo: "Repercussão Geral", numero: "895", situacao: "Vigente", tema: "DIREITO DO CONSUMIDOR", titulo: "Ofensa ao princípio da inafastabilidade de jurisdição na hipótese em que há óbice processual intransponível ao julgamento de mérito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=895",
    texto: "A questão da ofensa ao princípio da inafastabilidade de jurisdição, quando há óbice processual intransponível ao exame de mérito, ofensa indireta à Constituição ou análise de matéria fática, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-896", tribunal: "STF", tipo: "Repercussão Geral", numero: "896", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Cabimento de apelação contra decisão judicial que extingue execução fiscal de pequeno valor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=896",
    texto: "A questão do cabimento de apelação contra decisão judicial que extingue execução fiscal de pequeno valor tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-897", tribunal: "STF", tipo: "Repercussão Geral", numero: "897", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Prescritibilidade da pretensão de ressarcimento ao erário em face de agentes públicos por ato de improbidade administrativa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=897",
    texto: "São imprescritíveis as ações de ressarcimento ao erário fundadas na prática de ato doloso tipificado na Lei de Improbidade Administrativa." },
  { id: "stf-rg-898", tribunal: "STF", tipo: "Repercussão Geral", numero: "898", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Cabimento de mandado de segurança contra decisão que julga embargos infringentes opostos em execução fiscal de pequeno valor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=898",
    texto: "A questão do cabimento de mandado de segurança contra decisão judicial que examina embargos infringentes opostos em execução fiscal de pequeno valor tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-899", tribunal: "STF", tipo: "Repercussão Geral", numero: "899", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Prescritibilidade da pretensão de ressarcimento ao erário fundada em decisão de Tribunal de Contas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=899",
    texto: "É prescritível a pretensão de ressarcimento ao erário fundada em decisão de Tribunal de Contas." },
  { id: "stf-rg-902", tribunal: "STF", tipo: "Repercussão Geral", numero: "902", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Despesas processuais que compõem o preparo recursal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=902",
    texto: "A questão das despesas que compõem o preparo recursal tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-904", tribunal: "STF", tipo: "Repercussão Geral", numero: "904", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito ao reajuste da verba paga aos policiais militares do Estado do Paraná em razão da prestação de serviço extraordinário, nos termos da Lei estadual 13.280/2001.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=904",
    texto: "A questão do direito a reajuste do valor pago aos policiais militares do Paraná pelo serviço extraordinário prestado, sempre que houver reajuste do funcionalismo estadual, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-906", tribunal: "STF", tipo: "Repercussão Geral", numero: "906", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Violação ao princípio da isonomia (art. 150, II, da Constituição Federal) ante a incidência de IPI no momento do desembaraço aduaneiro de produto industrializado, assim como na sua saída do estabelecimento importador para comercialização no mercado interno.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=906",
    texto: "É constitucional a incidência do Imposto sobre Produtos Industrializados ? IPI no desembaraço aduaneiro de bem industrializado e na saída do estabelecimento importador para comercialização no mercado interno." },
  { id: "stf-rg-907", tribunal: "STF", tipo: "Repercussão Geral", numero: "907", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Constitucionalidade do art. 305 do Código de Trânsito Brasileiro.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=907",
    texto: "\"A regra que prevê o crime do art. 305 do Código de Trânsito Brasileiro (Lei nº 9.503/97) é constitucional, posto não infirmar o princípio da não incriminação, garantido o direito ao silêncio e ressalvadas as hipóteses de exclusão da tipicidade e da antijuridicidade." },
  { id: "stf-rg-908", tribunal: "STF", tipo: "Repercussão Geral", numero: "908", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de contribuição previdenciária a cargo do empregado. Definição da natureza jurídica de parcelas pagas ao empregado, para fins de enquadramento ou não na base de cálculo de contribuição previdenciária, conforme o art. 28 da Lei 8.212/1991.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=908",
    texto: "A questão da definição da natureza jurídica das parcelas pagas ao empregado, para fins de enquadramento ou não na base de cálculo da contribuição previdenciária, quota do trabalhador, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-909", tribunal: "STF", tipo: "Repercussão Geral", numero: "909", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Preenchimento dos pressupostos necessários ao gozo da imunidade tributária recíproca pela Rede Ferroviária Federal S/A – RFFSA.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=909",
    texto: "A questão do preenchimento dos pressupostos da imunidade recíproca pela Rede Ferroviária Federal S/A – RFFSA tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-910", tribunal: "STF", tipo: "Repercussão Geral", numero: "910", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência da contribuição do salário-educação sobre a folha de salário do produtor rural pessoa física.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=910",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à equiparação do produtor rural empregador pessoa física ao conceito de empresa para efeito de sujeição à contribuição para o salário-educação." },
  { id: "stf-rg-911", tribunal: "STF", tipo: "Repercussão Geral", numero: "911", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Possibilidade de exclusão, das bases de cálculo do IRPJ e da CSLL, dos créditos escriturais apurados no regime não cumulativo da contribuição ao PIS e da COFINS.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=911",
    texto: "A questão da exigibilidade de Imposto de Renda Pessoa Jurídica (IRPJ) e de Contribuição sobre o Lucro Líquido (CSLL) sobre os valores relativos aos créditos escriturais apurados no regime não cumulativo da contribuição ao Programa de Integração Social (PIS) e da Contribuição para o Financiamento da Seguridade Social (COFINS) tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-913", tribunal: "STF", tipo: "Repercussão Geral", numero: "913", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Verificação da ocorrência de reestruturação remuneratória da carreira de servidores públicos para efeito de aplicação da orientação firmada no RE 561.836-RG/RN (Tema 5).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=913",
    texto: "A questão da extinção do direito à incorporação dos 11,98%, ou do índice obtido em cada caso, na remuneração do servidor público cuja carreira tenha passado por uma reestruturação de vencimentos em período posterior à conversão do padrão monetário (Cruzeiros Reais para Unidade Real de Valor - URV), nos termos da jurisprudência fixada no Recurso Extraordinário 561.836, Tema n. 5, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-915", tribunal: "STF", tipo: "Repercussão Geral", numero: "915", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Extensão, por via judicial, aos servidores do Poder Judiciário do Estado do Rio de Janeiro do reajuste concedido pela Lei estadual 1.206/1987.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=915",
    texto: "Não é devida aos servidores do Poder Judiciário do Estado do Rio de Janeiro a extensão do reajuste concedido pela Lei nº 1.206/1987, dispensando-se a devolução das verbas eventualmente recebidas até 01º.09.2016 (data da conclusão deste julgamento)." },
  { id: "stf-rg-916", tribunal: "STF", tipo: "Repercussão Geral", numero: "916", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Efeitos jurídicos do contrato temporário firmado em desconformidade com o art. 37, IX, da Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=916",
    texto: "A contratação por tempo determinado para atendimento de necessidade temporária de excepcional interesse público realizada em desconformidade com os preceitos do art. 37, IX, da Constituição Federal não gera quaisquer efeitos jurídicos válidos em relação aos servidores contratados, com exceção do direito à percepção dos salários referentes ao período trabalhado e, nos termos do art. 19-A da Lei 8.036/1990, ao levantamento dos depósitos efetuados no Fundo de Garantia do Tempo de Serviço - FGTS." },
  { id: "stf-rg-917", tribunal: "STF", tipo: "Repercussão Geral", numero: "917", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência para iniciativa de lei municipal que preveja a obrigatoriedade de instalação de câmeras de segurança em escolas públicas municipais e cercanias.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=917",
    texto: "Não usurpa competência privativa do Chefe do Poder Executivo lei que, embora crie despesa para a Administração, não trata da sua estrutura ou da atribuição de seus órgãos nem do regime jurídico de servidores públicos (art. 61, § 1º, II,\"a\", \"c\" e \"e\", da Constituição Federal)." },
  { id: "stf-rg-918", tribunal: "STF", tipo: "Repercussão Geral", numero: "918", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Inconstitucionalidade de lei municipal que estabelece impeditivos à submissão de sociedades profissionais de advogados ao regime de tributação fixa ou per capita em bases anuais na forma estabelecida pelo Decreto-Lei n. 406/1968 (recepcionado pela Constituição da República de 1988 com status de lei complementar nacional).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=918",
    texto: "É inconstitucional lei municipal que estabelece impeditivos à submissão de sociedades profissionais de advogados ao regime de tributação fixa em bases anuais na forma estabelecida por lei nacional." },
  { id: "stf-rg-920", tribunal: "STF", tipo: "Repercussão Geral", numero: "920", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Possibilidade de responsabilização objetiva do empregador por danos decorrentes de doenças ocupacionais.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=920",
    texto: "A questão da responsabilidade civil objetiva do empregador nas ações de reparação de danos decorrentes de doenças ocupacionais tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-921", tribunal: "STF", tipo: "Repercussão Geral", numero: "921", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Tríplice acumulação de vencimentos e proventos decorrentes de ingressos em cargos públicos anteriores à EC n. 20/1998.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=921",
    texto: "É vedada a cumulação tríplice de vencimentos e/ou proventos, ainda que a investidura nos cargos públicos tenha ocorrido anteriormente à EC 20/1998." },
  { id: "stf-rg-923", tribunal: "STF", tipo: "Repercussão Geral", numero: "923", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Efeito repristinatório pela declaração de inconstitucionalidade dos incs. I e II do art. 25 da Lei n. 8.212/1991 alterada pelas Leis ns. 8.540/1992 e 9.528/1997.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=923",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à base de cálculo aplicável à contribuição previdenciária do empregador rural pessoa física, bem como a sua compensação, restituição ou lançamento, em razão da declaração de inconstitucionalidade da contribuição incidente sobre a comercialização de sua produção rural." },
  { id: "stf-rg-925", tribunal: "STF", tipo: "Repercussão Geral", numero: "925", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Possibilidade de a execução provisória de acórdão penal condenatório proferido em grau recursal, ainda que sujeito a recurso especial ou extraordinário, comprometer o princípio constitucional da presunção de inocência afirmado pelo art. 5º, inc. LVII, da Constituição da República.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=925",
    texto: "A execução provisória de acórdão penal condenatório proferido em grau recursal, ainda que sujeito a recurso especial ou extraordinário, não compromete o princípio constitucional da presunção de inocência afirmado pelo artigo 5º, inciso LVII, da Constituição Federal." },
  { id: "stf-rg-926", tribunal: "STF", tipo: "Repercussão Geral", numero: "926", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de a condição de irmão gêmeo de candidato sorteado em processo seletivo para preenchimento de vagas em escola pública de ensino fundamental determinar a matrícula compulsória do irmão gêmeo não sorteado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=926",
    texto: "A questão do direito de aluno à matrícula na mesma escola pública de ensino fundamental na qual o seu irmão gêmeo obteve vaga por meio de sorteio em processo seletivo não tem repercussão geral, pois ausente relevância econômica, política, social ou jurídica que transcenda o interesse das partes." },
  { id: "stf-rg-927", tribunal: "STF", tipo: "Repercussão Geral", numero: "927", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Legitimidade do reconhecimento administrativo da incidência de juros de mora sobre parcela atrasada devida a servidor público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=927",
    texto: "A questão da validade do reconhecimento administrativo de incidência de juros de mora sobre parcela atrasada devida a servidor público tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-928", tribunal: "STF", tipo: "Repercussão Geral", numero: "928", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência da Justiça do Trabalho para processar e julgar ação que discute verbas trabalhistas, referentes a período regido pela CLT, supostamente devidas a empregados públicos que migraram, posteriormente, para o regime estatutário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=928",
    texto: "Compete à Justiça do Trabalho processar e julgar ações relativas às verbas trabalhistas referentes ao período em que o servidor mantinha vínculo celetista com a Administração, antes da transposição para o regime estatutário." },
  { id: "stf-rg-929", tribunal: "STF", tipo: "Repercussão Geral", numero: "929", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "Possibilidade de compensação da agravante da reincidência com a atenuante da confissão espontânea, com base no disposto no art. 67 do Código Penal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=929",
    texto: "Não tem repercussão geral a controvérsia relativa à possibilidade ou não de compensação da agravante da reincidência com a atenuante da confissão espontânea." },
  { id: "stf-rg-930", tribunal: "STF", tipo: "Repercussão Geral", numero: "930", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Os benefícios concedidos entre 5.10.1988 e 5.4.1991 não estão, em tese, excluídos da possibilidade de readequação aos tetos instituídos pelas Emendas Constitucionais ns. 20/1998 e 41/2003. Eventual direito a diferenças deve ser aferido no caso concreto, conforme os parâmetros já definidos no julgamento do RE n. 564.354.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=930",
    texto: "Os benefícios concedidos entre 05.10.1988 e 05.04.1991 (período do buraco negro) não estão, em tese, excluídos da possibilidade de readequação segundo os tetos instituídos pelas EC´s nº 20/1998 e 41/2003, a ser aferida caso a caso, conforme os parâmetros definidos no julgamento do RE 564.354, em regime de repercussão geral." },
  { id: "stf-rg-931", tribunal: "STF", tipo: "Repercussão Geral", numero: "931", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Cômputo como horas in itinere do tempo gasto pelo trabalhador para deslocar-se da portaria até o local do registro de sua entrada na empresa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=931",
    texto: "A questão da contagem como horas in itinere do tempo gasto pelo trabalhador para deslocar-se da portaria até o local do registro de sua entrada na empresa tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-932", tribunal: "STF", tipo: "Repercussão Geral", numero: "932", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Possibilidade de responsabilização objetiva do empregador por danos decorrentes de acidentes de trabalho.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=932",
    texto: "O artigo 927, parágrafo único, do Código Civil é compatível com o artigo 7º, XXVIII, da Constituição Federal, sendo constitucional a responsabilização objetiva do empregador por danos decorrentes de acidentes de trabalho, nos casos especificados em lei, ou quando a atividade normalmente desenvolvida, por sua natureza, apresentar exposição habitual a risco especial, com potencialidade lesiva e implicar ao trabalhador ônus maior do que aos demais membros da coletividade." },
  { id: "stf-rg-935", tribunal: "STF", tipo: "Repercussão Geral", numero: "935", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Inconstitucionalidade da contribuição assistencial imposta aos empregados não filiados ao sindicato, por acordo, convenção coletiva de trabalho ou sentença.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=935",
    texto: "É inconstitucional a instituição, por acordo, convenção coletiva ou sentença normativa, de contribuições que se imponham compulsoriamente a empregados da categoria não sindicalizados." },
  { id: "stf-rg-937", tribunal: "STF", tipo: "Repercussão Geral", numero: "937", situacao: "Vigente", tema: "DIREITO PENAL", titulo: "É constitucional o tipo penal previsto no art. 2º, inc, II da Lei n. 8.137/1990, por não se configurar a conduta nele descrita como mero ilícito civil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=937",
    texto: "Os crimes previstos na Lei nº 8.137/1990 não violam o disposto no art. 5º, inc. LXVII, da Constituição da República." },
  { id: "stf-rg-938", tribunal: "STF", tipo: "Repercussão Geral", numero: "938", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Termo inicial do prazo decadencial para a revisão de benefício de pensão por morte derivado de outro benefício previdenciário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=938",
    texto: "Não tem repercussão geral a controvérsia relativa à definição do termo inicial do prazo decadencial para a revisão de benefício de pensão por morte derivado de outro benefício previdenciário." },
  { id: "stf-rg-940", tribunal: "STF", tipo: "Repercussão Geral", numero: "940", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade civil subjetiva do agente público por danos causados a terceiros, no exercício de atividade pública.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=940",
    texto: "A teor do disposto no art. 37, § 6º, da Constituição Federal, a ação por danos causados por agente público deve ser ajuizada contra o Estado ou a pessoa jurídica de direito privado prestadora de serviço público, sendo parte ilegítima para a ação o autor do ato, assegurado o direito de regresso contra o responsável nos casos de dolo ou culpa." },
  { id: "stf-rg-941", tribunal: "STF", tipo: "Repercussão Geral", numero: "941", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Possibilidade de afastar-se o prévio procedimento administrativo disciplinar – PAD, ou suprir sua eventual deficiência técnica, na hipótese de oitiva do condenado em audiência de justificação no juízo da execução penal, realizada na presença do ministério público ou defensor.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=941",
    texto: "A oitiva do condenado pelo Juízo da Execução Penal, em audiência de justificação realizada na presença do defensor e do Ministério Público, afasta a necessidade de prévio Procedimento Administrativo Disciplinar (PAD), assim como supre eventual ausência ou insuficiência de defesa técnica no PAD instaurado para apurar a prática de falta grave durante o cumprimento da pena." },
  { id: "stf-rg-942", tribunal: "STF", tipo: "Repercussão Geral", numero: "942", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de aplicação das regras do regime geral de previdência social para a averbação do tempo de serviço prestado em atividades exercidas sob condições especiais, nocivas à saúde ou à integridade física de servidor público, com conversão do tempo especial em comum, mediante contagem diferenciada.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=942",
    texto: "Até a edição da Emenda Constitucional nº 103/2019, o direito à conversão, em tempo comum, do prestado sob condições especiais que prejudiquem a saúde ou a integridade física de servidor público decorre da previsão de adoção de requisitos e critérios diferenciados para a jubilação daquele enquadrado na hipótese prevista no então vigente inciso III do § 4º do art. 40 da Constituição da República, devendo ser aplicadas as normas do regime geral de previdência social relativas à aposentadoria especial contidas na Lei 8.213/1991 para viabilizar sua concretização enquanto não sobrevier lei complementar disciplinadora da matéria. Após a vigência da EC n.º 103/2019, o direito à conversão em tempo comum, do prestado sob condições especiais pelos servidores obedecerá à legislação complementar dos entes federados, nos termos da competência conferida pelo art. 40, § 4º-C, da Constituição da República." },
  { id: "stf-rg-943", tribunal: "STF", tipo: "Repercussão Geral", numero: "943", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Possibilidade de conversão do tempo de serviço comum para especial, mediante a aplicação do fator 0,71 de conversão, nas hipóteses em que o trabalho fora prestado em período anterior à Lei n. 9.032/1995, para fins de concessão de aposentadoria especial com data de início posterior à essa legislação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=943",
    texto: "A questão da possibilidade de conversão do tempo de serviço comum para especial, mediante a aplicação do fator 0,71 de conversão, nas hipóteses em que o trabalho fora prestado em período anterior à Lei n. 9.032/1995, para fins de concessão de aposentadoria especial com data de início posterior à essa legislação, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-945", tribunal: "STF", tipo: "Repercussão Geral", numero: "945", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Possibilidade de extensão automática, considerando a equiparação do Decreto-lei n. 288/1967, do benefício fiscal do programa Reintegra (Lei n. 12.546/2011) às receitas oriundas de vendas efetivadas para a Zona Franca de Manaus.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=945",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à inclusão das receitas de vendas para a Zona Franca de Manaus na base de cálculo do REINTEGRA com amparo no Decreto-Lei nº 288/1967 e na Lei nº 12.546/2011." },
  { id: "stf-rg-946", tribunal: "STF", tipo: "Repercussão Geral", numero: "946", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Legitimidade dos Ministérios Públicos dos Estados e do Distrito Federal para propor e atuar em recursos e meios de impugnação de decisões judiciais em trâmite no Supremo Tribunal Federal e no Superior Tribunal de Justiça, oriundos de processos de sua atribuição, sem prejuízo da atuação do Ministério Público Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=946",
    texto: "Os Ministérios Públicos dos Estados e do Distrito Federal têm legitimidade para propor e atuar em recursos e meios de impugnação de decisões judiciais em trâmite no STF e no STJ, oriundos de processos de sua atribuição, sem prejuízo da atuação do Ministério Público Federal." },
  { id: "stf-rg-947", tribunal: "STF", tipo: "Repercussão Geral", numero: "947", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Imunidade de jurisdição dos organismos internacionais garantida por tratado firmado pelo Brasil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=947",
    texto: "O organismo internacional que tenha garantida a imunidade de jurisdição em tratado firmado pelo Brasil e internalizado na ordem jurídica brasileira não pode ser demandado em juízo, salvo em caso de renúncia expressa a essa imunidade." },
  { id: "stf-rg-948", tribunal: "STF", tipo: "Repercussão Geral", numero: "948", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Possibilidade de configuração de bitributação na instituição da Contribuição Sindical Rural pelo Decreto-Lei n. 1.166/1971.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=948",
    texto: "A Contribuição Sindical Rural, instituída pelo Decreto-Lei 1.166/1971, foi recepcionada pela ordem constitucional vigente e não configura hipótese de bitributação." },
  { id: "stf-rg-949", tribunal: "STF", tipo: "Repercussão Geral", numero: "949", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Progressão funcional de empregado que retorna ao serviço por ter sido reconhecida sua condição de anistiado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=949",
    texto: "A questão da progressão funcional de empregado que retorna ao serviço por ter sido reconhecida sua condição de anistiado tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE n. 584.608, rel. a Ministra Ellen Gracie, DJe 13/03/2009." },
  { id: "stf-rg-951", tribunal: "STF", tipo: "Repercussão Geral", numero: "951", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito dos servidores federais às diferenças relacionadas ao reajuste de 47,11% sobre a parcela denominada adiantamento do PCCS (adiantamento pecuniário) após a mudança para o regime estatutário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=951",
    texto: "Servidores que tiveram relação jurídica regida pela Consolidação das Leis do Trabalho, modificada considerado o Regime Jurídico Único, têm direito à diferença remuneratória decorrente do plano de cargos e salários - PCCS." },
  { id: "stf-rg-954", tribunal: "STF", tipo: "Repercussão Geral", numero: "954", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Retroatividade dos efeitos da promoção de servidor público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=954",
    texto: "Não tem repercussão geral a controvérsia relativa à retroatividade da promoção de servidor público, por depender do exame de normas atinentes a cada carreira do serviço público." },
  { id: "stf-rg-955", tribunal: "STF", tipo: "Repercussão Geral", numero: "955", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Composição da base de cálculo do Fundo de Garantia do Tempo de Serviço (FGTS).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=955",
    texto: "Não possui repercussão geral, em virtude de sua natureza infraconstitucional, a discussão acerca da definição da base de cálculo do Fundo de Garantia por Tempo de Serviço (FGTS)." },
  { id: "stf-rg-956", tribunal: "STF", tipo: "Repercussão Geral", numero: "956", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Inclusão da Tarifa de Uso do Sistema de Transmissão (TUST) e da Tarifa de Uso do Sistema de Distribuição (TUSD) na base de cálculo do Imposto sobre Circulação de Mercadorias (ICMS) incidente sobre energia elétrica.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=956",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa a inclusão dos valores pagos a título de Tarifa de Uso do Sistema de Transmissão (TUST) e Tarifa de Uso do Sistema de Distribuição (TUSD) na base de cálculo do ICMS incidente sobre a circulação de energia elétrica." },
  { id: "stf-rg-957", tribunal: "STF", tipo: "Repercussão Geral", numero: "957", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Inclusão de crédito presumido de ICMS, decorrente de incentivo fiscal estadual, na base de cálculo do IRPJ e da CSLL.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=957",
    texto: "A controvérsia relativa à inclusão de créditos presumidos de ICMS na base de cálculo do IRPJ e da CSLL não possui repercussão geral, tendo em vista sua natureza infraconstitucional." },
  { id: "stf-rg-958", tribunal: "STF", tipo: "Repercussão Geral", numero: "958", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aplicação do art. 2º, § 4º, da Lei federal n. 11.738/2008, que dispõe sobre a composição da carga horária do magistério público nos três níveis da Federação.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=958",
    texto: "É constitucional a norma geral federal que reserva fração mínima de um terço da carga horária dos professores da educação básica para dedicação às atividades extraclasse." },
  { id: "stf-rg-959", tribunal: "STF", tipo: "Repercussão Geral", numero: "959", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Concessão de liberdade provisória a preso em flagrante pela prática dos crimes descritos nos arts. 33, caput e § 1º e 34 a 37 da Lei n. 11.343/2006.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=959",
    texto: "É inconstitucional a expressão \"e liberdade provisória\", constante do caput do artigo 44 da Lei nº 11.343/2006." },
  { id: "stf-rg-963", tribunal: "STF", tipo: "Repercussão Geral", numero: "963", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do Imposto sobre Produtos Industrializados - IPI, de forma proporcional, na importação, pelo regime de admissão temporária, de produtos objeto de arrendamento mercantil.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=963",
    texto: "A controvérsia relativa à incidência proporcional do IPI na importação de bens para utilização econômica sob o regime de admissão temporária previsto no art. 79 da Lei nº 9.430/1996, e em seus regulamentos, não possui repercussão geral, tendo em vista sua natureza infraconstitucional." },
  { id: "stf-rg-965", tribunal: "STF", tipo: "Repercussão Geral", numero: "965", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Aposentadoria especial prevista no art. 40, § 5º, da Constituição: cômputo do tempo de serviço prestado por professor na escola em funções diversas da docência.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=965",
    texto: "Para a concessão da aposentadoria especial de que trata o art. 40, § 5º, da Constituição, conta-se o tempo de efetivo exercício, pelo professor, da docência e das atividades de direção de unidade escolar e de coordenação e assessoramento pedagógico, desde que em estabelecimentos de educação infantil ou de ensino fundamental e médio." },
  { id: "stf-rg-967", tribunal: "STF", tipo: "Repercussão Geral", numero: "967", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Proibição do uso de carros particulares para o transporte remunerado individual de pessoas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=967",
    texto: "1. A proibição ou restrição da atividade de transporte privado individual por motorista cadastrado em aplicativo é inconstitucional, por violação aos princípios da livre iniciativa e da livre concorrência; e 2. No exercício de sua competência para regulamentação e fiscalização do transporte privado individual de passageiros, os Municípios e o Distrito Federal não podem contrariar os parâmetros fixados pelo legislador federal (CF/1988, art. 22, XI)." },
  { id: "stf-rg-972", tribunal: "STF", tipo: "Repercussão Geral", numero: "972", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Possibilidade de fixação de regime inicial fechado para cumprimento de pena, com base unicamente na natureza hedionda do delito.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=972",
    texto: "É inconstitucional a fixação ex lege, com base no art. 2º, § 1º, da Lei 8.072/1990, do regime inicial fechado, devendo o julgador, quando da condenação, ater-se aos parâmetros previstos no artigo 33 do Código Penal." },
  { id: "stf-rg-973", tribunal: "STF", tipo: "Repercussão Geral", numero: "973", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de remarcação do teste de aptidão física de candidata grávida à época de sua realização, independentemente de haver previsão expressa nesse sentido no edital do concurso público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=973",
    texto: "É constitucional a remarcação do teste de aptidão física de candidata que esteja grávida à época de sua realização, independentemente da previsão expressa em edital do concurso público." },
  { id: "stf-rg-978", tribunal: "STF", tipo: "Repercussão Geral", numero: "978", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Possibilidade de fixação dos honorários do defensor dativo, em processo penal, a partir da tabela de valores do Conselho Seccional da Ordem dos Advogados do Brasil, conforme previsto no § 1º do art. 22 da Lei n. 8.906/1994.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=978",
    texto: "Não possui repercussão geral, em virtude de sua natureza infraconstitucional, a discussão a respeito da fixação, à luz do § 1º do art. 22 da Lei nº 8.906/94, de honorários advocatícios de defensor dativo a partir da tabela de valores de Conselho Seccional da Ordem dos Advogados do Brasil." },
  { id: "stf-rg-981", tribunal: "STF", tipo: "Repercussão Geral", numero: "981", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Necessidade de licitação específica para a criação de nova praça de pedágio no entroncamento das rodovias federais BR-153 e BR-369.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=981",
    texto: "A questão da criação de nova praça de pedágio, sem licitação específica, no entroncamento das rodovias federais BR-153 e BR-369, cujas concessões foram devidamente licitadas, tem natureza infraconstitucional, e a ela se atribuem os efeitos da ausência de repercussão geral, nos termos do precedente fixado no RE 584.608, rel. Min. Ellen Gracie, Dje de 13/3/2009." },
  { id: "stf-rg-983", tribunal: "STF", tipo: "Repercussão Geral", numero: "983", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Gratificações federais de desempenho: (I) termo final do pagamento equiparado entre ativos e inativos e (II) redução do valor pago aos aposentados e pensionistas e princípio da irredutibilidade de vencimentos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=983",
    texto: "I - O termo inicial do pagamento diferenciado das gratificações de desempenho entre servidores ativos e inativos é o da data da homologação do resultado das avaliações, após a conclusão do primeiro ciclo; II - A redução, após a homologação do resultado das avaliações, do valor da gratificação de desempenho paga aos inativos e pensionistas não configura ofensa ao princípio da irredutibilidade de vencimentos." },
  { id: "stf-rg-984", tribunal: "STF", tipo: "Repercussão Geral", numero: "984", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Natureza jurídica dos reajustes concedidos aos servidores da carreira militar pela Lei n. 7.622/2000, do Estado da Bahia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=984",
    texto: "O Supremo Tribunal Federal veda o aumento de vencimentos pelo Poder Judiciário com base no princípio da isonomia, na equiparação salarial ou a pretexto da revisão geral anual, não sendo devida, portanto, a extensão do maior reajuste concedido pela Lei estadual nº 7.622/2000 aos soldos de toda a categoria dos policiais militares do Estado da Bahia, dispensada a devolução de valores eventualmente recebidos de boa-fé até a data de conclusão do presente julgamento no Plenário Virtual desta Corte." },
  { id: "stf-rg-985", tribunal: "STF", tipo: "Repercussão Geral", numero: "985", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Natureza jurídica do terço constitucional de férias, indenizadas ou gozadas, para fins de incidência da contribuição previdenciária patronal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=985",
    texto: "É legítima a incidência de contribuição social sobre o valor satisfeito a título de terço constitucional de férias." },
  { id: "stf-rg-986", tribunal: "STF", tipo: "Repercussão Geral", numero: "986", situacao: "Vigente", tema: "DIREITO ELEITORAL", titulo: "Discussão acerca da constitucionalidade do § 3º do artigo 224 do Código Eleitoral no tocante à necessidade de realização de novas eleições sempre que ocorrer o indeferimento do registro de candidatura, em pleito majoritário, independentemente do número de votos então anulados.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=986",
    texto: "É constitucional, à luz dos arts. 1º, inc. I e parágrafo único, 5º, inc. LIV, e 14, caput e § 9º, da Constituição da República, o § 3º do artigo 224 do Código Eleitoral, com a redação dada pela Lei 13.165/2015, no que determina a realização automática de novas eleições, independentemente do número de votos anulados, sempre que o candidato eleito, em pleito majoritário, for desclassificado, por indeferimento do registro de sua candidatura, ou em virtude de cassação do diploma ou mandato." },
  { id: "stf-rg-990", tribunal: "STF", tipo: "Repercussão Geral", numero: "990", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Possibilidade de compartilhamento com o Ministério Público, para fins penais, dos dados bancários e fiscais do contribuinte, obtidos pela Receita Federal no legítimo exercício de seu dever de fiscalizar, sem autorização prévia do Poder Judiciário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=990",
    texto: "1. É constitucional o compartilhamento dos relatórios de inteligência financeira da UIF e da íntegra do procedimento fiscalizatório da Receita Federal do Brasil, que define o lançamento do tributo, com os órgãos de persecução penal para fins criminais, sem a obrigatoriedade de prévia autorização judicial, devendo ser resguardado o sigilo das informações em procedimentos formalmente instaurados e sujeitos a posterior controle jurisdicional. 2. O compartilhamento pela UIF e pela RFB, referente ao item anterior, deve ser feito unicamente por meio de comunicações formais, com garantia de sigilo, certificação do destinatário e estabelecimento de instrumentos efetivos de apuração e correção de eventuais desvios." },
  { id: "stf-rg-992", tribunal: "STF", tipo: "Repercussão Geral", numero: "992", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Discussão quanto à competência para processar e julgar controvérsias nas quais se pleiteiam questões afetas à fase pré-contratual de seleção e de admissão de pessoal e eventual nulidade do certame, em face de pessoa jurídica de direito privado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=992",
    texto: "Compete à Justiça comum processar e julgar controvérsias relacionadas à fase pré-contratual de seleção e de admissão de pessoal e eventual nulidade do certame em face da Administração Pública, direta e indireta, nas hipóteses em que adotado o regime celetista de contratação de pessoal." },
  { id: "stf-rg-993", tribunal: "STF", tipo: "Repercussão Geral", numero: "993", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Controvérsia relativa à definição da base de cálculo do Imposto sobre Transmissão de Bens Imóveis – ITBI.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=993",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à base de cálculo aplicada ao ITBI fundada na interpretação da legislação local, no Código Tributário Nacional e no princípio da legalidade." },
  { id: "stf-rg-996", tribunal: "STF", tipo: "Repercussão Geral", numero: "996", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Possibilidade de revisão de benefício previdenciário pelo valor nominal do reajuste do salário mínimo, sempre que mais vantajoso que o reajuste nominal dos demais benefícios.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=996",
    texto: "Não encontra amparo no Texto Constitucional revisão de benefício previdenciário pelo valor nominal do salário mínimo." },
  { id: "stf-rg-997", tribunal: "STF", tipo: "Repercussão Geral", numero: "997", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Controvérsia relativa à legitimidade de entidade sindical para o recebimento de contribuição sindical patronal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=997",
    texto: "São infraconstitucionais as discussões relativas a contribuições, registro, legitimidade ou cisões das entidades sindicais." },
  { id: "stf-rg-999", tribunal: "STF", tipo: "Repercussão Geral", numero: "999", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Imprescritibilidade da pretensão de reparação civil de dano ambiental.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=999",
    texto: "É imprescritível a pretensão de reparação civil de dano ambiental." },
  { id: "stf-rg-1005", tribunal: "STF", tipo: "Repercussão Geral", numero: "1005", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Possibilidade de reconhecimento de relação empregatícia a advogado com vínculo societário em escritório de advocacia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1005",
    texto: "São infraconstitucionais as discussões relativas ao reconhecimento de relação empregatícia a advogado com vínculo societário em escritório de advocacia." },
  { id: "stf-rg-1006", tribunal: "STF", tipo: "Repercussão Geral", numero: "1006", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Aplicação de juros de mora e de multa moratória sobre créditos de contribuição previdenciária atrelados a sentença trabalhista ou a acordo homologado judicialmente, considerado o momento da ocorrência do fato gerador da obrigação tributária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1006",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à aplicação de juros de mora e de multa moratória sobre créditos de contribuição previdenciária atrelados a sentença trabalhista ou a acordo homologado judicialmente, considerado o momento da ocorrência do fato gerador da obrigação tributária." },
  { id: "stf-rg-1008", tribunal: "STF", tipo: "Repercussão Geral", numero: "1008", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Incorporação do adicional de interiorização devido pela prestação de serviço militar no interior do Estado.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1008",
    texto: "Não tem repercussão geral a controvérsia relativa à incorporação do adicional de interiorização devido pela prestação de serviço público por policial militar no interior do Estado, por ser indispensável o exame de normas estaduais que regem a respectiva parcela remuneratória." },
  { id: "stf-rg-1009", tribunal: "STF", tipo: "Repercussão Geral", numero: "1009", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Realização de novo exame psicotécnico em candidato que teve o primeiro teste anulado por ausência de objetividade dos critérios de correção estabelecidos no edital.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1009",
    texto: "No caso de declaração de nulidade de exame psicotécnico previsto em lei e em edital, é indispensável a realização de nova avaliação, com critérios objetivos, para prosseguimento no certame." },
  { id: "stf-rg-1010", tribunal: "STF", tipo: "Repercussão Geral", numero: "1010", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Controvérsia relativa aos requisitos constitucionais (art. 37, incs. II e V, da Constituição da República) para a criação de cargos em comissão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1010",
    texto: "a) A criação de cargos em comissão somente se justifica para o exercício de funções de direção, chefia e assessoramento, não se prestando ao desempenho de atividades burocráticas, técnicas ou operacionais; b) tal criação deve pressupor a necessária relação de confiança entre a autoridade nomeante e o servidor nomeado; c) o número de cargos comissionados criados deve guardar proporcionalidade com a necessidade que eles visam suprir e com o número de servidores ocupantes de cargos efetivos no ente federativo que os criar; e d) as atribuições dos cargos em comissão devem estar descritas, de forma clara e objetiva, na própria lei que os instituir." },
  { id: "stf-rg-1011", tribunal: "STF", tipo: "Repercussão Geral", numero: "1011", situacao: "Vigente", tema: "DIREITO CIVIL", titulo: "Controvérsia relativa à existência de interesse jurídico da Caixa Econômica Federal para ingressar como parte ou terceira interessada nas ações envolvendo seguros de mútuo habitacional no âmbito do Sistema Financeiro de Habitação e, consequentemente, à competência da Justiça Federal para o processamento e o julgamento das ações dessa natureza.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1011",
    texto: "1) Considerando que, a partir da MP 513/2010 (que originou a Lei 12.409/2011 e suas alterações posteriores, MP 633/2013 e Lei 13.000/2014), a CEF passou a ser administradora do FCVS, é aplicável o art. 1º da MP 513/2010 aos processos em trâmite na data de sua entrada em vigor (26.11.2010): 1.1.) sem sentença de mérito (na fase de conhecimento), devendo os autos ser remetidos à Justiça Federal para análise do preenchimento dos requisitos legais acerca do interesse da CEF ou da União, caso haja provocação nesse sentido de quaisquer das partes ou intervenientes e respeitado o § 4º do art. 1º-A da Lei 12.409/2011; e 1.2) com sentença de mérito (na fase de conhecimento), podendo a União e/ou a CEF intervir na causa na defesa do FCVS, de forma espontânea ou provocada, no estágio em que se encontre, em qualquer tempo e grau de jurisdição, nos termos do parágrafo único do art. 5º da Lei 9.469/1997, devendo o feito continuar tramitando na Justiça Comum Estadual até o exaurimento do cumprimento de sentença; e 2) Após 26.11.2010, é da Justiça Federal a competência para o processamento e julgamento das causas em que se discute contrato de seguro vinculado à apólice pública, na qual a CEF atue em defesa do FCVS, devendo haver o deslocamento do feito para aquele ramo judiciário a partir do momento em que a referida empresa pública federal ou a União, de forma espontânea ou provocada, indique o interesse em intervir na causa, observado o § 4º do art. 64 do CPC e/ou o § 4º do art. 1º-A da Lei 12.409/2011." },
  { id: "stf-rg-1012", tribunal: "STF", tipo: "Repercussão Geral", numero: "1012", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Controvérsia relativa à incidência do Imposto sobre Circulação de Mercadorias e Serviços – ICMS - na venda de automóveis integrantes do ativo imobilizado de empresas locadoras de veículos adquiridos diretamente das montadoras, independentemente de a compra ter ocorrido em prazo inferior a um ano.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1012",
    texto: "É constitucional a incidência do ICMS sobre a operação de venda, realizada por locadora de veículos, de automóvel com menos de 12 (doze) meses de aquisição da montadora." },
  { id: "stf-rg-1014", tribunal: "STF", tipo: "Repercussão Geral", numero: "1014", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Controvérsia relativa à definição da base de cálculo do Imposto sobre Transmissão Causa Mortis e Doação de quaisquer Bens ou Direitos (ITCMD).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1014",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à base de cálculo aplicada ao Imposto sobre Transmissão Causa Mortis e Doação de quaisquer Bens ou Direitos (ITCMD) fundada na interpretação da legislação local, no Código Tributário Nacional e no princípio da legalidade." },
  { id: "stf-rg-1017", tribunal: "STF", tipo: "Repercussão Geral", numero: "1017", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Critérios legais de aferição da renda do segurado, para fins de percepção do benefício do auxílio-reclusão.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1017",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia sobre os critérios legais de aferição da renda do segurado, para fins de percepção do benefício do auxílio-reclusão." },
  { id: "stf-rg-1018", tribunal: "STF", tipo: "Repercussão Geral", numero: "1018", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Supressão da correção monetária das demonstrações financeiras determinada pelo art. 4º da Lei nº 9.249/95.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1018",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa i) à supressão da correção monetária das demonstrações financeiras pelo art. 4º da Lei nº 9.249/95 e ii) à consequência disso na apuração do imposto de renda das pessoas jurídicas (IRPJ) e da contribuição social sobre o lucro líquido (CSLL)." },
  { id: "stf-rg-1023", tribunal: "STF", tipo: "Repercussão Geral", numero: "1023", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Situações abrangidas pelo prazo decadencial previsto no art. 103 da Lei nº 8.213/91, tendo em vista a interpretação do termo revisão contido no referido dispositivo legal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1023",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa às situações abrangidas pelo prazo decadencial previsto no art. 103 da Lei nº 8.213/91 fundada na interpretação do termo revisão contido no referido dispositivo legal." },
  { id: "stf-rg-1025", tribunal: "STF", tipo: "Repercussão Geral", numero: "1025", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Possibilidade de execução de parcelas vencidas de benefício previdenciário reconhecido judicialmente anteriores à implantação de benefício concedido na esfera administrativa.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1025",
    texto: "É infraconstitucional e fundada em fatos e provas, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à possibilidade de execução de parcelas vencidas de benefício previdenciário reconhecido judicialmente anteriores à implantação de benefício concedido na esfera administrativa." },
  { id: "stf-rg-1026", tribunal: "STF", tipo: "Repercussão Geral", numero: "1026", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Termo inicial para percepção do benefício de auxílio-transporte pelos servidores públicos do Estado de Rondônia.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1026",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa ao termo inicial para percepção do auxílio-transporte pelos servidores públicos do Estado de Rondônia." },
  { id: "stf-rg-1027", tribunal: "STF", tipo: "Repercussão Geral", numero: "1027", situacao: "Vigente", tema: "DIREITO DO TRABALHO", titulo: "Extensão dos reajustes fixados pelo Conselho de Reitores das Universidades do Estado de São Paulo (Cruesp) aos empregados das instituições de ensino autônomas vinculadas às universidades estaduais paulistas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1027",
    texto: "A extensão, pelo Poder Judiciário, das verbas e vantagens concedidas pelo Conselho de Reitores das Universidades do Estado de São Paulo (Cruesp) aos empregados das instituições de ensino autônomas vinculadas às universidades estaduais paulistas contraria o disposto na Súmula Vinculante 37." },
  { id: "stf-rg-1028", tribunal: "STF", tipo: "Repercussão Geral", numero: "1028", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Aferição dos requisitos legais para a concessão do benefício previdenciário da pensão por morte.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1028",
    texto: "É infraconstitucional e fundada na análise de fatos e provas, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia atinente à aferição dos requisitos legais para a concessão do benefício previdenciário da pensão por morte." },
  { id: "stf-rg-1029", tribunal: "STF", tipo: "Repercussão Geral", numero: "1029", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Contagem do tempo de licença para tratamento de saúde e de faltas atestadas por médicos como de efetivo exercício para fins de aposentadoria e disponibilidade de servidor público.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1029",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia fundada na interpretação de lei local relativa à contagem do tempo de licença para tratamento de saúde como de efetivo exercício para fins de aposentadoria e disponibilidade de servidor público." },
  { id: "stf-rg-1030", tribunal: "STF", tipo: "Repercussão Geral", numero: "1030", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Definição do termo inicial do prazo para a propositura da ação rescisória em casos de alegada fraude contra o Erário e contra a administração da Justiça.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1030",
    texto: "É infraconstitucional, a ela aplicando-se os efeitos da ausência de repercussão geral, controvérsia acerca do termo inicial para o ajuizamento de ação rescisória, quando a decisão transitada em julgado, supostamente, foi proferida com fraude ao erário e à administração da Justiça." },
  { id: "stf-rg-1037", tribunal: "STF", tipo: "Repercussão Geral", numero: "1037", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Incidência de juros da mora no período compreendido entre a data da expedição do precatório ou da requisição de pequeno valor (RPV) e o efetivo pagamento.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1037",
    texto: "O enunciado da Súmula Vinculante 17 não foi afetado pela superveniência da Emenda Constitucional 62/2009, de modo que não incidem juros de mora no período de que trata o § 5º do art. 100 da Constituição. Havendo o inadimplemento pelo ente público devedor, a fluência dos juros inicia-se após o 'período de graça." },
  { id: "stf-rg-1038", tribunal: "STF", tipo: "Repercussão Geral", numero: "1038", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Reconhecimento de adicional noturno constante da legislação civil a servidores militares estaduais, sem previsão expressa do direito na Constituição Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1038",
    texto: "I - A Constituição Federal não prevê adicional noturno aos Militares Estaduais ou Distritais. II - Mandado de Injunção será cabível para que se apliquem, aos militares estaduais, as normas que regulamentam o adicional noturno dos servidores públicos civis, desde que o direito a tal parcela remuneratória esteja expressamente previsto na Constituição Estadual ou na Lei Orgânica do Distrito Federal." },
  { id: "stf-rg-1041", tribunal: "STF", tipo: "Repercussão Geral", numero: "1041", situacao: "Vigente", tema: "DIREITO PROCESSUAL PENAL", titulo: "Admissibilidade, no âmbito do processo penal, de prova obtida por meio de abertura de encomenda postada nos Correios, ante a inviolabilidade do sigilo das correspondências.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1041",
    texto: "Sem autorização judicial ou fora das hipóteses legais, é ilícita a prova obtida mediante abertura de carta, telegrama, pacote ou meio análogo." },
  { id: "stf-rg-1044", tribunal: "STF", tipo: "Repercussão Geral", numero: "1044", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Legitimidade do Ministério Público de Contas para impetrar mandado de segurança contra julgado do Tribunal de Contas perante o qual atua.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1044",
    texto: "O Ministério Público de Contas não tem legitimidade para impetrar mandado de segurança em face de acórdão do Tribunal de Contas perante o qual atua." },
  { id: "stf-rg-1045", tribunal: "STF", tipo: "Repercussão Geral", numero: "1045", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Existência de justo título de propriedade, por parte da União, das terras localizadas na gleba Rio Anil, situada na Ilha Upaon-Açu (Ilha de São Luís, Maranhão), para efeito de cobrança de foro, laudêmio ou taxa de ocupação após a Emenda Constitucional nº 46/05.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1045",
    texto: "É infraconstitucional e demanda o reexame do conjunto fático e probatório, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à aferição, para efeito de cobrança de foro, laudêmio ou taxa de ocupação após a EC nº 46/05, dos elementos hábeis a corroborar a prévia existência de justo título de propriedade por parte da União das terras localizadas na gleba Rio Anil, situada na ilha Upaon-açu (ilha de São Luís - Maranhão)." },
  { id: "stf-rg-1049", tribunal: "STF", tipo: "Repercussão Geral", numero: "1049", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de técnico em farmácia assumir responsabilidade por drogaria, após a vigência da Lei nº 13.021/2014.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1049",
    texto: "Surgem constitucionais os artigos 5º e 6º, inciso I, da Lei nº 13.021/2014, no que previsto ser do farmacêutico a responsabilidade técnica por drogaria." },
  { id: "stf-rg-1057", tribunal: "STF", tipo: "Repercussão Geral", numero: "1057", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Concessão de aposentadoria especial a guarda civil municipal com base no art. 40, § 4º, inciso II, da Constituição Federal, que prevê ser possível, por meio de lei complementar, a adoção de requisitos e critérios diferenciados para a concessão de aposentadoria para servidores que exerçam atividades de risco.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1057",
    texto: "Os guardas civis não possuem direito constitucional à aposentadoria especial por exercício de atividade de risco prevista no artigo 40, § 4º, inciso II, da Constituição Federal." },
  { id: "stf-rg-1058", tribunal: "STF", tipo: "Repercussão Geral", numero: "1058", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Definição das situações abrangidas pelo prazo prescricional previsto no art. 1º da Lei nº 7.515/86.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1058",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa às situações abrangidas pelo prazo prescricional previsto no art. 1º da Lei nº 7.515/86." },
  { id: "stf-rg-1059", tribunal: "STF", tipo: "Repercussão Geral", numero: "1059", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Concessão de diferenças salariais aos servidores do Município de Mogi Guaçu por decisão judicial em razão da incorporação de valores a seus vencimentos determinada pelas Leis Complementares municipais nºs 1.000/09 e 1.121/11.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1059",
    texto: "Viola o teor da Súmula Vinculante nº 37 a concessão, por decisão judicial, de diferenças salariais em razão da incorporação de valores aos vencimentos dos servidores públicos municipais de que trata as Leis Complementares nºs 1.000/2009 e 1.121/2011 do Município de Mogi-Guaçu." },
  { id: "stf-rg-1060", tribunal: "STF", tipo: "Repercussão Geral", numero: "1060", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Controvérsia relativa a procedimentos, critérios e requisitos para a restituição de imposto ou contribuição pago a maior no regime de substituição tributária progressiva.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1060",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia fundada na interpretação de legislação infraconstitucional que estabeleça procedimentos, critérios e requisitos para se postular a restituição do valor de imposto ou contribuição recolhido a maior no regime de substituição tributária 'para a frente' quando a base de cálculo real for inferior à presumida." },
  { id: "stf-rg-1061", tribunal: "STF", tipo: "Repercussão Geral", numero: "1061", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Concessão de diferenças salariais relativas a 13,23% a servidor público federal por meio de decisão judicial tendo em vista a instituição da vantagem pecuniária individual (VPI) pela Lei nº 10.698/03.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1061",
    texto: "A concessão, por decisão judicial, de diferenças salariais relativas a 13,23% a servidores públicos federais, sem o devido amparo legal, viola o teor da Súmula Vinculante nº 37." },
  { id: "stf-rg-1062", tribunal: "STF", tipo: "Repercussão Geral", numero: "1062", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Possibilidade de os estados da Federação e o Distrito Federal fixarem índices de correção monetária e taxas de juros de mora para seus créditos tributários.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1062",
    texto: "Os estados-membros e o Distrito Federal podem legislar sobre índices de correção monetária e taxas de juros de mora incidentes sobre seus créditos fiscais, limitando-se, porém, aos percentuais estabelecidos pela União para os mesmos fins." },
  { id: "stf-rg-1064", tribunal: "STF", tipo: "Repercussão Geral", numero: "1064", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Condenação de ente público ao pagamento de honorários advocatícios sucumbenciais em favor de defensoria pública vinculada a ente diverso.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1064",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia fundada na possibilidade de condenação de ente público ao pagamento de honorários advocatícios sucumbenciais em favor de defensoria pública vinculada a ente federado diverso." },
  { id: "stf-rg-1065", tribunal: "STF", tipo: "Repercussão Geral", numero: "1065", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Constitucionalidade da contribuição previdenciária devida por aposentado pelo Regime Geral de Previdência Social (RGPS) que permaneça em atividade ou a essa retorne.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1065",
    texto: "É constitucional a contribuição previdenciária devida por aposentado pelo Regime Geral de Previdência Social (RGPS) que permaneça em atividade ou a essa retorne." },
  { id: "stf-rg-1070", tribunal: "STF", tipo: "Repercussão Geral", numero: "1070", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência para denominação de ruas, próprios, vias e logradouros públicos e suas alterações.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1070",
    texto: "É comum aos poderes Executivo (decreto) e Legislativo (lei formal) a competência destinada a denominação de próprios, vias e logradouros públicos e suas alterações, cada qual no âmbito de suas atribuições." },
  { id: "stf-rg-1076", tribunal: "STF", tipo: "Repercussão Geral", numero: "1076", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Responsabilidade civil da União, do Estado do Paraná e da Fundação Faculdade Vizinhança Vale do Iguaçu (VIZIVALI) por danos decorrentes de demora ou negativa de entrega de diplomas ou certificados de conclusão de cursos superiores ministrados pela entidade de ensino no âmbito de programa estadual de capacitação docente.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1076",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à responsabilização, em esfera cível, da União, do Estado do Paraná e da Fundação Faculdade Vizinhança Vale do Iguaçu (VIZIVALI) pela demora ou negativa de entrega de diplomas ou certificados de conclusão de curso superior ministrado por entidade privada de ensino no âmbito de programa estadual de capacitação docente." },
  { id: "stf-rg-1077", tribunal: "STF", tipo: "Repercussão Geral", numero: "1077", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Competência do Departamento Nacional de Infraestrutura de Transportes (DNIT) para fiscalizar o trânsito nas rodovias e estradas federais e, nesse âmbito, aplicar penalidade por infração ao Código de Trânsito Brasileiro (CTB).", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1077",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à competência do Departamento Nacional de Infraestrutura de Transportes (DNIT) para fiscalizar o trânsito nas rodovias e estradas federais e para, nesse âmbito, aplicar penalidade por infração ao Código de Trânsito Brasileiro (CTB)." },
  { id: "stf-rg-1078", tribunal: "STF", tipo: "Repercussão Geral", numero: "1078", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Exigibilidade de verba por lotação em unidade estratégica (adicional de fronteira), prevista na Lei nº 12.855/13, enquanto não houver regulamentação da norma pelo Poder Executivo Federal.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1078",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia à relativa exigibilidade de verba por lotação em unidade estratégica (adicional de fronteira) prevista na Lei nº 12.855/13 enquanto ausente sua regulamentação pelo Poder Executivo federal." },
  { id: "stf-rg-1081", tribunal: "STF", tipo: "Repercussão Geral", numero: "1081", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Possibilidade de acumulação remunerada de cargos públicos, na forma do art. 37, inciso XVI, da Constituição Federal, quando há compatibilidade de horários.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1081",
    texto: "As hipóteses excepcionais autorizadoras de acumulação de cargos públicos previstas na Constituição Federal sujeitam-se, unicamente, a existência de compatibilidade de horários, verificada no caso concreto, ainda que haja norma infraconstitucional que limite a jornada semanal." },
  { id: "stf-rg-1082", tribunal: "STF", tipo: "Repercussão Geral", numero: "1082", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito à integralidade no pagamento de gratificação de desempenho de natureza pro labore faciendo recebida em atividade por servidor que se aposentou no regime do artigo 3º da Emenda Constitucional nº 47/05.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1082",
    texto: "As gratificações de natureza pro labore faciendo são incorporadas à aposentadoria conforme as normas de regência de cada uma delas, não caracterizando ofensa ao direito à integralidade a incorporação em valor inferior ao da última remuneração recebida em atividade por servidor que se aposentou nos termos do art. 3º da Emenda Constitucional nº 47/2005." },
  { id: "stf-rg-1085", tribunal: "STF", tipo: "Repercussão Geral", numero: "1085", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Majoração de taxa tributária realizada por ato infralegal a partir de delegação legislativa e viabilidade de o Poder Executivo atualizar os valores fixados em lei, de acordo com percentual não superior aos índices oficiais de correção monetária.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1085",
    texto: "A inconstitucionalidade de majoração excessiva de taxa tributária fixada em ato infralegal a partir de delegação legislativa defeituosa não conduz à invalidade do tributo nem impede que o Poder Executivo atualize os valores previamente fixados em lei de acordo com percentual não superior aos índices oficiais de correção monetária." },
  { id: "stf-rg-1088", tribunal: "STF", tipo: "Repercussão Geral", numero: "1088", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Obrigatoriedade de realização de prévio procedimento licitatório para outorga de serviços de radiodifusão com fins exclusivamente educativos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1088",
    texto: "São infraconstitucionais as discussões relativas à obrigatoriedade de realização de licitação para outorga de serviços de radiodifusão com fins exclusivamente educativos." },
  { id: "stf-rg-1089", tribunal: "STF", tipo: "Repercussão Geral", numero: "1089", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Natureza de gratificações ou outras vantagens remuneratórias concedidas a servidores ativos estaduais, municipais ou distritais para fins de incorporação aos proventos de servidores inativos e pensionistas.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1089",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à definição da natureza jurídica de gratificações ou outras vantagens remuneratórias concedidas aos servidores ativos estaduais, municipais ou distritais para fins de incorporação aos proventos de servidores inativos e pensionistas." },
  { id: "stf-rg-1090", tribunal: "STF", tipo: "Repercussão Geral", numero: "1090", situacao: "Vigente", tema: "DIREITO ADMINISTRATIVO E OUTRAS MATÉRIAS DE DIREITO PÚBLICO", titulo: "Direito de férias de sessenta dias por ano aos Procuradores da Fazenda Nacional.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1090",
    texto: "Os Procuradores da Fazenda Nacional não possuem direito a férias de 60 (sessenta) dias, nos termos da legislação constitucional e infraconstitucional vigentes." },
  { id: "stf-rg-1091", tribunal: "STF", tipo: "Repercussão Geral", numero: "1091", situacao: "Vigente", tema: "DIREITO PREVIDENCIÁRIO", titulo: "Constitucionalidade do fator previdenciário, previsto no art. 29, caput, incisos e parágrafos, da Lei nº 8.213/91, com a redação dada pelo art. 2º da Lei nº 9.876/99.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1091",
    texto: "É constitucional o fator previdenciário previsto no art. 29, caput, incisos e parágrafos, da Lei nº 8.213/91, com a redação dada pelo art. 2º da Lei nº 9.876/99." },
  { id: "stf-rg-1092", tribunal: "STF", tipo: "Repercussão Geral", numero: "1092", situacao: "Vigente", tema: "DIREITO PROCESSUAL CIVIL E DO TRABALHO", titulo: "Competência para processar e julgar demandas sobre complementação de aposentadoria instituída por lei, cuja responsabilidade pelo pagamento recaia diretamente sobre a Administração Pública direta ou indireta.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1092",
    texto: "Compete à Justiça comum processar e julgar causas sobre complementação de aposentadoria instituída por lei cujo pagamento seja, originariamente ou por sucessão, da responsabilidade da Administração Pública direta ou indireta, por derivar essa responsabilidade de relação jurídico-administrativa." },
  { id: "stf-rg-1094", tribunal: "STF", tipo: "Repercussão Geral", numero: "1094", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência do ICMS na importação de bens e mercadorias por pessoa física ou jurídica com base em lei estadual editada posteriormente à promulgação da EC nº 33/2001, porém antes da vigência da Lei Complementar Federal nº 114/2002.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1094",
    texto: "I - Após a Emenda Constitucional 33/2001, é constitucional a incidência de ICMS sobre operações de importação efetuadas por pessoa, física ou jurídica, que não se dedica habitualmente ao comércio ou à prestação de serviços, devendo tal tributação estar prevista em lei complementar federal. II - As leis estaduais editadas após a EC 33/2001 e antes da entrada em vigor da Lei Complementar 114/2002, com o propósito de impor o ICMS sobre a referida operação, são válidas, mas produzem efeitos somente a partir da vigência da LC 114/2002." },
  { id: "stf-rg-1098", tribunal: "STF", tipo: "Repercussão Geral", numero: "1098", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Inclusão do montante correspondente ao Imposto Sobre Circulação de Mercadorias e Serviços (ICMS) destacado nas notas fiscais ou recolhido antecipadamente pelo substituto em regime de substituição tributária progressiva na base de cálculo da contribuição ao Programa de Integração Social (PIS) e da Contribuição para Financiamento da Seguridade Social (COFINS) devidas pelo substituído tributário.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1098",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à inclusão do montante correspondente ao Imposto Sobre Circulação de Mercadorias e Serviços (ICMS) destacado nas notas fiscais ou recolhido antecipadamente pelo substituto em regime de substituição tributária progressiva na base de cálculo da contribuição ao Programa de Integração Social (PIS) e da Contribuição para Financiamento da Seguridade Social (COFINS)." },
  { id: "stf-rg-1099", tribunal: "STF", tipo: "Repercussão Geral", numero: "1099", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Incidência de Imposto Sobre Circulação de Mercadorias e Serviços (ICMS) sobre o deslocamento de mercadorias de um estabelecimento para outro do mesmo contribuinte localizados em estados distintos.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1099",
    texto: "Não incide ICMS no deslocamento de bens de um estabelecimento para outro do mesmo contribuinte localizados em estados distintos, visto não haver a transferência da titularidade ou a realização de ato de mercancia." },
  { id: "stf-rg-1100", tribunal: "STF", tipo: "Repercussão Geral", numero: "1100", situacao: "Vigente", tema: "DIREITO TRIBUTÁRIO", titulo: "Definição individualizada da natureza jurídica de verbas percebidas pelo empregado, bem como de sua respectiva habitualidade, para fins de incidência da contribuição previdenciária a cargo do empregador sobre a folha de salários e demais rendimentos conforme o art. 22, I, da Lei nº 8.212/1991.", fonte: "https://portal.stf.jus.br/jurisprudenciaRepercussao/tema.asp?num=1100",
    texto: "É infraconstitucional, a ela se aplicando os efeitos da ausência de repercussão geral, a controvérsia relativa à definição individualizada da natureza jurídica de verbas percebidas pelo empregado, bem como de sua respectiva habitualidade, para fins de incidência da contribuição previdenciária a cargo do empregador conforme o art. 22, I, da Lei nº 8.212/1991." },
]);
